window.BEAUBIRD_BIRD_PROFILE_SHARDS["shard-007.json"] = [{"name":"白翅侏秧鸡","english_name":"White-winged Flufftail","scientific_name":"Sarothrura ayresi","overview":"白翅侏秧鸡（英文名：White-winged Flufftail，学名：Sarothrura ayresi），是鹤形目侏秧鸡科侏秧鸡属的鸟类。非洲特有种，体长14-16厘米，雄鸟头部和尾巴栗色，具白色翅膀，雌雄均有独特的白色翼斑。分布于埃塞俄比亚高海拔湿地和南非部分地区，极其罕见。","appearance":"体长约14至16厘米，雄鸟有栗色头冠和尾巴，雌雄均展示显著的白色翼斑，羽毛呈暗色，腹部白色，背部暗色，翼上有白色次级飞羽。性成熟个体的翼上覆羽有白色斑点，雌鸟背部更偏棕色，头部、颈部和胸部颜色较暗淡。","call":"发出低沉、短促的\"oop\"音，重复频率约为每秒一次，持续时间可达约3分钟，常以异步二重唱形式出现，第二只鸟的声音更高。还会有深沉的哞哞声和高音的短长呼叫声。","habits":"栖息于高海拔季节性湿地，偏好密集的莎草覆盖和浅水区。主要以水生昆虫、谷粒种子和植物碎片为食，也捕食蚯蚓、淡水甲壳类和陆地昆虫。在清晨和傍晚觅食。","breeding":"繁殖季节估计为6月至9月，正值雨季。在植被密集处筑巢，巢由编织的活莎草和草构成，内部铺垫干草和莎草。每次产卵4-5枚白色蛋，孵化由两性共同承担。","identification":"与其它Sarothrura物种相比，白翅侏秧鸡最显著的区别在于飞行时可见的白色翼斑，以及尾部的栗色和黑色条纹。幼鸟与成鸟相似，但有细微差异。","protection":"IUCN：CR（极危）","distribution":"分布于埃塞俄比亚高原湿地、津巴布韦和南非东部。在埃塞俄比亚的苏卢塔、伯加和比拉查湿地有记录，南非的杜尔斯特朗和瓦克斯特鲁姆湿地也有发现。","other":"面临栖息地丧失的严重威胁，尤其是过度放牧、莎草收割和湿地排水。"},{"name":"细嘴侏秧鸡","english_name":"Slender-billed Flufftail","scientific_name":"Sarothrura watersi","overview":"细嘴侏秧鸡（英文名：Slender-billed Flufftail，学名：Sarothrura watersi），是鹤形目侏秧鸡科侏秧鸡属的稀有鸟类。主要分布在马达加斯加东部的山地湿地区域，与雨林相邻。雄鸟具有丰富的赤褐色和橄榄绿羽毛，而雌鸟则为暗褐色，两者都具有长而细的喙。该物种面临栖息地丧失的威胁。","appearance":"细嘴侏秧鸡体长约14至17厘米，尾部短而略蓬松，喙长且纤细。雄鸟的羽毛颜色较为鲜明，头部、颈部、胸部和背部呈暗淡的栗色，上体暗褐色带有不明显的深色条纹，下体灰褐色无斑点，尾巴栗色，末端黑色。雌鸟颜色更低调，上体巧克力棕色，脸侧浅棕色，下体暗棕色，尾巴黑色，有白色和较宽的栗色横纹。幼鸟的描述不详，但可能比成鸟更暗淡，胸背部分的栗色范围较小。","call":"细嘴侏秧鸡的叫声独特，与马达加斯加的其他侏秧鸡种类不同，发出的是低沉而庄重的声音，通常由2到3个音节组成，被描述为“gu-duk gu-duk gu-duk...”或“GOO-goo”或“tok-tok-tok-tok...”，节奏逐渐加快，中间音节有时稍短，类似于马蹄声。还有一种报警叫声，被描述为“tiec”。","habits":"细嘴侏秧鸡栖息在海拔930至1300米的中高山区，偏好有莎草科植物的大型湿地，也出现在稻田附近。它们的生活方式较为隐秘，白天会发出领地叫声。有关其饮食和觅食方式的信息尚未可知。","breeding":"细嘴侏秧鸡的繁殖习性未知，可能在雨季繁殖。已知雄鸟和雌鸟在繁殖季节会有特定的行为表现，如在安达帕地区早期九月发现处于繁殖状态的个体，而在其他月份如十月、十一月和三月听到雄鸟的叫声。","identification":"细嘴侏秧鸡与更为常见的马岛侏秧鸡相比，喙更长更细，脚趾更长，颜色更暗淡。雄鸟的颜色相对单一，而雌鸟则更加低调，可以通过颜色和鸣叫声音进行区分。","protection":"IUCN：NT（近危）","distribution":"细嘴侏秧鸡分布在马达加斯加东部的山地，主要在安达帕、塔那那利佛、佩里奈特阿纳拉马扎特拉、兰诺马法纳/沃希帕拉拉和托罗托罗福齐沼泽等六个地点，分布零散且稀少。","other":"细嘴侏秧鸡的种群数量估计在250至999只成熟个体之间，总体分布范围约为5900平方公里。由于栖息地丧失，其生存状况堪忧。"},{"name":"栗秧鸡","english_name":"Chestnut Forest Rail","scientific_name":"Rallicula rubra","overview":"栗秧鸡（英文名：Chestnut Forest Rail，学名：Rallicula rubra），是鹤形目侏秧鸡科栗秧鸡属的鸟类。分布于新几内亚的鸟头半岛山区和西部至中东部，栖息于亚热带或热带湿润的山地森林。","appearance":"体型较小，长度介于18至23厘米之间，雄鸟具有深栗色的背部，翅膀部分带有黑色羽毛，而雌鸟的翅膀全黑并点缀以白色斑点。亚成年雄鸟嘴基灰色，腿脚呈暗酒红色，幼鸟特征未详述。","call":"发出尖锐刺耳的“krill”或“keow”叫声，有时会连续重复多次，有时叫声更像吱吱声。有记录显示，雄雌鸟会进行对鸣，叫声变得更快更尖锐。","habits":"活跃于山地森林中，即使是在惊恐时也会煽动翅膀，露出白色的斑点。觅食时极为积极，甚至急躁，会掀开树叶和苔藓寻找无脊椎动物。","breeding":"相关繁殖信息未提供。","identification":"与麦氏栗秧鸡相似但地理隔离，雄性栗秧鸡较浅色，尾部无明显黑纹；雌鸟与黑翅栗秧鸡和麦氏栗秧鸡相似，但侧翼有斑点，下体无黑条纹，与白纹栗秧鸡极其相似，但尾部无细窄黑纹。","protection":"IUCN：LC（无危）。在伊里安查亚广泛分布，其中rubra和klossi两亚种较为常见；telefolminensis亚种在Telefomin附近及维克多埃曼纽尔山脉和兴登堡山脉区域较为罕见，但在Tari Gap森林中的种群较为普遍。","distribution":"分布于澳新界的鸟头半岛山区（新几内亚西北部）和西部至新几内亚中东部。"},{"name":"白纹栗秧鸡","english_name":"White-striped Forest Rail","scientific_name":"Rallicula leucospila","overview":"白纹栗秧鸡（英文名：White-striped Forest Rail，学名：Rallicula leucospila），是鹤形目侏秧鸡科栗秧鸡属的鸟类。分布于新几内亚西北部的鸟头半岛山区。其胸部呈栗色，背部和翅膀深色，带有醒目的白色条纹，体型中等，行动敏捷，难以观察。","appearance":"白纹栗秧鸡体长20至23厘米，雄鸟体重约为114至125克。雄鸟的上体黑色，饰以精细的白色条纹，明显区别于新几内亚的其他Rallina属物种。雌鸟体色斑点而非条纹，与较小的栗秧鸡雌鸟相似，但具有较窄的黑色尾羽条纹和颈部后方的斑点。幼鸟和未成熟个体特征未详述。","call":"在新几内亚的鸟头半岛，白纹栗秧鸡发出类似‘ko..ko..ko’的轻柔咕哝声；接触叫声为低沉的喵喵声。在库马瓦山脉记录了三种不同的叫声，其中一种为一系列快速上升加速的音符，结尾处音符成组，每组首音比其余音符低两全音。","habits":"白纹栗秧鸡栖息于海拔1000至1850米的山地森林内部地面，常见于塔姆劳、阿夫拉克、万达曼和库马瓦山脉。它们生活在新几内亚的中高山森林中，具体包括Tamrau、Arfak、Wandammen和Kumawa等山区。","breeding":"关于白纹栗秧鸡的繁殖行为、巢穴、交配和育雏等细节信息尚未记载。","identification":"与相似的栗秧鸡相比，白纹栗秧鸡略大，后侧有横纹，雄鸟背部有白色条纹而非纯色，雌鸟尾部略微裸露，颈部后方有斑点。与更小的栗秧鸡雌鸟相比，白纹栗秧鸡的尾羽条纹较窄，且颈部上方的栗色区域较少。","protection":"IUCN：LC（无危）。虽然目前认为该物种全球未受威胁，但在过去曾被列为数据缺乏。在Vogelkop和库马瓦山脉有发现，但未出现在中间的Fakfak山脉。在Vogelkop地区较为害羞且数量不多，而在库马瓦山脉1983年和2013年的调查中，该物种显得嘈杂且常见。由于其山地森林生境可能相对安全，目前没有迹象显示该物种受到威胁，尽管在Vogelkop地区存在当地狗猎行为。","distribution":"白纹栗秧鸡分布于印尼西巴布亚的鸟头半岛山区，包括Tamrau、Arfak、Wandammen和Kumawa山脉。","other":"关于白纹栗秧鸡的更多生态学信息尚待研究。"},{"name":"黑翅栗秧鸡","english_name":"Forbes's Forest Rail","scientific_name":"Rallicula forbesi","overview":"黑翅栗秧鸡（英文名：Forbes's Forest Rail，学名：Rallicula forbesi），是鹤形目侏秧鸡科栗秧鸡属的鸟类。分布于新几内亚的山区中西部至东北部（Adelbert Range和休恩半岛）和新几内亚东南部。具有明显的外部特征，包括棕色的身体和尾巴，以及带有白色横纹或斑点的黑色翅膀。","appearance":"这种鸟的嘴比中趾短，翅膀圆形，第3枚初级飞羽最长。次级飞羽短于初级飞羽。飞羽和翅下覆羽为暗褐色或黑色，带有白色横纹或斑点。全长约23厘米，头顶、颈项、背部和内侧飞羽为棕褐色，带有黑色横斑。翅膀黑色，有白色斑纹，初级和次级飞羽也有白色横斑。胸部和腹部以下为红棕色，有白色粗横斑。嘴为浅黑色，基部红色，脚为亮红色。","call":"它的声音类似于白纹森林秧鸡和蓝喉蜂虎的加速‘wokwokwokwokwok…..’叫声。","habits":"栖息于芦苇沼泽地、稻田、芋田以及河流、水边的灌木丛和林间湿地。在开阔的山坡、白茅草地、村庄周围的灌丛和草地中也能发现其踪迹。以草籽、甲壳动物和昆虫等为食。","breeding":"实行单配制，繁殖季节有领域性，用树叶和草构建粗糙的巢，通常远离水源，在灌木或矮树上。每窝产卵3～6枚，卵呈卵圆形，石灰白色，有光泽，偶尔带有少量模糊的暗红棕色斑点，由两性共同孵卵。","identification":"与栗色森林秧鸡相似，但黑翅栗秧鸡通常出现在较低海拔，雌鸟的后侧有条纹而非淡色斑点，且其翼部的斑点为淡黄色而非白色。","protection":"IUCN：LC（无危）","distribution":"分布于澳新界：山区中西部至东北部（Adelbert Range和休恩半岛）和新几内亚东南部。","other":"与白纹栗秧鸡和麦氏栗秧鸡关系密切，已确认四种亚种。"},{"name":"麦氏栗秧鸡","english_name":"Mayr's Forest Rail","scientific_name":"Rallicula mayri","overview":"麦氏栗秧鸡（英文名：Mayr's Forest Rail，学名：Rallicula mayri），是鹤形目侏秧鸡科栗秧鸡属的鸟类。相对较小的秧鸡，全身均匀呈红褐色，翅膀和背部为棕色，胸部和面部颜色较淡。分布于新几内亚中北部山区，常在海拔1100至2200米的山地森林地面活动。","appearance":"麦氏栗秧鸡体型较为小巧，整体毛色统一为红褐色，其翅膀和背部呈现棕色，而胸部与面部的色彩则更为柔和。雌鸟的翅膀上点缀着许多淡黄色斑点，更显独特。","habits":"麦氏栗秧鸡偏好在地面奔跑而非飞翔，栖息于新几内亚中北部的山地森林，活动范围集中在海拔1100到2200米之间。它们在特定的孤立山脉中分布，展现出独特的生态位。","identification":"在它的分布范围内，麦氏栗秧鸡是唯一的一种森林秧鸡，没有其他同属物种与其重叠分布，这使得它在识别上较为容易。","protection":"IUCN：LC（无危）","distribution":"麦氏栗秧鸡主要分布在新几内亚的中北部山区，具体可见于四个孤立的沿海山脉。在Foja山脉中，它们被记录为罕见到相当常见的种类。","other":"自上世纪60年代以来，麦氏栗秧鸡被认为在其安全栖息地中相对常见，然而在1992年的Cyclops山脉考察中并未发现其踪迹。"},{"name":"非洲鳍趾䴘","english_name":"African Finfoot","scientific_name":"Podica senegalensis","overview":"非洲鳍趾䴘（英文名：African Finfoot，学名：Podica senegalensis），是鹤形目日䴘科非洲鳍趾䴘属的鸟类。具有独特外形的水生鸟类。在非洲西部、中部及南部的河流湖泊中栖息，以鲜艳的橙色喙和腿著称。其体羽色彩随种族而异，一般底色较淡，背羽偏暗，雄鸟通常比雌鸟色泽更深。非洲鳍趾䴘在繁殖季节喉部呈灰色，非繁殖季变为白色，雌雄差异明显。","appearance":"非洲鳍趾䴘身长35至59厘米，体重338至879克。尾羽显著硬化，腕关节有小骨节，第一趾带有锐利爪，腿脚鲜红至橙色。雄鸟繁殖季节喉部灰白，非繁殖季转白；雌鸟较小，色调更棕，头部和颈部白纹较多。幼鸟与雌鸟相似，但上体暖棕色，无斑点，胸部淡黄色，侧腹有淡色斑点。物种变异大，不同个体间差异显著，包括背部白点数量、下体斑驳程度和羽毛色泽深浅。","call":"通常较为安静，但会发出类似咆哮牛或低沉隆隆声的鸣唱，其间穿插笛声般的‘pay-pay’音符。另有断续的犬吠‘kwark’声（雌鸟呼唤幼鸟）、爆发性的‘p-r-r-r’声、尖细的鸭雏般‘pay, pay-pay, pay’叫声（幼鸟），以及被捕时发出的低沉咆哮声，随后变成微弱的尖叫。","habits":"栖息于常年河流、湖泊、池塘等水域，偏好植被丰富的河岸，如芦苇丛和悬垂树荫。常见于森林地带，亦出现在林木稀疏的草原。偶尔在开阔地带观察到。主要以各种水生无脊椎动物为食，包括昆虫、蜘蛛、甲壳类、螺类、蛙类和小鱼，偶尔摄取植物。既在水中觅食，也在陆地上活动，善于捕捉水面和岩石、植物上的猎物。","breeding":"繁殖季节随地理位置而变，通常与高水位期相吻合。筑巢于水上1至4米处，巢由杂乱的芦苇和树枝构成，直径240至340毫米，深90至130毫米，内衬干叶或绿色苔藓。每窝产卵2枚，卵呈土褐色，带红色、紫色或蓝灰色斑点。孵化由雌鸟独自承担，雄鸟常在附近。孵化期约为12天以上。幼鸟出生后数日内离开巢穴，主要由雌鸟照料。","identification":"非洲鳍趾䴘的短颈和明亮的喙脚使其与鸬鹚和鱼狗区别开来。雄鸟喉部颜色在繁殖季与非繁殖季不同，雌鸟体型较小，色调偏棕。幼鸟与雌鸟相似，但具有一些独特的颜色模式。不同亚种间存在体型、颜色深浅和斑点分布的差异。","protection":"IUCN：LC（无危）非洲鳍趾䴘虽广泛分布，但密度不高，因隐秘习性而被视为罕见。在适宜生境中并不罕见，但在南非被认为受威胁，部分区域已消失。整个物种范围内，适宜的森林河流环境正在减少，由于观测困难，种群下降可能被忽视。","distribution":"非洲鳍趾䴘分布于非洲西部、中部和南部，包括森林、林木稀疏的草原、洪水泛滥的森林和红树林沼泽等各类水域。"},{"name":"亚洲鳍趾䴘","english_name":"Masked Finfoot","scientific_name":"Heliopais personatus","overview":"亚洲鳍趾䴘（英文名：Masked Finfoot，学名：Heliopais personatus），是鹤形目日䴘科亚洲鳍趾䴘属的鸟类。因其独特的黑面具延伸至喉咙而得名，雄鸟面部的黑色面具更显深邃和广阔。广泛分布于远东地区的印度东北部至东南亚，但在一些地区因栖息地破坏已极为罕见。","appearance":"亚洲鳍趾䴘体长43-55厘米，整体呈灰褐色，雄鸟具有完整的黑色面具和白色上颚基部。雌鸟比雄鸟略小，具白色下巴、喉咙和额头斑块。幼鸟似雌鸟，但缺乏冠部黑色。","call":"发出深沉的气泡声，像是水下吹出的大泡泡，随后是一连串加速的咯咯声，用于远距离交流。雌鸟在巢中会发出低沉的‘ga ga ga gackga gack’叫声，觅食时会发出独特的‘gurr’声。还有响亮尖锐的警报声‘kui-kui-kui…’或刺耳的‘keek-keek-keek’。","habits":"栖息于植被丰富的湿地，包括沼泽、过水池塘、湖泊边缘、溪流、缓慢流动的森林水域、潮汐沟渠，通常在水边悬垂的植被中。活动以晨昏为主，单独或成对出现，偶尔小家庭群。以水生昆虫、软体动物、蛙类、甲壳类、小鱼和少量植物为食，通过潜水和水面觅食。","breeding":"繁殖季节在雨季，确切时间未知。在柬埔寨，7月中旬发现带有卵的巢，9月发现幼鸟，表明确实在雨季筑巢。巢由小枯枝构成，有时铺有枯叶或其他植被，隐藏于离水面2-3米高的植被中。每窝产卵3-8枚，蛋壳呈淡奶油色，带有淡蓝灰色、鼠灰色、中棕色和深紫色斑点，平均大小51.2mm x 42.2mm。幼鸟出生后第二天即可离巢。","identification":"尾羽稍硬，不如非洲鳍趾䴘那么显著，飞行时尾巴显得宽圆。浅色腹面有轻微条纹，腿和脚绿色带黑色脚趾，喙和头部突出的肉质结节鲜黄色，虹膜红棕色。雌雄差异在于面具和下巴的颜色，幼鸟缺乏成年雄鸟的黑色面具。","protection":"IUCN：CR（极危）","distribution":"繁殖区位于印度东北部和东南亚，非繁殖区罕见至印尼苏门答腊岛和婆罗洲。在泰国、马来西亚、印尼和新加坡可能已被根除，主要繁殖地在孟加拉国南部的Sundarbans和缅甸西北部。","other":"面临的主要威胁有人类干扰和低地森林湿地的丧失，尤其是Sundarbans面临大型燃煤电厂建设的威胁。"},{"name":"日䴘","english_name":"Sungrebe","scientific_name":"Heliornis fulica","overview":"日䴘（英文名：Sungrebe，学名：Heliornis fulica），是鹤形目日䴘科日䴘属的鸟类。适应于游泳和潜水，脚部具有类似䴙䴘的瓣状蹼。分布于中美洲至南美洲，从墨西哥东南部延伸至阿根廷东北部，偏好热带低地的静水环境。","appearance":"日䴘是一种小型、身形修长的水鸟，平均长度约30厘米，体重介于110至140克之间。头部和颈部的羽毛以黑色为主，两侧有显著的白色条纹，喉咙和下巴呈白色。雌鸟脸颊处有橙色斑块，雄鸟则无此特征。其尾巴较长，占总身长近三分之一，飞行时明显伸出。脚部和腿部裸露皮肤呈黄色与黑色相间的带状。成年雄鸟和雌鸟在外观上相似，但雌鸟的脸颊在繁殖季节会变为鲜艳的肉桂橙色，且下喙底部颜色由暗红转为鲜红。幼鸟体型略小，羽毛色调偏灰，脸颊和颈部有更多的白色。","habits":"日䴘栖息于植被茂密的淡水湿地，偏好安静的森林溪流、河流、湖泊边缘等隐蔽水域。它们主要以螺类、昆虫、小鱼、青蛙和蜥蜴为食，偶尔摄取植物种子和果实。日䴘通常独居或成对出现，非迁徙性，随季节变化在湿润和干燥的栖息地间移动。","breeding":"繁殖期始于四月中旬的雨季，雌雄共同筑巢，巢位于水面一米左右的高度，由枝条、芦苇和干叶构成。每窝产卵2至4枚，孵化期仅10至11天。雏鸟出生时为盲弱状态，由雄鸟通过翼下的特殊皮囊携带和照料，直至能独立游泳和觅食。","identification":"日䴘的黑白条纹头部和颈部，以及雄鸟翼下的特殊皮囊用于携带幼鸟，是其独特的识别特征。与鸭类和䴙䴘相比，日䴘的体型更小，且头部和颈部的条纹明显。","protection":"IUCN：LC（无危）","distribution":"日䴘分布于中美洲至南美洲，具体范围从墨西哥东南部至阿根廷东北部，包括整个奥里诺科河和亚马逊河流域、潘塔纳尔湿地及巴西大西洋雨林。它们不在大多数加勒比国家中出现，似乎难以跨越广阔的盐水区。"},{"name":"灰翅喇叭声鹤","english_name":"Grey-winged Trumpeter","scientific_name":"Psophia crepitans","overview":"灰翅喇叭声鹤（英文名：Grey-winged Trumpeter，学名：Psophia crepitans），是鹤形目喇叭鸟科喇叭鸟属的鸟类。鸡类大小的陆栖鸟类，分布于南美洲亚马逊雨林北部。其独特的外形、习性和群居生活方式使其在雨林中难以混淆。这种鸟常见于未受猎捕影响的地区。","appearance":"灰翅喇叭声鹤具有长颈和长腿，背部呈隆起状。其灰白色的内翅和臀部与黑色躯体形成鲜明对比，构成显著的后翼斑点，边界处有一条栗棕色条纹。雌雄羽毛相似，雄鸟体型略大。颈部细长，头部看似较小，覆盖着短而密集的丝绒般羽毛。眼睛深褐色，喙尖锐、粗壮，微向下弯曲，类似鸡类。身体宽大，翅膀半开，遮掩短尾及部分身体。背部中间的栗棕色条纹与灰白的内翅及臀部共同形成一大片‘后翼斑’。","call":"能发出非常响亮的声音，尤其是受到惊吓时，会发出一系列奇怪的叫声，包括各种呼噜声、哀号和尖叫。","habits":"栖息于茂密的低地热带雨林，偏好远离人类居住区、林下层开阔、果实丰富的环境。通常以15只左右的群体生活，维护大片领地。它们全年留居在领地范围内，不跨过大型河流。主要以森林地面掉落的软果为食，也会食用小节肢动物，尤其是跟随蚁群时捕获的。雏鸟早期饮食中昆虫比例较高。","breeding":"实行一雌多雄制，由一群中的主导雌鸟与多达三只雄鸟交配，所有成员共同参与育雏。通常利用其他物种挖掘的树洞筑巢，有时利用自然裂缝。繁殖期通常与雨季开始同步，此时食物和昆虫丰富。每窝产卵2至4枚，通常为3枚。","identification":"与同属的白翅喇叭声鹤和绿翅喇叭声鹤相比，可通过翼和臀部的颜色轻松区分。白翅喇叭声鹤的后翼斑为白色或赭色，而绿翅喇叭声鹤的翅膀颜色较深，整体呈绿色光泽。","protection":"IUCN：LC（无危）","distribution":"分布于巴西、哥伦比亚、厄瓜多尔、法属圭亚那、圭亚那、秘鲁、苏里南和委内瑞拉的亚马逊雨林北部区域。","other":"在一些土著社区附近，灰翅喇叭声鹤被驯化用作哨兵，因其敏锐的警觉性和响亮的报警叫声。"},{"name":"白翅喇叭声鹤","english_name":"Pale-winged Trumpeter","scientific_name":"Psophia leucoptera","overview":"白翅喇叭声鹤（英文名：Pale-winged Trumpeter，学名：Psophia leucoptera），是鹤形目喇叭鸟科喇叭鸟属的大型鸟类，主要分布在南美洲的亚马逊雨林西部，包括秘鲁、玻利维亚和巴西的特定区域。其最显著的特征是拥有白色的翼部斑块，黑色的球形身体，黄色的喙，以及长腿。","appearance":"体长约45至52厘米，体重方面，雄鸟约为1.28到1.44千克，雌鸟约为1.18到1.32千克。全身几乎呈黑色，拥有独特的白色翼部斑块，下喉部缺乏绿色光泽，而外翼覆羽尖端带有紫色、绿色和青铜色的虹彩光泽。喙和腿为淡灰色，基部呈黄色。雌雄外观相似，幼鸟与成鸟相仿，只是轮廓羽毛的尖端有暗褐色边缘。","call":"发出低沉的振动音符组成的歌曲，每音节约1.5秒长。群体中的其他成员会加入一系列低沉、短促的‘呜’声，频率约每秒3至4次。此外，群体还会发出各种粗糙、尖锐或嘶哑的叫声，偶尔变得像咯咯声，叫声与同类相似。","habits":"生活在成熟的热带湿润森林中，从低地到海拔750米的高度，远离人类居住区。它们是非迁徙性的，全年保卫领地。主要以成熟果实的果肉为食，占饮食的90%，偶尔也会捕食节肢动物、环节动物和小型脊椎动物，如蛇。在野外，个体平均每天摄食量在低果期为260千焦耳，在高果期为470千焦耳。","breeding":"繁殖季节通常在9月至次年4月。形成合作多雄制群体，巢址位于树干中空处，平均高度11米，不筑巢。每次产卵2至4枚，一般为3枚，蛋白色，尺寸60至69毫米×47至50毫米，孵化期23至29天。雏鸟主要呈赤褐色，腹部奶油色，喉咙和上胸覆盖黑色围嘴；一条黑边白条纹从上颚后延伸至颈部底部，背部有四条类似条纹。雏鸟在孵化后第二天早晨跳出巢穴，前三周完全依赖成鸟喂食，直到大约3个月大时才逐渐独立。","identification":"与灰翅喇叭声鹤相比，白翅喇叭声鹤的后翼斑块为白色，下喉部无绿色光泽，外翼覆羽尖端带虹彩光泽，形态上更为独特。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲的亚马逊雨林西部，包括秘鲁东部、哥伦比亚东南部（莱蒂西亚）、巴西中部以南的亚马逊河和马代拉河以西地区，以及玻利维亚北部和东部。","other":"在过去的一个世纪里，由于火器的普及，狩猎压力增大，导致其数量减少。在未受干扰的雨林中相对普遍，但在以前常见的许多地区现在变得罕见或消失。"},{"name":"绿翅喇叭声鹤","english_name":"Dark-winged Trumpeter","scientific_name":"Psophia viridis","appearance":"绿翅喇叭声鹤身长45至52厘米，通体大致为黑色，雌雄外观相似。翼部颜色在西部种群中呈深绿色，在东部种群中则为黑色。喉部下方有紫色金属光泽，外侧翼羽尖端同样具有紫色金属光泽。喙和脚部颜色从暗褐色到橄榄绿色不等。幼鸟与成鸟相似，但翼部和下体的金属光泽较淡。","call":"其鸣叫声为一系列低沉的哼鸣音，起初单独发出，随后加倍重复。当受惊扰时，会发出急促、刺耳的‘tset’音，有时带有嘎嘎声。","habits":"绿翅喇叭声鹤生活在远离人类居住区的成熟热带湿润森林中，被认为是定居和领地性的。它们以小组形式活动，数量至少三只，最多可达19只。食谱包括果实、节肢动物、小型脊椎动物和腐肉，有时跟随行军蚁群以捕食被惊扰的昆虫。","breeding":"关于繁殖生物学知之甚少。一月份在帕拉州发现的一只雌鸟卵巢中带有大蛋，而亚马逊州的群体中，三月初有估计约10至15天大的较小幼鸟。圈养条件下，一窝可孵化五个蛋，其中一个蛋在27天后孵化。雏鸟覆盖着黑色绒毛。","identification":"与灰翅喇叭声鹤相比，绿翅喇叭声鹤的后翼斑块呈深绿色，与肩部颜色一致。Psophia dextralis的肩部和后翼斑块从棕色过渡到橄榄棕色，颈部和外翼覆羽缺乏色彩。Psophia obscura与Psophia dextralis非常相似，但在下颈和外翼覆羽上有少量紫色金属光泽。","protection":"IUCN：VU（易危）。","distribution":"绿翅喇叭声鹤分布于巴西南部的亚马孙河以南地区，包括马德拉河与塔帕若斯河之间、托坎廷斯河东侧的帕拉州东北部和马拉尼昂州西部。在玻利维亚东北部有零星记录，但其存在尚待确认。","other":"绿翅喇叭声鹤的系统发育历史显示它与其它同属物种关系密切，但分子证据支持其作为独立物种的地位。"},{"name":"灰冕鹤","english_name":"Grey Crowned Crane","scientific_name":"Balearica regulorum","overview":"灰冕鹤（英文名：Grey Crowned Crane，学名：Balearica regulorum），是鹤形目鹤科冕鹤属的鸟类。又名: 东非冠鹤，小型鹤类，们是留鸟，广泛分布于撒哈拉以南非洲的干旱大草原，尤其在东部和南部非洲常见。乌干达将其视为国鸟，出现在国家旗帜和徽章上。灰冕鹤拥有独特的金色羽冠和红白相间的面部特征。","appearance":"灰冕鹤高约1米，重约3.5公斤，翼展可达2米。其身体羽毛主要为浅蓝灰色，翅膀上有一块显著的黑色区域，头部戴着一顶由金色羽毛组成的冠状装饰。脸部两侧为白色，带有一个鲜艳的红色可膨胀喉囊。喙短且呈灰色，腿为黑色。性别外观相似，但雄鸟略大。幼鸟较成鸟灰色更深，面部有淡黄色绒毛。","call":"灰冕鹤发出低沉哀婉的‘maaah-hem’叫声，叫声中包含浑厚的鸣音。","habits":"灰冕鹤偏好湿地、泛洪草甸和人造水体，但在觅食时会广泛活动于各种开阔生境。它们在东非全年可见，而在南非则可能因雨量变化而局部游荡。灰冕鹤在混合了湿地和开阔草地或灌木丛的环境中栖息，也会在人类改造的生境如牧场、农田、休耕田和灌溉区活动。它们会在水中、树上或电线杆上过夜。","breeding":"灰冕鹤的繁殖季节受雨水影响，东非全年繁殖，高峰期在干燥期；南非干旱地区主要在雨季繁殖，大约10月至翌年4月，高峰期在12月至2月。巢建在湿地边缘，偶尔在树上，由拔起的草和莎草堆砌成圆形平台，隐藏在周围水生植被中。每次产卵1至4枚，平均窝卵数超过2.5枚，是所有鹤类中最大的。孵化期为28至31天，雏鸟出生时呈褐色至棕色，头部为淡黄色。离巢时间为56至100天。性成熟年龄为三岁（有时为两岁）。","identification":"灰冕鹤与黑冕鹤的区别在于其淡灰色的颈部和较大的红色喉囊；白色面颊斑仅顶部有红色。亚种gibbericeps的面颊斑比指名亚种regulorum有更多的红色。","protection":"IUCN：EN（濒危）","distribution":"灰冕鹤主要分布于非洲东部和东南部，包括乌干达、刚果民主共和国东部、肯尼亚、坦桑尼亚、莫桑比克、安哥拉和南非。在乌干达，灰冕鹤被尊为国鸟。","other":"灰冕鹤在某些地区受到当地文化传统中的尊重和保护。然而，由于快速的人口增长、土地使用变化、农药使用增加和其他因素，其栖息地正遭受威胁，导致全球数量自1985年以来明显下降。"},{"name":"黑冕鹤","english_name":"Black Crowned Crane","scientific_name":"Balearica pavonina","overview":"黑冕鹤（英文名：Black Crowned Crane，学名：Balearica pavonina），是鹤形目鹤科冕鹤属的独特鸟类，以其显著的金色羽毛冠和大部分黑色的羽毛著称。分布于撒哈拉以南非洲的干旱大草原，偏好浅湿地和草甸，尤其在雨季时。黑冕鹤分为两个亚种：西非的B. p. pavonina和东非的B. p. ceciliae，后者数量较多。黑冕鹤不仅是尼日利亚的国鸟，而且在文化和生态上具有重要意义。","appearance":"黑冕鹤体长约100至105厘米，体重介于3000至4000克之间，翼展可达180至200厘米。最显著的特征是其金色的羽毛冠，由螺旋状、一端白色一端棕色的刚毛组成，顶端呈黑色。虹膜呈淡灰色到淡蓝色。成鸟羽毛大多为深灰色至黑色，翅膀上有明显的白色斑块，脸颊上有一片粉红色和白色的斑点，以及红色的下颊斑。幼鸟整体呈灰色，头部和颈背为棕色，虹膜也是棕色的。两亚种间存在差异，特别是在颊斑的红色延伸程度和体型大小上。","call":"黑冕鹤的叫声为低沉的‘honk’声和‘ka-wonk’音，通常在飞行中发出，声音温和，与灰冕鹤的声音有所区别。","habits":"黑冕鹤生活在撒哈拉以南非洲的湿草甸和干燥的田野中，倾向于浅湿地环境。它们以昆虫、无脊椎动物、鱼类、两栖动物、小型爬行动物以及谷物和草籽为食。黑冕鹤在旱季会聚集在较大的永久湿地附近，而在雨季则分散到较小的临时湿地繁殖。它们有时会在牛羊群附近觅食，因为那里昆虫更为丰富。","breeding":"繁殖期通常在7月至10月，但受雨季影响较大。巢由双亲共同建造，位于密集的湿地边缘，由草和水生植物构成的圆形平台。每次产卵2至3枚，孵化期为28至31天，由双亲轮流孵卵。雏鸟孵化后不久即可随父母觅食，约在60至100天后离巢。","identification":"与灰冕鹤相比，黑冕鹤的底色更暗，脸部的粉色更多，两者在分布上很少重叠。黑冕鹤的幼鸟与成鸟在颜色上有明显差异，而两个亚种间的辨识主要依据颊斑的红色延伸程度。","protection":"IUCN：VU（易危）","distribution":"黑冕鹤分布于非洲东北部、中部和西部，从塞内加尔盆地和几内亚比绍排水区到埃塞俄比亚高地和东非西南部裂谷。西非亚种主要分布在西部，而东非亚种则主要分布在东部，特别是在苏丹的数量最多。","other":"黑冕鹤因其栖息地丧失和退化面临重大威胁，特别是农业发展、水利项目和狩猎贸易。在一些地区，如马里和苏丹，猎杀和贸易问题尤为严重。"},{"name":"白鹤","english_name":"Siberian Crane","scientific_name":"Leucogeranus leucogeranus","overview":"白鹤（英文名：Siberian Crane，学名：Leucogeranus leucogeranus），是鹤形目鹤科白鹤属的鸟类。别名: 西伯利亚鹤、黑袖鹤，大型涉禽，体长约130厘米。通体白色，翼端黑色，脸部鲜红，嘴赭红色，脚浅肉红色。栖息于芦苇沼泽湿地，主要分布于东北至长江中下游，沿海及新疆。鄱阳湖为其主要越冬地，以水位下降后露出的植物球茎及嫩根为食。中国国家一级保护动物，IUCN：CR（极危）。","appearance":"成鸟体长140厘米，体重4900–8620克，翼展210–230厘米，雄鸟略大于雌鸟。通体白色，脸部与头部侧面裸露部分为鲜艳的红色，翼端黑色。幼鸟体羽近白，头、颈、背及双翼均为浅棕色。黄色虹膜。","call":"鸣声清脆如笛，音乐般悦耳，与其它鹤类截然不同。","habits":"栖息于低地苔原及开阔湿地，偏好视线不受限制的环境。迁徙时，依赖沿途的大片孤立湿地作为休息站。在中国鄱阳湖越冬，主要食物为水生植物的地下茎和根，辅以少量动物。在中国，主要分布于东北至长江中下游，沿海及新疆。","breeding":"春季繁殖，5月下旬至6月中旬产卵，通常产两枚，孵化期27-29天。雏鸟85天后具有飞翔能力，但因幼鹤间强烈的攻击性，通常仅一只幼鹤能存活至飞行。繁殖地主要在西伯利亚的低地苔原。","identification":"与其他白色鹤类如美洲鹤和丹顶鹤的区别在于全白的头部，以及从喙部延伸至眼后的深红色面具。","protection":"IUCN：CR（极危）。CITES附录I。全球数量在极度快速减少，主要威胁来自三峡大坝等水利建设导致的栖息地改变，以及迁徙路线上的猎杀。","distribution":"繁殖区位于西伯利亚的西北部和中东部。非繁殖区包括伊朗、印度北部与中国南部，尤其是鄱阳湖。","other":"人工繁殖取得一定成功，但野外数量持续下降，主要受栖息地丧失和人为干扰影响。"},{"name":"沙丘鹤","english_name":"Sandhill Crane","scientific_name":"Antigone canadensis","overview":"沙丘鹤（英文名：Sandhill Crane，学名：Antigone canadensis），是鹤形目鹤科鹤属的鸟类。大型鹤科鸟类，体长可达120厘米，翼展约200厘米，全身灰羽，头顶有醒目的红色裸露皮肤。栖息于北美的广阔草原、湿地和农田，以及西伯利亚东北部。沙丘鹤在迁徙季节形成壮观的大规模群体，尤其在迁徙停歇地和越冬地，数量可达数万。在中国偶有记录，被列为国家二级保护动物。","appearance":"沙丘鹤体型庞大，身长1.0至1.2米，翼展1.8至2.0米，随亚种和性别差异而有所不同。羽毛灰色，有锈色斑点，成年个体头顶有红色裸露皮肤，脚和喙为深绿色至黑色。幼鸟具有橙棕色的绒毛，背部和翅膀上带有锈色。雄鸟通常比雌鸟大。","call":"沙丘鹤的叫声嘹亮，如同号角，传播甚远，尤其在迁徙和冬季聚集地最为明显。伴侣间会进行同步鸣叫，这是一种复杂而协调的二重奏。","habits":"沙丘鹤栖息于开阔的草原、牧场和淡水湿地，迁徙期间偏好在农业田地觅食，尤其是收获后的玉米残茬。它们生活在家庭群中，迁徙和越冬时会与其他无亲缘关系的个体组成生存群体，数量可达数千。","breeding":"繁殖期在5月至7月，沙丘鹤实行一夫一妻制，求偶时会有复杂的叫声和舞蹈。巢筑于靠近水源的灌木丛中或沙地上，通常产卵1至2枚，卵呈橄榄褐色。父母双方共同孵化，幼鸟出生后很快就能跟随父母移动。","identification":"沙丘鹤与美洲鹤相比体型较小，主要呈灰色而非白色，且一级飞羽尖端为黑色。与其他鹤类相比，沙丘鹤的脚和腿更长，飞行时脖子伸直，与缩颈的鹭类不同。","protection":"IUCN：LC（无危）。然而，某些亚种如古巴亚种和佛罗里达亚种被列为华盛顿公约附录一保护物种。","distribution":"繁殖区域广泛分布于北美，从美国东北部到加拿大中部，直至阿拉斯加和西伯利亚东部。越冬地至墨西哥中北部，偶见于中国。","other":"沙丘鹤拥有长达35年的野外寿命。首次繁殖年龄因亚种、个体发育而异，一般在2至8岁之间。它们的迁徙和越冬地聚集数量巨大，曾尝试利用沙丘鹤作为美洲鹤的养父母，但并未成功。"},{"name":"白枕鹤","english_name":"White-naped Crane","scientific_name":"Antigone vipio","overview":"白枕鹤（英文名：White-naped Crane，学名：Antigone vipio），是鹤形目鹤科鹤属的鸟类。又名: 红面鹤、白顶鹤，体形与丹顶鹤相似但略小的鹤科鹤属鸟类。其最显著的外部特征是珍珠灰色的体羽、红色的脸颊以及从头顶延伸至后颈的白色条纹。分布于黑龙江、吉林等省或更北的广大地区繁殖，冬季部分迁徙至江苏、安徽、江西等省的湿地越冬。","appearance":"成年白枕鹤体长约112-125厘米，高约130厘米，体重约为5.6公斤，拥有粉色的腿，颈部为灰色和白色条纹相间，脸部有一片红色斑块。亚成鸟与成鸟相似，但上体略带棕色。它们的飞羽长而下垂，赋予了它们优雅的体态。","call":"会发出尖锐刺耳的叫声，以及近距离时的低沉接触叫声。在飞行意图和侵略性的守卫叫声中，两性之间存在差异。","habits":"栖息于开阔平原的芦苇沼泽和水草沼泽地带，偏好靠近河流和湖泊的沼泽草地。饮食主要包括植物种子、草根、嫩叶、谷物、小型动物如鱼、蛙、蜥蜴、蝌蚪、虾、软体动物和昆虫。迁徙和越冬时，多由数个或十多个家庭群组成大群活动。","breeding":"繁殖期为春季，通常在4月至5月底产卵。巢由枯萎的芦苇和草构成，位于浅水区。每窝产卵2枚，孵化期大约为28-32天。雏鸟出生后不久即可站立行走，70-75天后便可飞翔。","identification":"与白头鹤和灰鹤相比，白枕鹤更不耐干旱环境，且常集成较小的群体。可通过其独特的红脸和白色颈纹进行辨识。","protection":"IUCN：VU（易危）; 中国国家保护级别：I级","distribution":"繁殖于西伯利亚东南部、蒙古东北部和中国东北部。非繁殖期分布于朝鲜半岛、日本南部和长江流域。","other":"自1950年代以来，由于栖息地丧失、狩猎和战争的影响，数量逐渐减少。近年来，由于繁殖和越冬栖息地的损失，特别是中国东北的三江平原和蒙古东部，数量迅速下降。"},{"name":"赤颈鹤","english_name":"Sarus Crane","scientific_name":"Antigone antigone","overview":"赤颈鹤（英文名：Sarus Crane，学名：Antigone antigone），是鹤形目鹤科鹤属的鸟类。鹤科鹤属的大型鸟类，体羽呈淡灰色，颈部裸露红色皮肤，展翅时可见黑色的初级飞羽和白色修长的内侧飞羽。分布于印度北部、东南亚和澳大利亚北部，尤其在印度被视为婚姻忠诚的象征。","appearance":"成鸟高约1.8米，为世界上最高的飞鸟，体羽灰白，头部、颈部上部裸露红色皮肤，初级飞羽和覆羽黑色，内侧飞羽白色，脚粉红色。幼鸟头颈部完全被覆羽毛，颜色偏黄褐色。雄鸟体型大于雌鸟。","call":"发出响亮且持久的喇叭声，叫声穿透力强，成对鸣叫时声音更为震撼。","habits":"栖息于开阔的草地、沼泽、湖边浅滩和农田地带。留鸟，性情胆小机警，以鱼、蛙、虾、蜥蜴、谷物和水生植物为食，晨昏活动频繁，常单独、成对或家族群活动。","breeding":"繁殖期7月至12月，巢建于沼泽植物丛中，以水生植物筑成。每窝产卵2枚，孵化期30天，双亲共同育雏。","identification":"赤颈鹤与澳洲鹤相比，体型略大，颈部无肉垂，头部红色更明显。","protection":"IUCN：VU（易危），CITES: 附录II，中国国家重点保护等级：一级。栖息地破坏和过度捕猎是其濒危的主要原因。","distribution":"分布于印度北部、东南亚（缅甸至越南）、澳大利亚北部。在中国仅见于云南。","other":"在印度文化中，赤颈鹤被视为婚姻忠诚的象征，有传说称一对赤颈鹤中的一个死亡后，另一个会因悲伤而死。"},{"name":"澳洲鹤","english_name":"Brolga","scientific_name":"Antigone rubicunda","overview":"澳洲鹤（英文名：Brolga，学名：Antigone rubicunda），是鹤形目鹤科鹤属的鸟类。大型留鸟，身高约1.55米，体长约160厘米，主要分布于澳大利亚东部、北部及新几内亚低地。其头部除具纤细黑羽毛外，其余裸露，顶和额部淡绿色，两侧和颈项红色，喉部悬挂黑色肉垂。","appearance":"澳洲鹤具有灰色体羽，头部裸露部分呈淡绿色，两侧和颈项红色。喉部有黑色肉垂，腿和脚黑色。成年个体身高1.6至2.4米，翼展2至2.3米，雄鸟平均体重6.8公斤，雌鸟平均5.66公斤，体重范围3.6至8.7公斤。雄鸟高度可达1.8米。雄鸟略大于雌鸟，虹膜橙色。","call":"叫声比其他鹤类更低沉、更浑厚。","habits":"栖息于湿地、洪泛平原及草地，偏好淡水沼泽，水深不超过50厘米，但也使用较深的沼泽、湿润草甸和咸水湿地。随季节变化移动，冬季至传统群聚区，夏季分散至繁殖地。饮食广泛，包括莎草块茎、昆虫、甲壳类、蛙类、小型哺乳动物和鸟类，以及农田中的谷物和坚果作物。","breeding":"繁殖期随雨季而定，北澳2月至5月，南澳9月至12月。筑巢于水位上升的密集植被湿地，通常产两枚卵，孵化期28至31天，幼鸟灰身，淡黄色头颈，约100天离巢。3至5岁性成熟。","identification":"与赤颈鹤相比，体型略小，喉部肉垂较小，全身羽毛均匀灰色，腿色更深，裸露皮肤仅限头部。幼鸟头部全被羽毛覆盖，虹膜深棕色。","protection":"IUCN：LC（无危）","distribution":"分布于澳大利亚北部、中部、东部，以及新几内亚的Trans-Fly地区。在澳大利亚南部，数量有所下降。","other":"受栖息地破坏影响，尤其是农田扩张、湿地排水和外来物种入侵。"},{"name":"肉垂鹤","english_name":"Wattled Crane","scientific_name":"Grus carunculata","overview":"肉垂鹤（英文名：Wattled Crane，学名：Grus carunculata），是鹤形目鹤科鹤属的鸟类。又名: 吐绶鹤。大型鸟类，身高达175厘米，是非洲四种鹤中最高大的。全身羽毛主要呈灰色，胸腹部黑色，头白色；喙红，两颌各有一个红色的扇形肉垂。雄鹤裸露的头顶呈灰色，雌鹤则带白色。广泛分布于东部和南部非洲，从埃塞俄比亚至南非。","appearance":"肉垂鹤拥有醒目的白颈，颈部下方悬挂着显眼的肉垂，面部皮肤部分呈现红色。其体长约175厘米，体重介于6.4至9千克之间，翼展可达230至260厘米。雄鸟较重，平均体重在7.5至9千克，而雌鸟则在6.4至8.28千克之间。成年肉垂鹤背部与翅膀呈灰白色，头部羽毛暗灰色，上颚至眼部前方延伸至肉垂顶端的皮肤裸露，覆盖有小圆形疣状突起，颜色鲜红。喙长且尖锐，腿和脚趾黑色。幼鸟的体型较成年鸟更暗淡，缺乏红色面部皮肤，肉垂尚未完全发育。","call":"肉垂鹤发出高亢刺耳的‘Koorok-kreek’叫声，具有独特性和快速的特点。","habits":"肉垂鹤依赖湿地生存，尤其偏好芦苇丛生的浅水湿地。它们在繁殖季节会成对活动，而在非繁殖季节，最多可达上千只的大群会在奥卡万戈三角洲等湿地区域聚集。它们以挖掘湿地土壤中的根茎、昆虫和其他小型脊椎动物为食。在埃塞俄比亚和南非的高地，肉垂鹤会在较小的永久性和季节性湿地中觅食。","breeding":"繁殖季节高度依赖于水位，主要发生在7月至8月间在埃塞俄比亚，南部种群则在4月至10月间。筑巢于水草丰茂的湿地中，巢由植被堆砌而成，周围环绕着宽阔的水域。每窝通常产一枚卵，有时产两枚，平均一窝产1.4枚，是最小的鹤类产卵数。孵化期长达33至36天，最长的孵化期之一。幼鸟在出生时颜色为淡至深棕色，肉垂略发育。离巢期为90至130天，性成熟年龄为3至4岁。","identification":"肉垂鹤与其他鹤类的区别在于其独特的白色颈部和显眼的肉垂，以及红色的面部皮肤。与同属的其他物种相比，其内侧二级飞羽延长，几乎触及地面，这是其显著的识别特征。","protection":"IUCN：VU（易危）","distribution":"肉垂鹤分布在非洲东部和南部，从埃塞俄比亚高原到南非，包括刚果民主共和国、坦桑尼亚、博茨瓦纳、津巴布韦和南非等地。","other":"自1980年代中期至1990年代以来，肉垂鹤的数量持续下降，全球估计约有6000至8000只个体。"},{"name":"蓝蓑羽鹤","english_name":"Blue Crane","scientific_name":"Grus paradisea","overview":"蓝蓑羽鹤（英文名：Blue Crane，学名：Grus paradisea），是鹤形目鹤科鹤属的鸟类。又名: 蓝鹤，南非的国鸟，优雅的中小型鹤类，身披均匀的蓝灰色羽毛，头部呈圆润状，缺乏裸露皮肤，翅膀颜色统一，没有明显的对比。在开阔地带以对或群体形式生活，主要分布于南非东部和南部，以及纳米比亚的埃托沙盐湖地区。","appearance":"蓝蓑羽鹤身高约110至120厘米，体重在4900至5300克之间，翼展可达180至200厘米，雄鸟体型略大于雌鸟。全身呈现均匀的蓝灰色，头部、颈部和身体颜色一致，脸颊和上颈背的松散羽毛赋予头部独特的‘眼镜蛇’形状。二级飞羽延长，黑色尖端几乎触及地面。虹膜呈深棕色。幼鸟颜色较淡，缺乏延伸的二级飞羽。","call":"蓝蓑羽鹤发出的叫声为断续的、号角般的‘kkk-kk-kk-kk-krraaak’声，音调低沉而粗糙。","habits":"蓝蓑羽鹤栖息于干燥的高地天然草地，以草本植物为主，偶尔在湿地过夜和筑巢。近年来，它们开始在农业区定居，利用牧场、农田和休耕地。它们是非迁徙性鸟类，但在南非内部有局部季节性移动。食物主要包括草籽、根茎、昆虫（如蝗虫）、蠕虫、蟹、鱼、蛙、爬行动物和小型哺乳动物。","breeding":"繁殖期主要集中在10月至12月，偶尔持续到3月。筑巢通常在接近水源的草地附近，巢由小石块和湿地植被构成，产卵数量通常为两枚，孵化期约为30至33天。雏鸟出生时呈灰色，头部和颈部黄色，胸部和下喉部白色，大约85天后离巢。","identification":"蓝蓑羽鹤与同属的其他鹤类相比，其特征在于完全被羽毛覆盖的头部，缺乏头部的红色裸露皮肤，全身羽毛呈现单一的蓝灰色。","protection":"IUCN：VU（易危）","distribution":"主要分布于南非东部和南部，以及纳米比亚的埃托沙盐湖地区。在南非的西开普省、卡鲁高原和东草甸有较大数量的群落。","other":"蓝蓑羽鹤自1980年代起数量急剧下降，主要受到人类人口增长、草原转化为商业林地和中毒的影响。"},{"name":"蓑羽鹤","english_name":"Demoiselle Crane","scientific_name":"Grus virgo","overview":"蓑羽鹤（英文名：Demoiselle Crane，学名：Grus virgo），是鹤形目鹤科鹤属的鸟类。又名: 闺秀鹤，小型鹤类，以其优雅纤细的身姿著称。体长85-100厘米，体重约2-3公斤，为全球15种鹤中体型最娇小者。头部与颈部黑色，两颊延伸出独特的白色长羽，如同披肩，赋予其‘蓑羽鹤’之名。分布于中欧至西伯利亚、黑海至蒙古及中国东北部，迁徙模式独特，西方群体冬季迁往非洲，东方群体则飞向印度次大陆。","appearance":"蓑羽鹤长约85-100厘米，身高76厘米，翼展达155-180厘米，体重2-3公斤。全身羽毛均匀灰色，颈部与头部黑色，具显著的白色耳羽丛，从眼后延伸至颈背。成鸟与幼鸟相似，但幼鸟色彩更淡，耳羽不甚明显。雄鸟略大于雌鸟。","call":"发出响亮的喇叭声，音调比灰鹤更高。","habits":"栖息于开阔的草原、沙漠边缘、湿地与农田，偏好水源附近的环境。春季迁徙，形成大群，迁徙时飞行姿态直颈。夏季以种子、植物材料为主食，辅以昆虫、小动物。冬季在印度次大陆的农田中觅食，可能对农作物造成损害。","breeding":"春季繁殖，主要在4月至5月，北方地区可能延至6月。在草地、农田或砾石地带筑巢，巢简单，由少量碎石和植物构成，直接在地面上孵化。通常产卵2枚，孵化期27-29天，幼鸟孵化后约55-65天离巢，可能是鹤类中最短的孵化周期。","identification":"与灰鹤相比，蓑羽鹤的胸部黑色羽毛更长，垂至胸部下方。","protection":"IUCN：LC（无危）。中国国家二级保护动物。","distribution":"繁殖于中欧至西伯利亚、黑海至蒙古及中国东北部。越冬于非洲中部、印度次大陆。在中国，繁殖于新疆、宁夏、内蒙古、黑龙江、吉林等省，迁徙途经河北、青海、河南、山西等地，越冬于西藏南部。","other":"在印度文化中，蓑羽鹤象征着美丽与优雅，被比喻为远离家乡或经历艰难旅程的人。"},{"name":"丹顶鹤","english_name":"Red-crowned Crane","scientific_name":"Grus japonensis","overview":"丹顶鹤（英文名：Red-crowned Crane，学名：Grus japonensis），是鹤形目鹤科鹤属的鸟类。别名: 仙鹤、日本鹤、鴜鷜，又名仙鹤、日本鹤、鴜鷜，是中国国家一级保护动物。标志性鹤科鸟类，以其鲜红的头顶、白色的身躯、黑色的次级飞羽、尾部和颈部著称。繁殖于沼泽草地和湿地，越冬于开阔地带，如田野、沼泽。在日本北海道为留鸟。","appearance":"成年丹顶鹤体长138至152厘米，体重7至10千克，翼展220至250厘米。头部顶部有一片独特的鲜红色裸露皮肤，身体大部分为白色，具黑色次级飞羽、尾部和颈部。幼鸟头部无红色，颈部呈浅棕色，翼上有褐色斑点。雄鸟脸颊、喉咙和颈部为黑色，雌鸟相应部位为珍珠灰色。","call":"鸣叫声高亢而穿透力强，用于领域声明和发情期交流。","habits":"偏好较深水域的沼泽、湿地和开阔地带。夏季活动于深水区的芦苇、香蒲和灯芯草沼泽，冬季迁徙至河流、淡水湿地、沿海盐沼和稻田。日间活动，警惕性强，通常成对或小群活动。","breeding":"春季繁殖，筑巢于水深约50厘米的湿地，主要由芦苇和草构建。通常产两枚卵，孵化期29至34天。雏鸟出生后约95天离巢。性成熟年龄为3至4岁。寿命可达50至60年。","identification":"与其它主要白色鹤类的区别在于黑色的次级飞羽和带有白色颈背的黑色颈部。较小的黑颈鹤虽有黑色颈部，但体型更小，身体呈灰色。","protection":"IUCN：VU（易危）。CITES I & II。全球估计数量约为2750只。日本北海道的稳定居民种群约1200只，大陆种群因繁殖和越冬地退化而下降。","distribution":"繁殖于西伯利亚东南部、中国东北部和日本北海道。越冬于韩国、中国江苏一带和日本北海道。在中国，主要繁殖地包括内蒙古、吉林、辽宁等地的湿地。","other":"自1950年代起，通过国际合作和保护区建立，丹顶鹤得到了密集的保护努力。然而，农业和工业发展导致的栖息地丧失和退化构成主要威胁。"},{"name":"美洲鹤","english_name":"Whooping Crane","scientific_name":"Grus americana","overview":"美洲鹤（英文名：Whooping Crane，学名：Grus americana），是鹤形目鹤科鹤属的鸟类。北美洲特有的鹤科鸟类，全球最稀有且濒危的鹤种之一。曾于1941年濒临灭绝边缘，仅剩15至16只野生个体在得克萨斯州过冬，另有6只非迁徙种群在路易斯安那州。经过数十年的努力，截至2011年8月，全球美洲鹤总数增至599只，包括437只野生个体和162只圈养个体。美洲鹤以其醒目的白色羽毛、红色头冠和黑色翼尖著称，体型高大，是北美最高的鸟类。","appearance":"成年美洲鹤全身雪白，头部具有鲜红的裸露皮肤，嘴长而尖，黑色或灰色，翼展可达2米。幼鸟毛色为锈棕色，头顶及背部有斑驳的锈色。成鸟雄鸟体重约7.3千克，雌鸟约6.4千克，雄鸟身高近1.5米，明显高于雌鸟及沙丘鹤。黑色的翼尖仅在飞行时显露。","call":"发出响亮的‘whooping’叫声，可在几公里外听到。通过‘警卫叫声’警告伴侣潜在的危险，而‘共鸣叫声’则在清晨醒来、求偶或捍卫领地时共同发出。","habits":"美洲鹤栖息于内陆淡水湿地和沿海咸水湿地，偏好开阔的沼泽地带。冬季在得克萨斯州墨西哥湾沿岸的湿地及周边地区越冬。以甲壳类、软体动物、鱼类、小型哺乳动物和水生植物为食。迁徙途中，也会在农田中觅食谷物。","breeding":"美洲鹤通常在3至4岁时开始繁殖，雌鸟年产1至2枚橄榄绿色斑点蛋，孵化期29至31天。一对父母共同照料幼鸟，喂养期长达10至11个月，通常每季只有一个幼鸟能存活。","identification":"美洲鹤体型远大于沙丘鹤，且通体纯白，翼尖黑色，头部有红色裸露部分。在飞行时，其长腿和长颈伸直，与灰鹭、大白鹭和木鹳等鸟类有显著区别。","protection":"IUCN：EN（濒危）；被列入《濒危野生动植物种国际贸易公约》（华盛顿公约）附录I。","distribution":"繁殖区主要位于加拿大中部的伍德布法罗国家公园及周边地区，非繁殖期分布在美国中南部和东南部，尤其是得克萨斯州墨西哥湾沿岸的阿兰萨斯国家野生动物保护区。","other":"美洲鹤的保护工作包括人工孵化和饲养，以及利用超轻飞机和遥控机器人引导幼鸟迁徙至佛罗里达州的野生动物保护区。"},{"name":"灰鹤","english_name":"Common Crane","scientific_name":"Grus grus","overview":"灰鹤（英文名：Common Crane，学名：Grus grus），是鹤形目鹤科鹤属的鸟类。俗称: 番薯鹤，别名: 千岁鹤、玄鹤，大型涉禽，体长95-120厘米，重约3000-5500克，羽毛以灰色为主，头部有黑色和白色的条纹，顶冠中央呈红色。分布广泛，繁殖于欧洲至亚洲，越冬于非洲东北部、远东和中国南部。在中国，灰鹤在山西南部、贵州草海等地越冬数量可达2000只以上，总越冬数量估计约为6000只。","appearance":"灰鹤体型高大，全长约95-120厘米，体重介于3000至5500克之间，翼展达180-200厘米。成鸟身体呈石板灰色，头部长有黑色和白色相间的图案，顶冠处有一小块红色裸皮，眼睛周围为黄色到橙色。下背部可见独特的蓬松簇状飞羽。幼鸟头部全被羽毛覆盖，身体羽毛尖端呈黄褐色，上体带有棕色色调，下背部和飞羽无黑色尖端，翅膀羽毛均匀且略显圆润。第二年逐渐获得成鸟般的头部和体羽特征，但顶冠不如成鸟裸露，三级飞羽和翼覆羽可能仍磨损且呈棕色。","call":"灰鹤的叫声高亢而穿透力强，尤其是在飞行和展示时，会发出深沉、回荡的“krro”或“karr”声。秋季，幼鸟会发出一种笛音般的‘cheerp’叫声，同时也会模仿成鸟的叫声。繁殖期，雄鸟会发出响亮的号角声，雌鸟随即跟以较低音调的‘kraw’或更尖锐的‘ka-ka-ka’。","habits":"灰鹤栖息于开阔的平原、草地、沼泽、河滩、旷野、湖泊以及农田地带，偏好富有水边植物的开阔湖泊和沼泽地带。它们通常以5至10余只的小群活动，迁徙期间可聚集至40至50只，越冬地则可能有数百只的大群。灰鹤性情机警，活动和觅食时会有鸟担任警戒，一旦发现危险，立即鸣叫并飞起。飞行时呈“V”字或人字形，头颈前伸，脚后伸。它们主要以植物的叶、茎、嫩芽、块茎、草籽、农作物、软体动物、昆虫、蛙、蜥蜴、鱼类等为食。","breeding":"灰鹤的繁殖期为4月至7月，求偶时两性会进行复杂的舞蹈，包括蹲伏、跳跃和鸣叫。巢筑于沼泽草地干燥处，由枯枝、叶、芦苇和草茎构成。每窝产卵2枚，偶尔1或3枚，卵呈褐色或橄榄绿，带有红褐色斑点。孵化期为28至30天，由两性轮流承担。雏鸟早熟，很快就能跟随父母离巢活动，主要以蠕虫和昆虫为食。","identification":"灰鹤与黑颈鹤和白头鹤的区别在于头部的白色条纹和红色裸皮顶冠，以及成鸟的黑白头饰。与丹顶鹤相比，灰鹤的头部图案更为复杂，且下背部有独特的蓬松簇状飞羽。不同亚种间主要差异在于顶冠的红色裸皮有无。","protection":"IUCN：LC（无危）；在中国，灰鹤是国家二级保护动物。","distribution":"繁殖区包括从斯堪的纳维亚和东北欧到中国北部和俄罗斯远东地区；土耳其和高加索，包括亚美尼亚和阿塞拜疆也可能有繁殖。越冬地分布于法国、伊比利亚半岛、西北和东北非洲、中东、巴基斯坦、印度和中国南部与东部。","other":"灰鹤历史上曾因中医认为其肉有益气功效而被捕猎。目前，全球种群稳定，部分地区如英国、丹麦、法国等国的种群正在恢复。"},{"name":"白头鹤","english_name":"Hooded Crane","scientific_name":"Grus monacha","overview":"白头鹤（英文名：Hooded Crane，学名：Grus monacha），是鹤形目鹤科鹤属的鸟类。又称: 锅鹤、玄鹤、修女鹤，广泛分布于欧亚大陆，尤其在中国东北部、西伯利亚东南部繁殖。成鸟体羽深灰色，头及颈白色，头顶具红色裸皮，眼先及前额黑色。白头鹤主要在农业地带和湿地栖息，常以家庭为单位或成大群活动，越冬于日本南部、朝鲜西部和中国东部。","appearance":"白头鹤体长约1米，体重可达3.7公斤，翼展约1.87米。成鸟体羽深灰色，头和颈为白色，头顶有一块明显的红色裸皮，眼先及前额为黑色。幼鸟的头部和颈部带有浅棕色，头顶和前额为深灰色，无红色裸皮。","call":"白头鹤发出响亮、滚动且高音调的叫声。","habits":"白头鹤在繁殖季节占据孤立的沼泽和较高海拔的森林湿地，如落叶松林区。非繁殖季则利用开阔的湿地、草地和农田。冬季栖息地多样，包括河流和浅湖岸线、草甸沼泽、稻田和农田。在韩国和日本，白头鹤会在喂食站和农田中觅食。","breeding":"春季繁殖，产卵期在4月末至5月初。巢由湿苔藓、泥炭、莎草茎叶和落叶松、桦木枝条构成，位于沼泽中散布的落叶松树旁。通常产两枚卵，孵化期27至30天。雏鸟上部呈深棕色，下部较淡，约75天后离巢。","identification":"白头鹤与白枕鹤相似，但体型更小，颈部全白。幼鸟头部和颈部有褐色色调，前额为暗色斑点而非红色区域。","protection":"IUCN：VU（易危）","distribution":"繁殖于俄罗斯远东地区（阿穆尔河中下游至比金河流域，索哈-雅库特地区）和中国东北（黑龙江）。越冬主要在日本南部，其次在朝鲜半岛和中国中部与东部。","other":"白头鹤在中国的保护级别为国家一级重点保护动物，全球数量估计约为11,600只。"},{"name":"黑颈鹤","english_name":"Black-necked Crane","scientific_name":"Grus nigricollis","overview":"黑颈鹤（英文名：Black-necked Crane，学名：Grus nigricollis），是鹤形目鹤科鹤属的鸟类。是鹤科鹤属中唯一的高原鹤类。其特征为头部和上颈部2/3为黑色，眼后和眼下方有一小块白色或灰白色斑。广泛分布于西藏高原及中国中西部，夏季栖息于高海拔湿地，冬季迁至较低海拔地区。在全球鹤类中最后被发现，于1876年由俄国探险家普尔热瓦尔斯基在中国青海湖首次记录。","appearance":"成年黑颈鹤身长约139厘米，翼展可达235厘米，体重约为5.5千克。全身羽毛呈灰白色，头部、上颈部黑色，腿部黑色，眼后方有白色斑块，头顶裸露部分呈红色。尾部羽毛黑色，与灰鹤等其他鹤类有显著区别。幼鸟羽毛呈灰黄色，颈部长有黑白相间的羽毛。","call":"发出高亢穿透的叫声，包括响亮或柔和的“gorr-kro, gon-kro, gorr-kro...”声，用于成鸟与幼鸟间的交流。","habits":"栖息于海拔2500至5000米的高原湿地，如沼泽、湖泊边缘和河流湿地。迁徙至较低海拔的农业山谷过冬，主要在清晨和傍晚觅食，食物包括植物根茎、昆虫、小型脊椎动物和农田残余作物。","breeding":"春季繁殖，多在5月初至6月中旬，于浅水湿地的小岛或陆地上筑巢，巢由芦苇、草和其他水生植被构成。每次产卵2枚，孵化期31至33天，幼鹤出生后约90天离巢。","identification":"与灰鹤相比，黑颈鹤体型稍大，头部全黑，仅眼周略灰；与丹顶鹤相比，黑颈鹤羽毛灰白，头部红色皮肤不如丹顶鹤明显。","protection":"IUCN：NT（近危）。在中国、印度和不丹受法律保护，但面临栖息地破坏、农业扩张和人类活动干扰的威胁。","distribution":"繁殖于欧亚地区的中国中西部，冬季迁至中国青藏高原东南部、云贵高原及中印、中巴边境。","other":"佛教文化中受到尊重，不丹有庆祝黑颈鹤的节日，印度拉达克将其定为州鸟。"},{"name":"秧鹤","english_name":"Limpkin","scientific_name":"Aramus guarauna","overview":"秧鹤（英文名：Limpkin，学名：Aramus guarauna），是鹤形目秧鹤科秧鹤属的鸟类。是秧鹤科唯一的现存物种，体型似鹳，分布于美洲热带水域，从美国东南部至阿根廷北部。以独特的饮食习性和响亮的叫声著称。","appearance":"秧鹤体长64-73厘米，翼展101-107厘米，体重900-1300克，雄鸟略大于雌鸟。全身呈暗褐色，带有橄榄光泽，头部、颈部、翼覆羽和部分背部及下体（除尾部）有白色斑点，使身体显得条纹状，头颈呈浅灰色。腿长而色深，喙长且弯曲，黄色基部稍暗，末端形成类似镊子的结构，便于取出蜗牛。第一年生的鸟白点较不明显。","call":"叫声独特，响亮且野性十足，常在夜晚、黎明或黄昏发出，伴有咔嗒声，被描述为'kwEEEeeer'或'klAAAar'。","habits":"栖息于淡水沼泽、湿地，常见于高芦苇丛中，有时出现在红树林。日间活动，但夜间亦会觅食。飞行时颈部前伸，腿部后摆，翅膀拍打浅而有力。主要以苹果蜗牛为食，也会吃其他软体动物、昆虫、蛙类、蜥蜴、甲壳类和蠕虫。","breeding":"繁殖期不固定，可能形成一夫一妻制或一雄多雌制。巢筑于地面、浮水植物、灌木或树上，由雄鸟先建巢。每窝产卵3-8枚，平均5.5枚，卵色变化大，从灰白到深橄榄绿，带斑点。双亲共同孵卵，孵化期约27天。雏鸟出生即有绒毛，能行走和游泳，跟随父母至7周大时达到成体大小，约16周后离开父母。","identification":"与幼年白鹮和彩鹮相似，但可通过其橄榄棕色的整体色调、白色斑点的羽毛、更直且厚实的喙和黑色腿脚加以区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域位于北美东南部至南美阿根廷北部，包括中美洲、加勒比海岛屿。在佛罗里达州，其分布与苹果蜗牛的栖息地紧密相关。","other":"存在四个亚种，其中三个分布于佛罗里达、墨西哥、加勒比海和中美洲大部分地区，相似度高；第四个亚种guarana分布在巴拿马东部至南美洲，体型较小，颜色较深，仅颈部有白色标记，部分学者认为应视为独立物种。"},{"name":"林三趾鹑","english_name":"Common Buttonquail","scientific_name":"Turnix sylvaticus","overview":"林三趾鹑（英文名：Common Buttonquail，学名：Turnix sylvaticus），是鸻形目三趾鹑科三趾鹑属的小型鸟类。类似鹌鹑的鸟，但实际上与涉禽关系更近。其分布范围广泛，包括欧洲南部、非洲、印度、东南亚直至印尼。林三趾鹑的胸部呈棕色，两胁有黑色斑点，常栖息于温暖的草地或灌木丛林中。","appearance":"林三趾鹑体长13至16厘米，体重32至74克，雌鸟通常比雄鸟大。上体复杂地花纹覆盖，具有淡色眉毛，锈色胸部和翅膀内侧，背部鳞状斑纹，侧腹有黑色斑点，眼睛周围有淡黄色到亮黄色眼圈，被淡蓝色眼环包围，喙细长蓝灰色；腿色淡粉色带黄或蓝调。雌鸟颜色比雄鸟更为鲜艳，主要为栗色。非繁殖季节羽毛较暗淡，上体颜色更浅，黑色条纹不明显，斑点更窄。幼鸟像成年雄鸟，但体型较小，胸部斑点黑色或深棕色，眼睛颜色较深。不同亚种在大小和上体及侧胸颜色上有差异。","call":"雌鸟的广告叫声是一声响亮、共鸣的约1秒的轰鸣声，类似“hoooo”，类似于牛低吼的声音，通常在清晨和傍晚重复，有时全天。雄鸟的回应声音为‘kek-kek-kek’。","habits":"栖息于平地及低海拔丘陵地带的温暖草地或灌木丛林中，偏好玉米田和草地平原。夜间或部分夜间活动，在非洲，早晨和傍晚最为活跃。主要以草籽和昆虫为食，会刮地寻找食物。","breeding":"一妻一夫制或一妻多夫制，雌鸟挑选巢址，双方共同筑巢。通常在草丛中的自然凹处筑巢，每窝产卵3至5枚，卵呈浅褐色带有深褐色斑点，雏鸟早熟，出生后2至3天就能自行觅食。","identification":"林三趾鹑与其它三趾鹑属鸟类相比，主要通过颜色和大小的细微差别来辨识，尤其是雌鸟的颜色更加鲜艳。","protection":"IUCN：LC（无危）；然而，指名亚种在地中海区域极度濒危。","distribution":"分布于欧洲南部（西班牙南端）、非洲、亚洲（巴基斯坦、印度、菲律宾等东南亚国家），在中国分布于广东、海南和台湾。","other":"在某些地区可能因人类活动而数量减少，但在适应多种植被类型方面表现出了广泛的适应性。"},{"name":"红背三趾鹑","english_name":"Red-backed Buttonquail","scientific_name":"Turnix maculosus","overview":"红背三趾鹑（英文名：Red-backed Buttonquail，学名：Turnix maculosus），是鸻形目三趾鹑科三趾鹑属的鸟类。小型陆栖鸟类。其分布广泛，从东南亚的印尼苏拉威西岛和小巽他群岛至新几内亚中南部、东北部、东南部，再到澳大利亚北部、东部及俾斯麦群岛东部。在不同的地理区域，还被称为黑背、黑斑或橙胸三趾鹑。","appearance":"红背三趾鹑体型圆胖，翼端呈圆形，尾短，长度在12至16厘米之间。雌鸟体型较大，重32至51克，而雄鸟体重较轻，介于23至39克。羽毛色彩丰富，背部呈红褐色，带有黑色和锈色条纹，胸部有明显的淡色斑点。头部两侧和喉部呈棕色，具有红色颈圈。眼睛淡色，腿脚黄色。雌鸟拥有更鲜艳的色泽和更加突出的栗色颈环，喙色更黄。幼鸟颜色更深，斑点更多，翅膀覆盖羽带白色斑点，眼睛深色，缺乏飞行中的浅色翼板。不同亚种在大小和色彩上有所差异。","call":"红背三趾鹑的叫声柔和，重复的‘oom-oom-oom-oom’音调，每次音符结尾音高上升，常在春季日夜发出，声音略高于彩三趾鹑的类似叫声。","habits":"栖息于茂密的湿地草丛中，偏好夏季降水量超过400毫米的地区，尤其在至少有800毫米夏季降水的地方定居。夜行性和黄昏活动，以种子、绿色植物和昆虫为食，更倾向于昆虫捕食。在澳大利亚，它通常在水边繁殖。部分种群迁徙，特别是在澳大利亚的热带地区，干燥季节集中在沿海地带，而在湿季更为广泛分布。","breeding":"繁殖季节从十月持续到六月。雌鸟连续多配偶制，雄鸟独自筑巢、孵化和照顾幼鸟。巢建于高草丛中，通常位于湿润区域的草丛底部，由草、桉树叶和牛粪铺垫，周围草茎编织成有侧入口的顶篷或穹顶。每窝产2至4枚灰白色至黄色的蛋，上面有淡棕色或灰色的密集斑点。孵化期约14天，自最后一枚蛋开始。幼鸟早熟，出生六周达到成鸟大小，约四个月后换上成年羽毛。","identification":"与小三趾鹑和红胸三趾鹑相比，红背三趾鹑有红褐色颈圈和肩部，飞行时可见内翼覆羽的淡色板，侧面和翼覆羽有明显标记。与蓝胸鹑和褐鹌鹑容易混淆，但后者体型更大，且飞行时没有特征性的浅色覆羽和红褐色颈圈。不同亚种在大小、颜色和红褐色颈圈的存在与否上有显著差异。","protection":"IUCN：LC（无危）","distribution":"红背三趾鹑的分布范围包括澳大利亚东海岸从西澳东北部至昆士兰州最北端，南至新南威尔士州东北部。在新几内亚，从苏拉威西岛和小巽他群岛至中部、南部、东北部和东南部。在俾斯麦群岛东部也有分布。在澳大利亚，主要栖息在有足够夏季降水的低地地区。","other":"尽管总体数量可能在下降，红背三趾鹑在大部分范围内仍保持常见状态。但在澳大利亚东南部，它被认为较为罕见。"},{"name":"非洲三趾鹑","english_name":"Fynbos Buttonquail","scientific_name":"Turnix hottentottus","overview":"非洲三趾鹑（英文名：Fynbos Buttonquail，学名：Turnix hottentottus），是鸻形目三趾鹑科三趾鹑属的鸟类，体型微小，仅比麻雀略大，是其分布范围内唯一的三趾鹑。栖息于南非的山地fynbos地带，从开普敦至东开普省的阿尔戈湾，偏好低矮而稀疏的植被环境。","appearance":"体长14-16厘米。这是一种较小、颜色较暗的Turnix，喙细长，脸部和胸部呈橙红色，侧胸有显著的条纹，胁部有斑点，眼睛淡黄色。雌鸟腹部颜色略显鲜亮。与部分共栖的林三趾鹑相比，背部更暗、更棕色，且背羽的鳞片状图案较少。雏鸟与成年雄鸟相似，但体型更小，少一些红色，下体标记更多；虹膜淡棕色，跗跖暗粉红色。","call":"夜间常发出低沉、深沉的重复‘oooooooppp’声，比黑腰三趾鹑的叫声更慢更长，有时发出类似flufftail的‘oooooop-oooooop’声，还有像小鸟一样的‘peep peep’声和更粗哑的咯咯声。","habits":"栖息于海拔50厘米高的tussock-like restio主导的fynbos地带，偏爱沿海平原，但可达海拔1500米。可能具有游牧性质，会在火灾后3-5年的适宜生境间迁移。以草地和杂草种子以及昆虫及其幼虫为食，通常单独或成对出现，偶尔会形成小群。","breeding":"繁殖季节为9月至次年2月。雌鸟可能为多配偶制。巢穴为浅坑（宽50-75毫米，深20毫米），铺有草，位于草丛下，草茎弯曲形成松散的顶篷，或在倒下的草堆下无顶篷。每窝通常产3枚黄灰色蛋，带有深灰色或橄榄褐色的斑点，孵化期由雄鸟单独承担，持续12-14天。","identification":"与花脸鹌鹑、非洲蓝鹑、和纹胸侏秧鸡相比，非洲三趾鹑具有更慢的翼拍频率、较长的身体和颈部，以及长长的拖腿，此外，其上体颜色更深，缺乏复杂图案，且侧腹无心形图案。","protection":"IUCN：LC（无危）","distribution":"分布于南非南部山区，冬季降雨区从西开普省西南部和南部延伸至东开普省的伊丽莎白港。"},{"name":"黑腰三趾鹑","english_name":"Black-rumped Buttonquail","scientific_name":"Turnix nanus","overview":"黑腰三趾鹑（英文名：Black-rumped Buttonquail，学名：Turnix nanus），是鸻形目三趾鹑科三趾鹑属的鸟类。小型鸟类。其特征包括棕色背部、赤褐色胸部、淡色腹部、黑色臀部以及较大的雌鸟和较亮的色彩。分布广泛，主要在非洲的开阔草地中，避开森林和干旱地带。","appearance":"黑腰三趾鹑拥有棕色的背部，赤褐色的胸部，以及浅色的腹部。它们的虹膜呈棕色，最显著的特征是黑色的臀部。雌鸟比雄鸟体型更大，颜色更为鲜艳。整体长度约15厘米，体重约30克。","call":"黑腰三趾鹑发出一系列低沉的‘hoo’音，这是检测其存在的最佳方式，尤其在繁殖季节，叫声可作为极强的繁殖证据。","habits":"生活在开放的草地上，主要分布在非洲除森林和更干燥的地区之外的地方。以草籽、杂草种子和昆虫及其幼虫为食，通常单独或成对出现，偶尔形成小群。它们在地面觅食，栖息地包括短草丛、开放的草原、干燥的沙质平原，高度从海平面至1800米。","breeding":"繁殖期跨越数月，通常在雨季或雨季结束时，如津巴布韦的9月至次年2月，主要集中在12月至1月。巢穴为浅坑，直径50-75毫米，深20毫米，通常由草铺垫，位于草丛下或之间，每窝产3枚绿白色蛋，带有深灰色或橄榄棕色斑点，孵化期约为12-14天，由雄鸟独自孵卵。","identification":"与小三趾鹑非常相似，但可通过橙色脸部和黑色臀部区分开来。与雌性鹌鹑的区别在于飞行时较为平稳且黑色臀部明显。","protection":"IUCN：LC（无危）。在某些地区，如刚果、乌干达和肯尼亚，数量可能较多，但在南非，由于过度放牧、人类定居、践踏和过度燃烧栖息地，其分布范围已大幅收缩。","distribution":"广泛分布于非洲的开放草地，避开森林和干旱地区。在非洲中部为留鸟，在北向乍得湖和中非共和国的方向为迁徙繁殖鸟。","other":"尽管常见或局部常见，但因其伪装的羽毛和行为使其容易被忽视或误认。"},{"name":"黄脚三趾鹑","english_name":"Yellow-legged Buttonquail","scientific_name":"Turnix tanki","overview":"黄脚三趾鹑（英文名：Yellow-legged Buttonquail，学名：Turnix tanki），是鸻形目三趾鹑科三趾鹑属的鸟类。俗名: 黄地闷子、三爪爬、水鹌鹑、水鸡、田鸡，体型略大于麻雀，鸣声极为响亮。雌鸟比雄鸟稍大，羽色更加鲜艳，胸部和枕部呈亮橙色，腹部黄色，喉部白色，上体有灰色斑点。雄鸟整体羽色相似，但色调更淡，胸部斑点较少，喉部呈黄褐色。分布于印度次大陆、东亚及东南亚，偏好受扰和耕种地区。","appearance":"小型三趾鹑，体长15至18厘米，体重35至113克，雌鸟较大。雄鸟有黑冠带淡边，有时有淡中央条纹，头部前侧淡色，喉部淡黄，边缘及胸部暗红，腹部渐白至尾下覆羽。背部灰褐，有红及深褐色斑纹，主翼羽黑褐，翼覆羽沙黄有黑斑。喙淡黄，虹膜灰白或黄褐，腿足深黄。雌鸟色彩更鲜艳，有宽红棕色颈环，斑纹和虹膜更亮黄。幼鸟似雄鸟，但羽色更暗淡，胸部颜色不鲜明，细斑较多。","call":"雌鸟发出持续约10至15秒的低沉哀鸣声，有时增强强度，几乎如人声。还有一种较弱但传播远的“off-off-off”声，怀疑“pook-pook”声仅由雄鸟发出。","habits":"栖息于草地、作物区（尤其水稻茬地）、次生林、竹林草地、灌木丛；海拔从海平面至2150米，主要在1200米以下。在印度和巴基斯坦干旱地区可能迁徙，雨季繁殖，夜行迁徙，受灯光吸引。地面觅食，以谷物、种子、绿芽和昆虫为食。","breeding":"繁殖期3月至11月，通常在雨季。雌鸟一妻多夫制，雄鸟独孵卵，独育雏。巢为浅凹地面，铺草，四枚灰白蛋有彩斑，孵化期12至16天。雏鸟5至6天能自食，10天会飞，七周达成鸟羽衣。","identification":"与其他Turnix种类相比，黄脚三趾鹑具有更明亮的裸露部位，雌鸟有定义明确的赤褐色颈环，上体黑色标记更开放，雄鸟喉部黄褐色。非繁殖期雌鸟较暗淡，缺乏赤褐色颈环，有淡色冠状条纹。","protection":"IUCN：LC（无危）。广泛分布，数量稳定，未检测到特定威胁。","distribution":"分布于印度次大陆、东亚洲及东南亚，包括巴基斯坦、印度、尼泊尔、缅甸、印度支那、中国东部，韩国半岛和俄罗斯东南部。在中国大陆，分布于南方地区。","other":"偏好受扰和耕种地区，未来似乎安全。"},{"name":"菲律宾三趾鹑","english_name":"Spotted Buttonquail","scientific_name":"Turnix ocellatus","overview":"菲律宾三趾鹑（英文名：Spotted Buttonquail，学名：Turnix ocellatus），是鸻形目三趾鹑科三趾鹑属的鸟类。带有明显的棋盘状花纹，翼部点缀黑色斑点，胸部为赤褐色，头部有斑点。雌鸟喉部黑色，雄鸟喉部白色，腿和喙为橙黄色。","appearance":"菲律宾三趾鹑体长17至18厘米，是一种中等体型的地面鸟类。背部棕色，头部图案明显，胸部纯赤褐色，翼部有大胆的斑点。雌鸟比雄鸟色彩更鲜艳，头部斑点更大，喉部黑色（雄鸟喉部白色），胸前有较多的赤褐色，翼部黑斑较少较小，颈部赤色更为突出。喙为角色至绿黄色，眼虹膜淡黄白色，腿为橙黄色（雌鸟颜色更深）。幼鸟体型较小，虹膜可能比成年鸟暗淡。年轻雄鸟喉部有黑斑，年轻雌鸟喉部斑点颜色不定。","call":"雌鸟的广告叫声典型，低沉而隆隆的“oomm”声，连续发出可达八次，每次持续约0.5秒。","habits":"菲律宾三趾鹑栖息于灌木丛生的草地、干燥森林、竹林边缘、稻田和花园，偶尔出现在开阔的草地上，海拔高度从海平面到2200米。它通常被认为是留鸟，很少离开其正常活动范围。与大多数三趾鹑一样，它只有在感受到近在咫尺的威胁时才会勉强飞起，飞行距离短，着陆后会奔跑或静止不动。","breeding":"繁殖季节为2月（雏鸟）和5月至8月。雌鸟可能为顺序多配偶制。巢穴是在地面的凹陷处，铺有树叶并用树枝遮掩，有时位于灌木根部。一窝产2至4枚灰白色蛋，密布灰色至紫色斑点。","identification":"与小型和吕宋三趾鹑相似，但体型较大，腿和喙为黄色，头部斑纹更强烈，胸部赤褐色，翼部斑点更大胆。","protection":"IUCN：LC（无危）","distribution":"菲律宾吕宋岛，包括吕宋岛周边的低地地区。"},{"name":"棕三趾鹑","english_name":"Barred Buttonquail","scientific_name":"Turnix suscitator","overview":"棕三趾鹑（英文名：Barred Buttonquail，学名：Turnix suscitator），是鸻形目三趾鹑科三趾鹑属的鸟类。直译: 横斑三趾鹑，体型小巧的三趾鹑科鸟类，雌鸟较雄鸟稍大，喉部呈黑色。活跃于开阔草地，受扰时能低飞一段距离后迅速隐入草丛。在中国南方有分布记录。该物种最初描述自爪哇。","appearance":"棕三趾鹑是一种小型短尾鸟，体长13.5-17.5厘米，体重雄鸟35-52克，雌鸟47-68克，雌鸟通常比雄鸟大9%左右。全身呈现锈红色，头部有鲜明的图案，胸部有密集的黑色条纹，侧翼为温暖的黄褐色。雌鸟的喉咙至胸上部为黑色，胸部和上侧腹有厚重的黑色条纹，腹部区域为深红褐色。腿部颜色多样，从粉色到蓝灰色、绿黄色或黄色，某些亚种的虹膜为淡黄色，但曾为红色。喙灰而带有黄色基部和尖端，但在某些亚种中可能更明亮或有灰色变化。","call":"雌鸟的广告鸣叫在印度和斯里兰卡被形容为远处摩托车的声音，一种腹语式的“drr-r-r-r-r-r”声突然结束，前有3-4个长而深的“groo”音符，间隔五秒，整个叫声持续约15秒；在日本，这种叫声则为远传的雾笛声“hoon-hoon-hoon”，初始音调平缓，逐渐变得上扬且响亮。","habits":"生活在草甸（如马来半岛的Imperata草甸）、作物地（包括甘蔗、咖啡和茶园）、废弃农田、次生林、灌木丛、竹林和森林边缘的沙质地，常靠近水源，海拔高度从海平面至2500米（喜马拉雅山区）或1650米（东南亚）。它在白天和夜晚都可能活动，但有证据显示在马来西亚可能主要是夜间活动。以草籽、杂草种子、昆虫和绿色嫩芽为食。","breeding":"繁殖季节全年都有记录，但各地有所差异，例如日本在4月至5月达到高峰。雌鸟连续多配偶制。巢筑于浅凹的草垫中，通常位于草丛中，草茎弯曲形成顶盖，侧面有入口，通常靠近小灌木或棕榈树下。每窝产卵2-6枚，通常是灰色橄榄色，密布棕色、薰衣草色和紫黑色斑点，卵大小为22.3-24.9毫米×19.2-20.5毫米。孵化期12-16天，由雄鸟单独孵卵和照顾雏鸟。雏鸟出生40-60天后可达成鸟大小。","identification":"与其他三趾鹑科鸟类的区别在于蓝色或灰蓝色的喙和腿，以及飞行时可见的淡黄色眼和翼上的淡色肩斑。雌鸟比雄鸟色彩更鲜艳，喉部和胸中部为黑色。","protection":"IUCN：LC（无危）","distribution":"分布于印度、斯里兰卡、日本、东南亚大部分地区，包括中国南方。在喜马拉雅山脉可达海拔2500米，在东南亚则常见于300米以下的高度。","other":"棕三趾鹑能够适应人类居住环境，从耕作和放牧中获益，这表明其种群状态相对稳定。"},{"name":"马岛三趾鹑","english_name":"Madagascar Buttonquail","scientific_name":"Turnix nigricollis","overview":"马岛三趾鹑（英文名：Madagascar Buttonquail，学名：Turnix nigricollis），是鸻形目三趾鹑科三趾鹑属的鸟类。体型小巧，羽毛图案复杂，雌鸟具有赤褐色侧身、灰色腹部和黑色面部标记。雄鸟较暗淡，呈棕色。广泛分布于马达加斯加的多种生境，包括草地、灌木丛、刺林和西部落叶森林。性格较为羞怯，但比鹌鹑更易接近。其鸣声为一系列快速脉动的低沉‘hwo’音符。","appearance":"马岛三趾鹑体长13至16厘米，体重雄鸟60至72克，雌鸟59至84克，雌鸟体型较大。拥有短翼和短尾，头部黑色，上体主要为灰棕色，带有黑色条纹，翅膀上有白色斑点。雄鸟胸部黑白相间，雌鸟胸部全黑，肩部有深赤褐色斑块。嘴部蓝灰色，虹膜奶油色到灰白色，腿色白灰至蓝灰色，长度超过中间脚趾及其爪。幼鸟类似雄鸟，但体型较小，翅膀显得更红棕色，羽毛边缘有黑色镶边的白色斑点。","call":"雌鸟发出深沉、低音的哼鸣声‘mmmmmmmmmut’，持续约3至8秒，开始柔和，突然结束。还有一种短促、中音的‘chut...chut...chut...’声，以每秒一音节的速率重复，可能表示警报，而快速模糊的‘bub-bub-bub-bub...’仅在近距离时可听见。","habits":"马岛三趾鹑栖息于草地、作物（尤其是木薯）、草地稀树草原、密闭冠层的森林、灌木和干燥森林，包括刺林和受干扰的森林。在海拔0至1900米的范围内活动，偏好草甸和高草地带。以种子和昆虫（如甲虫、蜗牛、蟑螂、蝇、真蝽、白蚁和鳞翅目幼虫）为食。日行性，通过在枯叶中刮擦形成特有的圆形或锥形觅食坑。","breeding":"繁殖期从8月末至2月，在马达加斯加，有报道显示雏鸟直到4月初仍可见，最早可在9月第二周出现。在留尼汪岛全年繁殖。巢为浅凹处，由两性共同建造，位于草丛下或小树下的草地中，通常铺有草。每窝产3至5枚变色的淡黄至红色或白色的蛋，带有棕色、红色或黑色斑点。雄鸟单独孵化，偶尔由雌鸟接替，孵化期13至16天。雏鸟出生时为棕色，背部有浅色条纹，两周后自食其力，三周后完全羽化并能飞行，四周后独立。雌鸟会彻底破坏被遗弃的巢穴。","identification":"与西鹌鹑和花脸鹌鹑相比，马岛三趾鹑稍小，头部图案更为丰富。雄鸟与雌鹌鹑相似，但体型更小，飞行时力量较弱且不直接。雌鸟颜色更为鲜艳，胸脯全黑，肩部有深赤褐色斑块。","protection":"IUCN：LC（无危）","distribution":"马岛三趾鹑主要分布在马达加斯加，包括北部、西部和南部，较少见于东部和高原地区。此外，在留尼汪、毛里求斯（已灭绝）、Glorieuses群岛和Juan de Nova岛也有分布，但后者可能为引入种。","other":"在马达加斯加，该物种在多种受干扰、耕作和次生栖息地中生存，包括森林空地，因此可能相对安全。然而，它在岛上受到弹弓和陷阱的猎捕威胁。"},{"name":"黑胸三趾鹑","english_name":"Black-breasted Buttonquail","scientific_name":"Turnix melanogaster","overview":"黑胸三趾鹑（英文名：Black-breasted Buttonquail，学名：Turnix melanogaster），是鸻形目三趾鹑科三趾鹑属的独特鸟类。分布于澳大利亚中东部的昆士兰东南部及新南威尔士东北角，栖息于森林覆盖层深厚的地区。雌鸟体型较大，头部、颈部和胸部黑色，点缀以细小白斑，形成独特的外观。雄鸟则拥有较为淡色的面部和白色的眼睛。","appearance":"黑胸三趾鹑是一种体形丰满的鸟，长度在17至19厘米之间，雌鸟体重80至159克，雄鸟50至127克。雌鸟具有显著的黑色头部、颈部和胸部，细小白点形成眉毛和胡须状图案，下体灰暗。雄鸟面部白色，带有黑色斑点，上体棕色灰色，胸部有黑白相间的斑点。幼鸟与成年雄鸟相似，但体型较小，上体颜色较暗，翅膀内侧有较宽的白色条纹。","call":"雌鸟发出低沉的‘oom’声序列，每组由5到7个音符组成，持续1.5至2秒，重复14至21次，通常在大雨后几天内发出。雄鸟则会发出一系列高音断奏和咕哝声。","habits":"生活在年降水量770至1200毫米的雨林、微叶藤森林、瓶树灌丛和草地边缘。在成熟但非年轻的阿里卡里松林和偶尔封闭的桉树林中也有发现，前提是具备茂密的下层植被。它们在深达1至4英寸的落叶层中觅食，主要以昆虫为食，包括甲虫、蚂蚁和蜘蛛等。","breeding":"繁殖季节通常在8月至翌年2月，与持续的大量降雨相关联。雌鸟连续多配偶制，雄鸟独自孵化3至5枚淡黄色带有深色斑点的卵，孵化期为15至16天。幼鸟出生后不久即可离巢觅食，但由雄鸟喂养两周，约8至12周获得成年羽毛，3至5个月后可繁殖。","identification":"与彩三趾鹑相比，雌性黑胸三趾鹑头部和胸部的黑色标记更为显著，雄鸟的脸部颜色更淡，下体标记较少。其排泄物球状物末端有独特的钩状结构。","protection":"IUCN：VU（易危）","distribution":"分布于澳大利亚东部沿海地区的昆士兰东南部和新南威尔士东北部，包括弗雷泽岛。在赫维湾以南至新南威尔士东北角的区域均有零星分布。","other":"由于栖息地丧失和碎片化，以及火频和进一步的栖息地破坏，黑胸三趾鹑的数量大幅减少。物种可能正在适应Araucaria cunninghami松林和Lantana环境，但其在破碎景观中的生存能力严重依赖于森林片段间发达的灌木层。"},{"name":"栗背三趾鹑","english_name":"Chestnut-backed Buttonquail","scientific_name":"Turnix castanotus","overview":"栗背三趾鹑（英文名：Chestnut-backed Buttonquail，学名：Turnix castanotus），是鸻形目三趾鹑科三趾鹑属的鸟类。得名来源于背部的栗色羽毛，是当地特有的小型鹑类。分布于澳大利亚北部，包括西澳大利亚的金伯利地区、北领地的顶端地区以及格罗特艾兰特岛。","appearance":"体型介于14至20厘米，体重因性别而异，雄鸟约68-70克，雌鸟较重，可达87-124克。拥有结实的淡褐色喙，橙黄色眼睛和宽大的灰白色眼环，黄色腿脚。上部羽毛呈鲜艳的赤褐色，翅膀亦然。雌鸟背部颜色更鲜明，带有较少黑色斑纹和较小的翼羽白点；头部两侧和额头有黑斑白纹，灰色颈后部带白色斑点，橄榄灰色胸腹部带有清晰的奶油白色标记。非繁殖季节，雌鸟外观更接近雄鸟，上部羽毛有更多黑色，头部侧面颜色更浅。","call":"声音记录稀少，已知的是一种低沉的‘oom’声，可能为求偶期间的广告叫声。","habits":"偏好受季风气候影响的森林或林地，常出现在夏季降雨量超过800毫米的地区，但在降水量低至200毫米的地方也有记录。栖息于开阔的干草原木地带，有时在桉树森林中，常在轻度植被覆盖的石质山坡和沙质山脊上活动。以种子（包括Triodia草）和昆虫（如甲虫、蚂蚁及其卵）为食，会吞食砂砾帮助消化。夜间和黄昏活动，群居，有时以多达20只的小群觅食。","breeding":"繁殖季节发生在湿季的12月至次年5月，确切的繁殖系统未知。巢建于草丛中的凹陷处，靠近水源，通常由草和叶子铺垫，有时呈穹顶状，侧向入口。每次产卵4枚，蛋壳颜色从白色到绿色，带有棕色或黑色斑点，孵化期约为14-15天。雏鸟出生时呈赤褐色，背部有奶油色条纹。","identification":"与彩三趾鹑和更小的小三趾鹑相似，但地理分布上无重叠。比褐鹌鹑小，后者偏好湿润环境，羽毛颜色更深且较暗淡，喙更细长，下体斑纹更多，虹膜颜色更深。遇险时倾向于奔跑而非飞离，移动时采用摇摆动作，头部和身体前后晃动3-4次才迈出一步。","protection":"IUCN：LC（无危）。全球数量估计不超过10万只，自1970年代以来在北领地的种群有减少迹象。可能受到外来草食动物放牧和频繁火灾的威胁，导致Sorghum草蔓延。","distribution":"主要分布在澳大利亚北部，范围从西澳大利亚的金伯利半岛横跨至西北昆士兰州的Westmoreland Station，可能延伸至Gregory Downs和Augustus Downs东部。在昆士兰的存在于2020年得到确认。","other":"曾广泛存在于Borroloola和McArthur河附近，但目前数量锐减。"},{"name":"黄胸三趾鹑","english_name":"Buff-breasted Buttonquail","scientific_name":"Turnix olivii","overview":"黄胸三趾鹑（英文名：Buff-breasted Buttonquail，学名：Turnix olivii），是鸻形目三趾鹑科三趾鹑属的鸟类。体型最大、可能也是最稀有的三趾鹑种类，仅见于澳大利亚东北部的约克角半岛。成鸟体长18至23厘米，体重通常超过110克。雌鸟体型大于雄鸟，背部呈栗色，头部侧面带有栗色斑纹，胸部温暖的淡黄色，使它在众多鸟类中独具特色。","appearance":"黄胸三趾鹑体长18至22厘米，雌鸟体型较大。具有大喙和黄色眼睛，背部呈栗色，胸部为温暖的淡黄色。雄鸟主要为沙褐色，头部灰暗，颈部有显著黑色条纹，肩部和翅膀上有黑栗相间的条纹。雌鸟的上体比雄鸟更鲜艳的栗褐色，图案更简单，翼盖上的白色斑点较少较小，额头较暗，颈部两侧有较少的白色斑点，冠侧大多为栗色。幼鸟特征未知，但可能与成年雄鸟相似。","call":"雌鸟的招唤声为逐渐增强的‘ooom-oom-oom’，声音从几乎听不见到逐渐响亮、音调更高、更短，可重复多达20次，持续时间可达30秒。雄鸟回应以深沉快速的‘chu-chu-chu’哨声。还有深沉的哼鸣声‘gug-gug-gug’，以及软弱的‘chirp-chirp-chirp’和响亮的‘kwaare-kwaare’叫声。","habits":"栖息于低地沿海草甸或林地，海拔可达400米。偏好有Melaleuca、Acacia、Alphitonia或Tristani等植物的草地树林，以及森林和沼泽边缘的草地。它们常出现在石质山坡或山脊上，草被稀疏，几乎没有落叶层。生活在草地树林中，以种子和昆虫为食，会吞咽粗砂以辅助消化。","breeding":"繁殖季节为1月至3月，雄鸟在12月底就被观察到与雏鸟在一起。筑巢于草地或低矮灌木丛中，巢为穹顶状，由草茎构成，有侧入口，通常隐藏在草丛或低矮灌木下。每窝产3至4枚蛋，蛋壳呈白色，带有栗色、蓝灰色或黑色斑点。孵化期未知，推测雄鸟单独负责孵化和照顾雏鸟，雏鸟为早熟型，出生后不久即可离巢。","identification":"与彩三趾鹑相比，黄胸三趾鹑体型更大，腿更长，喙更重，胸部更单一，没有肩部的栗色斑块。与彩三趾鹑和褐鹌鹑共存，但明显较大，与全黑色的Quail截然不同。最相似的是栗背三趾鹑，但在野外没有重叠。","protection":"IUCN：CR（极危）","distribution":"分布于澳大利亚东北部的约克角半岛，昆士兰东北部。在Iron和McIlwraith山脉以及Far North Queensland的Morehead河等地是其重要保护区。","other":"由于过度放牧、火灾影响和人类居住区的扩张，其原始分布范围内的大部分地区已经消失，种群数量估计只有500只，历史范围仅为2070平方公里。"},{"name":"彩三趾鹑","english_name":"Painted Buttonquail","scientific_name":"Turnix varius","overview":"彩三趾鹑（英文名：Painted Buttonquail，学名：Turnix varius），是鸻形目三趾鹑科三趾鹑属的鸟类。地面生活的鸟类，分布于澳大利亚的草木森林和林地。雌鸟色彩鲜艳，眼睛深红，头部、脸部和胸部点缀白色斑点，肩部栗色并带有细白纹。雄鸟体型较小，颜色较暗淡。","appearance":"彩三趾鹑长约17至23厘米，重53至134克，雌鸟体型大于雄鸟。头部、胸部有白色斑点，红眼（繁殖季节更明显）。雌鸟上部更为栗色，雄鸟相对较小且颜色较淡。幼鸟比成年雄鸟小，前颈、胸和侧翼有黑色斑点，背部条纹不那么显眼。不同亚种在大小、颜色强度和斑点上有差异。","call":"发出持续的低沉‘oom’声，重复多达八次，间隔约1.5秒，有时伴有脚踏声。雄鸟偶尔回应以微弱的‘cluck’声。快速鼓声和柔和的咕哝声在巢边或展示时发出。","habits":"生活在干燥的林地，夜间和黄昏时觅食，以种子、果实、绿色嫩芽和无脊椎动物为食。在落叶中形成圆形刮痕觅食。夜行性或晨昏性，有时日间活动。通常成对或小群活动。","breeding":"繁殖期从8月至翌年3月，雌鸟多配偶制，雄鸟独占巢穴。巢由雌鸟用草和细碎的叶子筑成，通常位于草丛或岩石基部。每窝产3至4枚淡褐色到灰白色的蛋，雄鸟单独孵化约13至14天。雏鸟早熟，10天能飞，16天羽毛丰满。","identification":"与澳洲鹌鹑相比，有更明显的眉纹，与黄胸三趾鹑相比，体型较小，腿不那么长，黑胸三趾鹑缺少下部的栗色，头部主要黑色。雌鸟比雄鸟更亮更栗色。","protection":"IUCN：LC（无危）","distribution":"分布在澳大利亚西南部、东南部、东部和塔斯马尼亚岛。在澳大利亚西南海岸的Houtman Abrolhos群岛有一个分离的种群。","other":"彩三趾鹑曾在1922年被引入夏威夷的毛伊岛，但在新西兰引进后是否释放未知。"},{"name":"吕宋三趾鹑","english_name":"Luzon Buttonquail","scientific_name":"Turnix worcesteri","appearance":"体型较小，体长约12至14厘米，雄鸟具有黑头白斑，棕或浅褐色体羽，黄色腿；雌鸟则为棕色，饰有黑白斑点。雌鸟较雄鸟大，喉部呈淡红褐色，腹部白色，脸部带有白色斑点。","call":"鸣叫特征未知。","habits":"栖息于吕宋岛中央山脉的高海拔草甸，偶尔在松树林下的高草丛中被发现，分布高度从海平面至1100米。其食性以昆虫为主，具体觅食行为不明。生活方式隐秘，可能依赖于森林，存在季节性迁徙的假设。","breeding":"繁殖信息有限，仅知一例雄鸟于三月时生殖腺略有增大，暗示可能的繁殖期为4月至6月。部分个体在7月至次年3月期间向南分散。","identification":"与条纹三趾鹑（T. ocellatus benguetensis）和斑点三趾鹑（T. suscitator fasciatus）共栖，但体型较小，具银色厚喙，雄鸟有红胸无红侧羽和尾下覆羽，雌鸟头部主要黑白色，颈圈红褐色。与异域的松巴三趾鹑和红胸三趾鹑有细微差别。","protection":"IUCN：DD（数据缺乏）；由于分布受限，偶遇率低，生物学信息未知，物种被认为稀少且可能受威胁。人类捕猎对其构成一定程度的威胁。","distribution":"分布仅限于菲律宾吕宋岛，确切地点仅六处，最近一次记录在2009年于Dalton Pass。","other":"吕宋三趾鹑曾被认为是已灭绝数十年的物种，直到2009年再次被拍摄到。"},{"name":"松巴三趾鹑","english_name":"Sumba Buttonquail","scientific_name":"Turnix everetti","overview":"松巴三趾鹑（英文名：Sumba Buttonquail，学名：Turnix everetti），是鸻形目三趾鹑科三趾鹑属的小型鸟类。其英文名松巴三趾鹑纪念了英国殖民官员兼动物收藏家Alfred Hart Everett。松巴三趾鹑仅分布于印尼的小巽他群岛西南部的松巴岛，栖息于干燥草原、亚热带或热带湿润灌木丛、低地干草原及农田地带。","appearance":"体长约14厘米，体重约28克，雌鸟体型略大。头顶黑色，中央具亮赭色条纹，背部暗色，羽缘白色，尾部橙赭色。肩羽边缘赭色，臀羽灰白边暗，尾羽橙赭边暗。初级飞羽深色，外侧边缘浅色，次级飞羽和三级飞羽边缘及尖端白色，翼覆羽边缘赭色。上眉线红褐色，头部两侧淡色，耳羽上方至颈侧有窄黑带；喉部和胸部白色，上胸橙赭色，两胁、大腿和下尾覆羽赭色，下腹白色。喙粗壮，蓝灰色或角灰色，虹膜黄至黄白色，腿粉色。雏鸟可能与成鸟有差异，但具体细节未知。","call":"松巴三趾鹑的叫声目前尚未被描述。","habits":"栖息于松巴岛的灌木草地和未开垦的田野，偶尔出现在稀疏草地与散生灌木地带，海拔记录到220米。偏好地面觅食，以种子为主食，可能能捕食比其同岛的T. maculosus sumbanus更大的食物。常成对或以六只左右的小群体活动，遇险时倾向奔跑躲避，但在必要时也会做短距离低飞。","breeding":"繁殖信息极少，据当地村民报告，干季（7月至10月）产卵，每窝2-3枚蛋。1949年曾收集到两只雏鸟，推测孵化于6月底或7月初。","identification":"与T. maculosus sumbanus相比，松巴三趾鹑具有更深的喙基，黄色腿部，更广泛但较淡的下体橙色，以及胸部黑斑。与蓝胸鹑和褐鹌鹑在颜色上有明显区别。","protection":"IUCN：LC（无危）","distribution":"松巴三趾鹑仅分布在印尼的小巽他群岛西南部的松巴岛，分布区域包括繁殖区和非繁殖区，未见于其他区域。","other":"松巴三趾鹑的生态习性和生物学特性尚不完全清楚，已知的标本数量极少，面临森林砍伐和植被焚烧的威胁，人类捕猎也可能对其构成一定程度的威胁。"},{"name":"红胸三趾鹑","english_name":"Red-chested Buttonquail","scientific_name":"Turnix pyrrhothorax","overview":"红胸三趾鹑（英文名：Red-chested Buttonquail，学名：Turnix pyrrhothorax），是鸻形目三趾鹑科三趾鹑属的鸟类。小型、暗色、隐秘的三趾鹑，具有浅色的眼睛，广泛分布于澳大利亚（除塔斯马尼亚州北部和东南部），常见于密集的草丛生境，通常以突然从隐蔽处飞出并迅速逃离的方式被观察到。雌鸟较亮，胸部呈丰富的锈橙色，雄鸟颜色较淡，下巴白色。叫声为连续的'oom-oom-oom-oom'，音调逐渐升高。","appearance":"体长12至16厘米，雄鸟体重27至46克，雌鸟31至83克，雌鸟体型更大。上体均匀灰棕色，与大多数其他三趾鹑相比，飞行羽和覆羽之间的对比较小。雌鸟胸部锈红色，雄鸟胸部白色，侧头有锈红色延伸，雄鸟的腹部条纹更窄、更密集，很少延伸到胸部形成鳞状斑点。幼鸟体型较小，上部较暗，有白色条纹和深色条纹，翼覆羽上有大胆的白色斑点，下体白色，带有赤褐色颈环和上胸鳞状斑点。","call":"鸣叫特征为快速重复的'oom'音符，音调和强度逐渐增加。受惊的鸟会发出尖锐的喋喋不休叫声，幼鸟若被人触摸会发出微弱的类似家鸡的叫声。","habits":"栖息于密集的草丛生境，有时位于沼泽边缘或泛滥平原，偏好开阔、草地覆盖的林地，包括金合欢、桉树或桃金娘科植物。也可见于作物、稻草和杂草丛生的田野，地面覆盖密集。海拔分布从海平面至1000米。一般在较湿润、植被更密集的地方比小三趾鹑更为常见，但也存在于半干旱地区。夜间迁徙，通常对危险做出反应时会静止不动，只有在近身或迫不得已时才会低飞。","breeding":"繁殖期在北部分布区为2月至7月/9月，在南部分布区为9月至2月。独居繁殖，雌鸟连续多配偶。巢由雌鸟建造，通常是用草衬垫的凹陷，有草丛遮蔽。通常产四枚白色带有栗褐色斑点的蛋，间隔一天或两天产一枚。孵化期为13至18天，仅由雄鸟孵化和照顾雏鸟。雏鸟离巢早熟，离开巢穴自行活动，灰色带暗色和浅色背纹。6至8周达到成鸟体型，2至3个月拥有成鸟般的羽毛，6个月性成熟。","identification":"与小三趾鹑和红背三趾鹑的区别在于上体颜色均匀，胸部橙红色斑块，翼覆羽面板仅略淡于其余上翼。地面活动时，胸部的黑白鳞状斑点提供了额外的识别特征。","protection":"IUCN：LC（无危）。虽然在维多利亚州被视为受威胁物种，但在澳大利亚的其他地区普遍认为数量不多但安全。面临的主要威胁是栖息地的丧失。","distribution":"分布在澳大利亚北部、东部和南部地区，但不在塔斯马尼亚州北部和东南部。","other":"过去曾因狩猎食物和运动而受到威胁，偶尔被野猫和狐狸捕杀。"},{"name":"新喀三趾鹑","english_name":"New Caledonian Buttonquail","scientific_name":"Turnix novaecaledoniae","overview":"新喀三趾鹑（英文名：New Caledonian Buttonquail，学名：Turnix novaecaledoniae），是鸻形目三趾鹑科三趾鹑属的特有鸟类。体型较小，与曾经认为同种的彩三趾鹑（彩绘三趾鹑）相比，其翼长仅约82毫米，显著小于后者。羽毛颜色深沉，上体几乎全黑，带白边或淡褐色边缘，胸部则为黑色条纹与淡灰色基部交错。仅分布在新喀里多尼亚Grande Terre岛上。","appearance":"新喀三趾鹑体长约19厘米，比彩三趾鹑小，翼展较窄，翼长仅约82毫米。全身羽毛深色，从背部至臀部大部分为黑色，羽缘白色或淡褐色。胸部呈黑色与淡黄色条纹，带有部分淡灰色底色。嘴、腿的裸露部位颜色未知。雏鸟特征尚未描述。","identification":"与彩三趾鹑相比，新喀三趾鹑体型更小，上体颜色更深，胸部斑纹更加鲜明，翼下覆羽黑色标记更多。两个物种在羽毛颜色、形态特征上有明显差异。","protection":"IUCN：CR (PE)（极危（可能已灭绝））。新喀三趾鹑仅在新喀里多尼亚特有种鸟区发现，若存活，估计数量不足50只。自1889年首次描述以来，后续调查未能再次发现，其生存状态存疑。","distribution":"新喀三趾鹑的分布仅限于澳新界的Grande Terre岛（新喀里多尼亚）。"},{"name":"白翅三趾鹑","english_name":"Quail-plover","scientific_name":"Ortyxelos meiffrenii","overview":"白翅三趾鹑（英文名：Quail-plover，学名：Ortyxelos meiffrenii），是鸻形目三趾鹑科白翅三趾鹑属的鸟类。小型地面生活的鸟类，分布于非洲萨赫勒地区和东非的断续区域，为该属下的唯一物种。在干燥草原和荆棘灌木丛中单独或成对出现，外观略似微型的石鸻，具有沙色偏赤褐色的上部羽毛和主要为白色的下部羽毛。","appearance":"白翅三趾鹑体长10至13厘米，雄鸟体重约15.7至19.5克，雌鸟体型较大。这种鸟有明显的翅膀闪光，由白色大覆羽和黑白相间的飞羽组成，形成独特的斜向白色翼缘。飞行时，其翅膀的黑白色图案鲜明，飞行姿态摇摆不定，类似大型蝴蝶。雌鸟的胸部更偏红棕色，尾巴末端较白，带有暗褐色亚端斑点。虹膜颜色从浅到深棕色，喙呈黄角质到淡绿色，腿色为白色肉色到奶油黄色。幼鸟色泽较淡，上部羽毛不那么红，斑点更多，每根羽毛边缘更宽，白色部分更明显，下部羽毛颜色更淡，侧胸部分更红棕色，翅膀标记不够均匀。","call":"白翅三趾鹑大多保持沉默，但在月光下夜间活动时，会发出柔和的低哨声，类似于风穿过管子的声音。","habits":"白翅三趾鹑栖息于干燥的草原和荆棘灌木丛，偏好隐蔽行动，常以石鸻的方式在开阔地带快速奔跑。当受到惊扰时，它倾向于蹲伏不动，只有当观察者接近时才突然起飞，展现其起伏的飞行姿态。它在干燥季节繁殖，随着雨季来临向北迁移。夜间活动更为频繁。","breeding":"关于白翅三趾鹑的繁殖习性了解有限。产卵期从9月至次年3月，处于凉爽干燥季节。巢穴通常建在裸露的地面（有时为沙地），用叶子和茎覆盖，靠近植物基部，周围常有小鹅卵石。每次产两枚带有黑色、棕色和灰色斑点的乳白色蛋，由雄鸟单独孵化。","identification":"白翅三趾鹑的翅膀图案和飞行姿态使其与其他鸟类区分开来，尤其是飞行时的黑白色对比和摇摆飞行。雌雄之间主要通过胸部颜色和尾巴末端的差异来辨认。","protection":"IUCN：LC（无危）。白翅三趾鹑的分布广泛，虽然确切的种群趋势未知，但没有证据表明其数量正在经历足以达到评估标准的快速下降，因此被评估为无危状态。","distribution":"白翅三趾鹑在非洲的分布包括从毛里塔尼亚和塞内加尔向东至苏丹、埃塞俄比亚和肯尼亚。在萨赫勒地区，从南部毛里塔尼亚和北部塞内加尔向东至北部喀麦隆、南部乍得、南苏丹和南部苏丹，以及在贝宁南部、加纳沿海地区有零星分布。东非地区包括乌干达、肯尼亚和埃塞俄比亚。","other":"白翅三趾鹑可能因沙漠化而扩大其分布范围，特别是在肯尼亚南部，但在某些地区，如塞内加尔，自1930年代以来可能变得不那么常见。"},{"name":"石鸻","english_name":"Eurasian Stone-curlew","scientific_name":"Burhinus oedicnemus","overview":"石鸻（英文名：Eurasian Stone-curlew，学名：Burhinus oedicnemus），是鸻形目石鸻科石鸻属的鸟类。其体型较大，约41厘米长，以黄色大眼和厚实的黄色腿脚著称，羽毛呈沙棕色，腹部和臀部白色，上体有深色条纹。分布广泛，从南欧、北非至中东及中亚，偏好干燥开阔、多石或半荒漠环境。","appearance":"石鸻身长40-44厘米，体重290-535克，翼展77-85厘米。羽毛沙棕色，腹部和臀部白色，上体有深色条纹。头部细密条纹，眼上方有一白线，眼周白色，下颌至后颊有宽幅条纹，下颌和喉部白色，胸部有重黑色条纹。翅膀覆羽有平行的深棕色和白色条带，内侧初级飞羽基部和尖端有白色斑点，外侧初级飞羽中央有白色斑点。喙黄色，尖端黑色，眼睛黄色，腿脚淡黄色。幼鸟与成鸟相似，但肩羽和内翼羽毛有亮红褐色尖端。亚种在色调上有差异，从粉色调到灰色调，大小和腿长也有变化。","call":"石鸻主要在黄昏和夜间鸣叫，发出响亮的'kurrr-leee'声，首音节通常低沉或沙哑，次音节纯正，似哨音，与白腰杓鹬的鸣声类似。有时缩短为'ku-weeee'或仅'keeeuw'。在繁殖地，展示飞行时会发出快速的一系列哨声。遇险或兴奋时，会发出重复的三声哨音。还有拉长的嘶哑音，有时以柔和的上滑音结尾。","habits":"石鸻栖息于半干旱、干旱和草原地带，开放的Argan树林（摩洛哥）、稀疏植被覆盖的开阔地带，不常靠近水体。春季迁徙始于3月，秋季迁徙在8月末至10月初，部分鸟群冬季迁至撒丁岛、突尼斯、南欧、中东乃至非洲。","breeding":"繁殖季节一般在春季，3月至6月间，在北非、巴勒斯坦为3月至6月，英国从4月开始，西伯利亚从5月底开始。一夫一妻制，通常一窝产两枚蛋，平均孵化期24-27天，由双亲共同孵化。幼鸟36-42天后离巢。","identification":"石鸻以其黄色大眼、厚实的黄色腿脚和独特的黑白相间的飞行翼纹为辨识特征，与同属其他物种在体型、羽毛色彩和分布区域上有明显区别。","protection":"IUCN：LC（无危）","distribution":"分布于南欧、北非、中东至中亚，夏季迁徙至欧洲和亚洲的温带地区，冬季迁至非洲。","other":"石鸻的生存受到农业集约化的影响，某些地区的数量有所下降。"},{"name":"印度石鸻","english_name":"Indian Stone-curlew","scientific_name":"Burhinus indicus","overview":"印度石鸻（英文名：Indian Stone-curlew，学名：Burhinus indicus），是鸻形目石鸻科石鸻属的鸟类。曾被归类为石鸻的亚种。这种鸟体型较大，羽毛呈条纹状棕色，拥有刺眼的黄色大眼睛。主要分布在南亚和东南亚的平原地带，包括印度、斯里兰卡、缅甸、泰国、柬埔寨和越南南部。","appearance":"印度石鸻长约40至44厘米，雄雌相似。其羽毛主要为棕色，脸部大部分白色，黑色眼纹和亚须纹明显，翼上有三条暗色和两条交替的白色条纹。飞行时可见黑色飞羽，银色中覆羽，翅膀基部内外侧有小白色斑点，尾巴大多深色（少部分白色），以及宽大的黑色下翼边缘。腿长且黄色，喙粗壮，主要为深色。在南印度和斯里兰卡，羽毛颜色更深，条纹更宽。幼鸟背部、内翼覆羽和三级飞羽边缘呈锈色，翼覆羽上的暗色条纹不那么明显，大覆羽尖端更白。","call":"黄昏和夜间最为活跃，发出一系列快速而尖锐的‘kli！’音符，通常在天黑后鸣叫。叫声为一连串10到30个短促的吹哨声，起初音量增加，变得更为尖锐，随后放慢并在结尾处减弱，每秒3至5个音节，有时哨声变为双音节。","habits":"偏好干燥地区，包括田野、荆棘森林和干涸的河床。白天常隐藏在阴凉植被下。常见于稀疏的干枯落叶林和荆棘森林、干燥的灌木草原、低强度农业区、石质干涸的河床带灌木丛、树丛甚至花园。一般生活在低地和低丘陵地带，最高可达1000米，偶尔在尼泊尔高达1310米。","breeding":"繁殖季节主要在3月至4月，但在斯里兰卡主要为6月至7月（总体上2月至9月）。巢穴为浅浅的、无衬垫（或几乎无衬垫）的地面凹坑，一次在Suaeda fruticosa灌木的遮蔽下。产卵2至3枚淡石色至米色蛋，偶有紫色或红色，带有黑色和灰色的斑点，平均尺寸为47.6毫米×34.7毫米。刚孵出的小鸟上部为浅沙灰色，额头、脸颊、背和侧有窄黑条纹，下部白色。","identification":"与石鸻相比，体型较小，身体和上部羽毛颜色更深，条纹更宽，喙更大，基部几乎没有黄色且鼻梁黑色，折叠翼上的苍白斑块更突出，腿明显更长，尾巴更短（94至108毫米，而石鸻为115至120毫米），翅膀更短（195至215毫米，而石鸻为218至240毫米）。在南亚和东南亚范围内，与其它厚膝鸟的区别在于体型较小，喙更小，背部、颈部和胸部有条纹，头部没有明显的黑色标记。","protection":"IUCN：LC（无危）。在整个印度次大陆普遍且广泛分布，尽管部分地区报告数量下降，但在巴基斯坦罕见（其状况知之甚少）。在不丹只有两次记录。在孟加拉国，直到最近才确认为稀有留鸟，2008年至2013年间至少有十次记录（包括证实的繁殖）。在缅甸、泰国（被视为近危）、印度支那半岛（老挝仅两次近期记录，越南似乎近期无记录）较为稀缺至不常见。最近在泰国东南部农业区发现繁殖，显示出对生境改变的适应能力。","distribution":"主要分布在印度次大陆南部和东南亚洲，包括印度西北内陆、西部、斯里兰卡东部至缅甸中部、泰国中部、柬埔寨和越南南部。在干枯落叶林、荆棘森林、灌木丛、石质山丘、休耕地等生境中都能找到它们。","other":"印度石鸻的饮食主要包括昆虫、蠕虫和小型爬行动物，偶尔也会吃一些种子。"},{"name":"小石鸻","english_name":"Senegal Thick-knee","scientific_name":"Burhinus senegalensis","overview":"小石鸻（英文名：Senegal Thick-knee，学名：Burhinus senegalensis），是鸻形目石鸻科石鸻属的鸟类。又名: 塞内加尔石鸻，是石鸻科石鸻属的一种大型水鸟，以突出的长黄色或绿黄色关节闻名。分布于非洲从撒哈拉沙漠到赤道地带，以及尼罗河谷。","appearance":"小石鸻是一种中大型的涉禽，具有强壮的黑黄相间的喙，大而黄的眼睛，以及隐蔽的羽色。其长暗色的喙、折翼上的单一黑条纹和较暗的脸颊条纹是与欧洲同类物种的区别。飞行时，宽阔的白色翼条纹十分醒目。","call":"它们在黄昏和黎明时最活跃，发出响亮的‘pi-pi-pi-pi-pi-pi-pi’的叫声。","habits":"偏好干燥开阔的环境，带有一些裸露地面，最好靠近水源。它们主要在夜间活动，食物包括昆虫、甲壳类和其他无脊椎动物，也会捕食其他小型猎物。","breeding":"通常在雨季前繁殖，当河流水位低时，暴露适合筑巢的河岸和岛屿。一窝产两枚带有棕色、灰色或赭石色斑点的淡褐色蛋，雏鸟出生几天后就会离开巢穴。","identification":"与欧石鸻相似但略小，欧石鸻有白色翼斑，而小石鸻有黑色翼斑。","protection":"IUCN：LC（无危）","distribution":"分布于非洲内陆，从塞内加尔至埃塞俄比亚和肯尼亚，北至埃及，尼罗河谷也有分布。"},{"name":"水石鸻","english_name":"Water Thick-knee","scientific_name":"Burhinus vermiculatus","overview":"水石鸻（英文名：Water Thick-knee，学名：Burhinus vermiculatus），是鸻形目石鸻科石鸻属的鸟类。俗称: 水大头鸻，产于非洲热带，其最显著的特征是黄色粗长的腿、一对大而黄的眼睛，以及后背、翅膀上的浅棕灰色斑纹。喉部和眉线为白色，翅膀上独特的上黑下白‘补丁’是其标志性特征。","appearance":"水石鸻体长38至41厘米，体重约293至320克。拥有厚实的喙，黑色基部带有黄色。其翼展宽而钝，尾部较短。幼鸟与成鸟相似，但背部灰翼覆羽上有淡褐色斑点，上体和尾巴的虫蚀状条纹更为丰富。","call":"水石鸻主要在夜间鸣叫，发出响亮而略显尖锐却哀婉的哨声，节奏先快后慢，通常以群或对的形式合唱。","habits":"水石鸻栖息于河流岸边、湖泊边缘、红树林和受保护的海滩，偏好靠近水源的地带，日间需要轻林木或其它遮蔽提供阴凉。它们在夜晚活跃，有时在泥土道路上觅食，以昆虫、甲壳类和软体动物为食，活动范围可延伸至离水源1公里之外。","breeding":"水石鸻的繁殖季节因地域而异，一般在旱季或雨季初期。一夫一妻制，单独筑巢。巢穴为简单的沙地或石质地面上的凹坑，常靠近水源，产卵数通常为两枚沙黄色带暗色斑点的蛋，由双亲共同孵育，孵化期约为22至25天。","identification":"与小石鸻相比，水石鸻的翼板更宽，上部有细白线，但下缘缺乏精细的黑色边线。其上体有精细的虫蚀状图案，仅近距离可见。飞行时，翅膀较宽且末端稍钝，脚略伸出尾端。不同于其它石鸻属物种，水石鸻的上体具有虫蚀状花纹。","protection":"IUCN：LC（无危）","distribution":"水石鸻广泛分布于撒哈拉以南非洲，包括安哥拉、博茨瓦纳、布基纳法索、布隆迪、喀麦隆、中非共和国、刚果共和国、刚果民主共和国、斯威士兰、象牙海岸、埃塞俄比亚、加蓬、加纳、肯尼亚、利比里亚、马拉维、莫桑比克、纳米比亚、尼日尔、尼日利亚、卢旺达、塞内加尔、索马里、南非、坦桑尼亚、乌干达、赞比亚和津巴布韦。在乌干达和赞比亚的记录高度分别为1500米和1800米。","other":"水石鸻的分布和确切数量在西非仍了解有限，尤其是在与非常相似的塞内加尔石鸻混淆的地区。在一些地区，如赞比亚，它被记录到形成高达100只的大群。"},{"name":"斑石鸻","english_name":"Spotted Thick-knee","scientific_name":"Burhinus capensis","overview":"斑石鸻（英文名：Spotted Thick-knee，学名：Burhinus capensis），是鸻形目石鸻科石鸻属的鸟类。又译: 点斑石鸻，体长约45.5厘米，长腿和棕白相间的斑点羽毛提供极佳的伪装，使其在草原和灌木丛中难以被发现。主要分布在撒哈拉以南的非洲内陆，包括阿拉伯半岛南部。","appearance":"斑石鸻身高可达45.5厘米，拥有长而黄的腿，以及显著的黄色眼。其头部大而圆，具有一双突出的黄色眼睛和短粗喙。羽毛呈棕色与白色斑点相间，提供良好的地面伪装。飞行时或站立时翅膀举起，展现出鲜明的对比色图案。","call":"斑石鸻发出响亮、独特的声音，常在黄昏或夜间鸣叫，叫声包括一系列柔和的过滑音哨声，有时快速连发“wiw-wiw-wiw-wiw...”，有时缓慢带有哀怨的音调“weew-weew-weew-weew...”。还有报警声“pi-pi-pi-pi-pi”以及嘶哑拉长的尖叫声“krrraaa”。","habits":"斑石鸻偏好干燥地区的栖息环境，远离水边，常见于开阔的林地、稀树草原、果园、草地、田野、石质斜坡、侵蚀或废弃地带，甚至大型公园、运动场和海滩。在黄昏和夜间活动，主要以昆虫为食，也会吃小型两栖动物、软体动物、甲壳动物和部分种子。","breeding":"繁殖期通常在旱季末期或雨季初期，筑巢于地面，用草、羽毛、小石子和树枝装饰。雌鸟一般产下两个蛋，颜色为淡陶土色、奶油色或象牙色，带不规则的赤褐色斑点。孵化期约为24天，由双方轮流孵卵，雌鸟主要在白天。雏鸟出生第一天体重约20克，呈灰白色，有黑色标记。","identification":"斑石鸻的上部羽毛有基部条纹和远端斑点，而非简单的轴向条纹。面部较暗且标记不明显。翼覆羽与上部羽毛颜色更为统一。幼鸟更显条纹，斑点较少，胸部条纹更细。不同亚种在羽毛色调上有差异。","protection":"IUCN：LC（无危）","distribution":"斑石鸻分布于阿拉伯半岛南部，广泛分布于撒哈拉以南非洲内陆，包括西非的塞内加尔、马里和毛里塔尼亚，东至埃塞俄比亚、肯尼亚、坦桑尼亚和南非，南至也门南部。","other":"斑石鸻能适应受扰动的地面，近人类活动区，近年来在几内亚比绍和刚果民主共和国新发现其分布。"},{"name":"长尾石鸻","english_name":"Bush Stone-curlew","scientific_name":"Burhinus grallarius","overview":"长尾石鸻（英文名：Bush Stone-curlew，学名：Burhinus grallarius），是鸻形目石鸻科石鸻属的鸟类。夜间活跃，发出独特哀怨的叫声。","appearance":"体长54至59厘米，雄鸟体重580至860克，雌鸟530至710克。两性相似，但雌鸟略小。长腿、长尾，体型纤细，羽毛有灰色和赤褐色变型，上体有深色条纹，下体羽毛斑驳，眼睛乳白色，逐渐变为黄色。头部大而圆，眼眶周围皮肤黑色，喙细长且全黑。","call":"主要在黄昏和夜晚发声，叫声为一系列凄婉的哀号，通常双音节，\"wheee-hoo...wheee-hoo...\"，有时以快速、尖锐的\"wee-whu-ho...wee-whu-ho...\"回应。","habits":"栖息于开阔森林、林地空地、草地、农田、盐沼边缘等，偏好地面有枯木或落叶覆盖的环境。夜行性，以昆虫、软体动物、蜘蛛、两栖动物、小型爬行动物和偶尔的种子为食。在明亮月光下特别活跃。","breeding":"春季繁殖，北部比南部早。一夫一妻制，单独繁殖。巢筑于地面，通常位于树下短草或长草中，平均距离最近树木约12米，视野开阔。产卵两枚，孵化期25天，由双方共同孵化。雏鸟59天后能飞，父母照顾至138天左右。","identification":"与澳洲石鸻相比，体型较小，喙较细，颜色更灰暗，生活环境远离海岸。","protection":"IUCN：LC（无危）。总数量约15万只。在南澳大利亚自1940年代以来急剧减少，但在袋鼠岛（Kangaroo Island）因缺乏红狐而数量稳定。","distribution":"分布于澳大利亚内陆南部（不含塔斯马尼亚）、新几内亚Trans-Fly内陆南部。常见于澳大利亚东北部城市如布里斯班、凯恩斯、汤斯维尔。","other":"历史上在西南澳大利亚普遍，20世纪数量大幅下降，主要归咎于红狐的引入。在一些地区，农业活动有利于局部种群增长。"},{"name":"双纹石鸻","english_name":"Double-striped Thick-knee","scientific_name":"Hesperoburhinus bistriatus","overview":"双纹石鸻（英文名：Double-striped Thick-knee，学名：Hesperoburhinus bistriatus），是鸻形目石鸻科 Hesperoburhinus 属的鸟类。以显著的白色粗眉纹而闻名，栖息于热带美洲，从墨西哥南部到哥斯达黎加西北部，多米尼加和海地北部，以及哥伦比亚到巴西北部的广阔区域。这种大型且奇特的石鸻，通常成对或小群体出现在低地干旱草地和大草原上。","appearance":"双纹石鸻是一种中大型涉禽，拥有强健的黑黄相间喙，巨大的黄色眼睛赋予其类似爬行动物的外观，以及具有伪装效果的羽毛。成鸟长约46至50厘米，体重约780至785克。它的上体呈灰褐色细条纹，颈部和胸部颜色较淡，逐渐过渡到白色的腹部。头部有一条明显的白色眉线，上方边界有一条黑色条纹。幼鸟与成鸟相似，但上体颜色略深，颈背部分呈白色。飞行时，双纹石鸻的翅膀下方白色与后缘黑色形成鲜明对比。","call":"双纹石鸻在夜间发出响亮的kee-kee-kee叫声。","habits":"这是一种主要在夜间和黄昏活动的物种，飞行时相当不情愿，更依赖于蹲伏和伪装以隐藏自身。它栖息于干旱的草地、大草原和其他干燥开阔的环境，以大型昆虫和其他小型脊椎动物及无脊椎动物为食。由于其控制昆虫的有益作用，有时被半驯化，且从林地开垦成牧场的过程中受益。","breeding":"双纹石鸻的巢穴是一个简单的坑洞，雌雄双方共同孵育两个橄榄棕色的蛋，孵化期为25至27天。刚孵化的绒羽幼鸟很快就能离开巢穴。","identification":"双纹石鸻与秘鲁石鸻相似，但体型更大，上体颜色更深，图案更复杂，喙更厚实，冠部颜色更暗，胸腹之间色差更明显。飞行时，翅膀的图案对比不那么强烈。两者在地理分布上没有重叠。","protection":"IUCN：LC（无危）","distribution":"双纹石鸻分布于中美洲和南美洲，具体范围包括墨西哥内陆南部至哥斯达黎加西北部，多米尼加和海地北部，以及从哥伦比亚到巴西北部的区域。"},{"name":"秘鲁石鸻","english_name":"Peruvian Thick-knee","scientific_name":"Hesperoburhinus superciliaris","overview":"秘鲁石鸻（英文名：Peruvian Thick-knee，学名：Hesperoburhinus superciliaris），是鸻形目石鸻科 Hesperoburhinus 属的中等体型的夜行性鸟类，分布于南美沿海地带，自厄瓜多尔南部至智利北部。其显著特征为大而淡色的眼睛、条纹头部和长长的黄白色腿。生活在干旱沙漠环境，偏好沙质和石质地表。","appearance":"体型介于38-43厘米，雌鸟平均重量约480克。拥有较长的颈部和腿。与B. bistriatus相比，体型更小，颜色偏灰，具有白色眼眉线，边缘黑色；喙较小，基部带有更多淡黄绿色；上体斑纹较轻；飞行时，展示出对比鲜明、无斑点的灰色翅膀覆羽，与深色飞羽形成明显对比。幼鸟上体羽毛呈更深的棕色，边缘温暖的赭色。","call":"黄昏和夜间较为活跃，主要发出响亮的‘kak’音节的展示叫声，类似黑颈 stilts 的叫声。受惊时发出一系列鼻音，常成对或短连串5-10声的‘ka-ka-ka-ka....ka-ka-ka-ka...’。","habits":"栖息于干燥农业土地、半沙漠和干草原，偶尔出现在人类聚居地的尘土飞扬的小块土地上。日间休息，常在阴凉处坐地休息。倾向于奔跑而非飞行以逃避危险。夜间活动，通过远距离传播的吠叫声揭示其存在。","breeding":"繁殖信息知之甚少。可能单独繁殖，但在繁殖季节可能出现小规模聚集。巢通常位于岩石斜坡上的轻微凹陷处，清除植物残渣。已知产卵数量为两个，蛋尺寸约为52.6-52.9毫米×35-36.7毫米。雏鸟记录在秘鲁利马省。","identification":"与B. bistriatus的区别在于体型更小、色彩更灰，以及独特的白色眼眉线和较轻的上体斑纹。","protection":"IUCN：VU（易危）","distribution":"分布于南美洲太平洋海岸，从厄瓜多尔最南端至智利最北端（Lluta和Azapa山谷）。","other":"物种被当地人视为神秘，因其夜间活动和响亮的叫声。目前无明确威胁，但需监测和研究基本生态需求。"},{"name":"大石鸻","english_name":"Great Stone-curlew","scientific_name":"Esacus recurvirostris","overview":"大石鸻（英文名：Great Stone-curlew，学名：Esacus recurvirostris），是鸻形目石鸻科大石鸻属的鸟类。大型涉禽，以其独特的暗色面罩、凝视的淡色眼睛和巨大的厚重喙著称。广泛分布于热带南亚地区，包括印度、巴基斯坦、斯里兰卡、孟加拉国直至东南亚。该物种在河流岸边及湖泊岩石或沙质岸线可见。","appearance":"大石鸻体型庞大，体长41.5至54厘米，翼展90至100厘米，重量约790克。拥有类似鹬类的外观，但比例更像鸨类。背部呈灰色无条纹，脸部有强烈的黑白对比图案，黑色颊斑上方环绕着白色，喙粗壮，尖端稍向上翘，基部黄色宽大。飞行时，黑色飞羽和显著的白色主翼斑点以及宽阔的浅灰色上翼覆羽带十分醒目。脚几乎不超出尾部。无季节性和性别差异的羽毛变化，幼鸟与成鸟相似，但新羽毛边缘呈淡黄色。","call":"大石鸻的叫声通常是一种高亢的、逐渐加速的口哨声，叫声为“tleeeeLIK！”并且通常在受惊时会重复发出。在夜间，这种叫声特别常见，传递着强烈的警告信号。警觉时，它也会发出响亮的刺耳的“see-eek”或紧张的“kree-ip”声音，有时还会快速连续发出“uit-uit-uit-uit-uit…”的声音。","habits":"偏好河流砾石岸、大湖旁的石头或泥滩（较沙质环境更为偏爱）。有时会在河流泛滥时造访附近的草地。偶尔出现在沿海沙滩、沙洲、潮间带和盐田。主要在黄昏后活动，但也可能在日间觅食，以螃蟹、昆虫和其他动物性食物为主食。通常独居或成对出现，偶尔形成家庭群，有时会聚集到大约20只左右的小群体。","breeding":"繁殖期在印度为2月至7月，巴基斯坦为3月至6月，斯里兰卡主要在4月至7月。筑巢于河流砾石岸、石岛或泻湖边缘的稀疏草丛中，巢穴简单，以干枝装饰，靠近水源。产卵1至2枚，颜色为淡黄白色，带有深色斑点，平均尺寸为54.4毫米×41毫米。双亲共同孵化，孵化期约28天，雏鸟覆盖着‘胡椒盐’状的黑色斑点绒毛。","identification":"与稍微相似的澳洲石鸻不同，大石鸻的额头为白色，次级飞羽为黑色而非浅灰色，嘴巴较为纤细。在生境中无相似物种，澳洲石鸻出现在沿海沙滩、泥滩和暴露的珊瑚礁。","protection":"IUCN：NT（近危）","distribution":"分布于远东地区，包括河流系统、亚洲南部和东南部、伊朗南部、巴基斯坦内陆的印度河谷、喜马拉雅山南麓的印度南部至斯里兰卡，以及泰国北部、柬埔寨北部和越南北部至南部。","other":"对栖息地改变有适应能力，能在水库边缘生存繁殖。但繁殖期较为警惕，需要大面积不受干扰的区域。"},{"name":"澳洲石鸻","english_name":"Beach Stone-curlew","scientific_name":"Esacus magnirostris","overview":"澳洲石鸻（英文名：Beach Stone-curlew，学名：Esacus magnirostris），是鸻形目石鸻科大石鸻属的鸟类。体型庞大的涉禽，广泛分布于澳洲、东南亚岛屿及南太平洋。其特征为硕大的喙，黑白相间的面部，以及黄色的大眼睛。常见于海岸线，尤其偏爱海滩、礁石和河口地带。","appearance":"澳洲石鸻体长51至57厘米，雄鸟体重870至1130克，雌鸟980至1020克。拥有厚重的头部和粗壮的喙，头部有鲜明的黑白灰条纹，喙呈黑色，基部有黄色区域。黄色的眼睛格外显眼，上体无斑纹，翅膀宽大且末端较方，飞行时展现出类似鸨类的外观。腿部中等长度且强健。幼鸟的裸露部分颜色较为暗淡，上体羽毛有淡黄色边缘，尤其是上翼覆羽。","call":"澳洲石鸻主要在夜间发出声音，鸣叫包括重复的双音节哨声“kee-wee”或“kee-loo”，比其他石鸻类更尖锐、更像笛声。还有短弱的警报声“wik!”以及沙哑的叽喳声。","habits":"严格沿海岸线栖息，偏好岛屿和大陆的海滩环境。适应性强，可栖息于各种类型的海滩，如沙地、泥滩、石滩或岩石区，无论狭窄或宽阔，平静或被浪花拍打。常见于河口处，偶尔出现在潮汐溪流。在珊瑚礁和环礁上也很活跃，甚至愿意进入高达1.5米的红树林中。受惊时会飞向大海，然后返回海滩；偶尔在沙丘或沿海泻湖边缘发现。","breeding":"繁殖期在澳大利亚的9月至11月，更北地区则从4月至11月。可能实行一夫一妻制。在较低密度下以孤立的配对形式繁殖，可能在同一区域持续多年居住。巢建在沙洲、沙嘴或岛屿上，位于广阔的海滩后方，可能在红树林或草地之间。巢为浅坑，有时用枯叶和树枝围成一圈。产一枚淡奶油色、淡棕色或灰色的蛋，上有黑色至深棕色的斑点，平均大小为63.7毫米×45毫米。孵化至少需30天，性别角色未知；幼鸟在五周开始长毛，约七周时外观接近成鸟，但仍有残留的绒毛持续五周；由两性共同照顾；约十二周能良好飞行，但可能需要7至12个月才能独立。","identification":"与较小的大石鸻相比，澳洲石鸻在喙形和面部图案上有差异；闭翅时，宽阔的淡色冀上的黑色带状标记更为明显；飞行时，次级飞羽全为灰色，内侧初级飞羽统一白色。","protection":"IUCN：NT（近危）","distribution":"分布于远东、澳新界，包括印度洋和太平洋的海岸线和岛礁，从安达曼群岛、马来半岛和菲律宾西南部、南部，延伸至印尼群岛、新几内亚和澳大利亚西北方的卫星岛，中北部至新南威尔士州东南部（澳大利亚西北部、北部、东部），覆盖俾斯麦群岛（含阿德默勒尔蒂群岛），最北可达所罗门群岛东南部（除Rennell岛）。","other":"由于栖息地丧失、低繁殖率以及引入的捕食者数量增加和人类活动的干扰，物种可能处于脆弱状态。在澳大利亚北部昆士兰州，尽管在适宜的生境中广泛分布，但已知的繁殖记录很少，这可能与高程度的人为干扰有关。"},{"name":"白鞘嘴鸥","english_name":"Snowy Sheathbill","scientific_name":"Chionis albus","overview":"白鞘嘴鸥（英文名：Snowy Sheathbill，学名：Chionis albus），是鸻形目鞘嘴鸥科鞘嘴鸥属的鸟类。是鞘嘴鸥科下的两种鞘嘴鸥之一，也是南极洲唯一的本土陆生鸟类。体长约380至410毫米，翼展约760至800毫米，通体纯白，仅面部呈粉色且有疣状突起。在南极半岛、南设得兰群岛、南奥克尼群岛和南乔治亚岛繁殖，冬季向北迁徙至智利中南部沿海和阿根廷中东部直至合恩角和福克兰群岛。","appearance":"白鞘嘴鸥体型健壮，全身羽毛洁白无瑕，除了一张裸露的淡粉色脸部皮肤和灰蓝色的腿脚。喙部呈锥形，粗壮，覆以淡绿色至橙色的鞘状物。成鸟与幼鸟的区别在于喙鞘的大小和面部疣状突起的程度，成鸟还拥有钝黑的腕刺，用于领土争斗。两性外观相似，但雄鸟平均体重比雌鸟重约15%，喙部和鞘状物更大。","habits":"白鞘嘴鸥主要栖息于南极半岛及周边岛屿，冬季会迁徙至南美洲最南端。它们在海洋鸟类和哺乳动物的聚居地附近活动，以寻找食物和食用其他动物的粪便，尤其是企鹅的。它们不畏惧人类，常在海狮和企鹅群落中大胆觅食，甚至吃排泄物。白鞘嘴鸥不会在水中停留，但会乘船航行。它们的觅食时间占日间活动的86%，其余时间休息。","breeding":"白鞘嘴鸥的繁殖习性资料较少，但已知它们在南极地区的特定岛屿上筑巢繁殖。具体繁殖期、求偶行为、巢穴建造、交配、产卵、孵化和育雏的细节尚需进一步研究。","identification":"白鞘嘴鸥与黑脸鞘嘴鸥最为相似，但后者面部特征全黑，两者地理分布不重叠。白鞘嘴鸥的面部色彩更为丰富，其鞘状物不如黑脸鞘嘴鸥显眼。此外，白鞘嘴鸥体型较小，步态类似鸽子，动作迅速，与鸥类（Larus）或白草雁有显著区别。","protection":"IUCN：LC（无危）","distribution":"白鞘嘴鸥主要在南极半岛、南设得兰群岛、南奥克尼群岛和南乔治亚岛繁殖。非繁殖季节，它们迁徙至智利中南部沿海和阿根廷中东部，直至合恩角和福克兰群岛。"},{"name":"黑脸鞘嘴鸥","english_name":"Black-faced Sheathbill","scientific_name":"Chionis minor","overview":"黑脸鞘嘴鸥（英文名：Black-faced Sheathbill，学名：Chionis minor），是鸻形目鞘嘴鸥科鞘嘴鸥属的白色鸟类。体型紧凑，颈部短，类似鸽子，具有黑色的喙、肉垂和面部皮肤。分布于南印度洋的亚南极岛屿，包括南非的王子爱德华群岛、法国的克罗泽特群岛和凯尔盖朗群岛，以及澳大利亚的赫德岛。","appearance":"体长38至41厘米，翼展74至79厘米，体重450至760克，雄鸟平均比雌鸟大约15%。喙、喙鞘和面部肉垂全黑，眼环粉红色，腿色在不同种群间和种群内部变异，从粉红到紫黑色不等。小体型的亚种通常略小于大多数非洲白颈鸦亚种。幼鸟的喙鞘和眼环较小，腿色较暗，是识别年龄的一个有用特征。","call":"一般被认为是相当沉默，除了偶尔发出短促的嘎嘎声或嘶哑的叫声。","habits":"夏季几乎所有的个体出现在企鹅群中，尤其是凤头黄眉企鹅和长眉企鹅的群落，冬季时王企鹅群落更为重要。在海豹栖息地、潮间带岩石和沙滩区、内陆沼泽、草地和距海岸1公里内的苔草丛中觅食，也常在人类聚居地附近活动。","breeding":"与企鹅群或其它海鸟群如鸬鹚一起筑巢，有时全年留在繁殖领地。在10月至11月间重新占领跳岩或长眉企鹅群落中的领地，12月至次年1月产卵，1月至2月孵化，3月底至4月离巢。通常产2至3枚蛋，孵化期平均28天，幼鸟孵化后14天内持续被照顾，之后逐渐减少，55至60天离巢（克罗泽特和马里昂岛），但在凯尔盖朗岛为65至70天。","identification":"在其分布范围内没有相似物种。东部（克尔盖伦和赫德）和西部（王子爱德华、马里昂和克罗泽特）的亚种在体型、喙鞘大小和腿色上有细微差异。","protection":"IUCN：LC（无危）","distribution":"分布于南印度洋亚南极西部和中部岛屿，包括南非的王子爱德华群岛、法国的克罗泽特群岛和凯尔盖朗群岛，以及澳大利亚的赫德岛。","other":"面对家猫和鼠类数量增加的威胁，以及全球变暖的影响，种群数量在某些地区有所下降。"},{"name":"短腿鸻","english_name":"Magellanic Plover","scientific_name":"Pluvianellus socialis","appearance":"体长19.5-21.5厘米，雄鸟体重79-102克，雌鸟69.5-87克。外观似蛎鹬，非常短的腿，柔软的灰上体和胸部，下胸带棕色色调，其余下体、喉咙和下巴白色。喙短而尖，基部有粉色斑块，腿和虹膜粉红至红色。飞行时展示相对醒目的白色翼条。雌雄相似，无季节性变化。幼鸟上体有白色和浅黄色斑点，胸带条纹灰，缺乏成鸟的深色眼睑；腿黄色，虹膜橙灰色，下喙基部黄色。","call":"发出类似鸽子的‘coo’或‘ceu’音，还有升调后降调的哨声‘weeEEEEooooo’，以及报警时的‘pip-wheet’声。","habits":"栖息于淡水或咸水湖泊的开阔湖岸，偶尔沿河流。冬季迁徙至海岸，主要在避风港湾、泻湖和河口。以微小的节肢动物为食，尤其在冬季依赖摇蚊幼虫。采用独特的行为寻找食物，如翻转石头、贝壳和碎片，甚至偶尔挖掘沙土，行为在涉禽中独一无二。活跃且奔跑迅速。","breeding":"繁殖期从9月初至11月中旬。在清澈或泥泞湖泊的宽广泥或鹅卵石岸上筑巢，巢由砾石铺成，靠近水面。尝试多次繁殖，即使首次成功也不例外。产卵1-2枚，平均大小34.8x25.2毫米，由双亲共同孵化24天。孵化后的小鸟体羽淡赭色和暗色相间，带有白色绒毛尖，非常虚弱，由父母喂养，有时通过反刍食物喂养。约28-35天后离巢，可能额外喂养十天。较弱的小鸟通常因饥饿而死亡。","identification":"其独特的外形，包括短腿、灰上体、白色翼条和粉红色的眼睛和腿，使其容易与其他涉禽区分开来。与蛎鹬相比，它的体型更健壮，腿色更鲜艳。","protection":"IUCN：VU（易危）。总数量可能不超过1500只，但估计可能高达10000只。在圣克鲁斯省的Río Gallegos河口和附近的Río Chico河口，以及火地岛的圣塞巴斯蒂安湾，冬季时观察到的个体数最多可达数百只。","distribution":"繁殖于阿根廷西南部的圣克鲁斯省内陆西部，智利远东南部的马加兰尼斯省东南部，以及火地岛北部和中部。非繁殖期分布于阿根廷中东部沿海，东南部至东南部布宜诺斯艾利斯省。在巴塔哥尼亚的Puerto Madryn和Península Valdes过冬。","other":"已知至少在圣克鲁斯省的四个保护区发现：Los Escarchados野生动物保护区、佩里托莫雷诺国家公园、蒙特莱昂国家公园和石化森林自然纪念碑。"},{"name":"智利蛎鹬","english_name":"Magellanic Oystercatcher","scientific_name":"Haematopus leucopodus","overview":"智利蛎鹬（英文名：Magellanic Oystercatcher，学名：Haematopus leucopodus），是鸻形目蛎鹬科蛎鹬属的大型涉禽。分布于南美洲南部，包括智利沿海和内陆中南部、阿根廷中南部至合恩角以及福克兰群岛。以其独特的黑色头部和上体、白色腹部以及鲜明的黄色眼环著称。","appearance":"体型大而粗壮，长度介于42至46厘米之间，体重在585至700克之间，雌鸟较重。拥有长而橙红色的喙、黄色的眼环和腿脚。头部、胸部、背部、翅膀和尾巴呈黑色，下体为白色。飞行时可见内侧翼上的白色羽毛。与美洲斑蛎鹬相似，但可通过黄色眼环和白色的次级飞羽加以区分。背部全黑，区别于其他种类的褐色背部。","call":"鸣声典型于蛎鹬，展示叫声为重复的、尖锐的“pee-pee”，另有‘peep’叫声用于联系和警报，以及一种独特、柔和、哀怨的双音节哨声“hoo-eep”或“pee-you”。","habits":"偏好岩石海岸线和邻近的河口，同时频繁出现在附近的草原和湖岸。繁殖季节在内陆高草地上筑巢，非繁殖季节则迁移到海岸线，形成大群。以贝类、海螺和螃蟹为食，也会捕食多毛纲蠕虫。在内陆主要摄食蚯蚓和昆虫幼虫。采用锤击、撬开、探查和刺戳等多种技巧攻击不同的猎物。","breeding":"繁殖期开始于10月至11月，在合恩角地区，而在福克兰群岛主要繁殖季节为9月下旬至10月下旬。雄鸟会展示翘尾行为，尾羽竖直以展示下尾羽的图案，这是蛎鹬中的独特行为。巢穴建在沙地、短草或枯海藻上，有时被附近植物部分遮蔽。每窝产卵1至2枚，通常为两枚，颜色为橄榄棕、米色或绿色，带有深黑色斑点。","identification":"与其他蛎鹬区别在于几乎完全白色的次级飞羽（从上方和下方看），以及黄色眼环。黑色延伸至胸部的程度超过其他种类。雌鸟与雄鸟相似，但喙更长、更细，比全黑的更为纤薄。","protection":"IUCN：LC（无危）。总体上数量常见到丰富，特别是在其分布范围的南部地区。福克兰群岛的估计种群量在7000至13,000对之间，物种在群岛中广泛分布。尽管分布范围有限，但由于人类活动影响较小，目前物种状态安全。","distribution":"繁殖于南美洲南部，包括智利中南部沿海和内陆、阿根廷中南部至合恩角，以及福克兰群岛。非繁殖季节迁移到海岸线。","other":"近年来，‘冒险’旅游的推广可能对智利蛎鹬造成影响，包括人类增加的存在、污染、娱乐活动和普遍的干扰，但目前看来物种处于安全状态。"},{"name":"南美黑蛎鹬","english_name":"Blackish Oystercatcher","scientific_name":"Haematopus ater","overview":"南美黑蛎鹬（英文名：Blackish Oystercatcher，学名：Haematopus ater），是鸻形目蛎鹬科蛎鹬属的鸟类。体型大而健壮的海滨涉禽，栖息于岩石海岸、邻近沙滩和河口。其显著特征为全暗色的羽毛，橙红的长喙和厚实的粉色腿脚。分布于南美洲，自秘鲁北部至阿根廷东南部，至合恩角和福克兰群岛。","appearance":"体长43-45.5厘米，重585-850克。羽毛深褐色，背部呈黑褐色；眼圈红色，眼黄色；喙橙红色，尖端较浅；腿粉灰色。雌鸟比雄鸟略大，喙更大，眼睛上的暗斑更明显。幼鸟羽毛有淡色边缘，非繁殖季节腹部羽毛边缘白色。种族差异主要体现在腿部颜色、体重和喙的深度。","call":"频繁发出连续的滑音哨声，如'peep'或'kleep'。展示时，一只鸟会发出这些哨声，另一只则开始发出响亮的颤音，随后是一系列延长的哨声。","habits":"繁殖于砾石和贝壳海滩。非繁殖季在鹅卵石和岩石海岸以及泥滩出现。主要以贝类为食，如贻贝和帽贝。在冬季，迁移到泥滩几乎专吃贻贝。","breeding":"繁殖始于11月，产卵数1-2枚，通常为两枚。筑巢于地面，靠近高潮水位线，巢穴由贝壳碎片和岩石碎片铺成。孵化期24-33天，雏鸟在40天左右离巢。繁殖成功率受天敌如鸥类和贼鸥的影响。","identification":"与其他蛎鹬相比，其全暗色的羽毛和橙红色的喙是明显的辨识特征。雌雄差异主要在于体型和喙的大小。","protection":"IUCN：LC（无危）","distribution":"繁殖于南美洲，包括秘鲁沿海北部至阿根廷东南部，至合恩角和福克兰群岛。非繁殖期至乌拉圭南部沿海。","other":"在一些地区，由于人类活动如娱乐干扰、风暴、蛋的不孕和天敌如乌鸦的影响，繁殖成功率较低。"},{"name":"北美黑蛎鹬","english_name":"Black Oystercatcher","scientific_name":"Haematopus bachmani","overview":"北美黑蛎鹬（英文名：Black Oystercatcher，学名：Haematopus bachmani），是鸻形目蛎鹬科蛎鹬属的鸟类。显著的黑色涉禽，广泛分布于北美洲西海岸，自阿拉斯加的阿留申群岛至墨西哥下加利福尼亚半岛。其科学命名源自约翰·詹姆斯·奥杜邦对其友人约翰·巴赫曼的致敬。","appearance":"体型较大，长约42-47厘米，重500-700克。全身黑色，仅在北美洲发现的全黑色滨鸟。头部、颈部及胸部为黑色，背部、腹部及翼覆羽呈灰褐色。颈后常显蓬松。拥有长而直的橙红色喙，喙尖黄色，明亮的黄色虹膜，橙红色的眼环，健壮的淡粉色腿。雌雄在羽毛上基本相同，但雌鸟体型更大，喙更长更细。","call":"会发出响亮的叫声，通常是快速连续的哀鸣和口哨声，尤其是在兴奋时更为明显。","habits":"严格依赖海洋沿岸环境，偏好岩石海岸线，以贝类和其他无脊椎动物为食。繁殖季节建立明确的复合领地用于觅食和筑巢，通常年复一年占据同一领地。成对或小群出现，冬季时可能会离开领地形成大群，尤其在高密度贝类区域，群体数量可达数百。人类活动导致的岛屿干扰已使某些巢区的黑蛎鹬局部灭绝。","breeding":"在岛屿、岬角和海滩上筑巢，于潮间带觅食，偶尔出现在开放的潮滩或草地。每窝产卵2-3枚，孵化期约26-28天。雏鸟出生一天后即可离巢，但会在领地停留较长时间，直至羽翼丰满后约40天。幼鸟在下一个繁殖季前仍留在领地，若父母迁徙，则当年的幼鸟可能随行，尤其是在北方地区。","identification":"大型，体型笨重的滨鸟，具有非常长且厚实的直喙。比矶鹬大，比长嘴鹬小。成鸟黑色，带有醒目的橙红喙和黄色眼环。近距离观察时，翅膀、尾巴和背部为深棕色。幼鸟总体呈褐色，喙尖深色。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美洲太平洋东岸北部，从阿拉斯加的阿留申群岛西部至墨西哥下加利福尼亚州中西部（墨西哥西北部）。"},{"name":"美洲斑蛎鹬","english_name":"American Oystercatcher","scientific_name":"Haematopus palliatus","overview":"美洲斑蛎鹬（英文名：American Oystercatcher，学名：Haematopus palliatus），是鸻形目蛎鹬科蛎鹬属的鸟类。以独特的黑白羽毛和醒目的橙红色喙著称。广泛分布于北美东海岸至南美的沿海地带，偏好盐沼和沙滩环境，以贝类和海洋无脊椎动物为食。在繁殖季节，沿大西洋和墨西哥湾海岸线活动，冬季则聚集在较温暖的南部地区。","appearance":"美洲斑蛎鹬身长40-44厘米，体重400-700克，头部和胸部为黑色，背部、翅膀和尾巴呈灰黑色，腹部白色。具有长而直的亮红至橙色喙，淡粉色腿，无第一趾。黄色虹膜，有时带有暗斑点。飞行时可见狭窄的白色翼条，喙侧压扁，黄色眼睛环绕着红色眼环和黑色头颈，与褐色背羽形成鲜明对比。雄鸟和雌鸟外观上无法区分，幼鸟的喙有尘土橙色至灰色的变化，背部羽毛有浅色边缘，直至完全成熟。","call":"发出响亮的叫声，通常是快速系列的尖叫声和哨声，特别是在兴奋时。","habits":"美洲斑蛎鹬主要栖息在沿海地带，偏好海滩、盐沼、沙丘和泥滩等环境。它们以贝类和其他海洋无脊椎动物为食，利用强壮的喙切割或砸开猎物。大部分时间在潮汐休息区度过，但在求偶、领地争斗和应对入侵者时会变得非常活跃且声音响亮。","breeding":"繁殖期通常在4月至7月，巢穴为沙地上浅凹的巢，由成鸟挖掘，内衬贝壳或鹅卵石。每窝产卵2-4枚，卵呈灰色并有深棕色斑点。孵化期为25至27天，双亲轮流孵卵。雏鸟出生时覆盖着淡色绒毛，约35天后离巢，但直到60天后喙才足够强壮以撬开贝类。","identification":"与北美黑蛎鹬杂交产生的个体在黑帽与白腹相遇处有杂乱的斑点，可能范围有限但往往相当广泛。成鸟与欧洲蛎鹬的区别在于褐色背羽、较淡的腿色和较短较窄的翼条；与智利蛎鹬的区别在于较暗的上部羽毛、红色眼环、暗尖二级飞羽和较暗的初级覆羽下部。","protection":"IUCN：LC（无危）","distribution":"分布于北美、中美和南美沿海，从墨西哥西部到智利南部；美国东北部海岸至墨西哥北部海湾，尤卡坦半岛；加勒比海地区（局部）至阿根廷南部。","other":"在美国某些州，由于数量低且下降，美洲斑蛎鹬被列为关注物种。"},{"name":"坎岛蛎鹬","english_name":"Canary Islands Oystercatcher","scientific_name":"Haematopus meadewaldoi","appearance":"成鸟体长约43厘米，通体深黑，眼红色，眼圈与喙呈橙红色，腿淡粉红。飞行时从下方可见初级飞羽基部色淡，但此特征可能与羽毛磨损有关。幼鸟特征无记录。","call":"无相关信息。","habits":"栖息于岩石与沙质海岸，可能主要偏好岩石海岸。推测为留鸟，迁徙行为未知。食物以贻贝和笠贝为主，潜在猎物包括Patella candei、P. pipperata、P. cf. aspera等笠贝及贻贝Perna picta；这些物种在加那利群岛东部均遭人类过度捕捞。蛎鹬科鸟类通常以敲击、撬、探、刺等多种技巧捕食不同猎物。","breeding":"巢与卵均无描述。1888年4月初于富埃特文图拉岛南部曾捕获一只“即将产卵”的雌鸟；1890年4月初于格拉西奥萨岛捕获一对处于繁殖状态的成鸟。推测每窝产卵1–3枚。","identification":"与非洲黑蛎鹬相比，其翼更短、喙更长；与美洲斑蛎鹬相比，背部为纯黑而非黑褐色，眼为红色而非黄色；与澳洲黑蛎鹬相比，翼与尾均较短，喙与翼长亦略短于新西兰蛎鹬黑色型","protection":"IUCN: EX（灭绝）","distribution":"繁殖及非繁殖区域：加那利群岛东部的格拉西奥萨岛、兰萨罗特岛、富埃特文图拉岛及其近海小岛（Montaña Clara、Roque del Este）。","other":"本种的物种有效性曾受质疑，因标本极少无法进行有意义分析。曾被视作与非洲黑蛎鹬或蛎鹬同种，或为两者共同的复合种。单型种，无亚种分化。过度捕捞潮间带无脊椎动物、人类干扰、外来鼠类与猫的捕食被认为是导致其灭绝的主要因素。"},{"name":"非洲黑蛎鹬","english_name":"African Oystercatcher","scientific_name":"Haematopus moquini","overview":"非洲黑蛎鹬（英文名：African Oystercatcher，学名：Haematopus moquini），是鸻形目蛎鹬科蛎鹬属的鸟类。大型且具魅力的海滨涉禽，广泛分布于非洲南部的大陆海岸和近岸岛屿。这种近威胁物种拥有超过6,000只成年个体，繁殖季节通常在11月至次年4月之间。其学名中的moquini是为了纪念法国自然学家Alfred Moquin-Tandon，他最早发现并命名了这一物种。","appearance":"非洲黑蛎鹬是一种体型较大的海滨鸟类，全身羽毛呈光泽黑色，具有醒目的鲑红色腿脚和红褐色眼睛、眼环及喙。雌雄外观相似，但雌鸟体型稍大，喙部略长。幼鸟羽毛色泽较淡，呈灰褐色，腿部和喙色较为暗淡，直到离巢后才逐渐展现出成鸟的特征。成鸟体长约42-45厘米，翼展可达80-88厘米，雄鸟体重约665克，雌鸟约730克。","call":"其鸣叫特征为响亮的笛声‘kleep’、‘kleep-a’或‘klee-eep’，在领土防御时会发出快速重复的‘kleepee-kleepee-kleepee-kleepee’叫声，音量和速度可变，有时伴有急促的颤音。","habits":"主要栖息于岩石和沙滩地带，偏好在岩石海岸和沙质海滩上筑巢。成鸟通常定居于其领地，而幼鸟则可能进行长达数千公里的迁移。以贝类、蠕虫和其他无脊椎动物为食，如贻贝、帽贝、多毛纲动物、螺类和甲壳类。","breeding":"繁殖期主要在9月至次年4月，通常在砂石或贝壳堆中筑巢，每次产卵1-4枚，平均为两枚，蛋呈蓝绿色或棕色。双亲共同孵化，孵化期27-39天。幼鸟孵化后35-40天离巢，期间由双亲共同喂养。","identification":"与蛎鹬相比，非洲黑蛎鹬具有全黑的羽毛，而后者腹部和喉部为白色。此外，非洲黑蛎鹬的叫声更为平缓。","protection":"IUCN：LC（无危）","distribution":"繁殖区域覆盖从纳米比亚北部沿海至南非夸祖鲁-纳塔尔省。非繁殖季节时，部分个体向北移动至安哥拉南部沿海。","other":"尽管总体数量较低，但非洲黑蛎鹬的种群似乎持续增长，这得益于当地社区参与的保护措施增强，以及海洋保护区的扩大。"},{"name":"蛎鹬","english_name":"Eurasian Oystercatcher","scientific_name":"Haematopus ostralegus","overview":"蛎鹬（英文名：Eurasian Oystercatcher，学名：Haematopus ostralegus），是鸻形目蛎鹬科蛎鹬属的鸟类。又称: 欧亚蛎鹬，大型涉禽，具有显著的黑白色羽毛、亮橙红色的喙、红眼和粉色腿。分布广泛，主要栖息于欧亚大陆的沿海地带，也出现在内陆水域和农田。繁殖季节在北部地区，非繁殖季节则南迁至非洲沿海和亚洲东部。","appearance":"蛎鹬体长40-47.5厘米，重量425-820克，性别差异不大。成鸟头部、颈部、上胸部和背部均为黑色，翅膀有宽大的白色条纹，腹部和尾下覆羽为白色。喙长且直，呈橙红色，腿为粉色。幼鸟羽色较暗，喙、腿和眼环为暗色，翅膀上有淡色边缘。不同亚种在喙长、翼展宽度和背部颜色上有所不同。","call":"蛎鹬最常听到的叫声是一种重复的、滑音式的哨声，类似于“peep”或“kleep”。也会发出类似双音节的“pi-peep!”，以及更拉长的“weeeep”。在展示时，一只鸟会发出重复的哨声，而另一只则开始发出管笛般的颤音。","habits":"蛎鹬栖息于各种沿海生境，包括海滩、滩涂、盐沼和内陆水域旁的田野。冬季会成群出现于海湾、入海口和开阔海岸的沙滩与岩石上。以甲壳类、软体动物、蠕虫、虾、蟹、沙蚕、小鱼、昆虫和幼虫为食。利用喙在贝类丰富的海滨地带觅食，或在潮涧地带用喙尖翻转石头，探觅蠕虫和软体动物。","breeding":"蛎鹬繁殖期为5月至7月，营巢于海边盐碱沼泽、沙滩、岩石、草地等各类生境。巢为开阔地上的凹坑，由亲鸟用脚刨挖而成，内垫干草茎、小圆石、贝壳和其他废弃物品。每窝产卵3枚，偶尔为2枚或4枚，孵化期22-24天。雏鸟早成性，出壳当日即能行走。","identification":"蛎鹬与澳洲的澳洲斑蛎鹬相似，但后者翼上的白色条纹更窄，且不延伸到初级飞羽。与美洲斑蛎鹬的区别在于前者眼为红色，背部为黑色而非黑褐色。与智利蛎鹬相比，蛎鹬眼为黄色，几乎全部次级飞羽为白色。","protection":"IUCN：NT（近危）","distribution":"繁殖于欧亚大陆的西北部、西南部、中部和远东北部。非繁殖季节迁至非洲沿海和亚洲东部。","other":"蛎鹬的繁殖成功受到天敌如美国水貂、鲱鸥、大黑背鸥和小黑背鸥的影响。"},{"name":"南岛斑蛎鹬","english_name":"South Island Oystercatcher","scientific_name":"Haematopus finschi","overview":"南岛斑蛎鹬（英文名：South Island Oystercatcher，学名：Haematopus finschi），是鸻形目蛎鹬科蛎鹬属的黑白色壮实的涉禽。在新西兰被亲切地称为SIPO，与‘typo’发音相近。该鸟种拥有独特的红色眼睛、长而厚实的红棕色喙，以及厚实的淡粉色脚和腿。主要在新西兰南岛的河床、牧场和湖泊繁殖，少数记录显示在北岛也有繁殖。大部分种群会在冬季迁徙至北岛和南岛北部的河口、港口和沙滩。偶尔在澳大利亚越冬期间可见。其鸣叫声独特，常听到‘kleep’声。","appearance":"成年南岛斑蛎鹬体重在518-622克之间，体长可达46厘米。头部、颈部和上胸部全黑；肩羽、上翼覆羽和尾巴也是黑色；宽阔的白色翼带从内侧二级飞羽延伸至中间初级飞羽，向尖端逐渐变窄和断裂；中背部、臀部、上尾覆羽、下胸部和腹部为白色；眼睛和眼环红色，喙橙红色，腿粉色。幼鸟类似成鸟，但眼、眼环、喙和腿颜色暗淡，上体羽毛有浅色边缘；冬季颈圈呈白色。喙长度在不同亚种间有差异，最长可达99毫米。","call":"最常听到的是重复的过滑音哨声，‘peep’或‘kleep’。也有类似的双音符，‘pi-peep!’，以及更拉长的‘weeeep’。在展示中，一只鸟发出连续的‘peep’哨声，而另一只则开始吹口哨颤音，音量增加，随后放慢并逐渐消失。","habits":"栖息于盐沼、沙石海滩，较少在岩石海岸；在新西兰内陆河流砾石岸或田野繁殖。冬季，大量鸟群聚集在主要海湾和河口。以各种贝类、蜗牛、海蚯蚓、蟹、昆虫幼虫和偶尔的鱼为食。在软质沿海底栖环境中，重要的猎物包括贻贝、蛤蜊、麦螺、海蛞蝓等。在西非沿海平原，会捕食血腥蛤蜊。在欧洲，由于商业贝类渔业的影响，现在也开始捕食非本地的菲律宾蛤蜊。","breeding":"繁殖期主要在4月至5月，幼鸟通常在9月中旬前离巢。雄鸟有时会一夫多妻，雌雌配对也可能发生在多配偶关系中。巢穴是一个浅坑，直径约20厘米，深5-7厘米，有时铺有贝壳碎片和岩石，甚至小型哺乳动物的粪便。每窝产卵1-3枚，平均2枚，孵化期25-30天，由两性共同孵卵。幼鸟出生后1-2天留在巢中，孵化成功率约47%，幼鸟存活率至离巢约为59%。","identification":"与新西兰蛎鹬黑白型相似，但南岛斑蛎鹬体型较小，黑白界限分明，白色翼带不延伸至初级飞羽；与美洲斑蛎鹬的区别在于红色而非黄色的眼睛，以及黑色而非棕黑色的背部色彩。","protection":"IUCN：LC（无危）","distribution":"繁殖于新西兰南岛内陆。非繁殖季节，迁徙至斯图尔特岛沿海北部和新西兰其他地区。","other":"南岛斑蛎鹬已被记录到七次出现在澳大利亚，一次在瓦努阿图，两次在新喀里多尼亚。"},{"name":"澳洲斑蛎鹬","english_name":"Pied Oystercatcher","scientific_name":"Haematopus longirostris","overview":"澳洲斑蛎鹬（英文名：Pied Oystercatcher，学名：Haematopus longirostris），是鸻形目蛎鹬科蛎鹬属的大型健壮涉禽。常见于澳大利亚海岸，以其独特的黑白羽毛和长而强壮的橙红色喙著称。分布于小巽他群岛沿海远东部、Tanimbar和印尼卡伊群岛（印尼摩鹿加群岛东南部）、澳大利亚沿海及塔斯马尼亚州。","appearance":"体长48-51厘米，雄鸟体重410-776克，雌鸟体重500-782克。外形浑圆，嘴长而强，适合开启坚硬贝壳。头部、颈部、胸部和上体为黑色，下体、尾覆羽及臀部为白色，形成鲜明对比。雄鸟和雌鸟外观相似，但雌鸟鸟喙更长。幼鸟羽毛呈褐色，眼圈裸露部分色彩较暗淡。眼环橙红色，眼鲜红色，喙长且厚重，深橙猩红色，腿珊瑚砖红色。","call":"最常听到的叫声是重复的过滑音哨声‘peep’或双音‘pi-peep’。展示时，一只鸟可能发出重复的‘peep’哨声，而另一只会发出逐渐增强后放缓的哨音三连音。","habits":"偏好盐沼、沙滩、卵石滩和牧场作为繁殖地。非繁殖季，常见于河口泥滩和沙滩。以海洋和陆地多毛类、腹足类、双壳类为食，亦食甲壳类、昆虫和鱼类。采用多种技巧攻击不同类型的猎物，如锤击、撬开、刺探等。","breeding":"繁殖期北区5月至9月，南区8月至1月。通常是单配偶制，但在一项记录中观察到一雄二雌的长期多配偶制。巢筑于地面浅坑，靠近高潮水位线。产卵数通常为2枚（1-3枚），颜色和标记变化大，孵化期28-32天。幼鸟灰色带斑点，背部和大腿有深棕色条纹，下胸和腹部白色。离巢时间42-49天，有时长达56天。每对每年成功繁殖0.25-0.89只幼鸟。","identification":"与蛎鹬相比，体型明显更大；背白较少，结束于肩胛骨间的锐利‘V’形；无季节性羽毛变化。与新西兰蛎鹬和查岛蛎鹬的区别在于胸黑下缘界限分明；与美洲斑蛎鹬的区别在于眼红而非黄，背部颜色黑而非深褐。","protection":"IUCN：LC（无危）","distribution":"主要分布在澳大利亚沿海地区和塔斯马尼亚州，包括小巽他群岛沿海远东部、Tanimbar和印尼卡伊群岛。在北昆士兰的北斯特拉德布鲁克岛记录到最多3475只个体。","other":"在某些年份和研究中，高达73%的巢穴因洪水而损失。首次繁殖年龄为4-6岁。长期的配偶和巢址忠诚度高。"},{"name":"新西兰蛎鹬","english_name":"Variable Oystercatcher","scientific_name":"Haematopus unicolor","overview":"新西兰蛎鹬（英文名：Variable Oystercatcher，学名：Haematopus unicolor），是鸻形目蛎鹬科蛎鹬属的鸟类。新西兰特有的大型粗壮滨鹬，通体羽色高度多变，个体可从全黑到黑白相间并存在大量中间型，故英文名直译为“多变蛎鹬”。它终年留居新西兰南北两岛及其近岸岛屿，以沿海沙滩、沙嘴、岩岸及偶见的滨海湖泊边缘为繁殖及觅食场所，偶入牧场觅食。该鸟因羽色差异曾被误作多个种或亚种，现已确立为单型种。","appearance":"成鸟体长47–49厘米，依羽色型态不同体重差异明显：黑色型雄鸟平均678克、雌鸟724克；黑白型雄鸟717克、雌鸟750克；中间型雄鸟710克、雌鸟779克。喙长亦随型态变化，黑色型最短（雄79毫米、雌89毫米），中间型最长（雄84毫米、雌95毫米）。黑色型通体乌黑发亮，眼、眼圈及长直而鲜红的喙均为红色，尾端收拢时不超过翼尖，外观极似澳洲黑蛎鹬，但喙更长。黑白型前额及上胸黑色向下延伸，胸腹分界呈不规则晕染，下胸及腹部以白色为主并杂少量黑羽；飞行时翼部白色翼带缩减，背部及腰羽黑色，仅尾上覆羽白色；肩前无白色块斑，以此区别于旧大陆其他黑白蛎鹬及查岛蛎鹬。中间型介于两者之间，体型更大，喙与翼相对更长。两性相似，雌鸟平均体型及喙长略大。幼鸟黑色部位呈褐色，肩、上翼覆羽具淡皮黄色羽尖，裸露部分色泽暗淡；喙端深色，腿灰色。","call":"最常见的叫声为反复而略下滑的高亮哨音“peep”或双音节“pi-peep”；受惊时发出短促“puk”及鼻音拖长的“keeoow”。求偶展示时发出由细急哨音渐强的颤音序列为“prrrrrr-pee-pee-pipeek-pipeeek-pipeeek”。雌雄同时鸣叫，常成齐奏；群栖时多只同时发声，形成连续高亢的哨音合唱。不同羽色型态间及两性间叫声无显著差异，整体与同属其他种类相似。","habits":"常年留居新西兰，无大规模迁徙，最远离散纪录仅61公里。非繁殖期集小群，栖息于沙质或岩质海岸。繁殖地选沙滩、沙丘、岩岸，偶尔利用滨海湖泊边缘及斯图尔特岛的小型岩石湾；后者若受惊，雏鸟会躲进上方悬树遮蔽的洞穴。觅食方式多样，包括敲击、撬开、探刺、猛戳等，猎物涵盖多毛类（如Glycera americana、Perinereis nuntia）、石鳖（Chiton pelliserpentis、C. glaucus）、腹足类（Haliotis iris、Cellana）、贻贝（Mytilus edulis、Aulacomya maoriana、Modiolus neozelandicus）及其他双壳贝、等足类、端足类与蟹类。偶尔进入牧场觅食。","breeding":"繁殖期10月中旬至翌年1月下旬，最早9月产卵，12月下旬至翌年3月中旬可见刚离巢幼鸟。巢为沙地或卵石滩上极浅的凹坑，几乎无衬垫。若首次产卵失败，可补巢多达四次。每窝通常2–3枚，偶见5枚；卵平均58.2×40.6毫米，孵化期25–32天。雏鸟羽色随亲鸟型态而异：黑色型雏鸟下体暗色，似黑蛎鹬雏鸟；黑白型雏鸟胸白、上体灰褐，花纹较南岛黑白蛎鹬雏鸟模糊。雏鸟42–49天可飞。繁殖成功率受地点影响，受保护区域平均每对年产0.5只雏鸟，他处更低；有连续18季仅育成18只雏鸟的记录。卵至雏鸟离巢总成功率约14%，孵化后成功离巢率为每巢1.06只。巢败主因依次为未知因素（53%）、天气及洪水（29%）、人类干扰与车辆（4%）、天敌捕食（8%）。平均寿命约18–19年，最早2岁即可繁殖，亦有30岁仍成功繁殖的纪录。","identification":"与南岛斑蛎鹬及查岛蛎鹬外观相近，但成年黑白型新西兰蛎鹬体型更大，胸腹黑白分界模糊，肩前白色面积明显缩减。与北美黑蛎鹬、南美黑蛎鹬及美洲斑蛎鹬的区别在于眼红色而非黄色，背部纯黑而非黑褐。与智利蛎鹬可凭眼色及次级飞羽主要黑色加以区分。","protection":"IUCN: LC（无危）。自1922年起受新西兰法律保护，此前因猎杀而数量下降。1980–1990年代种群估计3400–3900只，其中黑色型约70%、黑白型约20%、中间型约10%；2006年估计全国已增至约7000只，北岛增长尤为明显，年均增长率约3.5%。威胁包括人类活动（越野车、犬只等）导致的繁殖干扰及外来哺乳类对卵、雏的捕食。保护措施包括巢区围栏及减少干扰，部分种群近30年呈持续上升趋势。","distribution":"繁殖区与非繁殖区均位于新西兰，分布于北岛、南岛及其邻近沿岸岛屿的海岸带。","other":"历史上曾被视为与查岛蛎鹬及蛎鹬同种，各羽色型态亦曾被当作独立种或亚种，黑白型旧称“H. reischeki”。与南岛斑蛎鹬存在自然杂交记录。"},{"name":"查岛蛎鹬","english_name":"Chatham Oystercatcher","scientific_name":"Haematopus chathamensis","overview":"查岛蛎鹬（英文名：Chatham Islands Oystercatcher，学名：Haematopus chathamensis），是鸻形目蛎鹬科蛎鹬属的鸟类。体型较小，胸前黑白色界限模糊。IUCN评级为‘ENDANGERED’（濒危）。","appearance":"查岛蛎鹬体长约48至49厘米，雄鸟平均体重540克，雌鸟平均体重640克。其头部、颈部、胸部、背部、翅膀和尾巴呈黑色，下腹部白色，胸白黑过渡区斑驳。幼鸟上体羽缘呈棕色，裸露部位颜色较暗淡。雌雄外观相似，但雌鸟体型略大，喙较长。","call":"查岛蛎鹬的叫声包括重复的滑音哨声“peep”或双重音“pi-peep”，以及更短、更柔和的“puk”。展示叫声开始时为哨音颤音，音量逐渐增大，随后是几个双重音符，音调尖锐刺耳。","habits":"查岛蛎鹬主要栖息于岩石海岸，偶尔出现在砂质或砾石海滩，有时会在有短植被的地点筑巢。它们全年定居并具有领地性，幼鸟可能在岛屿间移动长达40公里。食物包括各种海洋生物，如海葵、多板纲动物、腹足纲动物、双壳纲动物、藤壶、等足类、棘皮动物和海鞘。它们使用多种技巧攻击不同类型的猎物。","breeding":"繁殖期为10月至翌年3月，大多数产卵发生在10月至12月。巢穴为地面凹坑，可能有或无衬垫，常建于岩石悬垂或植被遮蔽处，有时在小洞穴或悬崖平台上。每次产卵2至3枚，三枚卵的巢早期更为常见，孵化期约25天。雏鸟上体有明显的灰色斑点，尾部有显眼的白色亚端带。离巢期为46至49天，每对繁殖成功率0.20至0.85只雏鸟。","identification":"查岛蛎鹬最接近新西兰蛎鹬的黑白形态，但体型略小，喙更短，腿和脚更为粗壮。与美洲斑蛎鹬的区别在于红眼而非黄眼，背部黑色而非深褐色。与智利蛎鹬的区别在于红眼而非黄眼，次级飞羽大部分为黑色。","protection":"IUCN：EN（濒危）","distribution":"查岛蛎鹬仅分布于查塔姆群岛（位于新西兰东南方约680公里的群岛），每个主岛上都有小型繁殖群落。","other":"查岛蛎鹬面临的主要威胁来自引进的捕食者，如猫、鼠和新西兰秧鸡，以及人类活动的干扰。"},{"name":"澳洲黑蛎鹬","english_name":"Sooty Oystercatcher","scientific_name":"Haematopus fuliginosus","overview":"澳洲黑蛎鹬（英文名：Sooty Oystercatcher，学名：Haematopus fuliginosus），是鸻形目蛎鹬科蛎鹬属的鸟类。体型健壮的涉禽，全身羽毛深黑色，拥有醒目的红色眼睛、眼环和厚实的红色长喙，脚和腿呈淡粉色。主要栖息于澳大利亚沿海地带，偏好岩石海岸，但也可见于小岛上的岩石海滩和沙质海滩。分布于澳大利亚沿海和塔斯马尼亚州，是该地区特有种。","appearance":"体长约46至49厘米，体重介于550至980克之间。通体羽毛呈煤烟黑色，眼睛、眼环和喙为红色，脚和腿为粉红色。相较于其他黑色蛎鹬，尾部较长，翅膀折叠时不会触及尾尖。雌鸟平均稍大，翼短而喙宽。幼鸟色泽较暗，带有棕色，眼环、喙和脚色偏淡。存在两个亚种，opthalmicus亚种翼短、喙粗重，眼环明显呈黄色至橙色。","call":"其鸣声最常听到的是重复的滑音哨声，‘peep’或‘kleep’，也有类似双音节的‘pi-peep’和较长、略带哀伤的‘wheeeuu’叫声。展示时，一只鸟会发出连续的‘peep’哨声，另一只会开始发出逐渐增强再减慢的哨音颤音。","habits":"主要栖息于岩石海岸，有时也会出现在沙质海滩和河口泥滩上。大部分时间保持定居状态，冬季时会在霍巴特（塔斯马尼亚）附近岛屿到德温特河口的小范围内移动。以各种硬壳贝类为食，如海螺、海蜗牛、双壳类、藤壶、甲壳类、棘皮动物和被囊动物，也会吃搁浅的鱼。","breeding":"繁殖季节为8月至次年1月。巢建在地面凹处，通常位于岩石间，以贝壳碎片铺垫。通常产两枚蛋（2至4枚），孵化和雏鸟离巢时间未知。雏鸟头部有明显的黑色标记，全身呈均匀的锈色，腹部无白色绒毛。","identification":"与其它黑色蛎鹬的区别在于尾部更长，翅膀折叠时不及尾尖，眼环和喙颜色更红。雌雄差异主要体现在喙的长度和宽度上，雌鸟喙长而细，雄鸟喙短而粗。","protection":"IUCN：LC（无危）。总数量约11,500只，其中指名亚种数量不足4,000只，主要分布在澳大利亚南部和东部以及塔斯马尼亚。opthalmicus亚种数量约为7,500只，分布情况不详，但似乎分布零散，可能与其偏好岛屿和珊瑚礁附近的觅食环境有关。","distribution":"分布于澳大利亚沿海和塔斯马尼亚州，常见于塔斯马尼亚海岸线和巴斯海峡岛屿。","other":"黑红嘴是当地的一种称呼。opthalmicus亚种曾被认为足够独特，可能需独立为物种，但尚需进一步研究。"},{"name":"蟹鸻","english_name":"Crab-plover","scientific_name":"Dromas ardeola","overview":"蟹鸻（英文名：Crab-plover，学名：Dromas ardeola），是鸻形目蟹鸻科蟹鸻属的鸟类。独树一帜的鸻，拥有鲜明的黑白羽色和粗壮的黑色喙，体长介于38至41厘米之间，体重230至325克，翼展可达66至78厘米。其独特外观和生态习性使其在众多海滨涉禽中脱颖而出。分布于印度洋沿岸，包括红海、阿拉伯半岛和波斯湾周边的沙滩和岛屿。","appearance":"蟹鸻的成鸟通体洁白，背部和翅膀的主羽为黑色，配以长而蓝灰色的腿和厚重的黑喙。雄鸟比雌鸟体型稍大，尤其在喙的长度和深度上更为显著。非繁殖季节的个体头部会出现灰色条纹。幼鸟羽色较淡，背部呈灰褐色，头颈处有斑驳的黑褐色，银灰色的肩羽和棕色的尾巴。","call":"蟹鸻的叫声尖锐，类似鸥类，常在飞行中发出喧闹的叫声。","habits":"栖息于沙质海岸线、珊瑚礁、岩石海岸和红树林地带，以群居方式活动，偏好低潮时在泥滩上觅食。主要食物为螃蟹，也会摄食其他甲壳类、双壳类软体动物、海洋蠕虫和其他潮间带无脊椎动物。夜间活动频繁。","breeding":"繁殖期为4月至7月，通常在红海、阿拉伯半岛和波斯湾地区的沙滩筑巢。巢穴为沙土中的洞穴，深度可达100厘米，内部无衬垫。每窝产一枚白色大蛋，偶尔两枚。孵化期约32至33天，主要依靠环境温度而非亲鸟的保温。雏鸟依赖父母喂养，直至至少部分独立。","identification":"蟹鸻的独特外形和生态习性使其易于识别。与同类物种相比，其粗壮的黑喙和黑白相间的羽色是显著特征。幼鸟的羽色和成鸟有明显差异，有助于区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于红海、阿拉伯半岛和波斯湾的沙滩和岛屿。非繁殖季节广泛分布于印度洋热带至亚热带沿海，南至莫桑比克和夸祖卢纳塔尔，覆盖马达加斯加群岛，包括塞舌尔群岛南部和中部的珊瑚环礁，查戈斯群岛，马尔代夫，印度西海岸，斯里兰卡和安达曼群岛。","other":"蟹鸻是《非洲-欧亚候鸟保护协定》适用物种之一。"},{"name":"鹮嘴鹬","english_name":"Ibisbill","scientific_name":"Ibidorhyncha struthersii","overview":"鹮嘴鹬（英文名：Ibisbill，学名：Ibidorhyncha struthersii），是鸻形目鹮嘴鹬科鹮嘴鹬属的鸟类。以独特的长而弯曲的红色鸟喙命名。这种涉禽偏好于中亚和喜马拉雅地区的高海拔河流和溪流边的砾石滩，分布范围广泛，从塔吉克斯坦西部至中国东北部。上体灰褐色，腹部白色，脸部和胸部有黑色条纹，头部和颈部蓝灰色。善于隐蔽，单独觅食，以水生无脊椎动物为食。","appearance":"体长38-41厘米，体重约270-320克，喙长6.8-8.2厘米，呈鲜艳的红色并向下弯曲。成鸟上体灰色，腹部白色，有黑色胸带和面部斑块，腿灰色至紫红色。雌雄相似，但雌鸟略大，喙更长。幼鸟缺乏脸部和胸部的黑色，喙色较暗淡。","call":"发出类似青脚鹬的响亮‘Klew-klew’叫声。","habits":"栖息于高海拔河流的砾石滩，活动范围从100米至4400米。在冬季会下降到较低海拔，冬季常见于100米左右。主要以河流中的石蛾、石蝇、甲虫等水生无脊椎动物和小型鱼类为食，单独或小群觅食。","breeding":"繁殖期从4月末至7月，营巢于河流岸边的砾石间，通常产卵3-4枚，绿灰色卵上有黄褐色斑点，由双亲轮流孵化。","identification":"长而弯曲的红色喙和独特的黑白相间的羽毛图案是其显著特征，与多数涉禽明显不同。","protection":"IUCN：LC（无危），国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）。","distribution":"分布于中亚的河流，从塔吉克斯坦西部至中国东北部，包括喜马拉雅山脉和青藏高原。在中国，分布于新疆西北部、青海、甘肃、内蒙古东部、河北北部及北京北部。"},{"name":"黑翅长脚鹬","english_name":"Black-winged Stilt","scientific_name":"Himantopus himantopus","overview":"黑翅长脚鹬（英文名：Black-winged Stilt，学名：Himantopus himantopus），是鸻形目反嘴鹬科长脚鹬属的鸟类。又名: 红腿娘子、高跷鸻，分布广泛的长腿涉禽，属于反嘴鹬科。以其优雅的黑白羽毛和鲜艳的粉色长腿著称，广泛分布于非洲、欧亚大陆的温带和热带湿地。该鸟种在繁殖季节形成嘈杂的群体，在近水的裸地上筑巢。其繁殖范围涵盖欧洲南部至东亚，非洲南部至马达加斯加沿海，以及中亚至中国东北。","appearance":"成年黑翅长脚鹬体长约为33至36厘米，拥有细长的粉色腿和细长的黑色喙。上身通常为黑色，下身为白色，头部和颈部为白色，带有不同程度的黑色。雄鸟的背部常带绿色光泽，而雌鸟的背部则呈淡褐色。幼鸟的羽毛为灰色，翅膀有明显的沙色边缘，飞行时可见为白色线条。","call":"这种鸟类相当健谈，尤其是在繁殖季节。它们发出重复的鼻音、断续的、尖锐的‘kek..kek..kek…’叫声，有时声音略显沙哑，根据不同的环境会有轻微变化。一年生的幼鸟叫声更高亢、更清晰且更加断续。","habits":"黑翅长脚鹬偏好开放的浅水湿地，尤其是咸淡水环境，包括沼泽、湖泊边缘、河床、污水池和泛滥的田野，也会出现在盐沼和沿海盐沼。它们主要在春季迁徙，北方的繁殖群体会向南迁移到更温暖的地区。飞行时，长腿显著伸出尾部之外。它们通过视觉和触觉捕捉各种小型无脊椎动物和偶尔的种子。","breeding":"繁殖时间因地区而异，从热带地区的雨季到欧亚地区的春季。它们通常是季节性的一夫一妻制，但在繁殖期后可能会继续保持伴侣关系。巢建在地面，通常位于水边，由芦苇茎、叶和杂草构成。每窝产卵一般为四枚，偶尔三枚，卵为黄绿色或橄榄褐色，带有黑褐色斑点，孵化期为16至18天。","identification":"黑翅长脚鹬最显著的特点是其长粉色腿和黑白相间的羽毛。在东南亚部分地区，需与澳洲长脚鹬相区分。此外，雌雄之间在羽毛颜色上有细微差别，雄鸟背部常有绿色光泽，而雌鸟背部呈淡褐色。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧洲南部至东亚，非洲南部至马达加斯加沿海，中亚至中国东北。非繁殖期迁徙至东南亚和菲律宾的大巽他群岛。","other":"在某些地区，黑翅长脚鹬的数量似乎在增加，如英国南部和南非。然而，东欧的一些国家如希腊、匈牙利和保加利亚的种群数量下降，这归咎于湿地栖息地的丧失。"},{"name":"澳洲长脚鹬","english_name":"Pied Stilt","scientific_name":"Himantopus leucocephalus","overview":"澳洲长脚鹬（英文名：Pied Stilt，学名：Himantopus leucocephalus），是鸻形目反嘴鹬科长脚鹬属的大型黑白相间的鹬。分布广泛，从东南亚至澳大利亚与新西兰，栖息于多种湿地环境，包括淡水沼泽、盐滩和沿海盐沼。其显著特征为长而直的针状喙，粉色长腿，以及黑色后颈。","appearance":"体长约36厘米，翼展约67厘米。头部后方、颈部、背部及翅膀上表面呈闪亮的绿黑色，翅膀下方纯黑，其余部位羽毛白色，尾羽带有灰色调。粉色长腿，趾端有黑色爪子，细长的喙为黑色，虹膜与眼睑红色。雌鸟上部颜色较暗淡，缺乏绿色光泽。幼鸟类似成年雌鸟，但缺少后颈及颈背的黑色，可能呈现白色或灰色。","call":"发出狗吠般的重复鼻音、断续、尖锐的“kek..kek..kek…”叫声，有时声音嘶哑，随情境略有变化。兴奋时，叫声更快更高，类似“ki-ki-ki-ki-ki...”，警戒时则为拉长的“keyaa”。","habits":"栖息于浅水湿地，包括淡水沼泽、河流边缘、污水处理池和泛滥农田，也会出现在盐滩和沿海盐沼。以小型水生无脊椎动物和偶尔的种子为食，如甲虫、石蛾、蜻蜓、蜘蛛、蠕虫、蝌蚪、小鱼及其卵。采用视觉和触觉方法捕捉猎物，如在软泥中切割寻找猎物。","breeding":"繁殖季节因地域而异，通常在雨季或季节性水域。在新西兰，低海拔地区7月末至8月开始筑巢，高海拔地区则延迟至9月至10月。一夫一妻制，偶有延续至非繁殖期。蝶形飞行展示领地。巢位于地面，通常在草丛和莎草之间，由贝壳碎片、植物材料和盐粒组成。每次产卵3-6枚，间隔24小时，孵化期22-29天，双亲共同孵卵。雏鸟出生后很快离巢，孵化后28-32天离巢独立。","identification":"与黑翅长脚鹬相似，但具有白色头部，粉色长腿和黑色后颈。幼鸟和雌鸟的特征差异有助于区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于菲律宾中部和南部、印度尼西亚群岛、新几内亚、澳大利亚、新西兰和新不列颠岛东北部（俾斯麦群岛东南部）。非繁殖季节分布遍及菲律宾，迁徙至菲律宾、婆罗洲（沙巴）、越南、斯里兰卡。","other":"在19世纪殖民了新西兰，近年来开始在沙巴（婆罗洲）繁殖。"},{"name":"黑颈长脚鹬","english_name":"Black-necked Stilt","scientific_name":"Himantopus mexicanus","overview":"黑颈长脚鹬（英文名：Black-necked Stilt，学名：Himantopus mexicanus），是鸻形目反嘴鹬科长脚鹬属的鸟类。优雅的长腿滨鸟，以黑白分明的羽色和极长的粉红色腿脚著称，雄鸟背羽亮黑、雌鸟稍褐。其分布横跨美洲大陆，从北美西部至南美北部，并包含夏威夷群岛的特有亚种——夏威夷长脚鹬（H. m. knudseni，当地名Aeʻo）。该种依赖浅淡水或微咸水湿地觅食，以水生无脊椎动物为主食，繁殖期具强烈的护巢行为，曾受狩猎与栖息地丧失威胁，夏威夷亚种一度仅存约200只，经保护已回升至1400只以上。","appearance":"成鸟体长35–39厘米，翼展约71厘米，体重136–220克。雄鸟繁殖羽头顶、后颈、背及翅为亮黑色，具绿色金属光泽，眼上方有一白斑，余部雪白，胸部略带粉红，尾羽灰褐；雌鸟黑色部分偏褐且无金属光，无粉红胸羽。非繁殖羽色较暗淡。幼鸟上体暗褐具浅棕缘，呈鳞状斑，飞羽端白形成翼后白缘。夏威夷亚种成鸟头颈部黑色范围更大，眼上白斑常缩小或缺失。雌雄差异仅在于色泽深度及腿色鲜艳度。","call":"繁殖期遇干扰时发出连续尖锐的“yap-yap-yip”告警声，音高急促；夏威夷群体在非繁殖季会发出鸥样的“kwirk-kwirk”群叫声。雏鸟受惊时发出细碎的“chip-chip-chip”，成鸟夜间亦持续告警，叫声在繁殖湿地彻夜回荡。","habits":"栖息于浅淡水或微咸水湿地、盐田、稻田及人工晒盐池，偏好有挺水植物的生境。美洲种群多为短至中距离迁徙，春季3–5月北返，秋季8–10月南迁，集中停歇于加州中央谷、犹他大盐湖等地；夏威夷亚种基本留居，仅在诸岛间随水位移动。觅食以视觉为主，方式包括轻啄、探浸、掠食飞虫及扫掠式搜食，昼夜间均可取食，食物以小型甲壳类、昆虫、鱼苗为主；夏威夷种群70%觅食时间用于捕鱼。","breeding":"繁殖期随纬度与水源变化：北美4–7月，夏威夷2–8月。一夫一妻制，配对可维持至当季再营巢。巢为浅水中小岛或堤坝上的浅坑，内衬就近植物碎片，直径约12–21厘米，高出水面2–10厘米。每窝通常4枚梨形卵，底色褐至橄榄，密布褐斑；孵化期23–26天，双亲轮流坐巢，热环境中以湿腹羽降温。雏鸟早成性，24小时内离巢，28–31天可飞。领域性强，巢间距多大于10米，遇敌会集体“爆米花”式跃飞干扰。","identification":"北美范围内外形独特，不易混淆。偶见迷鸟黑翅长脚鹬头颈全白或灰斑，缺乏黑白分明界限。雏鸟与美洲反嘴鹬雏鸟区别在于脚色偏粉、趾蹼退化且缺后趾。与同属其他亚种区分：南美亚种H. m. melanurus（白背长脚鹬）背具宽阔白领；夏威夷亚种黑色范围最大，体型亦略大。","protection":"IUCN: LC（无危）。夏威夷亚种列入美国联邦及夏威夷州濒危物种法案。所有亚种受《候鸟条约法案》保护。","distribution":"繁殖于北美西部至南部、中美洲、加勒比及南美北部至秘鲁；夏威夷群岛为夏威夷亚种留居地。非繁殖期南迁至墨西哥、中美及南美海滨；北美内陆种群则集中于加州中央谷、萨顿海及墨西哥西北部湿地越冬。中国大陆无自然分布，偶见迷鸟记录。","other":"美洲与全球长脚鹬属分类长期存在争议，本种与旧大陆黑翅长脚鹬、澳洲长脚鹬等关系尚未完全厘清。已知与黑翅长脚鹬及美洲反嘴鹬在圈养条件下可杂交。化石记录显示北美更新世已有同种个体。"},{"name":"南美长脚鹬","english_name":"White-backed Stilt","scientific_name":"Himantopus melanurus","overview":"南美长脚鹬（英文名：White-backed Stilt，学名：Himantopus melanurus），是鸻形目反嘴鹬科长脚鹬属的鸟类。分布于南美洲，在当地某些湿地区域数量可观，从巴西西北部至秘鲁西南部，以及阿根廷中南部都有其踪迹。","appearance":"南美长脚鹬具有独特的外观，背部呈白色，这是其最显著的外部特征之一。雄鸟和雌鸟在外形上相似，幼鸟的细节可能有所不同，但具体描述资料有限。","habits":"这种鸟类偏好低地环境，常见于河口、湖泊、盐水池塘和新生湿地。它们主要以水生无脊椎动物为食，包括甲壳类、其他节肢动物和软体动物，偶尔也会摄取小鱼、蝌蚪乃至极少量的植物种子。南美长脚鹬在泥滩、湖岸及近岸浅水区觅食，同时在盐沼、湖边、甚至被水淹没的田野中休息。","breeding":"南美长脚鹬选择泥滩、干涸的湖岸边缘和堤坝作为筑巢地点，土壤需易于挖掘。巢通常距离觅食地点不超过1公里，鸟儿们会联合邻居共同巡逻，保卫巢群周边的领地。巢间距大约为20米，但在某些情况下，巢距仅7米，甚至有巢穴相隔40米之远。由于靠近水面，巢的稳定性受到水位波动的影响，尤其是在管理的盐水中，水位可能迅速变化。\n繁殖期间，每窝产3-5枚蛋，平均为4枚。孵化期为22-26天，由双亲轮流孵育。雏鸟出生后不久就能游泳，也能快速移动，但最初几天仍返回巢中休息。约一个月后羽翼丰满，但仍依赖父母几周时间。南美长脚鹬在1-2岁时开始繁殖。","identification":"南美长脚鹬与黑颈长脚鹬有密切关系，但在地理分布、生态习性上有所区别，特别是在繁殖区域的划分和食物偏好上。","protection":"IUCN：LC（无危）","distribution":"南美长脚鹬广泛分布于南美洲，从秘鲁内陆中东部到玻利维亚中部、巴西东南部，直至智利中南部和阿根廷中南部。它们在内陆和沿海地带均有栖息。","other":"曾为独立种，现为黑颈长脚鹬亚种。"},{"name":"黑长脚鹬","english_name":"Black Stilt","scientific_name":"Himantopus novaezelandiae","overview":"黑长脚鹬（英文名：Black Stilt，学名：Himantopus novaezelandiae），是鸻形目反嘴鹬科长脚鹬属的鸟类，又称kakī（毛利语）。其特征为全黑色羽毛，搭配长而红的腿及细长的黑喙。分布于新西兰，主要在南岛的马肯齐盆地的开放河流和相连湿地繁殖。黑长脚鹬的数量极为稀少，截至2020年5月，野生成鸟仅存169只。","appearance":"成年黑长脚鹬拥有独特的全黑色羽毛，带绿色光泽，搭配长而粉红色的腿和细长的黑色喙。雄鸟头部常见白色斑点，尤其在眼睛周围、眉线区域和头顶。雌鸟与雄鸟相似，但平均腿较短。幼鸟在离巢时几乎全身白色，随后发展出灰黑色斑纹。成年后的羽毛主要为黑色，散布着白色斑点和条纹。","call":"声音相当丰富，最常听到的是连续的尖锐‘yek...yek...yek...’叫声，与黑翅长脚鹬类似，但音调更高，鼻音更轻。与本地黑翅长脚鹬的杂交后代叫声介于两者之间。","habits":"栖息于马肯齐盆地的河流河床、湖岸、沼泽和浅水池塘。偏好有稳定边界的溪流或主洪泛河流通道旁，以及植被丰富的池塘和沼泽。非繁殖季节，会前往池塘、河流三角洲、湖泊边缘以及少数沿海泻湖和河口。","breeding":"繁殖季节在8月至次年1月，高峰期在10月。通常独居，保卫领地对抗同种。巢位于近水处，通常由四枚蛋组成（3-6枚）。孵化期约24至27天，双亲共同承担。雏鸟孵化后41至55天离巢，7至9个月后独立。","identification":"与黑翅长脚鹬相比，黑长脚鹬具有更短的腿和更长的喙。杂交个体的羽毛变化大，但通常具有黑色胸部羽毛。","protection":"IUCN：CR（极危）","distribution":"繁殖区主要集中在新西兰南岛中部的马肯齐盆地。非繁殖期部分鸟类会移动至新西兰北岛。","other":"面临的主要威胁包括外来哺乳动物捕食者，如挪威鼠、野猫、黄鼠狼和貂，以及环境破坏。自1981年起，实施了包括圈养繁殖和释放计划在内的强化管理措施，以防止其灭绝。"},{"name":"斑长脚鹬","english_name":"Banded Stilt","scientific_name":"Cladorhynchus leucocephalus","overview":"斑长脚鹬（英文名：Banded Stilt，学名：Cladorhynchus leucocephalus），是鸻形目反嘴鹬科斑长脚鹬属的鸟类。其最显著的特征是成年个体拥有白色头部、黑色翅膀和鲜明的铜色胸带，以及非常长的粉红色腿。分布于澳大利亚南部及中部，尤其是西澳大利亚和南澳大利亚的内陆盐湖附近。","appearance":"斑长脚鹬体型较大，长度在35至43厘米之间，体重约190至260克。其头部白色，背部黑色，胸部有明显的铜色带，这一特征在幼鸟中不明显。成年斑长脚鹬的嘴细长且黑色，腿长而呈橙粉色，比同属的其他物种腿稍短。两性外观相似，非繁殖期成年个体的胸带会因出现白棕色尖端的羽毛而变得模糊。","call":"斑长脚鹬发出类似犬吠的‘chowk’或‘chowk-uk’声，当群体中的大量个体同时发声时，声音显得嘈杂。","habits":"斑长脚鹬栖息于浅水盐湖、盐田池塘、盐沼、泻湖、河口、海湾和潮间带，偶尔出现在低盐度水域。它们高度依赖内陆的季节性降雨，仅在大而浅的盐湖被雨水或洪水填满时才进行繁殖。迁徙模式取决于降雨，通常在干旱时靠近海岸，雨后返回内陆。","breeding":"斑长脚鹬的繁殖习性尚不完全清楚，已知会在短暂形成的大型浅盐湖上聚集繁殖。巢筑于低岛或湖畔的沙洲，由裸土或少量死植被构成。每窝产卵3至4枚，孵化期为19至21天，双亲共同孵卵。雏鸟出生时覆盖着白色的绒毛，能立即离开巢穴，跟随父母到水中觅食。","identification":"斑长脚鹬与其它长脚鹬相比，具有独特的胸带和更明亮的腿部颜色。幼鸟缺乏胸带，与红颈反嘴鹬相似，但腿色更亮，嘴更直，且头部和颈部始终保持白色。","protection":"IUCN：LC（无危）；在南澳大利亚州列为Vulnerable（易危）。由于银鸥对繁殖群的捕食，斑长脚鹬可能面临突然下降的风险。","distribution":"主要分布于澳大利亚南部和中部，尤其是在西澳大利亚和南澳大利亚的内陆地区，以及沿海地带。","other":"斑长脚鹬的种群数量随栖息地的适宜程度波动极大，但近二十年来在东澳大利亚并未发现种群减少的证据。"},{"name":"反嘴鹬","english_name":"Pied Avocet","scientific_name":"Recurvirostra avosetta","overview":"反嘴鹬（英文名：Pied Avocet，学名：Recurvirostra avosetta），是鸻形目反嘴鹬科反嘴鹬属的鸟类。又名: 反嘴鸻，大型黑白色涉禽，以其独特的向上弯曲的喙而闻名。在欧洲温带地区和帕拉尔地区从中亚到俄罗斯远东地区繁殖，冬季迁徙至非洲或亚洲南部，部分留驻在较温暖的地区如西班牙南部和英格兰南部。","appearance":"成年反嘴鹬体长约41.9至45.1厘米，翼展约76至80厘米，喙长7.5至8.5厘米，腿长7.6至10.2厘米。其羽毛基本为白色，头部顶部、翅膀和背部有黑色斑块，长喙向上弯曲，腿呈蓝灰色。雌雄外观相似，幼鸟羽色更偏向灰褐色和赤褐色。雌鸟的喙部弯曲更强烈。","call":"反嘴鹬的鸣叫声音清脆悦耳，连续的液态音节kluit kluit，传播甚远。","habits":"反嘴鹬偏好在浅咸水或泥滩上觅食，常用独特的侧扫式觅食技巧，主要摄食甲壳类和昆虫。它们在有暴露的裸土和咸水的浅湖环境中繁殖，筑巢于开阔地面，有时与其他涉禽共栖。它们会单独或成对活动，善于游泳，甚至能在水中倒立。","breeding":"繁殖季节为5月至7月，筑巢于开阔平原上的湖泊岸边，巢多置于距水不远的裸露地上凹坑内，每窝产卵4枚，卵呈黄褐色或赭色，带有黑褐色斑点，孵化期约为22至24天，雌雄轮流孵卵。","identification":"反嘴鹬以其独特的黑白羽色和向上弯曲的长喙易于识别，雌鸟喙部弯曲更为明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于英国内陆和沿海南部、伊比利亚半岛、斯堪的纳维亚远南部至俄罗斯西南部、跨贝加尔地区、中国东北南部至中亚、阿富汗中东部、巴基斯坦沿海和印度西北部、非洲东部和南部。非繁殖季节分布至非洲沿海北部、非洲内陆西部、印度半岛、斯里兰卡、缅甸中部、泰国中部和中国东部。","other":"反嘴鹬曾在19世纪40年代在大不列颠灭绝，但在1947年成功重新定居于萨福克的米恩瑟尔，随后在英国向内陆、北向和西向扩散，2018年在苏格兰的Skinflats繁殖。"},{"name":"褐胸反嘴鹬","english_name":"American Avocet","scientific_name":"Recurvirostra americana","overview":"褐胸反嘴鹬（英文名：American Avocet，学名：Recurvirostra americana），是鸻形目反嘴鹬科反嘴鹬属的鸟类。大型水鸟。其最显著的特征是拥有长而弯曲向上的喙，蓝灰色细长的腿，以及黑白相间的背翼花纹。繁殖季节中，成鸟头部和颈部会呈现出橙色光泽，冬季则转为灰白色。广泛分布于北美洲，常见于西部和中部地区，东部美国部分地区罕见或不存在。","appearance":"体型较大，全长约43-47厘米，包括8.2-9.5厘米的喙长，翼展可达91厘米，体重在275-350克之间。雄鸟略大于雌鸟，且雌鸟的喙更为弯曲。繁殖季节头部和颈部呈锈色，冬季则为淡灰色。背部和翅膀为黑色，与白色下体形成鲜明对比，形成V字型图案。幼鸟绒羽为浅棕色，背部斑驳，随成长逐渐换羽接近成鸟。","call":"发出尖锐而悦耳的警报声'bweet'，音调随时间上升。具有三种不同的叫声：普通叫声、兴奋叫声和断翅叫声。","habits":"栖息于淡水到高盐度湿地，包括沼泽、海滩、草原池塘和浅湖。春季时，成群的反嘴鹬（数量从50到300只）迁徙至繁殖地。以侧扫的方式在水中觅食，主要捕食小型无脊椎动物。","breeding":"在春季到达繁殖地后迅速建立领地。繁殖期间，成对的反嘴鹬会进行一系列交配前和交配后的展示。在近水处筑巢，通常位于小岛或泥泞的岸边。每窝产卵3-5枚，孵化期为23-25天，双亲共同参与孵化和育雏。幼鸟出生后不久即可行走，约4-5周后开始飞行。","identification":"与北美其他涉禽明显不同，其独特的黑白相间体色、弯曲的喙、长蓝灰色腿以及较大的体型易于识别。雌雄在外观上相似，但雌鸟喙更为弯曲。","protection":"IUCN：LC（无危）。虽然面临栖息地丧失和污染的威胁，目前总体种群稳定。","distribution":"繁殖于北美，自加拿大不列颠哥伦比亚省东南部至安大略省西南部，南至美国西部和南部，包括加利福尼亚、得克萨斯州及墨西哥西北部至中部。冬季分布于美国南部、东南部至墨西哥南部。","other":"历史上，因猎杀和陷阱导致数量下降，后受《迁徙鸟类条约法》保护。近年来面临污染物和栖地减少的挑战，但数量保持稳定，东部美国有增长趋势。"},{"name":"红颈反嘴鹬","english_name":"Red-necked Avocet","scientific_name":"Recurvirostra novaehollandiae","overview":"红颈反嘴鹬（英文名：Red-necked Avocet，学名：Recurvirostra novaehollandiae），是鸻形目反嘴鹬科反嘴鹬属的鸟类。其深红色的头部和颈部是显著的特征。在澳大利亚广泛分布，除北部和东北部沿海地区较为少见。","appearance":"红颈反嘴鹬拥有长而弯曲的喙，头和颈部呈丰富的栗褐色，与白色的身体形成鲜明对比。眼圈白色，虹膜红褐色。背部、肩部和翼尖有黑色斑块。成年鸟平均体长43至45厘米，翼展约75厘米，体重约为310克。两性相似，无季节性变色。幼鸟头部和颈部颜色较淡，呈棕色。","call":"红颈反嘴鹬的叫声被形容为犬吠般的‘tuut’声，群飞时的声音类似小狗吠叫。","habits":"红颈反嘴鹬偏好盐湖或咸水环境，常见于浅水湿地，包括高盐度湖泊、淡水湖、水库、泻湖、沼泽、污水池和河流及河口的浅水边缘。它们会根据水位变化进行分散，冬季向内陆移动，夏季则移向海岸，干旱期间这种模式可能发生变化。日间觅食，主要以水生无脊椎动物为食，包括环节动物、软体动物、甲壳类和昆虫，也会摄取种子。","breeding":"繁殖季节通常在8月至1月，但具体时间受洪水影响。筑巢通常在单独的对或小群体中进行，有时与黑翅长脚鹬和其他水鸟共同筑巢。巢穴为地面凹陷，铺垫植被，间隔至少1.6米。每次产卵2至5枚，孵化期约23至25天。雏鸟出壳后由双亲共同照顾。","identification":"红颈反嘴鹬与其他反嘴鹬物种的区别在于其独特的深红色头部和颈部，以及上弯的喙。与反嘴鹬相比，性别差异较小。","protection":"IUCN：LC（无危）。总数量超过10万只，主要栖息地是澳大利亚的莱尔湖。虽然一些地区的湿地正在逐渐丧失，但盐田和污水池的创建提供了新的栖息地。","distribution":"主要分布在澳大利亚（除北部和塔斯马尼亚岛）。在东南部的西澳大利亚州，特别是在米兰达湖和箭矢湖，曾有繁殖记录。偶尔漂泊至新西兰。","other":"红颈反嘴鹬曾于1859年开始在新西兰短暂建立族群，但在20世纪仅有两次确切记录，现在仅被视为漂泊种类。"},{"name":"安第斯反嘴鹬","english_name":"Andean Avocet","scientific_name":"Recurvirostra andina","overview":"安第斯反嘴鹬（英文名：Andean Avocet，学名：Recurvirostra andina），是鸻形目反嘴鹬科反嘴鹬属的鸟类。体型较大，栖息于南美安第斯山脉高海拔盐湖、沼泽及泻湖岸边。其最显著特征为白色头部与身体与黑色上体形成鲜明对比，蓝灰色长腿与细长上翘的喙为其标识。繁殖于秘鲁山区中部、玻利维亚、智利北部和阿根廷远西北部。","appearance":"身长43-48厘米，体重315-410克，胫骨长度77-84毫米。体型紧凑，躯干丰满，腿相对较短，羽色似矶鹬，但具典型反嘴鹬上翘的长喙。头颈、上背、臀部及下体白色，常带铁锈色下缘；其余背部及翅膀深褐至黑色；喙黑色，长腿蓝灰色。雌雄羽毛相似，幼鸟上体边缘呈锈色，但很快磨损。","call":"叫声被认为与其他反嘴鹬相似，最典型的叫声为双音节的‘kluut-kluut’或更清脆上升且鼻音的‘kwip...kwip...kwip...’，受惊时重复速率加快。","habits":"栖息于高海拔，一般高于3100米（智利可低至2500米），偏好盐碱湖泊，偶尔出现在开阔的沼泽地带，季节性地在碱性草地和小水池活动。可能主要为留鸟，但有记录显示会作海拔迁移，且极少数情况下在非繁殖季向沿海或低地迁移。","breeding":"繁殖季节未知，似乎与当地雨季有关，曾在9月、10月、1月和2月记录到产卵，可能一年有两个繁殖季。巢由植物材料构成，直径约20厘米，内部宽12厘米，深2厘米。通常产卵4枚（有时3枚），蛋壳淡棕色带黑色和紫色斑点。雏鸟背部灰白，有暗色斑点，腹部白色。","identification":"与南美长脚鹬的色彩模式类似，但后者具红色长腿、白色尾巴和直喙。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲中部秘鲁山区、西部玻利维亚、北部智利及阿根廷远西北部，繁殖区域集中在安第斯山脉。"},{"name":"凤头麦鸡","english_name":"Northern Lapwing","scientific_name":"Vanellus vanellus","overview":"凤头麦鸡（英文名：Northern Lapwing，学名：Vanellus vanellus），是鸻形目鸻科麦鸡属的鸟类。直译: 北方麦鸡，以其长而飘逸的羽冠著称。广泛分布于温带欧洲至东亚，从英国群岛到中国东北部，栖息在开阔地带，如草原、农田、湿地和沿海滩涂。数量在某些地区因土地利用变化而下降。","appearance":"凤头麦鸡体长28-31厘米，体重128-330克，翼展82-87厘米。上体金属绿光泽，头部有黑色的长羽冠，肩部青铜色。翅膀宽大，尤其在繁殖季的雄鸟身上更为明显。雌鸟的头部图案不那么显著，喉部有白色斑点。非繁殖季成鸟脸部呈浅黄色，羽冠短，下巴和喉咙白色，翼覆羽和肩部有浅黄色边缘。幼鸟与非繁殖季成鸟相似，但羽缘更宽，胸部条纹更窄更棕色。","call":"在繁殖季节，雄鸟的领地歌唱在展示飞行中发出独特而复杂的\"ayhrre-willuch-o-weep\"声，首音模糊易被忽视。联系和警报叫声为\"pee-wi\"或\"peeawee\"，这一叫声是其旧英文名Peewit的由来。非繁殖季节，最常见的叫声是响亮尖锐的\"cheew\"或较为哀怨的\"cheew-ip\"或\"wee-ip\"，有时音调会上升或下降。","habits":"凤头麦鸡栖息在各种开阔生境中，从短植被覆盖的广阔区域到湿地，包括农田、牧场、沼泽和水稻田。在欧洲主要栖息于农田，但最近记录显示它们也会在瑞典的森林采伐区筑巢。繁殖高度可达约1000米，在印度次大陆的非繁殖季节主要低于1300米。在冬季，它们会出现在收获后的茬地和耕地上，与欧金鸻相伴，且越来越多地使用农田而非牧场，至少在西北欧的部分地区。","breeding":"凤头麦鸡在3月中旬至6月初繁殖，繁殖活动在北部和东部逐渐延迟。它们通常是季节性的一夫一妻制，但在一些地区会出现多配偶制。筑巢于短草丛中的浅洼处，用少量植被或裸露地面构筑。繁殖期间，雌雄双方共同参与孵化，孵化期21-30天。雏鸟出生后第二天就能离巢行走，成长迅速。雄鸟通常负责照顾第一窝雏鸟，而雌鸟则负责第二窝。","identification":"凤头麦鸡与同属其他物种的区别在于其明显的羽冠和独特的叫声。在不同亚种之间，羽色和头部图案可能有所差异。","protection":"IUCN：NT（近危）","distribution":"繁殖区分布在温带欧亚大陆，从英国群岛至中国东北部。非繁殖区扩展至北非、阿拉伯半岛、喜马拉雅山脉南部的巴基斯坦和印度北部、日本、朝鲜半岛、中国东部、台湾和越南北部。","other":"凤头麦鸡在19世纪和20世纪初由于土地利用强度增加、排水和收集鸟蛋，其欧洲种群有所减少。然而，由于栖息地转向农业用地，数量一度增加，直到近年来，西欧种群再次呈现下降趋势，这似乎是由不断强化和变化的农业实践导致的繁殖成功率降低所致。"},{"name":"长趾麦鸡","english_name":"Long-toed Lapwing","scientific_name":"Vanellus crassirostris","overview":"长趾麦鸡（英文名：Long-toed Lapwing，学名：Vanellus crassirostris），是鸻形目鸻科麦鸡属的鸟类。拥有白色的脸和喉部，被黑色的颈和胸带包围，长腿和异常长的趾，主要分布在非洲内陆中西部、东部及东南部。","appearance":"长趾麦鸡是一种大型的高地涉禽，约31厘米长，体重162至225克。它具有长而红的腿，长趾，黑蓝色光泽的颈背和胸部，脸部和喉部为白色。上体呈暗灰褐色，眼环红色，喙红带黑尖，短翼脊，腿深红色。雌雄相似，无季节变化。幼鸟的黑色部分较棕，羽端有淡褐色尖，上体杂有棕色和淡褐色斑点。","call":"发出一连串金属般的重复点击声，如‘kick-k-k-k’或‘kick-kick’，以及在受惊时发出哀怨的‘wheet’声。","habits":"栖息于湖泊、池塘、沼泽、河流和泛滥平原等水域，尤其偏好有漂浮植被的环境。在旱季，会在水池边缘的泥地上觅食；雨季，则出现在泛滥的草地和水稻田。主要以水生昆虫、幼虫、蜻蜓幼虫、甲虫、蚂蚁和小蜗牛为食。","breeding":"繁殖期在非洲中部主要是12月至翌年3月，东部非洲则从6月至11月。一夫一妻制，领土面积较小，平均约0.29公顷。巢穴由植物材料制成，位于草地上或水边的泥地上，或在水面高达1米的漂浮植被上的杯状巢。每次产卵1至4枚，孵化期约为27至30天。雏鸟孵化几小时后即可离巢，大约两个月后飞羽成熟。","identification":"长趾麦鸡与白冠麦鸡在翅膀上都有大量白色，但长趾麦鸡在主翼上有黑色标记，白冠麦鸡则在主翼和次翼上都显示白色。","protection":"IUCN：LC（无危）","distribution":"广泛分布于非洲中西部内陆、东部及东南部，从南苏丹向南延伸至博茨瓦纳、莫桑比克和南非东北部，以及乍得和安哥拉西部的零星群体。","other":"人类对水生地区的侵扰，包括放牧牲畜，对长趾麦鸡的栖息地构成威胁。"},{"name":"黑背麦鸡","english_name":"Blacksmith Lapwing","scientific_name":"Vanellus armatus","overview":"黑背麦鸡（英文名：Blacksmith Lapwing，学名：Vanellus armatus），是鸻形目鸻科麦鸡属的鸟类。中型涉禽，广泛分布在从肯尼亚至非洲南部和西南部。其得名源自其特有的金属敲击般‘tink-tink-tink’的报警叫声，如同铁匠锤击铁砧。具有鲜明的黑白灰相间羽毛，雄雌相似。","appearance":"黑背麦鸡体长28-31厘米，体重114-213克，中等体型，拥有对比强烈的羽毛颜色：光泽黑色的面部、前颈和背部，白色头顶和后颈，灰色上翼覆羽，黑色腕刺。雌雄外观相似，仅雌鸟翼刺稍短。无季节性变化，幼鸟头部呈褐色，下巴和喉咙白色，灰色肩羽和上翼覆羽之间有黑色羽毛，所有黑色羽毛边缘呈淡黄色。","call":"发出类似铁匠锤击铁砧的金属质感‘tink-tink-tink’报警叫声，频率和强度随焦虑程度变化。","habits":"常见于各种湿地附近，包括湖泊、河流、水坝、污水农场和沼泽；也出现在泥滩、盐滩和泛滥平原。常在开阔地带觅食，有时集群栖息于小岛。在赞比亚记录到海拔1400米，在马拉维记录到1200米的高度。主要定居，但在干旱地区和丰水期会局部迁移。","breeding":"繁殖期遍布全年，干季开始时最为频繁，尤其在南非7月至10月（高峰8月至9月）。一夫一妻制，领域性强。巢穴为浅洼，直径约140毫米，深度约40毫米，通常靠近水源，铺垫石子、植物材料和碎片。每次产卵3枚，偶尔1-4枚，疑似双雌产卵时可达5-6枚。孵化期23-31天，由双亲轮流孵化，自首枚卵开始。雏鸟孵化重约11克，上体混有棕褐色和淡黄色，下体和颈环白色；离巢期40-41天。","identification":"与其他麦鸡属物种相比，黑背麦鸡的黑白灰相间羽毛和独特的金属质感叫声易于识别。","protection":"IUCN：LC（无危）。数量一般较多，局部丰富。在津巴布韦因人工水源增加而受益。","distribution":"分布于非洲内陆，从中西部安哥拉至肯尼亚中南部，向南延伸至南非。20世纪因水坝建设和密集农业扩张，其分布范围扩展至南非西部开普地区。","other":"20世纪以前，仅在奥兰治河以南和纳塔尔发现，现分布已扩展至东南开普海岸，1939年首次在西开普出现，1947年开始繁殖。"},{"name":"黑胸麦鸡","english_name":"Spur-winged Lapwing","scientific_name":"Vanellus spinosus","overview":"黑胸麦鸡（英文名：Spur-winged Lapwing，学名：Vanellus spinosus），是鸻形目鸻科麦鸡属的鸟类。以其醒目的黑、白、褐色羽毛组合和刺耳的叫声著称。分布于东地中海至中东地区，非洲的撒哈拉以南至赞比亚和马拉维，也见于希腊东部、土耳其、塞浦路斯等地。","appearance":"黑胸麦鸡体长25至28厘米，翼展69至81厘米，体重127至177克。头部的冠羽、额头和喉咙呈黑色，脸颊和颈部两侧白色；胸部、上腹部和两胁黑色；眼睛深红色，翅膀上有隐藏的小爪。雌雄相似，但雌鸟的爪子较短，虹膜略显棕色。幼鸟的黑色羽毛呈褐色，带有白色斑点，上体羽毛边缘宽阔。","call":"非常喧闹，发出尖锐重复的“sik-sik-sik...”叫声。","habits":"栖息于干燥地带，但通常靠近水源，包括农田、草地、湖泊、河流附近的泥滩、盐滩、稻田、海滩和沙丘。主要以昆虫及其幼虫为食，偶尔也会吃小蜥蜴、蝌蚪和成蛙等。在非洲，它可能进行局部的季节性移动。","breeding":"繁殖期在热带非洲通常有限制，但在以色列为3月至9月。筑巢于干燥的裸露地面，一次产2至4枚带有黑、赭石色或淡紫色斑点的奶油色至陶土色蛋。双亲共同孵卵，孵化期22至24天。雏鸟早熟，7至8周后离巢。","identification":"与距翅麦鸡的区别在于更广泛的黑色下体和较短的冠羽。与黑背麦鸡和长趾麦鸡相比，具有明显的黑白头纹，而非黑色冠羽。","protection":"IUCN：LC（无危）。在欧洲和北非部分地区，数量有所下降，但在非洲热带地区普遍常见。","distribution":"繁殖区覆盖东地中海、中东至伊朗西南部和阿拉伯半岛，非洲从毛里塔尼亚至尼日利亚和东至厄立特里亚、索马里，北苏丹和埃及至尼罗河三角洲，南至赞比亚和马拉维。","other":"近年来在非洲东部和南部的分布范围有所扩大，首次在赞比亚出现是在1999年。"},{"name":"距翅麦鸡","english_name":"River Lapwing","scientific_name":"Vanellus duvaucelii","overview":"距翅麦鸡（英文名：River Lapwing，学名：Vanellus duvaucelii），是鸻形目鸻科麦鸡属的鸟类。以独特的黑、灰、棕色外观令人过目不忘。主要栖息于河流周边，常见于河岸及裸露岛屿，其黑色冠羽在展示时会竖起。该鸟种分布于北印度至中国西南部云南西部，向南延伸至泰国、马来半岛北部和越南北部。在中国，可见于云南、海南和福建等地。","appearance":"距翅麦鸡体长约29.5至31.5厘米，体重介于143至185克之间。面部、头顶和颈背为黑色，眼色深红，能竖起的冠羽和颈背羽毛形成独特冠状。胸部为灰色，头部和颈部两侧为淡灰色，腹部有小块黑色斑点。翅膀展开时，翼下白色，上翼二级飞羽黑色，上翼覆羽棕色，与肉垂麦鸡和黄垂麦鸡相似，但上翼白色较少，翼指骨上有白色带纹直至翼前缘，尾羽全黑。雄雌同型，季节变化不明显，幼鸟类似成鸟，但黑色部位边缘呈黄褐色，尖端为棕色。","call":"叫声尖锐响亮，特别是在展示或警戒时发出四音节‘did did do weet’的叫声，与肉垂麦鸡类似但音调较低。","habits":"距翅麦鸡偏好河流附近的栖息地，如耕作区、沙洲和砾石河岸，偶尔也会出现在静水附近。在不丹，它们的活动高度可达2800米，但在印度支那主要低于1100米。它们通常是定居的，仅在特定季节进行小规模游荡。以昆虫、蠕虫、甲壳类和软体动物为主食，偶尔捕食青蛙和蝌蚪。通常单独或成对活动，繁殖后会形成小群体。","breeding":"距翅麦鸡的繁殖期在印度次大陆为3月至6月，4月初在不丹已有雏鸟记录。繁殖行为复杂，由四鸟参与的展示已两次被观察到。巢筑于河中沙洲或砾石滩上的浅坑中，每次产卵3至4枚，卵色橄榄至黄色石色，带有棕色和黑色斑点，平均尺寸为41.1毫米 x 29.4毫米，孵化期约22至24天。","identification":"与黑胸麦鸡相比，距翅麦鸡具有灰色胸部，头部和颈部侧面颜色较淡，腹部有较小的黑色斑点。飞行时，翼型与肉垂麦鸡和黄垂麦鸡相似，但上翼白色部分较少，翼指骨上的白色条纹直达翼前缘。","protection":"IUCN：NT（近危）","distribution":"分布于北印度至中国西南部的云南西部，向南至泰国、马来半岛北部和越南北部。在中国，见于云南、海南和福建等地。","other":"距翅麦鸡曾被称为‘距翅鸻’，这一名称更适合非洲的。"},{"name":"非洲麦鸡","english_name":"Black-headed Lapwing","scientific_name":"Vanellus tectus","overview":"非洲麦鸡（英文名：Black-headed Lapwing，学名：Vanellus tectus），是鸻形目鸻科麦鸡属的鸟类。以黑色头部和白色额头、脸颊、头后部和颈背带纹的独特外观著称。分布于非洲萨赫勒内陆至东非地区，常见于接近水源的湿地繁殖。","appearance":"非洲麦鸡是一种中大型的涉禽，其显著特征是黑色头部，仅白色额头、下脸和头部后方的黑白条纹。它具有细长的黑色冠羽，类似北方麦鸡，红色的喙和腿。飞行时，可以看到翅膀上的黑色飞羽与棕色覆羽之间有一条白色横带，而下翼则呈现白色，边缘为黑色飞羽。","call":"非洲麦鸡发出金属质感的‘tink-tink’叫声。","habits":"非洲麦鸡主要栖息于接近水源的低洼湿地，但觅食时会前往较干燥的环境，如高尔夫球场和草丛，以地面的昆虫和其他无脊椎动物为食。它们通常在夜间、清晨或傍晚活动，经常成对或小群体出现。","breeding":"繁殖期受季节限制，地理上有所差异，可能在干季或雨季达到高峰。非洲麦鸡在沙地或土中筑浅坑巢，每窝产卵1-6枚，颜色为黏土色到温暖的米色，带有黑色、深褐色和栗色斑点。孵化期约为26天，由双亲共同承担。雏鸟背部有黑黄相间的斑点，颈部、脸颊和下体为白色。","identification":"非洲麦鸡与其他麦鸡种类的区别在于其独特的黑色头部和红色腿部，以及胸前垂直的黑色条纹。飞行时，其翅膀上的大块白色区域延伸至内翼，形成斜向的白色带状图案。","protection":"IUCN：LC（无危）","distribution":"非洲麦鸡广泛分布于撒哈拉以南非洲，从塞内加尔到埃塞俄比亚，包括内陆萨赫勒至东非。在冈比亚、尼日利亚常见；在加纳较为罕见；而在象牙海岸北部、多哥北部和中非共和国北部较为少见。","other":"非洲麦鸡能适应干旱至沙漠条件，甚至在人类居住区如机场、足球场和赛马场附近筑巢。"},{"name":"黄垂麦鸡","english_name":"Yellow-wattled Lapwing","scientific_name":"Vanellus malabaricus","overview":"黄垂麦鸡（英文名：Yellow-wattled Lapwing，学名：Vanellus malabaricus），是鸻形目鸻科麦鸡属的鸟类。优雅的长翼鸟，主要分布在印度次大陆，特别是在半岛印度的干燥平原。黄垂麦鸡拥有醒目的黑色头冠，鲜明的黄色面部褶皱，以及白色的腹部。通常在干燥开阔地带活动，而非紧邻水源。","appearance":"黄垂麦鸡体长24-28厘米，体重108-203克，翼展65-69厘米。成年繁殖期个体具有整洁的黑色头冠，边缘有狭窄的白色线条，黄色腿和面部褶皱，黑色的下巴和喉咙，棕色的颈和上身，白色的腹部，以及白色翼带和臀部。非繁殖期和幼鸟则更多斑驳，缺乏明显的黑色头冠。喙基部黄色，翅膀上的黑色飞羽与肉垂麦鸡相似，但上身颜色较浅，臀部的白色斑纹较窄。性成熟后，两性相似，但在兴奋时黑色头冠可竖起。幼鸟有棕色的顶冠，小而苍白的褶皱，深色的亚端条纹和背部羽毛的淡色边缘，下颌和喉咙为白色。","call":"黄垂麦鸡发出尖锐的‘tchee-it’呼唤声，以及在警报时的响亮‘cheee'it’叫声。在极度激动时，叫声变为急促的‘whit-whit-whit’。叫声与燕鸥类似，开始突然，起初平缓，然后下滑，结尾粗糙。","habits":"黄垂麦鸡偏好干燥开阔的环境，包括耕作和休耕地、荒地，偶尔在湿地边缘出现，但不一定靠近水源。它们主要在夜间觅食，食物主要包括昆虫及其幼虫，如蚱蜢和甲虫，以及软体动物。","breeding":"繁殖期主要在3月至7月，斯里兰卡可延续至8月。成年黄垂麦鸡保卫大片领地，攻击大多数入侵者。巢穴为浅坑，有时环绕着小石子或泥球，位于干燥、开阔的废弃土地上。一窝产四枚蛋，红色土壤上的蛋通常呈红色。孵化期为26-30天，由双亲共同承担。雏鸟孵化后不久即可离巢，跟随父母觅食。","identification":"黄垂麦鸡与肉垂麦鸡相比，上身颜色较淡，臀部白色斑纹较窄，叫声也有所不同，通常被认为较为安静。此外，黄垂麦鸡的分布区域更偏向干燥地带。","protection":"IUCN：LC（无危）。黄垂麦鸡在分布区内广泛存在，目前看来数量仍然较多。人类捕猎是导致其蛋损失的一个原因，但总体而言，适应干燥环境和对人类活动的容忍度表明该物种当前可能安全。","distribution":"主要分布于印度次大陆，包括巴基斯坦南部、印度内陆至阿萨姆邦中部（排除最北和东北部）、尼泊尔南部和斯里兰卡。在季风期间，它们会向更干燥的地区移动。","other":"黄垂麦鸡曾被置于单型属Lobipluvia中，但现归于Vanellus属。"},{"name":"白头麦鸡","english_name":"White-crowned Lapwing","scientific_name":"Vanellus albiceps","overview":"白头麦鸡（英文名：White-crowned Lapwing，学名：Vanellus albiceps），是鸻形目鸻科麦鸡属的鸟类。中型涉禽，广泛分布于热带非洲，常见于大河附近。其最显著的特征是头部主要为灰色，带有宽大的白色冠纹，以及独特的黄色彩带和长距。","appearance":"白头麦鸡体长28-32厘米，重约161-214克。其特征在于大型黄色肉垂、明显的白色头冠条纹和长的黑色腕刺。飞行时，几乎全白的翅膀带有黑色翼尖，令人印象深刻。雌鸟头部边缘呈棕色，无季节性变化。幼鸟的肉垂和距较小，冠纹呈棕白色，背部和翅膀覆羽边缘呈淡黄色，上体有深棕色斑点。","call":"它发出响亮而尖锐的‘pew’或‘peeuw’声，类似蛎鹬的叫声，尤其是在孵卵时会发出柔和的‘wheet’声。","habits":"白头麦鸡偏好栖息于开阔地带的沙质河岸和森林旁的大河，尤其喜爱有沙洲的河流，但在洪水期间也会前往小溪、浅水池和泻湖。它们在旱季时迁徙到更干燥的地区，主要在非洲西部和中部的河流泛滥时进行。白头麦鸡以昆虫、蠕虫、软体动物、甲壳类动物和小鱼为食，有时也会摄入一些植物物质。","breeding":"繁殖期在非洲西部和中部为1月至3月（12月至5月），而在非洲东南部（如赞比亚）为7月至10月（11月），主要在旱季进行。白头麦鸡为一夫一妻制，通常单独繁殖，但在刚果民主共和国形成松散的群体。筑巢在河流中的沙地或卵石地，巢为浅坑，内铺小枝和鹅卵石，或无铺垫。每窝产卵2-4枚，孵化期超过25天，由双亲共同承担。","identification":"白头麦鸡与类似的有距鸻区别在于其深色腹部和红色基部的肉垂。雌雄差异主要体现在头部颜色上，雌鸟头部边缘呈棕色。","protection":"IUCN：LC（无危）。总数量估计在56,000至128,000只之间，部分地区数量下降，如因污染导致的数量减少。","distribution":"分布于塞内加尔内陆至利比里亚和安哥拉北部，东至苏丹西部南部，乌干达西北部，坦桑尼亚，赞比亚至莫桑比克和南非东北部。","other":"在某些地区，如加纳，白头麦鸡被认为很常见，但在冈比亚则稀少且不规律出现。最近首次在乌干达被记录，可能正在扩展其分布区。"},{"name":"塞内加尔麦鸡","english_name":"Senegal Lapwing","scientific_name":"Vanellus lugubris","overview":"塞内加尔麦鸡（英文名：Senegal Lapwing，学名：Vanellus lugubris），是鸻形目鸻科麦鸡属的鸟类。其最显著的特征是灰褐色的外表、白色的腹部和额头上清晰的白色斑块。在非洲的干草原和短草平原上成小群活动，偏好在近期发生过森林火灾的地区繁殖。分布区域跨越西非至东非，北起几内亚南部和马里南部至尼日利亚西部，南至南非东北部。","appearance":"塞内加尔麦鸡体长22至26厘米，体重107至140克。拥有灰色头部，身体比较大的黑翅麦鸡更苗条，通常额头上的白色斑块更小且边界更清晰，背部上部颜色更绿，喙较短且呈黑色。飞行时，区别于黑翅麦鸡的是内翼的白色而非黑色。雌雄相似，无明显的季节性变化。幼鸟的白色额头和黑色胸带的羽毛末端有淡褐色，三级飞羽边缘带有淡褐色缺口。","call":"塞内加尔麦鸡会发出响亮的双音节‘chi-whoo’叫声，这通常是它们被发现的标志。","habits":"塞内加尔麦鸡栖息于干燥开阔的环境，有时伴有灌木、灌丛和树木，偏好最近烧过的草地和新生长的草地。它们也出现在耕作区、机场、湖泊和河流边缘。在西非，主要出现在沿海草原，偶尔在运动场和开阔的农场灌木丛中被记录。海拔高度可达1300米至1600米。","breeding":"繁殖期因地理位置而异，从3月至5月在塞拉利昂，6月至11月在南非（曾有一次记录在一月）。筑巢在新长出草的烧过地面，巢穴为地面的凹陷（宽度70至120毫米，深度20至40毫米），内铺少量干草、树皮和干叶。每次产卵2至4枚，卵色为土黄或暗橄榄棕色，上面有黑色、深棕色和黄棕色的重斑点。孵化期约为27至28天，由双方父母共同承担，自第一枚卵开始。雏鸟出生后约29至31天离巢。","identification":"与相似的黑翅麦鸡相比，塞内加尔麦鸡体型较小，腿为绿色而非红色，额头斑块更小且模糊，内翼背面有白色而非黑色边缘。","protection":"IUCN：LC（无危）。总体数量估计在25,000至70,000只之间，其中大部分分布在东非和东南非。虽然局部地区常见，但在某些国家如尼日利亚西南部和多哥海岸线变得不常见。","distribution":"塞内加尔麦鸡分布于几内亚内陆南部和马里南部至尼日利亚西部，加蓬南部至安哥拉中西部，东部至肯尼亚东北部，南部至南非远东北部。","other":"塞内加尔麦鸡可能因适宜栖息地的扩张而在某些地区增加，例如在马拉维。"},{"name":"黑翅麦鸡","english_name":"Black-winged Lapwing","scientific_name":"Vanellus melanopterus","overview":"黑翅麦鸡（英文名：Black-winged Lapwing，学名：Vanellus melanopterus），是鸻形目鸻科麦鸡属的鸟类。大型的高地涉禽，拥有棕色背部、白色腹部和深灰色头罩。分布于非洲东部和东南部，偏好高海拔的草地和耕作区。群居，常以群体形式出现。","appearance":"黑翅麦鸡体长26-27厘米，体重163-214克。与塞内加尔麦鸡相似但略大，腿稍短，额头有更多白色，腿更红，胸部有更多黑色。飞行时，其翼中部有一白色横纹，易于辨认。雌雄外观相似，无季节性变化。幼鸟灰白区域在成年后变为淡褐色，上体羽毛有宽阔的浅色边缘。","call":"发出多种响亮叫声，包括尖锐的‘tlu-wit’和‘che-che-che-chereck’声，以及一系列类似‘taytaytaytaytaytaytay’的断音，有时后跟双音节‘too-ghrweet’。最常见的是在繁殖、飞行或夜晚发出的哀怨‘titihoya’声。","habits":"栖息于高海拔平原、高原草地、山地斜坡、开阔平原和干旱草原。冬季迁移到较低海拔，出现在荒地、农田和沿海平原。以夜行和日间迁徙的方式移动。非繁殖季形成数十至上千的群体。","breeding":"繁殖期在埃塞俄比亚为3月至7月，肯尼亚和坦桑尼亚全年皆可，取决于雨季，南非为7月至10月。单配偶制，有时以小规模松散群体繁殖，相邻巢间距约50米。在草地上筑巢，通常在非常短的草丛中，或裸露地面和耕地上。巢穴为刮出的小坑，内铺植物材料和粪便，蛋数通常为3枚，孵化期27-28天，由双亲共同承担。","identification":"与塞内加尔麦鸡相比，黑翅麦鸡体型更大，腿更短，额头有更明显的白色斑块，腿部颜色更红，胸部黑色带更宽，飞行时翼上的白色条纹明显。","protection":"IUCN：LC（无危）","distribution":"主要分布在非洲内陆东北部至东南部，包括埃塞俄比亚高地到肯尼亚中部，以及南非的中间至沿海地区。"},{"name":"冕麦鸡","english_name":"Crowned Lapwing","scientific_name":"Vanellus coronatus","overview":"冕麦鸡（英文名：Crowned Lapwing，学名：Vanellus coronatus），是鸻形目鸻科麦鸡属的鸟类。中型涉禽，体型较鸻类大，具有显著的特征，如棕色顶冠，下部由黑白相间的环纹环绕。广泛分布于非洲东北部至南部，偏好接近水源的栖息地，如沼泽和湖畔，同时也可见于农田、旱草地和高原地带。其饮食主要包括蝗虫、蛙类、小型无脊椎动物及植物种子。","appearance":"冕麦鸡体型中等，长约24厘米，重量介于126至200克之间。其最显著的特征是头部上方的黑色冠羽，周围有一圈醒目的白色光环。背部和胸部呈淡棕色，下胸至腹部有黑色线条。雌鸟比雄鸟小。幼鸟的白色头带不够明显，上体羽毛边缘呈淡黄色。两性均无季节性变化。","call":"冕麦鸡发出一系列嘈杂、尖锐的‘kirre’叫声，极具辨识度。","habits":"冕麦鸡通常居住在干燥开阔的地区，如稀树草原、农田、机场、高尔夫球场等，尤其偏爱近期被火烧过的草地。它们主要在黄昏和月夜活跃，食物以昆虫及其幼虫为主，尤其是白蚁、甲虫、蚱蜢、蟋蟀和蚂蚁，也可能食用蚯蚓。它们会跟随牛群觅食，也被观察到与蝙蝠耳狐共同觅食。","breeding":"繁殖期随地理位置而异，通常在干季，如东非全年均可繁殖，而南非主要在6月至11月。筑巢于新鲜草地上，巢为地面的浅坑，内部铺垫植物材料。每次产卵2至3枚，偶尔可达4枚，孵化期为21至32天，由双亲共同承担。雏鸟孵化后约一个月左右离巢。","identification":"冕麦鸡的黑白环纹和棕色顶冠是其显著的辨识特征，与黑翼麦鸡和黑喉麦鸡有相似的羽毛特征，但通过冠羽和鸣叫声可区分。","protection":"IUCN：LC（无危）","distribution":"冕麦鸡广泛分布在非洲东北内陆至南部地区，包括稀树草原、干旱地带和靠近水体的地区。它们在索马里红海沿岸至南非西南部连续分布。","other":"冕麦鸡的数量在20世纪后期有所增加，得益于人类活动的多种影响，如农业开垦。它们的寿命可达20年。"},{"name":"黑喉麦鸡","english_name":"African Wattled Lapwing","scientific_name":"Vanellus senegallus","overview":"黑喉麦鸡（英文名：African Wattled Lapwing，学名：Vanellus senegallus），是鸻形目鸻科麦鸡属的鸟类。大型的鸻科麦鸡属鸟类，主要分布于撒哈拉以南非洲的大部分地区，避开雨林地带。其显著特征为大型黄色和红色皱褶，黑色头顶，白色额头，以及长黄色腿。","appearance":"成年黑喉麦鸡长约34厘米，体重介于160至287克之间。拥有大型黄色和红色皱褶；长黄色喙，靠近尖端有黑色；黑色腕刺；主要体羽呈棕色，翼上有白色条纹，飞羽为黑色。雌鸟喉部黑色较少。幼鸟皱褶非常小；下巴和喉部为灰白色，带黑色条纹；额头上白色较少。无季节性羽色变化。","call":"发出响亮连续的‘peep-peep-peep’叫声，紧张或兴奋时会变成急促的‘yip-yip’声。","habits":"栖息于多种低海拔环境，最高可达2200米。偏好湿地，如沼泽、湖泊边缘、水塘、河流和溪流附近的草地，也出现在干燥的灌木草原、短草田地、机场、农田、荒地、泛滥的稻田、池塘、烧过的草地。常在白蚁丘附近活动，将其作为观察点。","breeding":"繁殖期因地区而异，依赖雨季。一夫一妻制，领域性强。巢通常建在离水源100米内的裸露地面或短草丛中，浅凹槽形，用草茎、树枝、鹅卵石和干粪装饰。每窝产2-3枚蛋（南部非洲产4枚），孵化期30-32天，双亲共同孵化。雏鸟有黑色头部斑块，白色额部和颈背环，下体淡黄色，约40天后离巢。","identification":"与白头麦鸡相似，但体型较小，腹部白色，无红色皱褶基部。","protection":"IUCN：LC（无危）","distribution":"广泛分布于撒哈拉以南非洲内陆地区，包括中部、西南部和南部，但不在雨林地带。","other":"适应人类活动和农业环境，因此不太可能受到威胁。"},{"name":"斑胸麦鸡","english_name":"Spot-breasted Lapwing","scientific_name":"Vanellus melanocephalus","overview":"斑胸麦鸡（英文名：Spot-breasted Lapwing，学名：Vanellus melanocephalus），是鸻形目鸻科麦鸡属的鸟类。体型中等的鸻科麦鸡属鸟类，主要分布在埃塞俄比亚高原。其显著特征包括黑色顶冠、白色眉纹、黑色喉部和胸部粗大的斑点。","appearance":"斑胸麦鸡体长约34厘米，重约199至228克。外观呈现灰褐色，头部有黄色肉垂，黑色顶冠、下巴和喉部；白色的眉纹明显；背部略带绿色调；胸部有黑色斑点，甚至略微条纹状，腹部白色；颈背的羽毛可竖起形成冠状。飞行时，与Vanellus属其他物种区分在于更窄的黑色尾带。雌雄外观相似，无季节变化。幼鸟颜色较淡，顶冠和喉部呈暗色，眉纹比成鸟宽且边界不明显；上体羽毛灰棕色，边缘淡色；上胸部有灰色棕色的细纹；眼环柠檬黄色，腿色比成鸟淡，为较浅的黄色。","call":"鸣叫被描述为刺耳的‘ku-eep’或‘pewit’声，以及较长的‘kree-kree-kre-krep-kreep-kreep’声，类似于其他lapwing种类。","habits":"斑胸麦鸡栖息于湿润草地、高山沼泽地带，包括有巨型龙胆、巨型苔藓、Alchemilla和草丛的地方，同时出现在湿地和溪流旁，常见于牧场和牛群附近。它们通常在1800至4100米之间活动，主要活动高度为2420至3800米。除了繁殖季节，经常以30至40只的小群体出现，偶尔会多达240只。白天非常活跃，经常在牛群放牧的草地上觅食。","breeding":"繁殖季节在Bale山脉为四月，在Shewa地区为八月。已知的一个巢穴是在一片草和苔藓中浅浅的挖洞，位于一个小岩石岛上的浅水池中，处于巨型龙胆沼泽地带。巢中有四个蓝灰色到烟灰色的蛋，带有黑色重斑点。","identification":"与Vanellus属其他物种相比，斑胸麦鸡可通过其更窄的黑色尾带和独特的头胸部斑纹来区分。","protection":"IUCN：LC（无危）","distribution":"主要分布于非洲埃塞俄比亚中北部至中南部的山区。"},{"name":"褐胸麦鸡","english_name":"Brown-chested Lapwing","scientific_name":"Vanellus superciliosus","overview":"褐胸麦鸡（英文名：Brown-chested Lapwing，学名：Vanellus superciliosus），是鸻形目鸻科麦鸡属的鸟类。体型较大，长腿，适应于开阔地带，如短草地、新烧荒地及湖岸。具有独特的红棕色额部和胸部，黑色顶冠，窄白眼纹。分布于从尼日利亚内陆至刚果民主共和国北部，冬季迁徙至乌干达、肯尼亚西南部、坦桑尼亚西北部和刚果民主共和国东部。","appearance":"褐胸麦鸡体长约23厘米，重约150克。特征包括黑色顶冠，窄白眼线，绿色至棕色背部，小黄肉垂，以及红棕色前额和胸部。两性相似，无季节性变色。幼鸟头部无黑色，缺乏肉垂，前额和胸部颜色更淡；背部广泛带有红棕色边缘。","call":"鸣叫为尖锐的“chit-chit-chit”声。","habits":"栖息于开阔的萨瓦纳草原，有时接近河流和湖泊，也见于足球场、草坪和最近烧过的草地。迁徙时在刚果民主共和国的森林清除区也有发现。在非繁殖季节，通常以30只左右的小群出现，最多可达100只。","breeding":"繁殖期在尼日利亚和喀麦隆为1月至3月，可能在刚果民主共和国为12月至6月，假设在旱季繁殖。一夫一妻制，领域性强。在新烧过的地面筑巢，巢为土壤中的浅坑，衬以小石子和蚁丘碎片，覆盖蛋以保护。每次产卵2-4枚，蛋色与当地土壤相匹配，带有黑色、巧克力色和红棕色斑点。双亲共同孵化至少24天，雏鸟出生时有暗色斑点和白色颈背。","identification":"与其他麦鸡属物种相比，褐胸麦鸡具有显著的红棕色胸部和前额，以及黑色顶冠和窄白眼线。","protection":"IUCN：LC（无危）","distribution":"繁殖于尼日利亚内陆至刚果民主共和国北部。非繁殖期分布扩展至乌干达、肯尼亚西南部、坦桑尼亚西北部和刚果民主共和国东部。","other":"褐胸麦鸡是一种迁徙物种，对环境的适应性较强，但具体繁殖和非繁殖范围的界限尚不清楚，需要更多的调查研究。"},{"name":"灰头麦鸡","english_name":"Grey-headed Lapwing","scientific_name":"Vanellus cinereus","overview":"灰头麦鸡（英文名：Grey-headed Lapwing，学名：Vanellus cinereus），是鸻形目鸻科麦鸡属的鸟类。体型较大，以其灰色头部、鲜明的黑色胸带和白色的腹部而著称。分布广泛，从东北亚的中国、日本到东南亚的印度和中国南方。","appearance":"灰头麦鸡体长34至37厘米，体重236至296克，翼展可达75至76厘米。头部、颈部和上胸部为灰色，胸带深灰，背部棕色，腹部白色，腰部白色，尾羽黑色，尾尖黑色。飞行时，黑色初级飞羽与白色次级飞羽形成鲜明对比，翅膀上方的图案让人联想到，但黑色初级飞羽和棕色覆羽之间有白色羽毛相隔。成年雄鸟和雌鸟羽毛相似，但雄鸟略大。幼鸟的白色羽毛边缘带有灰色，胸带不明显，上体和翼覆羽有淡色边缘。","call":"灰头麦鸡发出尖锐的‘chee-it’声，飞行中的鸟偶尔会发出‘kik’音，从地面发出哀怨而坚持的‘chee-it’声，全年都能听到嘶哑的三音节警报声，如‘did-all-eet’或‘cha-ha-eet’。","habits":"灰头麦鸡栖息于湿地、河流边、稻田等环境，冬季时也可见于沼泽、河岸、湿草地、稻田残茬、池塘等。它们主要以昆虫、蠕虫和软体动物为食，常涉水觅食。在非繁殖季节，它们常以5至50只的小群出现。","breeding":"繁殖期在3月至4月，灰头麦鸡在一夫一妻制下于未受干扰的湿地或稻田中筑巢，巢为简单的凹坑，通常铺设苔草草茎和草叶。每窝产卵四枚，孵化期为28至29天，雏鸟在孵化后的第二天即可行走。","identification":"灰头麦鸡通过其独特的灰色头部、黑色胸带和白色的腹部与其它麦鸡种类区分。幼鸟与成鸟的区别在于幼鸟的白色部位有灰色边缘，胸带模糊。","protection":"IUCN：LC（无危）","distribution":"繁殖于东北亚的中国（内蒙古、黑龙江、江苏、福建）、日本本州至九州，以及俄罗斯的部分地区。冬季迁徙至南亚（从印度东北部至柬埔寨）和东南亚至马来半岛、越南北部和南部、中国东南部。","other":"灰头麦鸡曾作为迷鸟出现在俄罗斯、菲律宾、印尼、澳大利亚新南威尔士州、斯里兰卡、瑞典和英格兰等地。"},{"name":"肉垂麦鸡","english_name":"Red-wattled Lapwing","scientific_name":"Vanellus indicus","overview":"肉垂麦鸡（英文名：Red-wattled Lapwing，学名：Vanellus indicus），是鸻形目鸻科麦鸡属的鸟类。以及醒目的白腹和黑翼尖，使其在亚洲的湿地、农田和草原上容易辨认。响亮报警叫声是其另一个显著特征。肉垂麦鸡广泛分布于西亚、南亚，包括印度、斯里兰卡，以及中国西南部和越南北部。","appearance":"肉垂麦鸡体长约35厘米，翼展可达80至81厘米。头部、胸部呈黑色，背部具金属光泽的棕色，腹部白色，翅膀上有明显的白色条纹。眼前方有一对红色肉垂，喙红色带黑尖，腿黄色。性成熟个体在非繁殖季节翼羽换毛期间，冠部带有棕色调，喉部有白色斑点。幼鸟的羽毛较暗淡，喉部白色，胸部和冠部灰色至褐色，冠部有白色斑点。不同亚种之间主要在光泽、上体颜色和体型大小上略有差异。","call":"非常喧闹，无论昼夜，发出响亮刺耳的‘did-he-do-it’叫声，重复单调，常在巢穴防御时特别响亮。","habits":"肉垂麦鸡生活在海拔1800米以下的开阔地带，靠近淡水或咸水，如湖泊、河流、泥滩、湿草地，尤其是农田。它们在清晨、黄昏和月夜觅食，以昆虫为主食，包括甲虫、蚂蚁、蝴蝶幼虫、蝇蛆、蚱蜢、蟋蟀、臭虫、蠼螋和白蚁，也吃软体动物、蠕虫和甲壳类动物。它们在地面以典型的鸻科方式觅食，即短距离奔跑后低头捡食。","breeding":"繁殖期从3月至8月，主要在春季至夏季。它们在地面挖浅坑做巢，通常位于水源附近，巢穴可能由小石子、贝壳和碎片铺成。一窝产3至4枚蛋，蛋壳呈黄色底色，密布黑色斑点。孵化期约为26至30天，由双亲共同承担。雏鸟出生后即可跟随父母觅食，受到威胁时会平躺在地面或草丛中隐蔽。","identification":"肉垂麦鸡与黄垂麦鸡相比，上体颜色更深，飞行时可见明亮的白色翼下，黑色飞羽对比明显。不同亚种间主要在光泽、上体颜色和体型大小上略有差异，如aigneri亚种体型最大且最淡，lankae亚种体型最小且最暗。","protection":"IUCN：LC（无危）。西亚估计有10万只，南亚超过10万只，东南亚数量未知。阿拉伯地区的总数量估计为约1700对繁殖鸟，其中阿联酋有500对，阿曼有1200对，科威特极少数（少于5对）。斯里兰卡亚种lankae数量估计不超过5000至6000只。","distribution":"分布于西亚、南亚，包括土耳其东部、伊拉克、阿拉伯半岛东北部、土库曼斯坦南部、阿富汗、印度西北部、斯里兰卡、中国西南部、马来半岛和越南北部。在中国大陆，主要分布在西南部地区。","other":"肉垂麦鸡在当地文化中具有象征意义，如印度部分地区认为它在高处筑巢预示着好雨。"},{"name":"爪哇麦鸡","english_name":"Javan Lapwing","scientific_name":"Vanellus macropterus","overview":"爪哇麦鸡（英文名：Javan Lapwing，学名：Vanellus macropterus），是鸻形目鸻科麦鸡属的鸟类。大型水鸟。拥有显著的黄色肉垂，深黑色头部、腹部斑块及飞羽，暗棕色上体、胸部和上腹部，白色尾上覆羽和腹下部，黑色弯曲的脚距，以及黄色至橙色的腿。曾广泛分布在爪哇岛的湿地与河口三角洲，可能也存在于苏门答腊和帝汶岛，最后一次确切记录是在1940年。","appearance":"爪哇麦鸡体长27–29厘米，体重约325克。其特征为显著的亮黄色肉垂（有时误报为白色，可能源于死后褪色），深黑色头部、腹部斑块和飞羽，暗棕色的上体、胸部和上腹部，白色尾上覆羽和腹下部。脚距呈黑色或黄色，可能在非繁殖季节或幼鸟中颜色有所不同。腿色为黄橙色或接近胫骨处的火橙色，之后为鲜黄色，趾为深赤褐色。","call":"爪哇麦鸡发出一系列类似玩具喇叭的嘎嘎声，尤其是在傍晚时，从地面或飞行中发出，例如‘t[r]et t[r]et t[r]et t[r]ett[r]t！’，带有微弱的‘r’音，接着是‘tat tat tat tat - - tahhhhht！’交替着‘trrrek - terrrr！’或仅仅是‘trrrrrrr！’，还有重复的‘krahhh！’和‘ahhh！’，起飞前的‘trahhhhwu’，飞行中的愤怒‘krihhh！’，以及群体中的非嘎嘎声‘tetetititit’。","habits":"栖息于爪哇岛靠近淡水池塘和茂密的芦苇沼泽地带，也见于湿润的牛牧场和废弃稻田旁的鱼塘，背靠红树林。它们可能在岛上全年居住，但局部移动或迁徙由其在知名地点的零星出现所暗示，可能与雨季和季节性水稻种植有关。通常成对或单独观察到，但也曾记录到4–6只的小群体。","breeding":"繁殖行为似乎发生在5月至6月，在西爪哇。成鸟被观察到在7月和8月驱赶潜在捕食者，如栗鸢，可能意味着它们仍有蛋或幼鸟。已知的八个巢穴中，七个位于雅加达附近的Cabang Bungin和Rawah Tangerang，另一个来自未知地点。巢穴通常是一个深度挖掘的坑，以松散的草作为衬垫，一窝产卵数量从单一到四个不等，但多数可能是不完整的。蛋的尺寸大约为44.3–47.8毫米×30.8–33毫米。","identification":"爪哇麦鸡通过其独特的黄色肉垂、深黑与暗棕色的体色组合以及特定的叫声与其他麦鸡种类区分开来。然而，缺乏对其幼鸟、性别差异和季节性羽毛变化的描述，这使得与其他相似物种的鉴别变得复杂。","protection":"IUCN：CR (PE)（极危（可能已灭绝））","distribution":"主要分布于爪哇岛，历史上可能也存在于苏门答腊和帝汶岛。在爪哇岛，分布于西部和东部，特别是在湿地、河口三角洲、湿润的牛牧场和废弃稻田旁的鱼塘。","other":"尽管自1940年以来没有确凿的记录，当地人的报告声称在20世纪50年代中期、80年代和1999年（Jember）、1994年、2004年和2005年（Lumajang）以及2002年至2003年和2010年（Bekasi）见过爪哇麦鸡。"},{"name":"三色麦鸡","english_name":"Banded Lapwing","scientific_name":"Vanellus tricolor","overview":"三色麦鸡（英文名：Banded Lapwing，学名：Vanellus tricolor），是鸻形目鸻科麦鸡属的鸟类。中等体型的鸻科麦鸡属鸟类。主要分布于澳大利亚内陆和塔斯马尼亚州，偏好开阔的草地环境。以其独特的黑白红三色头部标记和U形黑色胸带著称。","appearance":"三色麦鸡体长25至29厘米，体重140至216克，翼展61至67厘米。具有白色眼纹，红色肉垂位于眼前方，以及完整的黑色胸带。头部黑白相间，上体呈暗紫褐色，喙小而红，喙和眼均为淡黄色。雌雄相似，但雄鸟平均稍大。幼鸟与成鸟相似，但具有较暗的喙和较小的肉垂，上体羽毛边缘呈淡黄色。","call":"发出尖锐的‘kew-kew, kew-kew’叫声，警戒时发出更快且略嘶哑的‘er-chill-char, er-chill-char’叫声，与白颈麦鸡的叫声类似但音调有所不同。","habits":"栖息于开放、短草覆盖的平原，包括牧场、机场和半干旱地区的开阔灌木草原。通常在内陆地区活动，雨后数量激增，干旱时移至海岸。日间觅食，夜间也会活动，以种子、叶片、软体动物、昆虫和蜘蛛为食，偏好在短草地上觅食。","breeding":"全年繁殖，受降雨影响，常见于6月至11月。一夫一妻制，选择在牧场、耕地、盐碱地和机场筑巢。巢穴简单，由草和其他植物材料组成。每窝产卵3至5枚，孵化期26至28天，双亲共同孵化。雏鸟约8周后离巢，5.5周时羽毛丰满。","identification":"与白颈麦鸡相比，体型较小，腿较短，具有全白胸部、无白色翼纹，头部图案不同。成鸟通过独特的胸带和头部标记易于识别。","protection":"IUCN：LC（无危）总数量估计约27,000只，但在1983至2006年间，东部种群数量显著下降。","distribution":"主要分布在澳大利亚内陆（除北部和西中部）和塔斯马尼亚州。在维多利亚州春季和冬季最常见，可能与降雨量有关。","other":"历史上曾被视为狩猎对象。随着森林和灌木地开垦为农田，适宜栖息地增加。部分地区因小麦农场终止和牧草过高导致数量减少。"},{"name":"白颈麦鸡","english_name":"Masked Lapwing","scientific_name":"Vanellus miles","overview":"白颈麦鸡（英文名：Masked Lapwing，学名：Vanellus miles），是鸻形目鸻科麦鸡属的鸟类。大型且常见，广泛分布于澳大利亚（北部和东部为主）、新西兰和新几内亚。以其醒目的黄色额饰和尖锐的翼刺著称，常在开阔地带活动，以昆虫和蠕虫为食。","appearance":"体型大，长30-37厘米，重191-412克，翼展75-85厘米。头部黑色，颈侧至胸侧有黑色条纹（仅限于南方亚种）。上体橄榄棕色，下体白色。具黄色长翼刺和黄色喙，眼周有明亮的黄色环。两性相似，但雄鸟平均较大。幼鸟上体灰褐色，翼刺和额饰较小，腿和脚呈暗灰色。","call":"具有多种叫声，包括响亮的警告声、防御叫声、求偶叫声以及对幼鸟的呼唤。叫声穿透力强，昼夜皆可听见。","habits":"偏好短草覆盖的开阔环境，包括牧场、空地、机场边缘和各类湿地。常见于城市公园、运动场和草地路缘。夜间可能也会觅食。食谱主要包括昆虫、蠕虫、蜘蛛、软体动物、甲壳动物、种子和叶子。","breeding":"繁殖期在澳大利亚为11月至翌年4月，在新几内亚为8月至11月及3月。一夫一妻制，对繁殖地忠诚。通常在短草丛中筑巢，有时靠近水源。巢为地面凹陷，可能铺垫植物材料、卵石和杂物。每窝产卵4枚，孵化期28-30天。幼鸟出生后即可游泳，约6-7周后离巢。","identification":"与三色麦鸡的区别在于黑色肩带不相接（仅限于南方亚种），以及更大的黑色顶冠。北方亚种缺乏黑色肩带，具有更大黄色额饰。","protection":"IUCN：LC（无危）。总数量估计为约287,000只，其中258,000只在澳大利亚。","distribution":"在澳大利亚广泛分布，特别是在北部和东部地区。在新西兰自1930年代自然扩散，现已遍布全国。新几内亚内陆也有其踪迹。","other":"白颈麦鸡在澳大利亚的繁殖栖息地因农业开垦而显著增加。在新西兰，随其分布扩张，与飞机碰撞事件增多，因此在机场进行了大量控制措施。"},{"name":"黄颊麦鸡","english_name":"Sociable Lapwing","scientific_name":"Vanellus gregarius","overview":"黄颊麦鸡（英文名：Sociable Lapwing，学名：Vanellus gregarius），是鸻形目鸻科麦鸡属的鸟类。中型鸻科鸟类，以半干旱草原、牧场和开阔地带为栖息地。其分布区主要集中在哈萨克斯坦北部及邻近的俄罗斯南部，历史文献中曾将其称为黑腹燕鸻。种群数量自1960年代以来急剧下降，被列入国际极危物种名单。","appearance":"黄颊麦鸡身长27-30厘米，体重150-260克，翼展64-76厘米。其橄榄褐色的羽毛上有明显的白色眉纹，在额头和颈背相连，黑色的冠羽和眼纹，腹部呈黑色和栗色，腿为深色。夏季羽毛更加鲜艳，背部变为灰褐色，脸颊呈赭色，眼纹和冠羽颜色加深，下胸羽毛变黑，逐渐过渡为接近肛门处的栗色羽毛。幼鸟背部有边缘化的羽毛，呈现出鳞状外观，头部图案痕迹较淡。","call":"在繁殖区较为安静，但在筑巢期间会发出刺耳的‘kets’、‘rech’或‘etch’声。冬季会发出短暂尖锐的鸣叫，以及起飞时特别粗哑的‘sklech’声。","habits":"黄颊麦鸡主要栖息在禾本科植物和蒿属植物草原的过渡带，偏好植被覆盖稀疏的半干旱环境，靠近人类居住区的放牧地，以及开垦、耕作和休耕地。迁徙时，它们出现在沙质平原、干草场、荒地和农田。在越冬地，选择烧过的草原、灌木丛、未开垦的荒地、废弃牧场和收割后的谷物田，通常靠近水源。","breeding":"黄颊麦鸡在4月中旬至5月底或6月初开始繁殖，单配偶制。繁殖前，5-10只鸟群会在开阔田野上展示打斗。巢穴建在盐碱地或短草丛中，通常靠近水边。巢由11-12厘米宽、5-6厘米深的凹坑构成，可能用少量植物材料、石头和碎片铺垫。每窝产卵2-5枚，卵壳橄榄绿至暖黄色，带有主要为黑色和部分灰色的斑点。孵化期长达28-29天，主要由雌鸟承担。雏鸟出生时呈淡粉色至奶油色，上面有黑色斑点和条纹，脸颊纯奶油色，后颈和下体呈浅黄色。幼鸟大约在35-40天后离巢。","identification":"黄颊麦鸡与白尾麦鸡的区别在于黑色的腹部、较短的深色腿和鲜明的头部图案。在飞行中，显示棕色的内翼覆羽、黑色的初级飞羽、白色的次级飞羽以及主要为白色、中央尾羽有黑色次端带的臀部和尾巴。","protection":"IUCN：CR（极危）。黄颊麦鸡的全球种群数量自1960年代以来急剧下降，目前估计仅存约11,200只成熟个体。在叙利亚北部发现的大规模越冬种群为保护工作带来了希望，但该物种仍面临严重的生存威胁。","distribution":"繁殖于哈萨克斯坦北部及邻近的俄罗斯南部，越冬于苏丹至厄立特里亚、以色列、阿拉伯半岛、巴基斯坦中部和印度西北部。曾在乌克兰东部、克里米亚和伏尔加地区以及中国新疆繁殖，但这些地区已不再有繁殖记录。","other":"历史上，黄颊麦鸡曾是常见越冬鸟种，在巴基斯坦和印度西北部广泛分布，但现在极为罕见。"},{"name":"白尾麦鸡","english_name":"White-tailed Lapwing","scientific_name":"Vanellus leucurus","overview":"白尾麦鸡（英文名：White-tailed Lapwing，学名：Vanellus leucurus），是鸻形目鸻科麦鸡属的鸟类。其特征在于拥有长黄色腿，白色尾羽，以及独特的棕色、白色和黑色翅膀图案。分布于土耳其、阿塞拜疆至哈萨克斯坦南部、乌兹别克斯坦、土库曼斯坦、阿富汗西北部、约旦北部、波斯湾至巴基斯坦西南部，繁殖区域广泛。2012年在中国新疆南部首次记录。","appearance":"成鸟为修长的鸟类，具有棕色背部和前颈，较浅的脸色和灰色胸部。其最显著的特征是长而亮丽的黄色腿，纯白色的尾羽，以及由棕色、白色和黑色组成的独特翼纹。幼鸟背部呈鳞片状，尾羽可能带有棕色。体型中等，站立时姿态挺拔。","call":"繁殖季节时发出类似'peewit'的叫声，与凤头麦鸡相似。","habits":"栖息于湖泊和河流附近的湿地，偏好沙漠和半沙漠环境中的湿润地带。中亚繁殖种群为迁徙性鸟类，中东伊朗和伊拉克的种群为留鸟。春季迁徙期为3月中旬至4月初，秋季迁徙期为7月底至8月，最晚至9月底。以昆虫和其他小型生物为主食，常在水面上捕食。","breeding":"繁殖期从4月底持续至6月初，集群现象始于7月。在地面筑巢，每窝产四枚蛋。孵化期为21-24天，幼鸟由双亲共同照顾，大约30天后离巢。","identification":"与其他麦鸡相比，白尾麦鸡以其长黄腿、全白色尾羽和独特的三色翼纹最为突出。与社会麦鸡的区别在于尾羽颜色全白，而非黑尖。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆的土耳其内陆中部至阿塞拜疆东部，向北至里海北部，南至哈萨克斯坦南部、乌兹别克斯坦、土库曼斯坦和阿富汗西北部，东至约旦北部和波斯湾至巴基斯坦西南部。非繁殖期分布延伸至厄立特里亚、埃塞俄比亚北部、苏丹、红海和波斯湾南部，以及印度西北部和中北部。","other":"在一些分布区域，该物种面临因栖息地破坏和意外狩猎带来的威胁。"},{"name":"凤头距翅麦鸡","english_name":"Southern Lapwing","scientific_name":"Vanellus chilensis","overview":"凤头距翅麦鸡（英文名：Southern Lapwing，学名：Vanellus chilensis），是鸻形目鸻科麦鸡属的鸟类，别称包括quero-quero（巴西）、tero（阿根廷和乌拉圭）、tero-tero（巴拉圭）和queltehue（智利）。广泛分布于南美洲，除了亚马逊密林、安第斯山脉高处及西岸干旱地带。凤头距翅麦鸡是南美特有的冠涉禽，以其独特的外形和分布闻名。","appearance":"凤头距翅麦鸡身长32到38厘米，体重约250至425克。上身主色为褐灰色，肩部带有青铜光泽。头部显著，灰色为主，前额、喉咙和胸部黑色，脸部与头部间有白色边界，下身白色。眼睛、腿和喙均为粉红色。飞行时，可见明显的白色翼条，臀部白色，尾巴黑色。虹膜红色，喙基部粉红色，喙尖黑色，腿红色。","call":"凤头距翅麦鸡的叫声响亮刺耳，特征性的'keek-keek-keek'声是识别它们的重要线索。","habits":"凤头距翅麦鸡栖息于湖河岸边、开放的草地及人类活动频繁的区域。它们适应了因养牛业扩展的草地环境，夜间采用跑停结合的方式觅食，主要食物为昆虫、小鱼和其他小型无脊椎动物。在城市区域，如里约热内卢、蒙得维的亚和拉普拉塔，它们甚至会在夜间在照明的足球场觅食。","breeding":"凤头距翅麦鸡在5月至7月期间繁殖，营巢于草地或沼泽边缘，巢穴简陋，通常在地面上的凹坑中。每窝产卵2至3枚，孵化期约为25至28天。雏鸟为早成性，出生后第二天即可离巢行走。","identification":"凤头距翅麦鸡的辨识要点包括其大型的体型、黑色面部与胸部、白色翼条以及特有的叫声。在南美范围内，它不易与其他物种混淆。北部和南部的亚种在头部颜色和声音上有细微差别。","protection":"IUCN：LC（无危）","distribution":"凤头距翅麦鸡广泛分布于中美洲和南美洲，从尼加拉瓜内陆至智利南部和阿根廷南部，包括拉普拉塔盆地。","other":"凤头距翅麦鸡已逐渐扩散至中美洲，甚至在特立尼达、多巴哥和巴巴多斯建立了小群体。"},{"name":"安第斯麦鸡","english_name":"Andean Lapwing","scientific_name":"Vanellus resplendens","overview":"安第斯麦鸡（英文名：Andean Lapwing，学名：Vanellus resplendens），是鸻形目鸻科麦鸡属的大型、鲜明模式的涉禽，分布于南美洲安第斯山脉的高山沼泽、湿地和湖岸，也会出现在北部范围内的草地牧场。其分布区域从哥伦比亚西南部至智利东北部和阿根廷西北部。","appearance":"体长约33厘米，重193至230克。头部呈奶油灰，眼周有暗棕色斑块，背部为青铜绿色，翼盖上有紫色斑块，胸部深灰色，腹部白色。喙为粉橙色带黑色尖端，眼睛红色，腿也是红色。幼鸟头部和颈部呈棕色，胸部有淡褐色斑点，背部羽毛边缘较浅。两性相似，无季节性羽毛变化。","call":"通常发出尖锐的‘wik’声警报，刺耳的‘criee-criee-cri’叫声，急促的‘cwi-cwi-cwi...’或更柔和旋律的‘dididi---celeec-celeec-celeec-ce...’声，偶尔会发出柔和的‘cow’音或低沉颤抖的‘kwiwiwiwirrr’声。","habits":"栖息于海拔2700至4600米的安第斯山脉开放景观，包括高山草甸、湿地边缘和湖泊附近，避免盐水环境。冬季期间，会迁移到较低海拔，偶尔到达海岸。行为上，它基本上是留鸟，但在冬季会进行海拔迁移。","breeding":"繁殖季节主要在10月至12月间，巢筑于地面的凹陷处，铺垫有植物材料，每窝产卵3至4枚。孵化期和离巢时间未知。","identification":"可通过其奶油灰色头部、无冠的鸽灰色头部和胸部、粉红的喙和腿（幼鸟颜色较暗）以及飞行中展示的黑白翅膀和尾巴图案来识别。与凤头距翅麦鸡在低地和山脚的分布范围极少重叠。","protection":"IUCN：LC（无危）","distribution":"分布于南美洲安第斯山脉，从哥伦比亚西南部至智利东北部和阿根廷西北部，海拔范围从2700至4600米，偶尔在南部地区低至1500米，冬季可能迁至更低海拔。","other":"在一些地区非常常见，如3000至4500米的高海拔地区，但在某些地方如厄瓜多尔较为局部化。"},{"name":"红膝麦鸡","english_name":"Red-kneed Dotterel","scientific_name":"Erythrogonys cinctus","overview":"红膝麦鸡（英文名：Red-kneed Dotterel，学名：Erythrogonys cinctus），是鸻形目鸻科红膝麦鸡属的鸟类。名称虽含‘红膝’，实则膝盖为粉红色。成鸟具黑色头罩、白色下巴、黑色胸带和栗色侧腹斑块，幼鸟灰白相间，缺乏黑色特征。常见于淡水湿地，常以小群出现。","appearance":"红膝麦鸡体长17至19.5厘米，重35至77克，翼展33至38厘米。中等体型，头部黑色，与白色喉咙形成鲜明对比；黑色胸带及中间侧腹，逐渐变为栗色向后延伸；上侧腹白色；长腿双色，胫部和‘膝盖’粉红红色，跗跖和脚灰色；长而细的微微弯曲的喙。两性相似，无季节变化。幼鸟头部、颈背淡棕色，背部羽片边缘淡黄褐色；大部分白色下体，棕色胸部斑块；喙较暗淡。","call":"发出低沉的滚动颤音，飞行、展示或威胁时的‘prr prip-prip’声，遇险时则发出清晰的双音节‘wit, wit’声。","habits":"栖息于内陆湿地，如沼泽、湖泊、溪流及人造水体，偏好临时或永久淡水湿地，尤其在雨季或洪水泛滥时。干旱时向南迁移至沿海地区；雨季和洪水后，内陆数量增加，有时会形成数百只的大群。以螺类、贝类、甲壳动物、蜘蛛、昆虫及种子为食，白天觅食，沿泥滩边缘搜索，偶尔游泳于深水区。","breeding":"夏季、秋季或早冬雨后繁殖，通常8月至12月。筑巢于沙地、湿土或泥地上，常位于密集植被中，与黑翅 stilts、红颈 avocets 和灰头 grebes 共存。巢由枝条、草和其他植物材料构成，一窝四枚蛋，孵化期未知，雏鸟由双亲照料。","identification":"与同类物种相比，红膝麦鸡具有独特的黑色头部、白色喉咙和栗色侧腹斑块，长腿粉红色，易于识别。","protection":"IUCN：LC（无危）","distribution":"分布于极南新几内亚和澳大利亚（除塔斯马尼亚州和中南部）。"},{"name":"澳洲小嘴鸻","english_name":"Inland Dotterel","scientific_name":"Peltohyas australis","overview":"澳洲小嘴鸻（英文名：Inland Dotterel，学名：Peltohyas australis），是鸻形目鸻科小嘴鸻属的鸟类。主要分布在澳大利亚内陆，除北东部和塔斯马尼亚州之外。具有独特的外观特征，包括橙褐色的下部和上部的黑色条纹图案，白色臀部，通过眼睛的垂直黑色线条以及明显的‘Y’形胸部标记。其分布范围广泛，栖息在干旱、开阔的内陆地区。","appearance":"澳洲小嘴鸻体长19至23厘米，翼展43至47厘米，体重64至107克。特征包括一条非常显眼的黑色垂直眼线延伸至头顶，‘Y’形胸带延续到颈后，淡栗色下部，带有深栗色边缘和白色下腹部，薄白眼环，下翼显著的丰富红棕色。性别相似。非繁殖季节几乎失去眼线和胸带，幼鸟类似非繁殖季节的成鸟，仅显示出暗色面部和颈圈的痕迹。","call":"通常被认为不是很爱鸣叫，但在被惊扰时会发出安静、粗哑的‘kr-root’声，以及快速而有时重复的‘quick’声以保持联系或警报。","habits":"主要生活在平坦、开放的干旱地区，偏好20至40厘米高的盐灌木、蓝灌木或盐碱草丛生的环境，常在内陆公路旁活动。日间较不活跃，但能耐受高温；夜间在道路上寻找昆虫。饮食包括种子、叶子、昆虫和蜘蛛，白天偏草食，夜晚偏肉食。","breeding":"繁殖行为了解不多，但似乎全年都可繁殖，对雨水反应。可能为一夫一妻制。单独或以最多六对的小松散群体繁殖。巢筑在裸露的石质或沙地上，浅坑或凹陷处，可能铺垫小石子、植物材料和碎片。每窝产卵三枚，有时两枚，孵化期26至30天，可能由双亲共同孵化，但主要由雌鸟承担。成鸟离开巢时会迅速用土和碎屑覆盖卵。","identification":"与其他鸟类区别明显，尤其是其独特的黑眼线和‘Y’形胸带。幼鸟与非繁殖季节的成鸟相似，缺乏明显的暗色标记。","protection":"IUCN：LC（无危）。总数量估计约14,000只，分布广泛且相对不受人类影响，似乎相当安全。存在于昆士兰州的Diamantina国家公园。偶尔因夜行撞上围栏而死亡。","distribution":"分布于澳大利亚内陆，包括西南部、南部和东部（除塔斯马尼亚州和北部部分区域）。","other":"在极端干旱或大雨后，可能会出现迁移现象，具体取决于降雨和干旱情况。"},{"name":"弯嘴鸻","english_name":"Wrybill","scientific_name":"Anarhynchus frontalis","overview":"弯嘴鸻（英文名：Wrybill，学名：Anarhynchus frontalis），是鸻形目鸻科弯嘴鸻属的鸟类。仅见于新西兰，当地毛利人称之为Ngutuparore。拥有独特的向右侧弯曲的黑色长喙，用于探觅石头下的无脊椎动物。繁殖期雄鸟胸前有明显的黑色环带，雌鸟的环带较窄且颜色较淡。分布于新西兰南岛的坎特伯雷和奥塔哥地区的大型河流河床。","appearance":"弯嘴鸻体型小巧，长度介于20至21厘米，重量在43至71克之间。上身呈灰色，下身白色，雄鸟头部有白色额头和浅灰色顶部，繁殖季节时胸前有黑色环带，雌鸟的环带较细。最显著的特征是其黑色的喙，自然向右弯曲约20度，使其能在石头下或泥地中寻找食物。","call":"发出类似‘weet’或‘peep’的叫声，群聚时偶尔会发出叽叽喳喳的声音。","habits":"栖息于新西兰南岛的大型辫状河流，偏好动态的砾石河床。冬季迁徙至北岛的港湾和河口，常见于泰晤士湾和马努卡乌港。白天活动，以昆虫幼虫和其他水生无脊椎动物为食，有时也会捕食小型鱼类。","breeding":"繁殖季节为8月至10月，有时会二次筑巢。单配制，长期保持伴侣关系。在大石头和沙子中筑巢，每窝产两枚蛋，孵化期30至36天，幼鸟在35至37天后离巢独立。","identification":"与其他鸻科鸟类相比，弯嘴鸻最显著的区别是其向右侧弯曲的喙。雄鸟在繁殖期有明显的黑色胸带，而雌鸟的胸带更细且颜色较淡。","protection":"IUCN：VU（易危）","distribution":"繁殖于新西兰南岛的坎特伯雷和奥塔哥地区，冬季迁徙至新西兰北岛北部，尤其集中于泰晤士湾和马努卡乌港。","other":"历史上曾因奇特的弯曲喙被猎捕作为标本，自1940年得到保护后，数量从约2000只增加到现在的5000只左右。"},{"name":"新西兰鸻","english_name":"New Zealand Plover","scientific_name":"Anarhynchus obscurus","overview":"新西兰鸻（英文名：New Zealand Plover，学名：Anarhynchus obscurus），是鸻形目鸻科弯嘴鸻属的鸟类。大型鸻，体型较大，分布于新西兰北岛沿海北部和斯图尔特岛山区。其上部呈淡灰褐色，下部在非繁殖季节为白色至米白色；繁殖季节时，下部会变成不同程度的橙红色。南部亚种比北部亚种更大、更暗，红色面积更广。","appearance":"新西兰鸻体长26-28厘米，体重128-169克，翼展46-50厘米。体羽上部棕色，羽缘较浅；额头白色，下体白色，眼周有一条深色线。繁殖期成鸟下体变为红褐色，雄鸟整年胸部略红，但非繁殖期两性相似；喙黑色，腿和脚灰至中灰色，眼睛深棕色。幼鸟上部颜色更深，下体泛淡橙色，并有胸侧暗斑。非繁殖期成鸟与幼鸟外观相似，但幼鸟保留幼羽，部分个体在繁殖季会获得一些红色下体，但不及成鸟鲜艳。整体上，幼鸟色彩较淡，上部更灰，下体红度较低，几乎所有测量值都小于原属种Charadrius obscurus。","call":"新西兰鸻相对安静。最常听到的叫声是短暂的芦苇般的颤音“trrrt”，有时重复两次。也会发出上升的“tweet”。在繁殖地，可能的领域或防御叫声是芦苇般的‘chweerrrr-whreet’或‘chweeeerr-whrrrr’。","habits":"新西兰鸻栖息于沙滩、沙洲、壳滩、沙丘；偶尔出现在石滩、沉积池和短草牧场，包括高尔夫球场甚至路边草地。它们在沙滩、沙洲、壳滩或沙丘上筑巢，偶尔在石滩、短草牧场或人造场所。它们在白天和夜晚觅食，主要食物包括软体动物、甲壳动物、跳虫、小蟹、昆虫（如蚱蜢、蟋蟀、鞘翅目、潜蝇、蛾子）和小鱼。在潮汐河口觅食，受潮汐周期支配。","breeding":"新西兰鸻在8月末至1月初产卵，首次产卵通常在8月末至9月，有时会尝试多达三次替代巢。一夫一妻制，全年保持配偶关系。巢通常位于海滩、贝壳堆或沙洲，偶尔在砾石或石质海滩，有时相隔仅7米。每窝2-3枚蛋，罕见4-6枚，可能是两个雌鸟在同一巢中产卵的结果。蛋孵化后，幼鸟具有黄白色的绒毛，上面带有黑色、棕色和黄色的标记，孵化后28至52天离巢，之后可能继续与成鸟共同生活数日到数月。管理下的繁殖成功率高于未管理的栖息地。","identification":"新西兰鸻与Charadrius obscurus的区别在于体型较小、颜色较淡，上体更灰，下体红度较低，以及在繁殖季时下体的颜色差异。南方亚种与北方亚种在大小、颜色和红色覆盖面积上有明显区别。","protection":"IUCN：NT（近危）","distribution":"新西兰北岛沿海北部，特别是在东海岸，以及斯图尔特岛山区。在西海岸稀疏分布，从塔哈罗阿向北至北角，少数在塔拉纳基。83%的种群分布在北角至东角之间的东海岸。2012年，最南端的繁殖记录在北瓦拉拉帕的里弗斯代尔。","other":"新西兰鸻的当前种群数量严重依赖于管理措施，如果停止密集管理，可能会立即显著减少。最大的威胁是外来捕食者，住房开发和稳定沙丘的杂草入侵减少了栖息地，而牲畜、人类、狗和车辆的干扰影响了筑巢成功率。"},{"name":"厚嘴鸻","english_name":"Wilson's Plover","scientific_name":"Anarhynchus wilsonia","overview":"厚嘴鸻（英文名：Wilson's Plover，学名：Anarhynchus wilsonia），是鸻形目鸻科弯嘴鸻属的鸟类。与海岸紧密相关的中型鸻科鸟类，以厚重的黑色喙和较大的体型著称。其分布广泛，从美国东海岸的弗吉尼亚州向南延伸，横跨墨西哥湾、加勒比海，直至巴西西北部，以及从下加利福尼亚南部沿太平洋海岸至北秘鲁。主要栖息于盐分较高的地带，如潮间带海滩、沙丘区和泻湖边缘。","appearance":"厚嘴鸻是一种中等体型的鸻科鸟类，总长度介于165至200毫米之间，翼展111至128毫米，体重约55至70克。其显著特征是全黑色的厚重喙，灰褐色的上体，白色的下体，以及黑色至棕褐色的胸带。腿和脚呈粉灰色至粉色。繁殖期成鸟的灰褐色背部颜色介于淡色的笛鸻和深色的半蹼鸻之间。雄鸟的胸带、眼上纹和前额为黑色，而雌鸟则为灰褐色带红棕色调。地理变异导致外观差异，如西印度群岛和南美洲的繁殖个体头部和胸带更显红棕色，太平洋沿岸的个体上体颜色更深，前额和眉线白色较少，胸带较窄，雌鸟头部和胸带上的红棕色更明显。","call":"鸣叫为尖锐的哨音。","habits":"厚嘴鸻栖息于沿海沙滩和沙洲，通常单独或形成松散的小群。它们偏好在中低纬度的沿海地区活动，冬季部分种群会迁徙至巴西南部避寒。主要以甲壳类动物为食，如招潮蟹，同时也吃昆虫、蠕虫和其他无脊椎动物。","breeding":"繁殖期在春季至夏季，筑巢于沙质或石质裸露地面的浅坑中。成鸟在繁殖季节保卫领地，非繁殖季节则聚集在一起休息和觅食。求偶、筑巢、交配、产卵、孵化和育雏的详细信息尚未充分了解。","identification":"与相似的领鸻相比，厚嘴鸻具有更大、更重的全黑色喙和粉色的腿。半蹼鸻体型较小，背部颜色更深，喙短而钝，呈双色，腿部橙黄色；笛鸻体型较小，背部颜色更淡，腿部橙色，喙短而钝；雪鸻体型较小，背部颜色更淡，腿部暗色，喙较细长；双领鸻体型相似，但具有双胸带；铁嘴沙鸻体型和喙大小相似，但缺乏厚嘴鸻所有羽衣中明显的白色颈圈。","protection":"IUCN：LC（无危）","distribution":"分布于北美、中美和南美的温带至热带沿海地区，从美国东海岸至加勒比海，巴西中东部和秘鲁。在美国，主要在东海岸和墨西哥湾沿岸繁殖，冬季部分种群南迁至巴西。","other":"在北美的种群监测数据显示厚嘴鸻的数量正在下降，分布范围也在缩小。城市化和人类活动导致的海滩生境丧失是其面临的主要威胁之一。此外，气候变化引起的海平面上升也对其构成了威胁。"},{"name":"黑斑沙鸻","english_name":"Madagascar Plover","scientific_name":"Anarhynchus thoracicus","overview":"黑斑沙鸻（英文名：Madagascar Plover，学名：Anarhynchus thoracicus），是鸻形目鸻科弯嘴鸻属的小型鸟类。其特征为背部褐色，腹部淡色，拥有醒目的黑色胸带，以及独特的头部条纹图案。马达加斯加特有种，主要分布于岛的西部和南部沿海地带。偏好开阔的短草草原和邻近的海滨泥滩栖息。","appearance":"黑斑沙鸻体型小，成年体重约31-43克，雌雄羽毛相似但雌鸟略重且翼展更宽。繁殖期具有一条黑色过眼线和环绕颈部的黑色胸环，其余头部白色，背部灰褐，下腹部泛黄色，尾部中央两羽灰色，外侧较浅具暗色末端和白色尖端。喙、腿和眼睛在繁殖季节呈黑色，非繁殖季节整体色泽变淡。幼鸟下喙基部黄绿色，逐渐转为黑褐色，腿色较淡，胸带模糊。","call":"其叫声包括连续的中高音‘pip’，每2-3秒一次，以及快速重复3-6次的‘pipipipreeeet’单音节，伴随短暂颤音。还有‘twitwitwi’和‘簇胸吸蜜鸟或‘twiz’的嘶哑声用于示警，幼鸟会发出‘tsick’声以引起父母注意。","habits":"常在海岸牧场草地、盐水沼泽边缘和浅水池塘附近活动，偶尔出现在沙滩和河口泥滩。以昆虫为主食，可能也会摄食蜘蛛、蠕虫、软体动物等。通常与其他滨鸟如环颈鸻、剑鸻和白腰燕鸻共同出现。","breeding":"繁殖期主要在8月至次年5月，高峰期为12月至翌年4月。偏好在开阔草地和干燥泥滩筑巢，靠近红树林和碱性湖泊。每次产卵1-2枚，平均孵化期26-28天，由双亲轮流孵卵。雏鸟出生时重约7克，30-37天后可离巢飞翔，再过1-5天即可独立。","identification":"与基氏沙鸻的区别在于具有明显的胸带，比普通环颈鸻小且色彩更淡，头纹更为复杂。雌雄虽羽毛相似，但可通过体重和翼展差异辨认。","protection":"IUCN：VU（易危）","distribution":"分布局限于马达加斯加岛的西部和南部沿海地带，从西北部的Boanamary至东南部的Tapera。偶尔在东海岸有记录，内陆记录罕见。","other":"种群数量估计在1800-2300只成熟个体，或总共3100只左右，面临持续下降的趋势。主要威胁来自栖息地丧失和退化，如虾塘开发和稻田扩张。"},{"name":"基氏沙鸻","english_name":"Kittlitz's Plover","scientific_name":"Anarhynchus pecuarius","overview":"基氏沙鸻（英文名：Kittlitz's Plover，学名：Anarhynchus pecuarius），是鸻形目鸻科弯嘴鸻属的鸟类。小型鸻科鸻属涉禽，分布广泛，遍及非洲的撒哈拉以南内陆地区（除中部）、尼罗河谷至尼罗河三角洲，以及马达加斯加岛。其独特头部图案，黑眼线和黑额纹，使其在众多鸻类中脱颖而出。","appearance":"基氏沙鸻体型小巧，重约35-40克，背部呈棕色，腹部颜色较淡。头部特征显著，有一条黑色条纹穿过眼睛延伸至颈部，另一条黑色条纹横跨额头。繁殖季节，雄鸟头部的黑色条纹更为明显，额头白色，上背暗灰褐色，下背和翅膀边缘带沙色。脸部、下巴和上喉部为白色，其余下体呈现黄色调，腹部淡色。雌鸟外观与雄鸟相似，但前额的黑色条纹较窄。非繁殖季，眼纹颜色变浅，前额条纹消失，下体颜色变淡。幼鸟与成鸟类似，但缺乏面部黑色标记，上体呈棕色，颈后环带为肉桂色，下体白色。","call":"基氏沙鸻的叫声包括‘pipip’、‘towhit’、‘tit-peep’、‘trit-tritritrit’、‘perrup’和‘kich-kich-kich’。遇险或被惊扰时发出报警声，如‘chirrt’、硬‘trip’、‘tric’、‘prrrt’或哀怨的‘pip-ip’。打斗时，雄鸟会发出刺耳的叫声，当假装受伤时，它们发出‘cheep-cheep’声，父母邀请幼鸟归巢时发出‘chip-chip’声，警告幼鸟时则发出‘trr-trr’声。幼鸟的叫声为尖细的‘peep’。","habits":"基氏沙鸻偏好低海拔的开阔地带，如靠近水源的干燥地面，通常在湖泊、盐沼、河流、潮间带泥滩或内陆盐沼以及人造水域活动。它们在月光之夜也会觅食，单独或结成2-5只的小群体，有时与其他小型涉禽混群。主要以昆虫、昆虫幼虫、蜘蛛、小型甲壳类和软体动物为食，表现出典型的跑停搜索觅食行为，有时会用脚震动地面吸引猎物。","breeding":"基氏沙鸻全年均可繁殖，但在不同地理区域存在繁殖高峰差异。一窝产卵1-3枚（通常为2枚），间隔1-2天产一枚。卵为椭圆形，暗灰褐色，带有黑色斑点。双亲共同孵卵，孵化期为21-27天。孵化成功率为16%-77%，每对亲鸟平均成功抚养0.5到<2只幼鸟。幼鸟出生后不久即能自行觅食，由一位亲鸟带领至远离巢穴的觅食区，直至26-32天左右能够飞行。。全年均可繁殖，但在不同地理区域存在繁殖高峰差异。一窝产卵1-3枚（通常为2枚），间隔1-2天产一枚。卵为椭圆形，暗灰褐色，带有黑色斑点。双亲共同孵卵，孵化期为21-27天。孵化成功率为16%-77%，每对亲鸟平均成功抚养0.5到<2只幼鸟。幼鸟出生后不久即能自行觅食，由一位亲鸟带领至远离巢穴的觅食区，直至26-32天左右能够飞行。。","identification":"基氏沙鸻与白胸鸻（Charadrius thoracicus）在形态上有显著差异，没有胸带，腿稍长，色彩更鲜艳。与圣赫勒拿鸻（Charadrius sanctahelenae）相比，体型较小，腿较短，下体颜色更亮丽。雌雄鸟大小相似，但雌鸟下体颜色略浅，前额的黑色条纹较窄。","protection":"IUCN：LC（无危）","distribution":"基氏沙鸻广泛分布于撒哈拉以南非洲内陆（除中部）、尼罗河谷至尼罗河三角洲，以及马达加斯加岛。在南非较为常见，但在博茨瓦纳和纳米比亚的干旱地区较为罕见。马达加斯加岛上也有分布，估计数量在10,000-20,000只之间，使其在当地相对常见。","other":"基氏沙鸻适应了人造水坝和其他改造栖息地，至少在某些地区如此。"},{"name":"圣岛沙鸻","english_name":"St. Helena Plover","scientific_name":"Anarhynchus sanctaehelenae","appearance":"体长约15厘米，与Charadrius pecuarius相似但体型更大，喙与细长的腿（最长可达40%）更为突出。胸部和背部羽毛边缘少有淡黄色。两性外观相同，无季节性变化。幼鸟头部图案模糊，无黑色区域，顶羽和背部羽毛边缘呈淡棕色。","call":"主要叫声为短促柔和的'kee-vit'声，飞行时发出类似颤音的鸣叫。","habits":"常驻于圣赫勒拿岛，年轻个体可能在岛上广泛游荡。偏好炎热石质平原、线草丛生地和侵蚀区的卡菲尔无花果地带，亦可见于牛群放牧过的高地牧场、耕作田地、偏远蔬菜园，从未出现在海岸。食性不明，已知以昆虫和蜗牛为食。","breeding":"繁殖期主要在干燥季节，从9月末至次年1月，尤其集中在12月至1月，受条件影响可能每年略有变动。筑巢于岛屿北部的开阔平原，推测为独居一夫一妻制。巢穴简单，以干草或牛粪铺垫。产卵1-3枚，灰色带深色斑点，孵化期约28天，由双亲共同承担，雄鸟主要在夜间孵化。雏鸟5周左右离巢，通常留在巢域。","identification":"与Charadrius pecuarius相比，圣赫勒拿沙鸻更大，喙和腿更长，胸部和背部羽毛边缘颜色更淡，头部黑色线条在颈背处不相接。叫声与C. pecuarius相似。","protection":"IUCN：VU（易危）","distribution":"仅分布于南大西洋的圣赫勒拿岛，特别是在北部较平坦的内陆地区。","other":"自1894年起，圣赫勒拿岛上所有鸟类均受法律保护。"},{"name":"白额沙鸻","english_name":"White-fronted Plover","scientific_name":"Anarhynchus marginatus","overview":"白额沙鸻（英文名：White-fronted Plover，学名：Anarhynchus marginatus），是鸻形目鸻科弯嘴鸻属的鸟类。小型鸻科鸟类，分布于撒哈拉以南非洲沿海和内陆地区以及马达加斯加。栖息于沙滩、沙丘、河湖岸线、泥滩和岩石海岸，偏好在高水位线附近的沙地筑巢。成鸟重约45-50克，具有独特的白色前额和黑色眼后纹。雌雄差异细微，雄鸟的黑色冠带更明显。","appearance":"白额沙鸻体长约18厘米，体重介于27至55克之间，存在个体和种族变异。上体颜色从赤褐色到灰褐色不等，下体纯白至泛奶油色或赤褐色。面部平实，有显著的白色额头和锐利的黑色眼后纹。雌鸟与雄鸟相似，但黑色区域较淡，胸部赤褐色可能更淡或缺失。非繁殖季节雄鸟似雌鸟，但黑色替换为棕色；非繁殖季节雌鸟有时会失去黑色额纹。幼鸟缺乏黑色额纹，上体有缓冲色边缘，下体白色。","call":"主要的叫声为低沉的短‘pwut’或‘prrut’声，以及干燥的颤音‘trrrr’。此外，还有哀婉的‘pi-peep’声。繁殖季节追逐入侵者时发出喘息的哨声‘rroweee...rrroweee...’，或是干涩的叽喳声和尖锐的音符。雏鸟向成鸟发出尖锐的‘tsick’声，而成鸟鼓励雏鸟进食时则发出间隔较大的‘tick...tick...tick’声。","habits":"白额沙鸻偏好沙滩环境，也出现在泥滩、河岸和其他湿地。它们通常沿海岸分布，偶尔在内陆局部出现。迁徙模式复杂，部分内陆群体迁往东海岸（南至东开普），当河流泛滥时（12月至5月）。以昆虫、软体动物、甲壳类和蠕虫为食，通过探查、啄食、脚震等方式捕食。白天和月光下的夜晚活动，成对或小群觅食，非繁殖季节偶尔形成大群。","breeding":"白额沙鸻在2月至9月间繁殖，具体时间随地理位置而异。通常是季节性一夫一妻制，伴侣关系可维持多年，年离婚率约为10%。巢为浅坑，位于沙地高水位线附近，有时铺垫石头、贝壳碎片、干海藻或树枝。每窝通常产两枚蛋，孵化期26至33天，由双方共同承担。雏鸟孵化后35至38天离巢，家庭群可能再一起2至3个月。","identification":"与砂鸻相比，体型较小，具有白色颈圈。比红胸鸻明显更小。面部更平实，与基特尔茨鸻不同。短、直、厚的鸻喙使其区别于所有沙鸻。种族间色彩差异大，但均在个体变异范围内。","protection":"IUCN：LC（无危）","distribution":"撒哈兰以南非洲沿海和内陆地区，以及马达加斯加。在南非沿岸普遍存在，也见于大型湖泊和河流附近。马达加斯加的繁殖群体遍布所有海岸，也有内陆分布。","other":"白额沙鸻的寿命平均为7.5年，最长可达9年以上。其全球数量估计在66,000至90,000只之间，尽管总体数量呈下降趋势，但下降速度并不令人担忧。"},{"name":"环颈鸻","english_name":"Kentish Plover","scientific_name":"Anarhynchus alexandrinus","overview":"环颈鸻（英文名：Kentish Plover，学名：Anarhynchus alexandrinus），是鸻形目鸻科弯嘴鸻属的鸟类。中小型鸻科鸟类，以其独特的后颈白色领圈而得名。分布广泛，从欧亚大陆到非洲，栖息于海滨沙滩、盐碱湿地和内陆湖泊等地。繁殖季节，雄鸟具有黑色头饰和胸带，雌鸟颜色较淡。全球数量众多，但在某些地区面临栖息地丧失的威胁。","appearance":"体长15-17.5厘米，体重32-56克，翼展42-45厘米。特征为淡色羽毛，具断裂状黑色颈环，背部呈沙色，腿灰色，喙细长黑亮。繁殖期雄鸟头部有黑色条纹，胸部两侧有黑色斑块，而非繁殖期黑色部分变为棕色。雌鸟的黑色部分替换为棕至深棕色，体型略小于雄鸟，但差异不易察觉。幼鸟类似淡色繁殖期雌鸟，有淡黄色边缘的背部羽毛。","call":"叫声包括短促柔和的‘pit’声或双重‘pidup’声，有时结合短颤音，以及哀怨的上升调‘wheet’或‘toeeet’声。繁殖地声音包括粗糙的鸣叫，‘dree-dree-dre-dridridri’，沙哑的哨声‘prrrorrr’，以及低沉的腹语式气泡颤音。","habits":"主要栖息于海岸沙滩、泥滩、盐田及近水的开放地带，偏好砂质或干泥表面，避开岩石或崎岖地面。快速适应新形成的适宜栖息地，如采石场和水库。以昆虫、甲壳类、软体动物和蜘蛛为主食，通过震动脚爪觅食，或在湿沙和泥地中探查。迁徙期间可能高达98%的日间低潮时间用于觅食。","breeding":"繁殖期为4月至7月，营巢于海滨沙滩或附近沼泽湿地，巢由小石子、贝壳碎片和植被组成。每窝产卵2-5枚，多为3枚，孵化期约24天。雏鸟早熟，出生后不久即可跟随父母活动。","identification":"与相似物种区别在于后颈的白色领圈，胸部黑色斑块，以及黑色额冠和眼线。雌鸟头部黑色部分替换为棕色至深棕色。与马来鸻相比，羽色更单调，脚色偏粉红。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚、非洲沿海及内陆南部至亚洲东北部，迁徙至撒哈拉以南、中西部至非洲中东部、中国东部、印尼群岛和菲律宾。在中国大陆，繁殖于福建、海南，越冬于东南沿海。","other":"分拆白脸鸻独立成种。"},{"name":"雪鸻","english_name":"Snowy Plover","scientific_name":"Anarhynchus nivosus","overview":"雪鸻（英文名：Snowy Plover，学名：Anarhynchus nivosus），是鸻形目鸻科弯嘴鸻属的鸟类。小型的鸻科弯嘴鸻属鸟类，以其独特的繁殖系统和濒危状态而闻名。广泛分布于美洲的海岸线和内陆盐湖边，尤其在北美的太平洋沿岸和墨西哥湾地区。雪鸻拥有淡褐色的上体和白色的下体，最显著的特征是在繁殖季节雄鸟头部的黑色斑块和耳侧斑点。","appearance":"雪鸻体长15-17厘米，体重34-58克，具有一双相对长的灰色至黑色腿。繁殖季节的雄鸟具有明显的黑色冠纹、耳羽和颈侧斑块，雌鸟的这些部位可能呈现棕色或黑色。雌雄个体在非繁殖季节外观相似，主要区别在于繁殖季节雄鸟的鲜艳标记。幼鸟的上体有棕色到黑色的斑点，下体白色。","call":"雪鸻的典型叫声是一连串重复的“tu-wheet”，这种叫声在多种情境下发出，包括领土宣告、求偶、威胁和警报。","habits":"雪鸻栖息于开阔的沙滩和盐湖岸边，偏好植被稀少的环境。它们以沙中的无脊椎动物如甲壳类、蠕虫、甲虫和苍蝇为食，通过视觉搜索和快速移动来捕捉猎物。雪鸻在日间和夜间都可能觅食，能够适应淡水和咸水环境。","breeding":"雪鸻实行一种罕见的多配偶制，雌鸟在幼鸟孵化后不久会离开，寻找新的伴侣再次繁殖。雄鸟负责照顾幼鸟。它们在沙地上挖掘巢穴，每窝通常产三枚卵，孵化期23-49天。幼鸟出生后几小时就能行走和游泳，由父母带领至觅食区。","identification":"雪鸻与管道鸻、项圈鸻、半蹼鸻和威尔逊鸻在外形上有明显区别，可通过其细长的全黑喙、灰色至黑色的腿以及独特的“断开”的颈带进行区分。","protection":"IUCN：NT（近危）","distribution":"雪鸻繁殖于北美华盛顿州沿海至墨西哥下加利福尼亚州中部，内陆从萨斯喀彻温省至美国加州和德克萨斯州中部，墨西哥湾沿岸至尤卡坦半岛，墨西哥内陆中部，巴哈马南部至维尔京群岛，以及秘鲁至智利中南部。在中美洲北部沿海为非繁殖区。","other":"雪鸻因其栖息地破坏、人类干扰和入侵物种的影响，数量正在减少，特别是在北美的太平洋沿岸和大平原地区。保护措施包括划定保护区、控制捕食者和恢复栖息地，这些努力在某些地区已取得局部成功。"},{"name":"爪哇鸻","english_name":"Javan Plover","scientific_name":"Anarhynchus javanicus","overview":"爪哇鸻（英文名：Javan Plover，学名：Anarhynchus javanicus），是鸻形目鸻科弯嘴鸻属的鸟类。小型涉禽。分布于印尼南部苏门答腊沿海、爪哇岛、巴厘岛、小巽他群岛及苏拉威西岛西部。其独特的特征包括棕色上部与白色下部，以及整洁的白色颈环、前额和眉纹。繁殖期成鸟有橙色耳后斑块，腿色较淡。与环颈鸻相似，但可通过其耳后暖棕色斑块、繁殖期冠部无橙色及较淡的腿色加以区分。","appearance":"相对较小的普通鸻，上部呈棕色，下部为白色，具整洁的白色颈环、前额和眉纹。繁殖期成鸟在耳后和颈环周围有橙色色调。幼鸟与非繁殖期成鸟相似，但上部羽毛边缘呈淡色。腿色较淡，喙较长且钝厚基部。头部图案为椭圆形，叫声柔和上升。","call":"发出柔和上升的‘kweek……kweek’声或单个‘kweek’声，以及软弱上升的‘tu-wit’声，用于吸引人类远离幼鸟或带蛋的巢穴。","habits":"栖息于沿海低地的沙滩、鹅卵石海滩及内陆鱼塘，有时可达30公里内陆。以螃蟹为食，采用典型的Charadrius小型鸻类捕猎方式。","breeding":"繁殖季节主要在5月至8月，但在4月末已有雏鸟记录。在东爪哇，繁殖季期间会攻击白额燕鸥的幼鸟和成鸟。蛋壳颜色为浅黄褐色至深橄榄奶油色，布满非常不规则的黑色或近乎黑色的标记。","identification":"与环颈鸻的区别在于耳后暖棕色斑块，繁殖期冠部无橙色，腿色较淡。与马来鸻相比，后者上部羽毛边缘总是白色，头部有暖色调。","protection":"IUCN：LC（无危）","distribution":"分布于印尼南部苏门答腊沿海、爪哇岛、巴厘岛、小巽他群岛东部直至帝汶岛，以及苏拉威西岛西南部。在爪哇岛南岸的马杜拉岛、阿拉斯普尔沃国家公园和爪哇北岸的多个地点较为常见。","other":"目前全球数量估计不超过6000只，可能因近期数据而需列为易危物种。"},{"name":"红顶鸻","english_name":"Red-capped Plover","scientific_name":"Anarhynchus ruficapillus","overview":"红顶鸻（英文名：Red-capped Plover，学名：Anarhynchus ruficapillus），是鸻形目鸻科弯嘴鸻属的鸟类。小型鸻科鸟类，以其独特的红褐色头顶和灰白色的下体著称。分布广泛，主要见于澳大利亚及其塔斯马尼亚州，偶尔在新西兰也有记录。红顶鸻与环颈鸻、爪哇鸻及白额沙鸻亲缘关系密切。","appearance":"红顶鸻体型小至中等，体长约为14至16厘米，翼展27至34厘米，体重介于27至54克之间。其特征为白色下体和灰褐色背部，头部有显著的红褐色帽状羽毛，雌鸟的冠部略显淡灰褐色。非繁殖季节的个体颜色较暗，红褐色特征减弱。幼鸟头部背面有变色痕迹，上体羽毛边缘呈淡黄色。","call":"红顶鸻较为安静，常见叫声为短促的\"pit\"或更硬的\"prit\"声，有时会连续快速发出。此外，也会发出哀怨的哨音\"toeeet\"和低沉的颤音。整体叫声与C. alexandrinus相似，但其完整的发声范围仍有待研究。","habits":"红顶鸻栖息于各种盐水湿地环境，偏好沿海的沙滩和附近泥泞或沙质的滩涂，尤其喜欢盐沼和盐田等咸水湿地。它们也出现在内陆湿地的开阔地带，如盐湖和人工湿地，包括污水池和盐场。红顶鸻会根据洪水、干旱和食物供应的变化，在内陆湿地和海岸间迁移，通常全年都能在多个地点找到它们，数量随季节变化，夏季沿海数量增多。","breeding":"红顶鸻在沿海地区繁殖季节为7月至次年1月，内陆繁殖则受不可预测的降雨和洪水影响。它们可能单独或形成松散的群落繁殖，巢建于沙地、贝壳碎片、泥沙或海藻中，巢穴浅且可能由贝壳碎片、石子、植被和杂物衬垫。通常产卵2枚，偶尔3枚，孵化期约30至31天，主要由雌鸟在白天孵化，雄鸟夜间接替。雏鸟孵化后立即活动，由双亲共同照顾。","identification":"红顶鸻与号声扇尾莺、C. alexandrinus、C. dealbatus、C. nivosus和C. javanicus关系密切，但可通过头部的红褐色帽状羽毛、体色和分布地区加以区分。幼鸟与非繁殖期成鸟的特征有所不同，主要体现在红褐色痕迹的缺失和上体羽毛的淡黄色边缘。","protection":"IUCN：LC（无危）。红顶鸻总数量约95,000只，广泛分布于澳大利亚和塔斯马尼亚。帝汶岛有一小群繁殖种群，可能也在附近的印尼罗提岛和塞毛岛上出现。通过在巢周围设置防捕食者围栏，繁殖成功率显著提高。","distribution":"繁殖区主要位于澳大利亚内陆和沿海地区，包括塔斯马尼亚州，以及帝汶岛（小巽他群岛东部）。非繁殖期间，它们可能会迁徙至爪哇岛东部。在中国大陆地区，红顶鸻为旅鸟，迁徙期间几乎遍及全国。","other":"红顶鸻曾于1950至1980年间在新西兰小规模繁殖。沿海栖息地可能受到低密度住宅开发的威胁。"},{"name":"马来鸻","english_name":"Malaysian Plover","scientific_name":"Anarhynchus peronii","overview":"马来鸻（英文名：Malaysian Plover，学名：Anarhynchus peronii），是鸻形目鸻科弯嘴鸻属的鸟类。小型涉禽，体重约35至42克，常见于东南亚的沙滩和盐滩。其显著特征包括细窄的颈部带纹，雄鸟呈黑色，雌鸟为赤褐色，以及独特的苍白腿脚。在中国有记录，但具体地点不明。马来鸻被列为近危物种。","appearance":"马来鸻长约15厘米，具有短嘴。雄鸟有明显的细黑颈环，雌鸟则是较淡的赤褐色领环。与环颈鸻相比，马来鸻拥有完整的白色颈环，且耳斑不会与过眼线相接。虹膜呈褐色，嘴部黑色，腿灰色。雌雄差异在于雌鸟的黑色部位比雄鸟更显赤褐色，有时带有黑色斑点，冠部赤褐色较少。幼鸟外观类似雌鸟，但胸部斑块从未有黑色斑点。","call":"马来鸻发出轻柔的'kwik'声，与环颈鸻的叫声相似。","habits":"马来鸻成对活动于沙滩，偏好小海湾中的珊瑚沙滩，不混群。它们主要栖息在东南亚沿海地区的沙滩上，包括泰国南部、马来半岛、柬埔寨南部、越南南部到苏门答腊、婆罗洲、菲律宾、苏拉威西岛和巴厘岛，直至帝汶岛。马来鸻基本上是留鸟，但在马来西亚半岛的西南海岸，非繁殖季节会有轻微的分散现象。它们依赖于Scopimera globosa蟹作为主要食物来源，常在低潮时于潮间带觅食，靠近水边。马来鸻经常成对觅食，偶尔会形成多达27只的小群体。","breeding":"马来鸻的繁殖期从2月底持续到7月，主要在5月于吕宋岛（北菲律宾）和泰国湾发现繁殖活动。雏鸟在3月中旬至6月中旬期间被观察到，刚孵化的幼鸟在6月的苏门答腊岛上发现，依赖的幼鸟在1月的廖群岛和10月的婆罗洲被记录。马来鸻是独居和一夫一妻制的，具有高度的巢址忠诚度，连续的窝巢距离仅10米，平均约60米。它们通常双窝繁殖，尤其是在泰国，没有证据显示整个繁殖季节中窝巢大小和繁殖成功率有差异。巢穴位于海滩高处，缺乏植被覆盖，通常有三枚蛋，颜色为奶油色至淡石色，带有黑色、棕色和薰衣草灰色标记。幼鸟在27至33天后离巢。","identification":"马来鸻与环颈鸻非常相似，但可以通过更细的颈环和眼线来区分，以及独特的苍白羽缘，使鸟看起来磨损褪色。雌鸟和幼鸟的白色颈环和面部特征也用于识别。马来鸻的叫声与环颈鸻相似，但有其独特的音调。","protection":"IUCN：NT（近危）","distribution":"马来鸻分布于泰国南部、马来半岛、柬埔寨南部、越南南部至苏门答腊、婆罗洲、菲律宾、苏拉威西岛和巴厘岛，直至帝汶岛。在中国大陆，虽有记录但具体地点不详。在廖群岛、苏门答腊和婆罗洲均有发现。","other":"马来鸻的总数量可能不足10,000只，且可能正在减少，但由于数据稀缺，没有准确的估计。亚洲水鸟普查中最高的总数是在1992年记录的410只。"},{"name":"栗斑鸻","english_name":"Chestnut-banded Plover","scientific_name":"Anarhynchus pallidus","overview":"栗斑鸻（英文名：Chestnut-banded Plover，学名：Anarhynchus pallidus），是鸻形目鸻科弯嘴鸻属的鸟类。小型鸻科鸟类，以其独特的胸带著称。分布于非洲南部及东部沿海地区，偏好盐湖与人工盐田环境。","appearance":"体长约15厘米，腿较长，头部前端至眼纹黑色，冠部前方及胸部有栗色带。背部与冠部灰褐色，腹部白色。雌鸟缺少黑色部分。幼鸟无栗色及黑色特征，胸部灰色带模糊，背部灰白相间。","call":"叫声为柔和的\"pit\"音，或重复的\"pidup\"和\"pididip\"，以及落地或起飞时的\"hweeet\"和\"chuck\"声。繁殖季有特殊喉音。","habits":"偏爱盐湖、碱湖及海岸泻湖，很少出现在淡水环境。随季节移动，旱季向沿海迁移。清晨活跃，单只、成对或小群活动，食谱包括昆虫与小型甲壳类。","breeding":"繁殖期横跨4月至10月，筑巢于近水边缘，通常产卵2枚，孵化与育雏期未知，雏鸟具灰色羽衣与黑色标记。","identification":"与白额沙鸻幼鸟相似，但胸带模糊，背部更冷灰。亚种venustus体型较小，喙相对较大，背部较暗。","protection":"IUCN：LC（无危）","distribution":"非洲南部和东部沿海地区，包括肯尼亚、莫桑比克、纳米比亚、南非等地。","other":"全球数量约17,800只，面临栖息地减少威胁，关键繁殖地包括纳米比亚的Walvis Bay、Sandwich Harbour以及坦桑尼亚的Lake Natron。"},{"name":"领鸻","english_name":"Collared Plover","scientific_name":"Anarhynchus collaris","overview":"领鸻（英文名：Collared Plover，学名：Anarhynchus collaris），是鸻形目鸻科弯嘴鸻属的鸟类。属于鸻科，小型的涉禽，体型约18厘米长，重约35克。广泛分布于美洲热带至温带的海岸和河岸，从墨西哥中部到智利和阿根廷。其特征包括黑色的胸带，白色的前额和棕色的背部，腿部呈黄色。","appearance":"领鸻是一种小型的滨鸟，全长约18厘米，体重25.8-42克，翼展36-39厘米。具有狭窄的黑色胸带、黑色前额条纹和眼周，上体羽毛边缘呈栗色，中央冠部有淡栗色。与C. nivosus相比，领鸻没有眼后的暗色条纹，上体颜色更深更棕色，喙相对长而细，腿呈黄褐色。雌雄相似，但雌鸟的栗色可能较少，黑色区域有时呈褐色。幼鸟无胸带，两侧有土褐色斑块，头部无黑色，背部羽缘呈浅色。","call":"领鸻相当健谈，最常听到的叫声是短促而强调的“pit”或“chit”，与厚嘴鸻类似，还有短促的颤音“pi-drr”。在兴奋时，这些音符会快速连续发出。展示飞行时，会发出重复的口吃声“pi-pi-ddddrrr...”。","habits":"领鸻栖息于沙质海滩、内陆和河口湿地、河岸和池塘，偶尔出现在开放的沙质稀树草原。已记录到海拔1500米的内陆地带。它通常是定居的，或大部分时间定居，但在某些地区，如萨尔瓦多，它被认为是稀有的迁徙鸟种，秋季在7月底至12月初出现（10月底数量最多）。在委内瑞拉内陆和巴西北海岸报告了短距离的季节性迁移。在南美洲，似乎在冬季比夏季更常见于海洋海滩。","breeding":"繁殖季节随纬度变化：墨西哥西部11月至12月；在伯利兹发现带有卵的巢穴（5月）；哥斯达黎加3月至6月；哥伦比亚南部8月和北部3月至4月；厄瓜多尔东部3月；巴西9月至12月，以及次年9月至1月间孵化的小鸟；阿根廷10月至12月中旬。巢穴通常是一个简单的无衬里的凹坑（60-80毫米宽，25-50毫米深），距离水边可达150米。巢中通常有两枚蛋，但也有单蛋和三蛋的情况。蛋呈奶油色，有黑色或咖啡色的斑点和线条。","identification":"与雪鸻相似，但后者颜色更淡，腿色较暗，且不会形成完整的胸带。Semipalmated Plovers更大，喙较粗，有浅色颈环。领鸻因缺乏浅色颈环而得名。","protection":"IUCN：LC（无危）","distribution":"广泛分布于新热带地区的沿海和河流地带：从墨西哥锡那罗亚州和塔毛利帕斯州南部（但不包括尤卡坦半岛），中美洲沿海，尼加拉瓜湖周围和巴拿马运河区；哥伦比亚北部和委内瑞拉，委内瑞拉北部岛屿，特立尼达岛，智利北部沿海和阿根廷中部。","other":"领鸻的分布范围正在智利沿岸扩张。旅游业在物种分布范围内某些地区的增长可能对其产生负面影响。"},{"name":"山鸻","english_name":"Puna Plover","scientific_name":"Anarhynchus alticola","overview":"山鸻（英文名：Puna Plover，学名：Anarhynchus alticola），是鸻形目鸻科弯嘴鸻属的鸟类。分布于南美秘鲁山区中部至玻利维亚、智利东北部和阿根廷西北部的高安第斯山脉区域。其特征明显，拥有独特的黑白色脸谱和淡栗色的冠顶、颈背与胸带。","appearance":"山鸻长约16.5至17.5厘米，体重41至49克，颈部短而粗壮，喙与腿均为黑色。成年雄鸟的脸部为白色，具有一条黑色的前额条纹和一条连接到侧胸黑色斑块的眼后条纹，头顶、颈背和胸带呈淡栗色。雌鸟较暗淡，胸带可能为灰色，黑色部位可呈棕色。幼鸟缺乏成鸟的黑栗色图案，通体较为灰褐色。","call":"山鸻通常较沉默，最常听到的叫声为短促有力的“pit”声，兴奋时会快速连续发出此类音节。展示歌曲由两声重复音符后跟一段沙哑的颤音组成，例如“pit-pit-krrrrrt...”。","habits":"山鸻栖息于高海拔的高原地带，偏好宽广的硬质泥地或黏土区域，常在盐水湖和淡水湖周围被强烈放牧的草地中活动。非繁殖季节时，它以小群活动，数量可达30只，觅食小型甲壳类动物。","breeding":"山鸻主要在9月至10月繁殖，偶尔延至1月。巢筑于矮草丛中，每窝产2至4枚蛋，蛋壳呈沙色，带有紫斑和黑色点状条纹。雏鸟上部呈淡黄色，点缀有黑色斑点。","identification":"山鸻与双斑鸻在分类上曾被视为同种，但现被视为超物种。其独特的面部图案和色彩组合使其容易与其他鸟类区分开来。","protection":"IUCN：LC（无危）","distribution":"山鸻分布于秘鲁中部山区、玻利维亚、智利东北部至阿根廷西北部的高安第斯山脉区域，海拔高度通常在3000至4500米之间，但也可见于2400至5000米的范围内。","other":"山鸻在南美洲的中南部地区较为常见，但在某些季节会向较低海拔迁移，甚至到达沿海地区。"},{"name":"双斑鸻","english_name":"Two-banded Plover","scientific_name":"Anarhynchus falklandicus","overview":"双斑鸻（英文名：Two-banded Plover，学名：Anarhynchus falklandicus），是鸻形目鸻科弯嘴鸻属的鸻类，常见于南美洲的海岸线、草原和湖边。拥有独特的外观，包括鲜明的锈色头冠和两条黑色胸带，尤其是上胸带常在福克兰群岛的个体中不完整。繁殖季节时，雄鸟颜色更为鲜艳。分布于智利、阿根廷、乌拉圭、巴西东南部和福克兰群岛。","appearance":"双斑鸻体型稍大，身长17至19厘米，体重约62至72克，具有圆胖的外观，喙和腿呈黑色。繁殖季节的雄鸟头部前方白色，脸部下方、胸部和腹部也是白色，前额有一条黑色横带，头顶和颈后为淡栗色，背部棕色。两条黑色胸带，上胸带在福克兰群岛的个体中常断裂。雌鸟的头顶颜色较暗淡，黑色部分呈现褐色，上胸带有白色斑点。非繁殖季成鸟的黑色部位变为灰色，栗色部位变为灰褐色。幼鸟与非繁殖季成鸟相似，但胸带为棕色，面部颜色更深，上体羽毛边缘呈淡黄色。","call":"最常听到的叫声是一种短促而有力的‘pit’声或更柔和的‘whit’声。展示歌曲被认为是重复的一系列2到3个温和音符后跟一个沙哑的颤音，例如‘whit-whit-whitrrrrrrt’。","habits":"双斑鸻栖息于砾石和石头海滩、沙质海滩、湿润的草原和短草地带，通常靠近溪流或淡水或咸水池塘。在非繁殖季节，也会出现在潮间带泥滩上。主要沿海岸分布，但在阿根廷南部的圣克鲁斯州，繁殖高度可达1200米。它们以小型无脊椎动物为食，包括多毛纲动物、双壳类动物、腹足类动物、昆虫和蜘蛛。","breeding":"繁殖季节大致在9月至次年1月，有时会延后，尤其是在高海拔地区。单独筑巢，巢穴简单，位于地面凹陷处，偶尔铺有少量草，经常隐藏在覆盖物下，特别是在福克兰群岛。每窝产2至4枚橄榄绿或淡黄色蛋，带有棕色或深灰色斑点，由双亲轮流孵化，孵化期间以雌鸟为主，雄鸟在夜间接替。","identification":"双斑鸻通过其独特的双黑胸带和锈色头冠与其他鸻类物种区分开来，尤其是与山鸻相比，其体型略大，喙较长，头部特征明显不同。","protection":"IUCN：LC（无危）","distribution":"繁殖区包括智利中部和南部沿海地区，阿根廷中南部、东南部，巴西局部地区，以及福克兰群岛。非繁殖季节分布至智利北部沿海和巴西东南部沿海。"},{"name":"栗胸鸻","english_name":"Double-banded Plover","scientific_name":"Anarhynchus bicinctus","overview":"栗胸鸻（英文名：Double-banded Plover，学名：Anarhynchus bicinctus），是鸻形目鸻科弯嘴鸻属的鸟类。在新西兰广泛分布，两个已知的亚种包括：指名亚种Charadrius bicinctus bicinctus，繁殖于新西兰全境，包括查塔姆群岛；以及Charadrius bicinctus exilis，繁殖于新西兰的南极圈岛屿——奥克兰群岛。","appearance":"成年栗胸鸻拥有灰褐色背部，其显著特征为白色胸部搭配一条紧贴颈部下方的黑色细带，以及其下的较大棕色带纹。繁殖季节中，雄鸟的这两条带纹尤为突出。幼鸟则不具备明显的带纹，其上体多为斑点状的棕色，白色部分较少。它们的腿相对较长，利于在浅水区活动，翅膀长而尖，适应长途飞行。头部明显，有深棕色的大眼睛和坚固的黑色喙。在适宜的栖息环境中，由于颜色相近，发现它们可能有一定难度，但其特有的\"chirp-chirp\"叫声容易辨识。","call":"最常听到的叫声是尖锐的\"pit!\"，略弱的变体为\"chit\"或\"wit\"，偶尔会发出拉长音的\"peet\"。飞行时的叫声是突然而悦耳的\"tink\"。在繁殖地的歌声是重复的低沉模糊的\"kwereep\"。在保卫领地时，会发出重复的沙哑声\"chee-a-ree\"或\"chewee-a-ree\"。","habits":"栗胸鸻主要栖息于新西兰内陆的沙砾河床，高海拔地区的干燥山地生境，以及沿海海滩、牧场、耕地、采石场和荒地。非繁殖季节时，它们广泛分布于各种沿海和淡水湿地，如河口、泻湖、沼泽、沙滩、盐湖和盐田，同时也会出现在盐沼、草地和牧场。夜间，它们倾向于聚集在传统地点休息，尤其是在难以接近的区域，如小岛、岬角和受保护的海滩。","breeding":"繁殖期自8月至12月，低地和高地繁殖时间略有差异。季节性一夫一妻制，有时延续至第二年。高度的巢址忠诚度和出生地回归特性，尤其是雄鸟。筑巢于裸露地面，通常仅铺垫少许石子、植被碎片和粪便。通常产卵3枚（2-4枚），间隔不到60至120小时产一枚；最多可产三次替代窝，但双窝育雏罕见。孵化期25-28天，由双亲共同承担，母鸟白天孵化，公鸟可能夜晚孵化更多。幼鸟有金黄色和灰色两种形态，孵化后5-6周离巢，由双亲照料至离巢两周后。首次繁殖年龄为一岁。","identification":"与Greater和Lesser Sand Plovers相比，栗胸鸻具有较短的腿和较短、更细的喙。非繁殖期的成鸟胸部带纹减弱为灰色侧斑，具有清晰的淡色眉纹。幼鸟的胸部带纹非常模糊，上体有白色或淡黄色边缘。","protection":"IUCN：NT（近危）。在新西兰广泛分布，总数量估计约为5万只，其中约3万只在澳大利亚越冬，超过4000只在塔斯马尼亚。然而，指名亚种自1970年代以来在新西兰南岛部分地区数量下降，某些地区降幅高达70%，尽管局部仍保持数量。exilis亚种目前数量约为730只，19世纪因猫和猪的引入数量减少，自1970年代初开始回升，当时总数仅为100-200只。","distribution":"繁殖于新西兰斯图尔特岛、查塔姆群岛和奥克兰群岛。非繁殖期分布至澳大利亚南部和东部沿海、塔斯马尼亚、Lord Howe和Norfolk岛（澳大利亚远东），以及新喀里多尼亚。","other":"1908年前，栗胸鸻在新西兰被大量猎杀，用于商业贸易。1908年后被列入保护名单，禁止猎杀，现为常见物种。"},{"name":"蒙古沙鸻","english_name":"Siberian Sand Plover","scientific_name":"Anarhynchus mongolus","overview":"蒙古沙鸻（英文名：Siberian Sand Plover，学名：Anarhynchus mongolus），是鸻形目鸻科弯嘴鸻属的鸟类。雄鸟的胸部、额头和后颈显现出醒目的红色。分布于俄罗斯远东地区，主要在西伯利亚南部和东南部的裸露沿海平原繁殖。迁徙至东亚和东南亚的沙滩、澳大利亚、新几内亚地区、美拉尼西亚和西密克罗尼西亚越冬。","appearance":"蒙古沙鸻体型健硕，长腿长喙。繁殖期雄鸟背部呈灰色，腹部白色，胸部、额头和后颈为红褐色，眼周有黑色面罩。雌鸟颜色较淡，非繁殖期和幼鸟缺乏红色特征，仅头部略带红褐色。腿部暗色，喙黑色。与铁嘴沙鸻相比，体型较小，喙短且腿色较深。","call":"飞行时发出尖锐的颤音。","habits":"栖息于沿海、沙滩、河口、湖泊边缘以及附近的沼泽、草地和农田地带。活动于荒漠、半荒漠和高山地带的水域及其周边沼泽。喜独行或成小群活动，冬季可能形成大群。以昆虫、软体动物、蠕虫等小型动物为食。","breeding":"繁殖期为6-7月，营巢于高山林线以上或苔原地带。巢多位于苔原地面或水域边缘。每窝产卵2-4枚，多为3枚，卵呈赭褐色或皮黄色，带有黑褐色斑点。","identification":"与铁嘴沙鸻区分，铁嘴沙鸻体型更大，喙更长更粗，腿长且偏黄色。蒙古沙鸻腿色较深，喙短。","protection":"IUCN：EN（濒危）","distribution":"繁殖于俄罗斯东部，越冬分布于日本九州岛南部、琉球群岛、台湾、越南至澳大利亚、新几内亚、美拉尼西亚和西密克罗尼西亚。","other":"迁徙路线主要沿海岸线，从繁殖地向南至越冬地，春季返回繁殖地时遵循类似路径。"},{"name":"铁嘴沙鸻","english_name":"Greater Sand Plover","scientific_name":"Anarhynchus leschenaultii","overview":"铁嘴沙鸻（英文名：Greater Sand Plover，学名：Anarhynchus leschenaultii），是鸻形目鸻科弯嘴鸻属的小型鸻类。繁殖期雄鸟胸部、额头和后颈显红色，雌鸟和非繁殖个体无红色。铁嘴沙鸻体型比蒙古沙鸻大，嘴较长较厚，腿较长而偏黄色。分布于欧亚内陆西部至亚洲中东部，冬季迁徙至非洲东部沿海、南至琉球群岛南部、澳大利亚、美拉尼西亚和密克罗尼西亚西部。","appearance":"小型鸻类，背部灰色，下体白色。繁殖期雄鸟胸部、额头和后颈显红色，雌鸟较为暗淡。嘴长且厚，腿长而偏黄色。非繁殖期和幼鸟羽毛颜色较淡，上体沙棕色，下体白色，具白色喉部和“眉纹”。体型比蒙古沙鸻大，嘴型更厚更长。","call":"最常听到的叫声为短促滚动的“trrri”或“trrrr”，有时会快速连续发出3-4声，也有较长的颤音叫声，如“trrrreew”，平均音量和长度可能比蒙古沙鸻的类似叫声更大更长。","habits":"栖息于海滨沙滩、河口、内陆河流、湖泊岸边以及附近沼泽和草地。常呈2—3只的小群活动，偶尔形成大群。偏好水边沙滩或泥泞地带，特别喜爱海岸沙滩。奔跑迅速，常跑跑停停。以昆虫、昆虫幼虫、小型甲壳类和软体动物为食。","breeding":"繁殖期为4—7月，营巢于有稀疏植物的沙地或沙石地上，巢甚简单，由沙地上的凹坑构成，四周垫以贝壳、小卵石或盐碱土，内垫少许细草茎和干苔藓。每窝产卵3—4枚，卵的颜色为赭土色或灰褐色，带有大的黑褐色斑点。","identification":"与蒙古沙鸻相比，铁嘴沙鸻体型较大，嘴较长较厚，腿较长而偏黄色。铁嘴沙鸻与所有其他越冬鸻类的区别在于它缺少明显的胸横纹或领环。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚内陆西部至亚洲中东部，包括土耳其至蒙古东部。冬季迁徙至非洲东部沿海、南部至琉球群岛南部、澳大利亚、美拉尼西亚和密克罗尼西亚西部。"},{"name":"红胸鸻","english_name":"Caspian Plover","scientific_name":"Anarhynchus asiaticus","overview":"红胸鸻（英文名：Caspian Plover，学名：Anarhynchus asiaticus），是鸻形目鸻科弯嘴鸻属的鸟类。又名: 里海鸻，分布于亚洲西部和中部。繁殖季节，雄鸟展现出引人注目的外观，拥有白色的脸部和腹部，与宽阔的红棕色胸部形成鲜明对比；雌鸟颜色较淡，有温暖的锈棕色胸部。非繁殖季节和幼鸟呈现灰棕色，上体有淡色羽缘，面部和腹部苍白。红胸鸻分布于中亚地区，包括俄罗斯内陆、哈萨克斯坦、乌兹别克斯坦、土库曼斯坦至中国西北部的新疆。冬季迁徙至东非和南非，最远可达赞比西河。","appearance":"红胸鸻体长约18至20厘米，体重约60至91克，翼展55至61厘米。具有清晰的白色眉纹、前额和喉咙，棕色的冠部和上体，红棕色或栗色的胸带，与白色的腹部由黑色线条分隔。上翼有白色闪光，覆羽下侧白色。腿色变化，从粉红色到灰色或棕色。雌鸟的胸部为灰棕色，没有黑色边缘，头部和喉咙颜色较浅。非繁殖期成鸟的胸带为灰棕色，面部、前额和喉咙呈淡黄褐色，上体带有赤褐色边缘。幼鸟类似非繁殖期成鸟，上体羽毛有明显的赤褐色和黄褐色边缘。","call":"红胸鸻发出短促而略带鼻音的“chup”声，有时会连续快速重复或颤动。也有柔和的哨音“tik”和尖锐的“kwhit”。在繁殖地，展示飞行时，会发出重复的、悦耳的、清脆的口哨声“ty-ur-lee..ty-ur-lee...”。","habits":"红胸鸻栖息于低地沙漠、半沙漠、盐滩或盐碱土壤地带，常在水边繁殖，冬季远离水源。繁殖季节活动于海拔0至约800米的环境。在非洲，它们出现在最近烧过的草地、重度放牧的草地和远离水源的干涸洪泛平原。它们以昆虫及其幼虫为主食，偶尔食用植物材料，如草籽。","breeding":"红胸鸻在4月至6月间繁殖。营巢于开阔的盐碱地或草地，尤其偏好山边荒漠或半荒漠地区的盐碱地。巢通常置于稀疏植被覆盖的干燥地面。巢为简单的凹坑，内部垫有少量植物茎叶或小石子。每窝产卵3枚，卵色为土黄色，带有黑褐色斑点，平均大小为38mm x 27mm。双亲共同孵化，孵化期未知。雏鸟头顶、背部和腿部有淡奶油色，点缀着黑色斑点，形成头部、背部和前翅的条纹；额头、头部两侧、颈后环和下体为白色。由双亲照料，至少30天后离巢。","identification":"红胸鸻与东方鸻相似，但在非繁殖期可通过飞行时翅膀上的白色条纹来区分。与Charadrius veredus相比，颈部和腿稍短，上翼无白色闪光，下翼覆羽棕色。体型较高大，不如C. mongolus或C. leschenaultii紧凑。雌鸟胸部灰棕色，无黑色边缘，头部和喉咙颜色较浅。","protection":"IUCN：LC（无危）","distribution":"繁殖于中亚地区，包括俄罗斯内陆、哈萨克斯坦（除北部）、乌兹别克斯坦、土库曼斯坦至中国新疆西北部。冬季迁徙至肯尼亚内陆至非洲中南部。","other":"红胸鸻主要受到自然草原和草地破坏的威胁，主要是过度放牧和转化为集约化农业，尤其是在欧洲范围内。"},{"name":"东方鸻","english_name":"Oriental Plover","scientific_name":"Anarhynchus veredus","overview":"东方鸻（英文名：Oriental Plover，学名：Anarhynchus veredus），是鸻形目鸻科弯嘴鸻属的鸟类。中等体型的鸻类。繁殖期主要分布于蒙古、俄罗斯东部和中国东北部，迁徙至印尼、新几内亚和澳大利亚北部度过非繁殖季节。其独特的外观特征和迁徙模式使其成为研究对象。","appearance":"繁殖雄鸟头部淡色，喉部和前额冠白色，后颈灰褐色，背部灰褐，腹部白色，胸部具亮橙色带，与腹部间有一黑色横纹。雌鸟、幼鸟及非繁殖期雄鸟上体灰褐，腹部白色，脸部淡色，眼上具白色条纹。体长21-25厘米，翼展46-53厘米，体重约95克，腿较长，飞行时可见翼下覆羽深褐色。","call":"飞行时发出响亮、清晰的“chip-chip-chip”声，还发出尖锐的哨音“hweet”和短促的“tip”声。","habits":"栖息于干旱平原、山脚岩石荒地、盐碱沼泽、草地和淡水湖泊与河流岸边。迁徙和冬季期间集成大群，常在水边浅水处和沙滩奔跑觅食，奔跑速度快，飞行有力。主要食物为昆虫。","breeding":"繁殖期为4月至7月，筑巢于地面，形成浅杯状巢，通常在牛蹄凹印中，每窝产2枚卵，由雌鸟独自孵化。","identification":"与红胸鸻区别明显，体型较大，腿和颈部相对更长，具有较宽的黑色胸带和白色眉纹。","protection":"IUCN：LC（无危）。全球种群估计约70,000只，其中至少40,000只在澳大利亚越冬。","distribution":"繁殖于欧亚温带区域，包括西伯利亚中南部、蒙古和中国东北部。非繁殖期分布于印尼群岛内陆和沿海至澳大利亚中北部。","other":"曾有少数个体流浪至新西兰和欧洲部分地区。"},{"name":"岩鸻","english_name":"Mountain Plover","scientific_name":"Anarhynchus montanus","overview":"岩鸻（英文名：Mountain Plover，学名：Anarhynchus montanus），是鸻形目鸻科弯嘴鸻属的鸟类。中等体型的鸻科弯嘴鸻属鸟类。尽管其名，实际上并不栖息于山区，偏好开阔的草原地带。其特征为淡褐色上体，白色下体，无胸带，繁殖季节时额部黑色，眉纹白色。广泛分布于北美西部大平原的干燥台地，冬季迁往加州和墨西哥北部的干旱草原。","appearance":"岩鸻体长约20-25厘米，高约5-9英寸，体重约102克。上体沙褐色，下体和面部白色，额部和眼先有黑色羽毛。繁殖期额头黑色，眼至喙有黑色条纹，而非繁殖期这些特征变为淡棕色。腿色偏淡，脚爪黑色。雌雄同形同色。","call":"发出低沉、多变的哨声，叫声通常为低音颤鸣或咕噜哨声，与同类相比更为安静。","habits":"栖息于干燥的短草草原和裸露地面，以昆虫和其他小型节肢动物为食。常与牲畜共生，后者能吸引并惊扰昆虫。在早春筑巢于裸露地面，偏好与美洲野牛和黑尾土拨鼠共享栖息地。","breeding":"繁殖季节为夏季，巢筑于4月，需有裸露地面和短而稀疏的植被。每窝产3枚斑点状的蛋，由两性轮流孵育。孵化期28-31天，雏鸟出壳几小时后即可离巢，家族会在数日内迁移至牧场附近的良好觅食区。","identification":"与其他鸻科鸟类区别在于无胸带，上体沙褐色，下体白色，眼至喙有黑色条纹。幼鸟背部呈棕褐色，胸部和脸部呈淡黄色。","protection":"IUCN：NT（近危）","distribution":"繁殖于加拿大中南部的阿尔伯塔省和萨斯喀彻温省远南部，南至美国中西部的犹他州东北部和得克萨斯州西部。非繁殖期分布于美国加州中部内陆、亚利桑那州南部至得克萨斯州南部，以及墨西哥北部的下加利福尼亚州北部，索诺拉至扎卡特卡斯、圣路易斯波托西和塔毛利帕斯州。","other":"由于生境丧失和破碎化，如农业扩张和城市化，岩鸻的种群数量正在下降。"},{"name":"白脸鸻","english_name":"White-faced Plover","scientific_name":"Anarhynchus dealbatus","overview":"白脸鸻（英文名：White-faced Plover，学名：Anarhynchus dealbatus），是鸻形目鸻科弯嘴鸻属的鸟类。现确认为独立物种。体型小巧，羽毛淡色，具沙色背部，粉红色腿脚，黑色喙。繁殖期雄鸟头部锈色显著，头顶及胸侧有小黑斑，脸部几乎全白，喙眼间白色。雌鸟和非繁殖期成鸟较暗淡，缺乏黑锈色，脸部仍偏白，略带褐色。分布于东亚沿海区域，具体繁殖地未知，仅有一巢记录来自越南。","appearance":"体长约16至17厘米，头部圆润，羽毛呈浅色，上体沙灰褐色，下体洁白，脸部尤其是前额至眉纹白色，眼周和鼻基白色，喙尖钝，中等长度，黑色，腿脚较长，带有粉红色调。繁殖期雄鸟额头、眼周及鼻基完全白色，头顶有黑色横条，冠后橙色，胸侧有黑色斑块；雌鸟在这一时期胸部两侧有灰色褐色斑块，无锈色后冠。非繁殖期成鸟整体更暗淡，上体统一灰褐色，无黑色羽毛。幼鸟外观预计与非繁殖期成鸟相似。","call":"在非繁殖期大多保持沉默。已知叫声与环颈鸻类似，飞行时发出高音的‘tip’或‘tee’声。具体鸣唱特征尚未详细记录。","habits":"栖息于沿海沙滩、泥滩和盐沼，冬季可见于东南亚海岸线，包括砂质改造地和盐田。通常加入混合种群的滨鸟群，尤其与其他鸻科鸟类一起活动。偏好砂质较硬的栖息地，而非软泥。活动范围广泛，觅食时快速奔跑，以小型甲壳类动物为主食。","breeding":"繁殖习性资料稀缺。最近在越南发现的一巢显示，巢位于粗砂中的浅坑，含有多个贝壳碎片，内有三枚橄榄色带黑色斑点的蛋。确切的繁殖期、求偶、营巢、交配、孵化和育雏细节尚待研究。","identification":"与环颈鸻、马来鸻等种类区分，主要依据脸部颜色（尤其是喙眼间的白色）、上体色调、胸侧黑斑的大小以及翼上的白色条纹宽度。繁殖期雄鸟通过眼周及鼻基的白色区域、头部和胸侧黑斑的限制性分布来区分。雌鸟和非繁殖期个体通过更白的脸部、较小的胸侧黑斑、较淡的腿脚、稍重的喙以及更宽的翼上白色条纹（飞行时可见）来辨认。","protection":"IUCN：LC（无危）","distribution":"繁殖地可能位于中国东南沿海，南至福建；越冬区覆盖越南南部、泰国湾、马来半岛、新加坡及印尼苏门答腊岛东部。在中国大陆的分布主要在东南沿海。","other":"历史上的分类争议导致其真实状况长期不明。近年来在非繁殖区的观察增多，但繁殖区的情况仍然未知。中国沿海地区的环境退化可能对其繁殖地构成威胁。"},{"name":"青藏沙鸻","english_name":"Tibetan Sand Plover","scientific_name":"Anarhynchus atrifrons","overview":"青藏沙鸻（英文名：Tibetan Sand Plover，学名：Anarhynchus atrifrons），是鸻形目鸻科弯嘴鸻属的鸟类。具有独特的黑色面罩和橙色胸颈部，在繁殖季节尤为明显。雄鸟比雌鸟色彩更加鲜艳。分布于亚洲内陆中部和青藏高原的高海拔湖泊和河流边缘繁殖，冬季迁徙至东非、南非、印度洋岛屿、印度次大陆至中国南部沿海、东南亚、大巽他群岛和印尼苏拉威西岛。","appearance":"青藏沙鸻是一种中等大小的鸻类，喉部苍白，背部棕色，腹部白色。繁殖期成年鸟具有黑色面罩和鲜亮的橙色胸颈部，雄鸟的颜色通常比雌鸟更为鲜艳。非繁殖期和幼鸟上体呈褐色，下体白色，前额和眉纹颜色可变。与体型略大的大沙鸻相比，青藏沙鸻头部比例较小，腿色较暗，喙短且尖端稍有隆起。与肯特沙鸻在非繁殖羽衣相似，但青藏沙鸻更高大，腿较长，没有肯特沙鸻强烈的白色颈环。","habits":"青藏沙鸻通常以群居形式在潮间带泥滩和沙滩觅食，常与其他涉禽混合。其捕食方式为跑停啄食法，食物包括各种小型无脊椎动物，如昆虫、蟹类、多毛纲蠕虫和双壳类。它们可能在夜间进行部分觅食，因为高潮期间在夜间栖息地发现的数量较多。","breeding":"青藏沙鸻在亚洲内陆和青藏高原的高海拔湖泊和河流边缘繁殖。","identification":"青藏沙鸻与西伯利亚沙鸻和大沙鸻非常相似，尤其是非繁殖期和幼鸟。与西伯利亚沙鸻的区别在于，青藏沙鸻的橙色胸带更广泛，西伯利亚沙鸻通常有完整的胸带和较为锐利的前额边界。与大沙鸻相比，青藏沙鸻看起来较小，腿较长，喙形状有细微差异。","protection":"IUCN：LC（无危）","distribution":"青藏沙鸻在亚洲内陆中部和青藏高原繁殖，冬季迁徙至非洲东部、南部，印度洋岛屿，印度次大陆至中国南部沿海，东南亚，大巽他群岛和印尼苏拉威西岛。","other":"青藏沙鸻最近被从‘少沙鸻’（Lesser Sand Plover）中分离出来，成为独立物种。"},{"name":"欧金鸻","english_name":"European Golden Plover","scientific_name":"Pluvialis apricaria","overview":"欧金鸻（英文名：European Golden Plover，学名：Pluvialis apricaria），是鸻形目鸻科金鸻属的鸟类。大型鸻科鸟类，体型较厚实，翅膀略短于尾巴，以独特的'白S型'带纹闻名，从头部延伸至侧翼。分布于北极苔原至泛北极地区，自冰岛至中央西伯利亚，常群居于开阔地带，如草场、农田和平坦草地。","appearance":"成年欧金鸻体长26-29厘米，体重140-312克，翼展67-76厘米，是最庞大且体态丰满的金鸻种类之一。繁殖季节上身呈现金色斑点，脸和腹部有黑色斑块；非繁殖季则全身呈淡黄色，腹部白色。飞行时可见明亮的白色翼下。雌鸟较雄鸟少黑色，腹部有棕色标记。幼鸟似非繁殖期成鸟，但侧翼和腹部有微弱的灰色边缘。","call":"最常听到的叫声是在非繁殖地的圆润、拉长的纯哨音“puuuu”，音调单一或前缀短暂高音“tle-oooo”。在繁殖地，展示飞行时发出重复的哀婉双音管声“puuuu-wheeeuw...”，第二音节拖长并下滑。","habits":"欧金鸻偏好于湿润苔藓、苔藓与地衣、矮树丛苔原等地带繁殖，海拔可达约1200米。迁徙和冬季则出现在牧场、开阔农田、耕地、休耕田等大开敞空间，偶尔在潮间带滩涂觅食。夜间活动频繁，不论月相。","breeding":"繁殖期晚三月至五月中旬，单配制，部分记录显示多配偶制。每窝通常产四枚蛋，偶有三、二或五枚，间隔48-60小时产一枚，蛋色为橄榄绿、红褐色或奶油色，带有红色或黑褐色斑点，平均尺寸52.1x35.5毫米。孵化期27-31天，幼鸟25-33天离巢，但在北英格兰需34-42天。孵化成功率约为81%，平均每对产0.57只幼鸟。","identification":"与金鸻和美洲金鸻相比，欧金鸻体型更大，腿相对较短，翼下腋羽白色而非灰色。","protection":"IUCN：LC（无危）","distribution":"繁殖于低北极内陆至温带海洋区域，包括格陵兰中部至东部、冰岛、法罗群岛、英国群岛、德国北部、丹麦、芬兰斯堪的纳维亚半岛、波罗的海东至泰米尔半岛（俄罗斯中北部）。非繁殖期分布至欧洲内陆和沿海南部，北非至中东地区。","other":"在冰岛文化中，首只欧金鸻的出现标志着春天的到来，媒体会报道这一事件。"},{"name":"金斑鸻","english_name":"Pacific Golden Plover","scientific_name":"Pluvialis fulva","overview":"金斑鸻（英文名：Pacific Golden Plover，学名：Pluvialis fulva），是鸻形目鸻科金鸻属的鸟类。又称:金斑鸻鸻、太平洋金斑鸻，繁殖于北极圈内的西伯利亚和阿拉斯加。金斑鸻以其独特的金黄色斑点和优雅的身形著称，成鸟在繁殖季节腹部和脸部呈黑色，两侧有白色的纵纹，头部和背部布满金黄色斑点。该鸟种广泛分布于亚洲、澳大利亚、新西兰、太平洋岛屿等地。","appearance":"金斑鸻成鸟在繁殖季节展现出鲜明的外观，腹部和脸部为黑色，侧面有白色的纵纹，头部和背部点缀着金黄色的斑点。非繁殖季节，整体颜色较淡，上体呈灰色背景下的金黄色斑点，下体偏白色，两侧和胸部带有棕色条纹。喙为黑色，腿灰色至黑色。雌雄差异在于雌鸟的黑色胸部较为模糊，不如雄鸟明显。幼鸟羽毛较成鸟更为柔和，带有金黄色和棕色的混合色调。","call":"金斑鸻发出高亢的上升哨声，通常表现为‘pip’音后紧跟‘plooEEP!’，第一个音节短促且尖锐，区别于其他类似物种。","habits":"金斑鸻栖息于沿海滩涂、沙滩、开阔的草地和农田。它们在繁殖季节迁徙至北极苔原地带，冬季则南迁至东南亚、澳大利亚、新西兰等地。金斑鸻主要以昆虫、蠕虫、小型软体动物和甲壳类为食，采用跑-停-啄的方式觅食。","breeding":"繁殖期在6月至7月，金斑鸻在北极苔原上营巢，巢穴简单，由苔藓和枯草搭建。每窝产卵4-5枚，卵色为黄色或赭肉桂色，带有黑褐色或黑色斑点。孵化期约为27天，由雌雄鸟轮流承担。","identification":"金斑鸻与美洲金鸻相似，但可通过体型更纤细、腿更长、背部金黄色调更浓来区分。此外，金斑鸻的叫声也与美洲金鸻有所不同。","protection":"IUCN：LC（无危）","distribution":"繁殖于北极圈内的西伯利亚和阿拉斯加，越冬分布广泛，包括非洲之角沿海、印度次大陆、东南亚、印尼群岛、台湾、菲律宾、新几内亚、澳大利亚、新西兰、美拉尼西亚、密克罗尼西亚至波利尼西亚东部。","other":"金斑鸻适应能力强，能在人类活动频繁的区域如公园、墓地、屋顶、牧场和高尔夫球场中生存。"},{"name":"美洲金鸻","english_name":"American Golden Plover","scientific_name":"Pluvialis dominica","overview":"美洲金鸻（英文名：American Golden Plover，学名：Pluvialis dominica），是鸻形目鸻科金鸻属的鸟类。体型中等的鸻科金鸻属鸟类，以其独特的黑色脸面、颈部、胸部和腹部，以及白色冠部和颈背而著称。繁殖季节，其背部呈斑驳的黑白相间，点缀以淡金色斑点，雌鸟较雄鸟色彩稍淡。广泛分布于北美的高北极地区，包括美国阿拉斯加州的亚北极地带和加拿大北部地区。迁徙路径长且独特，冬季南迁至南美洲南部。","appearance":"成年美洲金鸻在繁殖季节，头部、颈部、胸部和腹部为深黑色，冠部和颈背白色，延伸至侧胸。背部为斑驳的黑白色，点缀以淡金色斑点。雌鸟与雄鸟相似，但颜色稍显柔和，脸颊可能呈现棕色或白色。非繁殖季节，上体灰褐色，下体淡灰褐色，眉纹白色。喙部短小，体形结实，翅膀长且尖锐，尾巴短而平截。","call":"常见叫声为两到三音节的哨声，具有辨识度。","habits":"栖息于北极苔原地带，偏好干燥开阔的环境。迁徙期间，常出现在浅水湾、泥滩、海滩和牧场。迁徙路线长，采取椭圆形迁徙路径，春季经由中美洲，秋季则向东飞越北大西洋和加勒比海。食物主要包括昆虫、昆虫幼虫、甲壳类动物、小型鱼类、浆果和种子。","breeding":"在繁殖地，会使用地面的干涸开放区域筑巢，巢穴为简单的凹坑，内部铺垫地衣、草和叶子。每窝产四枚蛋，蛋壳颜色为白色至米色，表面布满黑色和棕色斑点，平均尺寸约48×33毫米。孵化期约为26至27天，雄鸟白天孵卵，雌鸟夜间。雏鸟孵化后几小时内即可离巢，一天内能自行觅食。","identification":"与金斑鸻极为相似，但美洲金鸻体型略小，腿较长，翼展更宽。在繁殖季节，美洲金鸻的雌鸟较金斑鸻雌鸟颜色更深，更接近雄鸟外观。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美高北极地区，包括美国阿拉斯加州亚北极地带和加拿大北部（包括育空地区、不列颠哥伦比亚省中北部、哈德逊湾以西的巴芬岛）。非繁殖季节，主要分布于巴西沿海和内陆草原、巴拉圭至阿根廷东部和阿根廷东南沿海。","other":"历史上曾因大量猎杀导致数量减少，但目前种群状况稳定。"},{"name":"灰斑鸻","english_name":"Grey Plover","scientific_name":"Pluvialis squatarola","overview":"灰斑鸻（英文名：Grey Plover，学名：Pluvialis squatarola），是鸻形目鸻科金鸻属的鸟类。大型鸻科鸟类，繁殖于北极地区的岛屿和沿海地带。长距离迁徙鸟，非繁殖季节几乎遍布全球沿海地区。体长27-30厘米，展翅71-83厘米，体重190-280克。繁殖羽时，背部黑白相间，脸部和颈部黑色，边缘白色；胸部和腹部黑色，臀部白色，尾部有黑色条纹。非繁殖羽时，上身灰色，胸部杂有灰色斑点，腹部白色。幼鸟与成鸟的非繁殖羽相似，但背部羽毛更黑，边缘呈奶油白色。所有羽衣中，内侧腹侧和腋下羽毛为黑色，这是它与其它Pluvialis物种的主要区别。","appearance":"灰斑鸻体型较大，长度27-31厘米，翼展71-83厘米，重量165-395克。拥有厚重的身体，大头，厚颈和相对同类和大多数鸻科鸟类而言较大的喙。喙短而粗，逐渐均匀地收尖至钝尖。翅膀尖锐，稍超出尾尖；尾巴略微圆润。腿和脚趾相对较短，外趾和中间趾基部之间有发达的蹼，中间趾和内趾之间有较小的蹼。后趾变异（5-20%中间趾长度），罕见缺失。是鸻科（Pluvialis和Charadrius）中唯一具有后趾的物种。","habits":"灰斑鸻栖息于沿海海滨、沙洲、河口、江河与湖泊沿岸，特别偏好海滨潮涧地带。迁徙和越冬期间，也会出现在沼泽、水塘、草地、水稻田和农田地带。夏季栖息于北极冻原带和北极海岸附近。通常成小群活动，迁徙和越冬期间则会形成大群。性情胆小且机警，遇人即远飞，不易接近，飞行力强且迅速。","breeding":"繁殖期为6月至8月。在北极苔原上筑巢，巢通常位于地面上的凹坑内，内部铺设苔藓和草茎。每窝产卵3-4枚，卵的颜色为橄榄灰色、黄色或绿色，上面布满黑褐色斑点。卵的大小为45.7-55.2×34-38毫米，平均尺寸为51.66×35.92毫米。","identification":"繁殖羽的灰斑鸻与美洲金鸻（金鸻）的区别在于，灰斑鸻的尾下白色，而美洲金鸻的尾下黑色；灰斑鸻的上体为银灰色，而美洲金鸻的上体为金黄色。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于北美、帕拉：高（局部低）北极海岸和岛屿（除埃尔斯米尔岛、格陵兰、斯堪的纳维亚半岛和从斯瓦尔巴群岛到北地群岛的岛屿）。非繁殖区遍布全球，从温带海洋至海岸线热带地区（不包括偏远岛屿）。在中国大陆，分布于华北、四川、湖南、江苏和东南沿海等地。"},{"name":"剑鸻","english_name":"Common Ringed Plover","scientific_name":"Charadrius hiaticula","overview":"剑鸻（英文名：Common Ringed Plover，学名：Charadrius hiaticula），是鸻形目鸻科鸻属的鸟类。中小型鸻，广泛分布于北欧亚大陆及格陵兰。具有粗壮的体型，喙短而色彩鲜明，腿呈橙色，春季成鸟尤为明显。繁殖个体头部和胸部有黑白相间的醒目图案，而非繁殖个体则呈现较为柔和的褐色。飞行时可见显著的白色翼带，叫声轻柔，‘poo-ee’声独特，区别于体型更纤细的金眶鸻。繁殖于海滩、湖泊边缘的沙石地带及高海拔的树线之上，越冬于沿海地区。","appearance":"体型中等，长度约为17-19.5厘米，翼展可达35-41厘米。背部和翅膀呈灰褐色，腹部及胸部白色，胸部有一黑色颈环。头部有棕色顶冠，前额白色，眼睛周围有黑色面罩，喙短且橙黑相间。腿橙色，仅外侧两趾稍有蹼，区别于半蹼鸻。幼鸟颜色较淡，胸带可能不完整，喙色暗，腿呈黄灰色。","call":"发出轻柔的‘poo-ee’哨音，第一音节较长，叫声在飞行中最为常见，与金眶鸻的叫声明显不同。","habits":"栖息于沿海、河口、湖泊、沼泽、农田和草地，偏好湿润的沙地或泥滩。以蠕虫、甲壳类、软体动物等小型无脊椎动物为食。迁徙至非洲南部和地中海沿岸越冬。","breeding":"繁殖期在5月至8月之间，巢筑于沙地或石地，简陋无衬垫，每窝产卵3-5枚，多为4枚，卵呈淡黄色或灰色，带有暗色斑点，大小约35.31×25.67毫米，孵化期23-25天。","identification":"与半蹼鸻相比，剑鸻的脚蹼仅限于外侧两趾，胸带略宽，超眼圈更大，眼环更清晰，雌鸟侧胸和耳盖有棕色色调。不同亚种在大小、上体颜色上有细微差异。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆北部，从格陵兰至西伯利亚东北部，以及温带欧洲。越冬地遍及南欧、地中海、非洲撒哈拉以南地区、中东至波斯湾。","other":"被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》，受到中澳两国政府协定的保护。"},{"name":"半蹼鸻","english_name":"Semipalmated Plover","scientific_name":"Charadrius semipalmatus","appearance":"半蹼鸻是一种小型涉禽，体长约17-19厘米，体重约47克。繁殖季节时，背部呈中棕色，腹部白色，胸前有一条黑色的环带，额头白色，前额和头部两侧黑色，有窄白眼纹。翅膀和尾巴深色，翼上有单一的白色条纹。喙短而粗，腿短。喙黑色，基部黄至橙色；腿淡黄至橙色；眼周裸露皮肤黄至橙色，形成眼环。雌雄相似，但雌鸟通常头、面罩和胸带的褐色羽毛更多，眉线更醒目（在雄鸟中可能不那么明显或有时缺失），喙的橙色较暗。雄鸟的喙上橙色比雌鸟更多，翅膀也更长。成年个体的初级飞羽有10根，次级飞羽14-15根（包括3-4枚小覆羽），尾羽12根。","call":"半蹼鸻发出独特的两音节‘chu-weep!’叫声，以及一系列的咯咯声和咕噜声。","habits":"半蹼鸻主要栖息在开阔地带，靠近北极湖泊、沼泽和河流，或内陆干燥、砾石或植被稀少的地区。一些种群在亚北极南部的北温带地区被发现。它们是社会性和遗传上的单配偶制，两性都积极参与照顾蛋和早熟的雏鸟。作为一种中到长距离的迁徙鸟，它们主要在海洋环境中过冬，很少出现在内陆。由于其在食物和栖息地选择上的灵活性，以及广泛的沿海冬季分布，近年来其种群似乎保持稳定。","breeding":"繁殖期在北极圈附近，筑巢于地面开阔区域，偏好少量或无植被覆盖的地点。求偶行为包括视觉展示和叫声交流。营巢由两性共同完成，巢位于地面凹陷处，通常铺垫少量植被。交配后，雌鸟产卵，一般一窝产4枚卵，由双亲轮流孵化。孵化期约24天。雏鸟早熟，出生后不久就能跟随父母活动。","identification":"半蹼鸻与管鼻鸻、雪鸻、笛鸻和领鸻在外观上有相似之处，但可以通过以下特征区分：管鼻鸻体型更大，头部比例更大，喙更长更厚；雪鸻胸带不完整，背部颜色更浅，腿黑色；笛鸻背部颜色更浅（通常）且胸带不完整；领鸻体型略小，背部颜色更红，喙更细长，腿粉色，后颈黑色。此外，半蹼鸻与剑鸻极为相似，但剑鸻眼后条纹平均更长更厚，前额白色斑块更大且通常更尖锐，头部黑色区域更广泛，眼环不完整或暗橙色且不那么显眼。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于北美，从高北极内陆延伸至俄罗斯东北部和美国阿拉斯加州的亚北极地区，加拿大：从楚科茨半岛东部（俄罗斯东北部）、阿留申群岛中部和东部，整个阿拉斯加、不列颠哥伦比亚大陆北部和西北部至班克斯群岛和巴芬岛，南部至詹姆斯湾西部，加拿大纽芬兰和新斯科舍省（东北至加拿大，东南部）。非繁殖区沿海岸线分布，从俄勒冈州和新泽西州（西北和东海岸美国）向南至智利北部和阿根廷东部；同时遍及百慕大、整个西印度群岛和加拉帕戈斯群岛。","other":"尽管半蹼鸻与剑鸻在外观上极为相似，但它们在地理分布上基本隔离，剑鸻主要在欧亚大陆繁殖。"},{"name":"长嘴剑鸻","english_name":"Long-billed Plover","scientific_name":"Charadrius placidus","overview":"长嘴剑鸻（英文名：Long-billed Plover，学名：Charadrius placidus），是鸻形目鸻科鸻属的鸟类。中等体型的鸻科鸟类。分布广泛，自东亚至南亚，包括中国东北、日本、朝鲜半岛、俄罗斯远东等地。以其独特的长喙和尾巴著称，体长约18至21厘米，重约41至70克。","appearance":"长嘴剑鸻具有灰褐色背部和白色下体，头部前额白色，带有黑色颈环，领部和眉纹白色，但无金眶鸻的黄色眼圈。两性外观相似，但雄鸟的黑色前额带和胸带通常比雌鸟宽大。黄色眼圈比金眶鸻窄。非繁殖季节成鸟的头部和胸部图案较暗淡，且具棕色眉纹。幼鸟类似非繁殖成鸟，但缺乏成鸟的黑色前额和胸带，且胸带可能几乎完全缺失。","call":"长嘴剑鸻的叫声清脆金属般，最常听到的是飞行中的长滑音‘peeeuw’，持续约0.25秒。在繁殖地展示飞行时，会发出一系列20到30个哨音，音量和音调逐渐增强然后减弱。","habits":"长嘴剑鸻栖息于河流、湖泊边缘的砾石、碎石或岩石区域。分布广泛，包括俄罗斯远东、中国东北、韩国和日本，以及印度东北部等地。它们主要在河流、湖泊、海岸、河口、水塘、水库岸边和沙滩上活动，也出现在水稻田和沼泽地带。以单独或小群体活动，常沿水边边走边觅食，以昆虫、幼虫、蚯蚓、螺、蜘蛛等小型无脊椎动物和植物嫩芽和种子为食。","breeding":"繁殖期从三月中旬开始，持续至七月。在砂石地面或河漫滩上筑巢，巢穴为地面凹坑，无额外衬垫。每窝产卵3-4枚，颜色为灰色，有细小的深色斑点，由双亲共同孵化，孵化期为27-29天。","identification":"长嘴剑鸻与金眶鸻及剑鸻相比，嘴和尾较长，白色翼上横纹不如剑鸻粗大明显。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚地区的河岸温带西伯利亚东南部，从北海道至九州北部，朝鲜半岛北部至中部，中国东北部、中东部，以及印度东北部。非繁殖期间分布至尼泊尔中部、印度东北部、中国南部和东南部、朝鲜半岛南部、台湾、泰国北部和越南北部。","other":"长嘴剑鸻在全球范围内数量稳定，但在一些地区面临栖息地丧失的威胁，特别是在日本，过去20年里，其栖息地减少了17%。"},{"name":"金眶鸻","english_name":"Little Ringed Plover","scientific_name":"Charadrius dubius","overview":"金眶鸻（英文名：Little Ringed Plover，学名：Thinornis dubius），是鸻形目鸻科鸻属的鸟类。精致的小型鸻，身长约为16厘米。最显著的特征是亮黄色的眼圈，以及繁殖期成鸟的淡粉色腿和前额大片白斑。广泛分布于欧亚大陆内陆亚北极地区至热带、印度次大陆、东南亚、菲律宾、新几内亚和俾斯麦群岛。","appearance":"成年金眶鸻拥有灰色至棕色的背部和翅膀，白色的腹部和胸部，以及一条黑色的颈带。头部呈褐色，前额白色，眼睛周围有黑色面罩，上面有白色条纹，以及短而暗的喙。腿肉色，脚趾全部有蹼。繁殖期成鸟与非繁殖期成鸟的羽色差别不大，但幼鸟的上体橄榄棕色，边缘有浅色毛缘。不同亚种在大小和喙的颜色上有差异。","call":"发出清脆的‘peu’叫声，与相似的长嘴剑鸻截然不同。","habits":"栖息于开阔平原和低山丘陵地带的湖泊、河流岸边以及附近的沼泽、草地和农田地带。常单只或成对活动，偶尔集成小群。主要食物包括昆虫、蠕虫、蜘蛛、甲壳类和软体动物等小型水生无脊椎动物。","breeding":"繁殖期为5月至7月，营巢于河流、湖泊岸边或河心小岛及沙洲上，巢由沙地上刨出的圆形凹坑构成，或利用自然凹窝。每窝产卵3-5枚，孵化期24-26天，由雌鸟承担孵卵，雄鸟在巢附近警戒。雏鸟早成性，出生后不久即可行走。","identification":"与剑鸻的区别在于金眶鸻具有一条完整的黑或褐色胸带，腿黄色；与半蹼鸻的区别在于金眶鸻的胸带和黄色腿，以及更小的体型；与长嘴剑鸻的区别在于黄色眼圈和无翼上的横纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于欧亚大陆内陆亚北极地区至热带，印度次大陆，亚洲东南部，菲律宾，新几内亚和俾斯麦群岛；非繁殖期分布在撒哈拉以南非洲、中东、东南亚、印尼群岛。","other":"自19世纪晚期以来，欧洲的数量可能大幅下降，由于洪水调控导致栖息地丧失。但在20世纪30年代后，尤其是在1960年代后期，西北欧的数量有所增加，与人造栖息地的发展有关，如砂石坑。"},{"name":"双领鸻","english_name":"Killdeer","scientific_name":"Charadrius vociferus","overview":"双领鸻（英文名：Killdeer，学名：Charadrius vociferus），是鸻形目鸻科鸻属的鸟类。广泛分布于北美、中美和南美，从内陆亚北极地区至温带的北美洲，延伸至中美洲，以及厄瓜多尔沿海至秘鲁一带。其最显著的外部特征是背部褐色，腹部白色，胸前有两条黑色的带状长纹，飞行时可见黑白相间的翅和褐色的尾。常在人类开发的地区筑巢，如停车场、学校屋顶、道路边缘和农田，通常在裸露的碎石上。双领鸻非常善于模仿受伤的表演，以此吸引掠食者远离巢穴和幼鸟。","appearance":"双领鸻体型中等，长度在20-28厘米之间，翼展约46-48厘米，体重介于75-128克。背部呈灰褐色，腹部白色，胸部有两条明显的黑色带纹。飞行时，可见其翅膀上的黑白条纹和棕色的尾巴。腿呈粉红色，尾巴、臀部和下背部有明显的橙色斑纹。眼睛棕色，两性外观相似，但存在繁殖季节和冬季羽毛的差异。雏鸟有单个胸部带纹，缺乏成鸟的橙色臀部特征。","call":"双领鸻的鸣叫声嘹亮且连续不断，尤其是其标志性的“双领鸻”叫声。","habits":"双领鸻迁徙的原因主要是为了避开寒冷的天气，春季会较早返回繁殖地。它们主要以甲虫、蚱蜢、蜻蜓和其他昆虫为食。栖息地偏好于田野、牧场和干燥的高地，如高尔夫球场、航空地坪、多草的泥滩和短草牧场。","breeding":"双领鸻在地上挖掘浅坑作为巢穴，内衬以石块。雄鸟会建造多个巢穴，而雌鸟从中挑选一个。每窝产卵4枚，卵呈淡灰色，具有黑色斑纹。双亲轮流孵化，孵化期约为24天，共同照顾幼鸟，幼鸟出生后不久就能自行行走并觅食。若巢穴附近有入侵者，亲鸟会在地面假装受伤，通过跛行或拍打翅膀的方式将敌人引离巢穴，这种行为被称为“折翅”。","identification":"双领鸻是唯一在北美拥有两条黑色胸带的鸻类，这一特征可将其与其他类似物种区分开来。此外，其独特的橙色臀部和飞行中的黑白翼纹也是辨识要点。","protection":"IUCN：NT（近危）","distribution":"双领鸻广泛分布于北美、中美和南美的沿海地区，从亚北极地区向南至温带的北美洲，覆盖整个美国，进入中美洲，远至厄瓜多尔沿海至秘鲁一带。在北美洲，它们遍布各地，但在太平洋沿岸的南美洲北部地区分布较为局部。","other":"双领鸻曾经是市场猎人的目标，数量严重下降，但由于人类活动改变的栖息地，如今可能比历史上任何时候都更常见。然而，它们也面临着农药、油污染、割草机和汽车等现代问题的威胁。"},{"name":"笛鸻","english_name":"Piping Plover","scientific_name":"Charadrius melodus","overview":"笛鸻（英文名：Piping Plover，学名：Charadrius melodus），是鸻形目鸻科鸻属的鸟类。小型、沙色的鸻，体型类似麻雀，以其钟铃般的鸣叫而闻名。主要栖息于北美沿海沙滩和砾石海滩，分布于大西洋沿岸、五大湖地区以及中西部的河流湿地。成年个体具有橙黄色腿脚，繁殖季节时前额有黑色条纹，颈部可见黑色环带，雄鸟颈环通常比雌鸟更宽。全球数量估计约为57000只，属于近危物种。","appearance":"笛鸻体长17-18厘米，翼展45-47厘米，体重43-63克。头部较大且圆，颈短而厚，喙短小。成鸟在繁殖季节展现出独特的黑色前额条纹和颈环，雌雄差异仅在于雄鸟的颈环较为明显。幼鸟特征包括素面、黑色短喙及黄色腿脚。","call":"笛鸻的鸣叫声音清脆，如同钟铃，其特有的“pwee-doo”声调降低的双音节鸣叫易于识别。","habits":"笛鸻栖息于开阔的沙滩和泥滩，偏好干燥的高地。它们在白天频繁觅食，主要以昆虫、海洋蠕虫和甲壳类为食。冬季迁徙至墨西哥湾、美国南部大西洋海岸和西印度群岛。在受到威胁时，成鸟会展现出折翼行为以吸引捕食者远离雏鸟。","breeding":"繁殖期始于春季，笛鸻会在沙滩上筑巢，通常每窝产卵4枚，间隔一天产一枚。孵化期约27天，由双亲共同承担。雏鸟孵化后几小时内即可行走，主要由父母保护并引导觅食。约30天后，雏鸟学会飞行。","identification":"与雪鸻(C. nivosus)相比，笛鸻体型稍大，喙短而粗，腿脚颜色鲜艳。与半蹼鸻区别在于，后者背部颜色更深，眼上方和耳覆羽处颜色更暗。此外，笛鸻在飞行时露出完整的白色尾羽覆盖。","protection":"IUCN：NT（近危）","distribution":"繁殖区域包括加拿大中南部至五大湖南部至科罗拉多州东部和堪萨斯州北部，以及加拿大东部纽芬兰南部至北卡罗来纳州。非繁殖区域延伸至北卡罗来纳州至佛罗里达州的南大西洋海岸，墨西哥湾至尤卡坦半岛；巴哈马和大安的列斯群岛（除牙买加）。","other":"由于栖息地丧失和人类活动影响，笛鸻在某些地区被列为濒危或近危。保护措施包括栖息地管理、公众教育和限制宠物进入繁殖区域。"},{"name":"三色鸻","english_name":"Three-banded Plover","scientific_name":"Charadrius tricollaris","overview":"三色鸻（英文名：Three-banded Plover，学名：Charadrius tricollaris），是鸻形目鸻科鸻属的鸟类。小型涉禽，以其独特的黑白相间的胸带和宽阔的白色额头著称。广泛分布于东非至南非和马达加斯加的淡水湿地和盐碱湿地。","appearance":"成年三色鸻体长约18厘米，体重25至49克，具有深色的上体，红眼环，以及一条宽阔的灰褐色过喙带，喙尖黑色，基部粉红色。头顶黑色，两侧至颈背有一宽白带，喉部灰色，胸前有两条黑色带纹，中间以一白色带隔开，腹部其余部分白色。幼鸟的上体羽缘呈淡棕色，胸带不完整，额部颜色较浅，红眼环不明显。","call":"发出快速的金属质感的高音\"peet!\"，受惊时连续发出\"pit-pit-pit-peet!-peet!\"。展示时发出稍长的重复\"peeee\"或\"preeee\"声，常伴随短暂颤音。","habits":"栖息于内陆淡水湖泊、池塘、河流边缘的坚实砾石或泥地上，偶尔出现在海岸泻湖和河口，偏好低盐度区域。觅食时，它会沿水边快速移动，啄食水面下的昆虫、蠕虫和其他无脊椎动物。","breeding":"繁殖季节通常为4月至9月，筑巢于沙地或干泥地上，巢简单，铺有植物碎片、小石子和杂物。每次产卵2枚，有时仅1枚，孵化期约26至28天，由双亲共同承担。雏鸟孵化后30至32天离巢，但有时在21至22天就能飞行。","identification":"与福氏鸻的区别在于后者具有暗褐色的额部和大部分暗色的喙，基部红色，而非红喙黑尖。","protection":"IUCN：LC（无危）","distribution":"分布于埃及至东非、南部非洲以及马达加斯加，近年来在埃及阿斯旺发现繁殖记录。","other":"在许多分布区内，因人造湿地的增加而受益，但其全球数量估计为7万至13万只，可能因湿地丧失和干扰而逐渐减少。"},{"name":"福氏鸻","english_name":"Forbes's Plover","scientific_name":"Charadrius forbesi","overview":"福氏鸻（英文名：Forbes's Plover，学名：Charadrius forbesi），是鸻形目鸻科鸻属的鸟类。小型涉禽，最显著的外部特征是黑色的顶冠、灰色的前额、环绕眼睛的白色条纹，以及胸部两条黑色的带状斑纹。这种鸻鸟广泛分布于西非内陆的河流、湖泊和池塘附近，偏好岩石地带的繁殖环境。","appearance":"成年福氏鸻体长约20厘米，体重46-49克，拥有长翼和长尾，使其在飞行中与多数小鸻鸟区别开来。繁殖期的成鸟上体呈暗棕色，下体大部分为白色，胸部有两道黑色的横带，中间夹着一道白色带，头部黑白相间，眼圈和嘴基为红色。非繁殖期成鸟的胸部横带可能变为深棕色，眉线带有淡色。幼鸟与非繁殖期成鸟相似，但色泽较暗淡。","call":"福氏鸻发出哀婉的‘pee-oo’声，有时重复，或单个‘peeuw’声，在展示飞行时会发出尖锐的‘pee-pee-pee-pee’或‘pleuw-pleuw-pleuw-pleuw…’声。","habits":"福氏鸻栖息于各种开阔生境，包括短草甸、耕作地、湿地边缘和最近烧过的区域。它在繁殖季节后移居到附近的草地，包括机场和高尔夫球场，也会出现在稻田、池塘或水库附近。它的食物主要包括甲虫、蚱蜢和其他昆虫及其幼虫，以及小型软体动物、甲壳类和蠕虫。","breeding":"福氏鸻在雨季繁殖，通常在岩石高地上筑巢，巢穴为浅坑，内铺细石，以防水流侵蚀。每次产卵2-3枚，蛋壳呈奶油色或淡粉色，带有红褐色或淡紫色斑点。孵化期至少22天，由双亲共同承担。幼鸟被双亲照顾直至离巢。","identification":"福氏鸻比三色鸻体型更大，颜色更深，头部更显深褐色，且有明显的红眼圈和嘴基。三色鸻的前额和翼上有白色条纹。","protection":"IUCN：LC（无危）","distribution":"福氏鸻的繁殖区域位于几内亚内陆至南苏丹，向南至刚果民主共和国、乌干达西部、安哥拉中部和赞比亚北部。非繁殖季节时，它们会出现在乌干达西北部等地。","other":"福氏鸻的种群数量估计至少有100,000只，但在某些地区，如塞内加尔东南部，记录极为稀少，而在安哥拉，似乎非常罕见。"},{"name":"黑头鸻","english_name":"Hooded Plover","scientific_name":"Charadrius cucullatus","overview":"黑头鸻（英文名：Hooded Plover，学名：Charadrius cucullatus），是鸻形目鸻科鸻属的鸟类。以其黑色头罩和红眼圈为显著特征。","appearance":"黑头鸻体长19-23厘米，翼展36-44厘米，体重79-110克。其特征为短腿、颈部不明显，头部和宽白颈环为黑色，背部灰色并带有黑色边纹，延伸到胸部的小黑斑，眼圈深红色，喙基橙红色，尖端黑色，腿橙粉色。雌雄相似，无季节变化。幼鸟后颈、头顶和胸斑淡灰棕色，点缀白色，下巴和喉咙白色，上身淡棕灰色，边缘淡色，喙黑色，基部粉红，眼圈较浅。","call":"黑头鸻相对沉默。飞行叫声低沉粗哑的“kew-kew”。也有粗糙的叽叽声。受惊时会发出安静的高音管道声“kseep”。","habits":"主要栖息于广阔的沙质海洋海滩，偶尔靠近岩石或沙覆盖的珊瑚礁、河口、入海口和近海岸的咸淡水湖泊。日间和夜间觅食，主要依靠触觉夜间觅食，持续啄食。非繁殖季节以松散小群或大群活动。","breeding":"繁殖期从8月至次年3月，可能因替换和第二次筑巢而延后。一夫一妻制，有时持续多年。巢建在沙地上，开放环境，通常巢间距几公里，密度0.2-2对/千米，高度地点忠诚。巢为浅坑，可能铺有鹅卵石、海藻、树枝和贝壳碎片。每窝2-3枚蛋，孵化期27-31天，由双亲轮流孵化。雏鸟孵化成功率17%-31%，每对成功育雏0.1只。巢失败原因包括洪水、人类干扰、车辆破坏、牲畜践踏和捕食。","identification":"黑头鸻与其他鸻科鸟类的区别在于其独特的黑色头罩、红色眼圈和橙粉色腿。与澳洲斑蛎鹬相比，黑头鸻体型更小，颜色更淡，具有明显的黑色头罩。","protection":"IUCN：VU（易危）","distribution":"黑头鸻分布于澳大利亚南部，包括西澳大利亚沿海和内陆西南部、南澳大利亚南部沿海、新南威尔士州东南部以及塔斯马尼亚州。","other":"黑头鸻的种群受到人类活动的严重影响，包括海滩休闲活动的干扰，导致繁殖成功率降低。"},{"name":"滨鸻","english_name":"Shore Plover","scientific_name":"Charadrius novaeseelandiae","overview":"滨鸻（英文名：Shore Plover，学名：Charadrius novaeseelandiae），是鸻形目鸻科鸻属的小型鹬鸻。头部黑色，头顶及上体褐色，下体白色，具独特的白色头环。分布极为有限，仅存于新西兰的几个无掠食者的岛屿，全球数量约200只，是世界最濒危的涉禽之一。","appearance":"滨鸻长约20厘米，重52-69克。身体短胖，比例近似于翻石鹬，具黑色头部（除灰褐色的冠部被白色带环绕）、橙色至红色的眼环及橙色短粗腿。雌鸟头部的黑色替换为暗棕色，嘴尖更黑。无季节性变化。幼鸟面部主要为白色，有深棕色眼纹和冠部，上体斑点更为明显，喙主要为黑色，腿和眼圈淡色；约6个月大时获得暗色面具。","call":"发出响亮清脆的“kleet”、“peep”或“splew”叫声，兴奋时加速成响亮的颤音，类似蛎鹬的叫声。也有柔和的接触叫声“kleet”或“pip”。飞行展示时发出拉长的“beep-beep”声。雏鸟受威胁时发出高音重复的尖叫，随年龄增长声音变得更响亮刺耳。雌鸟的叫声比雄鸟更高，幼鸟的叫声比成年鸟更高。","habits":"滨鸻栖息于岩石海岸带有广阔潮间带浅池的区域，有时覆盖着藤壶、海螺或藻类斑块；也出现在附近散落巨石的海滩和较少见的盐草甸。繁殖于巨石堆中的沙滩和内陆盐草甸。活动于低潮时分，于浅潮池边缘和湿岩石上觅食，食物包括小甲壳类、蜘蛛、腹足类、双壳类和昆虫。日间和夜间皆活跃，视潮汐而定。非繁殖季常以小群（最多15只）觅食。","breeding":"滨鸻在10月中旬至12月筑巢，直至次年1月可能再筑巢；长期一夫一妻制。保卫巢址及雏鸟养育区，有时也保卫觅食区。巢建于巨石间的凹陷处或盐草甸的沙砾中，由根和死草构成，衬以植物材料、偶尔羽毛、贝壳和鹅卵石。一般单窝，但已记录到二次繁殖。三枚卵，有时两枚，平均大小37毫米×26毫米，孵化期约27-28天，由双亲轮流孵化，主要由雄鸟夜间孵化。雏鸟上体有斑驳的白色、米色、浅棕色和黑棕色斑点，缺乏白色颈背环，下体淡黄色；由双亲照料，但雌鸟照料更密集；离巢时间极不稳定，29-63天（通常35-45天），可能取决于食物供应；幼鸟独立时间为41-67天。大多数鸟首次繁殖在2-3岁，少数在第一年。每对鸟平均孵化成功率83%，其中7-43%成功育雏，即每对鸟0.5-0.8只幼鸟。","identification":"滨鸻与栗胸鸻（带纹点水鸟）幼鸟易混淆，但滨鸻喙明显更长。","protection":"IUCN：EN（濒危）","distribution":"分布于查塔姆群岛的东南岛（=Rangatira）；已重新引入新西兰的卫星岛屿。","other":"历史上滨鸻遍布新西兰沿海，但现在仅限于查塔姆群岛的几个岛屿。"},{"name":"黑额鸻","english_name":"Black-fronted Dotterel","scientific_name":"Charadrius melanops","overview":"黑额鸻（英文名：Black-fronted Dotterel，学名：Charadrius melanops），是鸻形目鸻科鸻属的鸟类。自成一属。小型鸻类，身长16至18厘米，体重27至42克，翼展33至35厘米，具有独特的黑色面部条纹和V形胸带。广泛分布于澳大利亚内陆、塔斯马尼亚州、北岛和南岛（新西兰）。","appearance":"黑额鸻为小型鸻，体长16–18厘米，体重约27–42克，翼展33–35厘米。特征明显，有黑色眼纹和前额，白色眉纹在颈背汇合；喙红色，尖端黑色；肩部上方有紫色斑块；胸部有黑色V形带；臀部和尾羽上覆羽深棕色到栗色，边缘宽而淡；下尾覆羽有黑色条纹；腿粉红或浅橙色。成年和幼鸟性别相似，无季节变化。幼鸟额头和冠部呈奶油色，眼纹暗褐色，眉纹淡色；背部有淡褐色和棕色边缘，臀部无栗色；胸带模糊；喙棕至灰黑色；腿粉棕色。","call":"最常听到的叫声为短促、强调的‘pit’声。在繁殖地，会发出几种芦苇般的叫声‘drre-drre-rreeeuw’，有时简单的‘rreeuw’声，或是一连串的摩擦声‘drr-drr-drr-drr-drr..’。夜间也会发出声音。","habits":"栖息于淡水湿地的裸露或稀疏植被边缘，如湖泊、池塘、水坑、泉水旁的泥地、坚实地面或砾石地带，包括沼泽、人造环境如水库、农场水坝、甚至路边沟渠。在新西兰，主要栖息于浅溪流的碎石河床，洪水时移至附近农田，亦见于道路旁沟渠和湿地边缘。在干旱地区，偶尔接近盐水。","breeding":"繁殖季在澳大利亚为9月至翌年2月，在新西兰为8月至翌年3月，但受降雨和温度影响，时间可能提前或延后。一夫一妻制，至少有时连续多个季节。巢置于开阔的石头地带，如沙、砾石、鹅卵石或碎石河岸；巢穴为凹坑或浅坑，可能无衬垫或以石子、植物材料和杂物作衬。每窝产卵三枚，有时两枚，间隔两天产一枚；双亲轮流孵卵，孵化期22至26天；雏鸟背部淡色，有黑色斑点和斑块，背侧黑色，下体白色；由双亲照料；离巢23至40天；首窝雏鸟与父母共处至第二窝孵化开始或第二窝孵化后；第二窝雏鸟与父母共处至少八周。","identification":"黑额鸻的识别要点在于其独特的黑色眼纹和V形胸带，以及红眼环和红嘴（尖端黑色）。与同类物种相比，黑额鸻的色彩更为鲜明，体型较小。","protection":"IUCN：LC（无危）。全球范围内不构成威胁。由于人工湿地的建设，如农场水坝和污水处理池，导致适宜栖息地的增加，其分布范围最近有所扩大。在澳大利亚，是分布最广泛的鸻类，总数量至少15,500只；在新西兰，自1950年代末起从澳大利亚迁入，现已遍及北岛东部和南部、南岛东北部和东部，1990年代初估计数量约为1,700只，但南岛许多适宜栖息地尚未被占据。","distribution":"广泛分布于澳大利亚内陆，塔斯马尼亚州，北岛和南岛（新西兰）。在新西兰，主要栖息于浅溪流的碎石河床，洪水时移至附近农田，亦见于道路旁沟渠和湿地边缘。"},{"name":"小嘴鸻","english_name":"Eurasian Dotterel","scientific_name":"Eudromias morinellus","overview":"小嘴鸻（英文名：Eurasian Dotterel，学名：Eudromias morinellus），是鸻形目鸻科 Eudromias 属的鸟类。小型鸻科鸟类，具有独特的白色眼纹和橙红色胸带。雌鸟比雄鸟色彩更鲜艳，表现出性别角色的反转。分布于北欧和欧亚大陆北部，冬季迁徙至北非和中东地区。","appearance":"小嘴鸻体长20-22厘米，体重86-142克，翼展57-64厘米。体态丰满，繁殖期雄鸟具鲜明的白眉纹和白胸带，雌鸟颜色更为鲜亮，黑冠和腹部更显深色。非繁殖期颜色暗淡，羽色转为淡褐色，上体边缘呈沙色，下体灰褐色带淡白色条纹，腹部白色。幼鸟与非繁殖期成鸟相似，但背部对比更明显，下体带有更多肉桂色，两胁有条纹，胸部线条呈肉桂色，腹部略带肉桂色。","call":"叫声温和，常发出\"pyurr\"声，以及轻柔的\"pweet-pweet-pweet\"或\"kwip-kwip\"声，有时伴有颤音。","habits":"栖息于开阔、干燥的高地和山脉，偏好苔原和高山地带，远离水源。在迁徙期间可见于开阔地带、牧场、耕地和高尔夫球场。主要以昆虫为食，包括甲虫、双翅目幼虫、蝴蝶和蛾子的幼虫、蚱蜢、蟋蟀、蠼螋和蚂蚁，偶尔食用蜗牛、蚯蚓、植物叶片、种子、浆果和花朵。日间和夜间觅食，主要在白天活动。","breeding":"繁殖期在5月中旬至7月初，一窝产卵2-4枚，孵化期21-25天，由雄鸟负责孵化。雏鸟孵化后不久即可行走，约30天后可随亲鸟飞翔。","identification":"繁殖期的雌鸟比雄鸟色彩更为鲜艳，黑冠和腹部更深色。非繁殖期颜色暗淡，与其它鸻科鸟类的区别在于白色的眉纹和胸部线条。","protection":"IUCN：LC（无危）","distribution":"繁殖于北欧至欧亚大陆北部，包括英国北部岛屿、斯堪的纳维亚、俄罗斯西北部至西伯利亚东北部、中国新疆北部和蒙古中部北部。冬季迁徙至北非、中东至伊朗东南部和阿拉伯半岛东部。"},{"name":"棕胸鸻","english_name":"Rufous-chested Dotterel","scientific_name":"Zonibyx modestus","overview":"棕胸鸻（英文名：Rufous-chested Dotterel，学名：Zonibyx modestus），是鸻形目鸻科 Zonibyx 属的鸟类。这一独特的中型鸻科鸟种主要在南美洲南部的草原和荒野地带繁殖，冬季迁往海滩和沿海平原。其显著特征为鲜明的白色眉纹，深色的上体与亮红褐色的胸部，黑色宽边勾勒，非繁殖季节羽毛颜色较淡。成年个体长度介于19至22厘米，体重约71至94克。","appearance":"成年棕胸鸻拥有灰面白眉，喉部灰，冠部棕色，胸部亮丽的红褐色，下体白色，上体棕色。繁殖期雌雄相似，但雌鸟略显暗淡。非繁殖期成鸟颜色转为淡棕色，上体羽毛边缘明亮，眉纹乳白。幼鸟上体及胸部颜色更深，呈深棕色，具清晰的淡色边缘。","call":"飞行叫声为柔和的双音节“peeeu-dip”，有时简化为“peeu”。还发出沙哑的哨声“wheeerr”。繁殖地的叫声为一系列短促的断音，常以低沉拉长的咕噜声结尾。","habits":"繁殖季节栖息于内陆短草甸，海拔可达2000米，亦可见于沼泽低地或高山湖泊周边的干燥石质地带。非繁殖季节则活动于内陆水淹草地、侵蚀草甸、湿地、溪流、滩涂、沙滩和岩石海岸。","breeding":"繁殖期主要在10月至11月，偶尔延续至1月。筑巢于开阔地带，通常在蕨类植物和Empetrum灌木丛中，提供遮蔽。每窝产卵2枚，有时3枚，孵化由双亲共同承担。","identification":"通过其独特的红褐色胸部、黑色下缘和白色眉纹易于识别。与同属物种相比，其体型较大，色彩更为鲜艳。","protection":"IUCN：LC（无危）","distribution":"繁殖于南美智利内陆中南部、阿根廷南部和福克兰群岛。非繁殖季节迁至秘鲁南部沿海、巴西东南部，偶见于乌拉圭和阿根廷北部。","other":"尽管自1970年代中期以来，其在阿根廷北部的越冬地数量似乎有所下降，但在目前栖息地相对较少人类干扰的状况下，该物种似乎安全。"},{"name":"橙喉鸻","english_name":"Tawny-throated Dotterel","scientific_name":"Oreopholus ruficollis","overview":"橙喉鸻（英文名：Tawny-throated Dotterel，学名：Oreopholus ruficollis），是鸻形目鸻科橙喉鸻属的鸟类。独特而引人注目的鸻，分布于从阿根廷的巴塔哥尼亚草原到安第斯山脉高处的开阔草甸和沙丘，亦在迁徙和冬季时见于农田。这种鸻以优雅的站立姿态、大胆的脸部图案、笔直尖锐的喙、鲜亮的红棕色喉咙和条纹背部为显著特征，无相似物种。繁殖区位于南美洲的秘鲁沿海和内陆北部至火地群岛，非繁殖季节迁徙至乌拉圭沿海和巴西东南部。","appearance":"橙喉鸻体长25至29厘米，体重介于120至154克之间，站立时较为挺拔，喙长而细。羽毛主要呈丰富暖色系，背部重叠条纹，羽片有深色条纹和宽广的沙色至红棕色边缘；下巴白色，喉咙橙红，颈与胸灰色；腹部有一小块显眼的黑色斑点；腿色暗粉。飞行时，翼下呈现鲜明的白色。性别间外观相似，季节变化不明显。幼鸟的喉咙为暖色调，上体羽片中心为深色，边缘较窄，下体较淡，腹部斑点为棕色，腿色为灰色。亚种pallidus比指名亚种更淡，体型较小。","call":"橙喉鸻通常较为安静，被惊飞或飞行中会发出振动的延长哨音“prrrrruu”，音调相同或略降，以及节奏感强的“chup!-prri-rri-rruu”。群居时，数只飞行中的鸟同时鸣叫。受到惊吓时，会发出强调的“chee!-chu-chup”声，以及单独的“chup”声。","habits":"主要栖息于风力强劲的半干旱地带，如开阔的荒野和过度放牧的普纳草原，海拔可达3500至4600米，或植被稀疏的沙滩地带；季节性出现在秘鲁沿海平原和灌溉部分的沿海沙漠。迁徙期间，也会出现在低地的田野和草地。繁殖于高安第斯山脉的鸟群在繁殖季后迁徙至较低海拔，最南端的群体则北迁至厄瓜多尔、巴西东南部、乌拉圭和阿根廷东部。","breeding":"关于繁殖行为知之甚少，推测繁殖期可能从六月至一月，具体时间随纬度有所变化。亚种pallidus在近海水平的沙地和几乎无植被的洛马斯区域筑巢。每窝产四枚卵，雏鸟为肉桂色，身上有复杂的黑色线条和密集的白色‘粉扑’状花纹。亚种pallidus的雏鸟颜色非常浅淡。","identification":"橙喉鸻以其独特的红棕色喉咙、条纹背部和优雅的站立姿态与其他鸻类区别开来，无相似物种混淆。","protection":"IUCN：LC（无危）","distribution":"繁殖于南美洲秘鲁沿海和内陆北部至火地群岛，非繁殖季节迁徙至乌拉圭沿海和巴西东南部。"},{"name":"黑顶鸻","english_name":"Diademed Sandpiper-Plover","scientific_name":"Phegornis mitchellii","overview":"黑顶鸻（英文名：Diademed Sandpiper-Plover，学名：Phegornis mitchellii），是鸻形目鸻科黑顶鸻属的鸟类。近危物种，以独特的羽饰和弯钩状喙闻名，分布于南美洲的安第斯山脉高海拔沼泽地带，从秘鲁中部山区至智利和阿根廷的中南部。","appearance":"黑顶鸻体长介于16.5到19厘米之间，体重在28到46克之间。其喙呈黑色，略微向下弯曲，腿和脚橙色。成鸟面部黑色，具宽阔的白色眉纹环绕头部后部，头顶黑色，颈背鲜亮的赤褐色，上体大部分暗灰褐色，臀部和上尾覆羽黑色，尾巴黑色而边缘白色。喉咙白色，胸部、腹部和两胁黑白相间的细条纹，肛区和下尾覆羽纯白色。幼鸟比成鸟暗淡，上体主要为灰褐色，带有肉桂色斑点和条纹，眉纹灰色，颈背杂有肉桂色或赤褐色。","call":"发出清脆的‘pic’或‘pic-pic’声，无论是觅食还是飞行中均可听到。疑似警戒叫声包括哀婉、略带拉长的‘wheehu’，较不哀婉、较为尖锐的‘whee-u!’，以及意外响亮的尖叫哨声‘whEEHU!’。","habits":"黑顶鸻几乎总是单独或成对出现，生活在高山沼泽和泥炭地环境中，这些地方位于霜冻线和雪线之间，由交错的草堤和长流溪流与季节性水塘组成。它在南部分布区是海拔迁移者，从最高处的繁殖地迁移到较低海拔过冬，再于秋季返回繁殖地。在南端的种群可能还存在一定程度的南北迁徙。以独自或成对的方式觅食，通过在湿润地面或浅水中探查以及从水面和水生植物中拾取猎物来获取食物，主要食物为淡水无脊椎动物。","breeding":"繁殖期在智利从10月持续到12月，在玻利维亚延伸至1月。巢建于地面的浅坑或干草平台，已知的窝卵数均为两个。蛋的颜色为橄榄灰色，带有黑色斑点。孵化期和幼鸟离巢时间尚不清楚。","identification":"成年黑顶鸻的独特外观使其易于识别，幼鸟的暗淡色彩和肉桂色颈背可以帮助与小型滨鹬（Calidris属）区分开来，后者无上体条纹，颈背无肉桂色，跗跖和趾颜色较暗。","protection":"IUCN：NT（近危）","distribution":"分布于安第斯山脉的中北秘鲁、玻利维亚、智利中北部和阿根廷中北部。","other":"由于气候变化导致的需求增加、过度放牧、道路网络扩展和人类干扰，黑顶鸻的生存环境正受到威胁。预计到2100年，高达75%的安第斯高原独特泥炭地生态系统将因气候变化而严重缩减。"},{"name":"杂色麦鸡","english_name":"Pied Plover","scientific_name":"Hoploxypterus cayanus","overview":"杂色麦鸡（英文名：Pied Plover，学名：Hoploxypterus cayanus），是鸻形目鸻科杂色麦鸡属的鸟类。其显著的黑白相间羽毛，橙色腿，以及独特的黑色V字形背纹使其在热带低地河流的生境中格外醒目。分布于南美洲安第斯山脉以东，从哥伦比亚东部至玻利维亚中部，以及巴西东南部。","appearance":"体长21-24厘米，体重54-84克，较其他Vanellus属种类小。具有黑色与白色相间的羽毛，背部呈棕灰色，腹部为白色，头顶部有明显的黑色与白色条纹。胸前有一黑色横带，肩部有醒目的黑白条纹，翅膀上有宽阔的白色翼斑。两性相似，无季节性换羽差异。幼鸟与成鸟类似，但头部颜色更偏棕色，胸带较小且灰暗。","call":"发出悦耳的双音节叫声“kee-oo”，后半部分音调较低，受惊飞起时叫声变为尖锐而短促的‘whee-whuu’声。在波浪状飞行展示时会重复发出‘klee’声。","habits":"栖息于热带低地河流、沙洲和泥滩，以及森林地带的湖泊岸边，偶尔出现在海岸边。海拔分布从海平面至约2600米。通常单独或成对活动，对环境中的水位变化敏感，会随季节迁移。","breeding":"繁殖行为在5月至7月被观察到，筑巢于地面浅坑中，巢穴无衬垫，直接接触地面。每窝产2-3枚橄榄褐色蛋，带有深棕色斑点，集中在蛋的较大一端。雏鸟在7月和8月记录到。","identification":"与Charadrius属的滨鸟在某些方面相似，但具有更长的红色腿和黑色腕刺。幼鸟相比成鸟头部颜色更偏棕色，胸带较小且灰暗。","protection":"IUCN：LC（无危）。在某些地区可能面临威胁，如委内瑞拉的萨瓦纳地区有大量个体，但在巴西南部、哥伦比亚、苏里南和法属圭亚那罕见。","distribution":"分布于南美安第斯山脉以东，包括哥伦比亚东部、厄瓜多尔东部、委内瑞拉、圭亚那、亚马逊河口、秘鲁东部、玻利维亚、巴拉圭、巴西东南部（至Paraná州）及阿根廷东北极点（Misiones州）。","other":"历史上曾被认为属于鸻亚科（Charadriinae），现归类于Vanellinae亚科。虽然被称为杂色麦鸡，但基于分类学，更准确地应称为lapwing。"},{"name":"蓝腿燕鸻","english_name":"Egyptian Plover","scientific_name":"Pluvianus aegyptius","overview":"蓝腿燕鸻（英文名：Egyptian Plover，学名：Pluvianus aegyptius），是鸻形目埃及燕鸻科埃及燕鸻属的鸟类。别名: 牙签鸟、鳄鸟，为埃及燕鸻科的唯一成员。该鸟拥有蓝灰色背部，鲑粉色下体，头部和胸部以黑白相间的鲜明标记著称。体型中等，分布于撒哈拉以南非洲的大型热带河流沙洲，曾在尼罗河沿岸广泛分布，现已在埃及灭绝。","appearance":"成鸟长19-22厘米，翼展47-51厘米，体重73-92克。背部、头冠、眼纹和胸带为黑色，边缘白色；眉纹白色；翼覆羽和尾羽蓝灰色，末端白色；翅膀形成醒目的黑白图案；下体奶油色至淡褐色；喙黑色；腿和脚蓝灰色。幼鸟与成鸟相似，但更暗淡，背部羽毛边缘呈棕色。","call":"常见鸣叫为响亮的“chersk”声，常在飞行中发出，尤其是在激动或攻击时。警戒或接近巢穴时会发出单个“wheep”声，接近巢穴时跟随数个“cherk”音符。","habits":"栖息于低地热带河流的沙砾洲，避免密集森林和河口水域。食物包括蠕虫、软体动物、水生昆虫、小飞虫，偶尔吃种子和鱼类残渣。通过多种方式获取食物，如表面觅食、捕捉飞虫、探查湿润沙地等。成对或小群活动，密度可达每公里10只。","breeding":"繁殖期主要在1月至4月或5月，筑巢于河床沙洲上的深坑，雌雄共同参与。每次产2-3枚土黄色带红棕斑点的蛋，孵化期28-31天，由双方轮流孵化。雏鸟孵化后即能行走，约30-35天离巢。","identification":"蓝腿燕鸻具有独特的蓝灰色背、黑白色头部标记和橙色下体，飞行时黑白分明的翅膀图案是辨识要点。与其它类似鸟类的区别在于其特有的色彩组合和栖息环境。","protection":"IUCN：LC（无危）","distribution":"分布于从塞内加尔到埃塞俄比亚的撒哈拉以南非洲，南至安哥拉北部，刚果民主共和国和苏丹。曾广泛存在于尼罗河流域，包括埃及，但现已在埃及灭绝。","other":"历史上，蓝腿燕鸻曾被认为与鳄鱼存在共生关系，清理鳄鱼口腔内的残留食物，但这一说法缺乏确凿证据支持。"},{"name":"彩鹬","english_name":"Greater Painted-snipe","scientific_name":"Rostratula benghalensis","overview":"彩鹬（英文名：Greater Painted-snipe，学名：Rostratula benghalensis），是鸻形目彩鹬科彩鹬属的鸟类。雌鸟比雄鸟更加艳丽且体型更大。广泛分布于非洲内陆和热带至亚热带亚洲，包括马达加斯加、印度河流域到中国南部、日本中部、菲律宾及小巽他群岛东部。栖息于芦苇水塘、沼泽、河渠等地。","appearance":"中等体型，两性差异显著，雌鸟拥有亮红褐色头部，背部和翅膀显绿色光泽，雄鸟则为暗淡的浅褐色头部和橙色、棕褐色斑点的上体。两者眼周都有亮白的“逗号”状标记，下体白色向上延伸至肩部。","call":"雌鸟在求偶时会发出一系列类似鸮类的叫声，金属质感，拖长音。","habits":"栖息于湿地环境，偏好低海拔热带和亚热带地带，常出现在沼泽、芦苇丛、水稻田等处，主要在黄昏和夜晚活动。以昆虫、甲壳类、软体动物及植物种子为食。","breeding":"繁殖期为5至7月，实行一雌多雄制，雌鸟与多个雄鸟交配并产卵，每窝产卵3-6枚，孵化期约19天，由雄鸟单独孵化。","identification":"与半领彩鹬相比，彩鹬体型更大，喙更直，羽色细节不同。与真鹬类在飞行中可能混淆，但彩鹬飞行速度较慢，翅膀圆润，腿常悬垂。","protection":"IUCN：LC（无危）","distribution":"非洲、马达加斯加、印度河流域至中国南部、日本中部、菲律宾及小巽他群岛东部。","other":"彩鹬曾普遍遭到猎杀，现在因湿地破坏和生境丧失面临威胁。"},{"name":"澳洲彩鹬","english_name":"Australian Painted-snipe","scientific_name":"Rostratula australis","overview":"澳洲彩鹬（英文名：Australian Painted-snipe，学名：Rostratula australis），是鸻形目彩鹬科彩鹬属的鸟类。中等体型、长喙、具有独特羽色图案的涉禽。分布于澳大利亚（除塔斯马尼亚州中西部、中北部、东北部以外），数量极其稀少，面临严重的生存威胁。","appearance":"成年雄鸟头部、颈部及上胸部呈巧克力棕色（雄鸟暗灰色，头顶有淡黄色中线），后颈中央渐变为赤褐色，背部变为暗灰条纹状。眼周有奶油色的逗号形斑纹，胸部侧面至肩部有一条白色条纹，是其显著特征。上翼灰色（雄鸟有淡黄色斑点），下胸至腹部白色。雄鸟通常比雌鸟稍小且色彩略淡。幼鸟与成年雄鸟相似，但白色条纹不明显，翅膀内侧大多为浅灰色，喙紫褐色，尖端黑褐色。","call":"据报告，雌鸟会发出柔和、金属质感的低沉轰鸣声，叫声与亚洲和非洲的同属物种有所不同。此外，还有“kek”或“kak”的大声叫声，间隔小于1秒，被惊扰时重复多达四次；尖锐的重复‘cuck-cuck’声；雌鸟发出的深沉嘶吼；雄鸟在分散注意力的展示中发出响亮的嘶嘶声；受伤鸟在被捕获时发出软弱的嗡嗡声；正面展示时发出柔和的音乐般的‘booo’声；回应幼鸟求救时的轻柔声音，以及接近巢穴时的‘click-click’叫声。","habits":"澳洲彩鹬偏爱浅水淡水湿地，包括湖泊、沼泽、泛滥或水淹草地、盐沼、水库、稻田、污水处理场和水井排水沟，周围有草丛、莎草、芦苇或芦苇，有时有树丛。它们会在夜间或黄昏活动，以植被、种子、昆虫、蠕虫、软体动物、甲壳类和其他无脊椎动物为食，包括蜗牛和蜈蚣。它们在水边或泥地上觅食，探入软土或在浅水中用喙割草。通常独居，偶尔成对或小群活动，极少数情况下可达约30只。","breeding":"繁殖季节主要在9月至12月，南部澳大利亚一般为8月至2月，北部则更早。雌鸟可能独自筑巢，巢位于地面，掩藏在植被中，通常是一个浅坑或干草、大麦草、水生植物、树枝、叶子等构成的浅碗状巢，如果建在水上则结构更为坚固。每窝通常产3-4枚（极少数6枚）蛋，蛋壳呈乳白色或淡黄色，带有黑色条纹、不规则的斑点和污渍，以及少量棕色斑点，大小约为33-37.3毫米×24.6-26.4毫米；仅由雄鸟孵化15-16天。绒毛雏鸟呈黄褐色，背部有纵向黄褐色、亮棕和黑色条纹，至少有时由雌鸟照料，但关于离巢期的信息未知。","identification":"与同属物种相比，澳洲彩鹬的翼展较长，喙和腿较短，头部颜色更深，尾部斑点较小，雄鸟的翅膀覆羽斑点更明显，尾巴和臀部颜色更淡。幼鸟与成年雄鸟相似，但白色条纹不明显，翅膀内侧大多为浅灰色。","protection":"IUCN：EN（濒危）","distribution":"澳洲彩鹬分布于澳大利亚，主要沿东海岸和东南海岸，从北昆士兰到南澳大利亚（艾尔半岛）。它在澳大利亚的分布零散且不可预测，主要出现在东部澳大利亚，包括昆士兰、新南威尔士、维多利亚和东南南澳大利亚的多个地点，尽管在某些看似适宜的栖息地，如悉尼周边，它仍然极为罕见。在澳大利亚南部、北部领地和西部，该物种的记录较少，分布更为零散。","other":"自20世纪以来，澳洲彩鹬的数量急剧下降，主要原因是湿地丧失，包括直接排水和转向农业用水和水库，以及河流资源管理变化和盐碱化。据估计，自欧洲人定居以来，澳大利亚大约50%的湿地已被转换，某些地区的损失甚至更大。此外，湿地本土植被被外来杂草取代也可能使栖息地变得不适合或完全无法居住。牛的放牧和相关植被践踏在某些地区可能也是一个威胁，特别是在干旱季节，放牧集中在湿地附近。"},{"name":"半领彩鹬","english_name":"South American Painted-snipe","scientific_name":"Nycticryphes semicollaris","overview":"半领彩鹬（英文名：South American Painted-snipe，学名：Nycticryphes semicollaris），是鸻形目彩鹬科半领彩鹬属的鸟类。拥有鲜明的外观，但因其栖息于南美洲的淡水和微咸水湿地而鲜为人知，尤其是那些浅水区和草高仅及膝盖的地方。偶尔可见其安静地在植被边缘觅食，更多时候是在被惊扰时才得以一见。该物种在南美东南部至阿根廷中南部和智利中部有零星分布。","appearance":"体长约19-23厘米，体重约65-86克。具有长而弯曲的喙；金色的冠纹、眉纹和肩部“V”字形标记；头部、颈部和上胸呈深红棕色；眼周和眉纹的淡色区域可能比描绘的更广泛；背部主要是深灰棕色和黑色，肩羽和翼覆羽上有变化的白色斑点，飞羽上则有较小的淡色斑点；臀部和楔形尾巴为灰色，带有细窄的暗色条纹；腹部白色。性别二态性几乎不存在，雌鸟平均稍大些，可能略微鲜艳，但缺乏确凿证据。幼鸟肩羽和翼覆羽上的斑点为奶油色，飞羽上的淡色斑点显著减少，喉部和胸部有白黑相间的条纹。","call":"声音描述不多，已知的包括飞行中的沙哑低沉音调，以及繁殖季节中听到的哀怨哨声，功能不明。","habits":"栖息于热带和亚热带低地，常见于开阔的沼泽和湿地、河流和溪流旁，以及稻田和湿润草地，通常在75-150毫米深的水中。偏好比更为开阔的区域，包括阿根廷和乌拉圭的河口。一般在接近海平面的地带发现，但在智利的海拔可达500米，在巴西部分地区超过1000米，阿根廷圣胡安省曾有一例记录在2750米的高度。主要以甲壳类、昆虫及其幼虫、水生无脊椎动物和种子为食。在浅水区，利用半圆形扫动动作的喙捕捉贝类，同时保持喙尖浸入水中。在非繁殖季节，偶尔会有大量集中出现的记录。","breeding":"主要在南半球春夏季繁殖，可能在7月至次年2月间，具体时间取决于当地条件；巴西也有五月繁殖的记录；雄鸟在3月末阿根廷西部门多萨省睾丸增大；可能从冬季中期到晚期开始配对。一夫一妻制；小群聚居，常在1-1.5公顷的区域内找到5-6个巢穴，但无证据显示多雄现象。简单的地面巢由草和芦苇茎构成，直径9-10厘米，深度0.5-2厘米；位于沼泽中，经常被水环绕，或在湿润草甸的密林中，溪流或开阔水面边缘，包括河口。通常产两枚蛋，偶尔三枚，颜色为赭石色或奶油色，带有变化的栗色、黑色、棕色或灰色斑点，尺寸为33.4-35.9毫米×23.7-24.6毫米；孵化和离巢期未知；雏鸟似乎由双亲共同照顾。","identification":"与南美沙锥和麦哲伦沙锥相比，半领彩鹬的羽毛颜色更深，喙弯曲程度更明显，肩羽和翼覆羽上有独特的白色斑点，眼周金色斑块缩减为眉纹，喙尖部更圆润，尾巴形状明显不同。","protection":"IUCN：NT（近危）。全球范围内不被视为受威胁物种。关于种群水平和趋势的具体信息不可得；其隐秘和夜行的生活习性使其难以检测。在智利被视为非常局部和不常见的物种。在阿根廷和巴西的部分地区，20世纪70年代时并不罕见，甚至在某些地方相对频繁。在巴西，1961年前仅有一笔记录，之后在里约热内卢州和南里奥格兰德州发现。农业发展导致的栖息地改变和破坏影响了多种干草原鸟类，湿地鸟类也可能受到类似影响。该物种因肉质美味而备受猎人青睐；在繁殖季节常遭猎杀，因为它们往往在地方狩猎季节结束前就开始筑巢。在相对较少的保护区中被记录，包括巴拉圭的Serranía San Luís国家公园和阿根廷的多个保护区。","distribution":"零星分布于南美洲，包括巴拉圭东部至巴西东南部、乌拉圭、阿根廷中南部和智利中部。"},{"name":"小雉鸻","english_name":"Lesser Jacana","scientific_name":"Microparra capensis","overview":"小雉鸻（英文名：Lesser Jacana，学名：Microparra capensis），是鸻形目水雉科小雉鸻属的鸟类。又称: 小非洲水雉，体长约15-16厘米，重约41克。其显著特征是拥有长腿和爪，使它能在水上植物如荷叶上行走。分布于中非至南非，包括马里至加纳、东至埃塞俄比亚、南至纳米比亚等地。","appearance":"小雉鸻体长15-16厘米，体重约41克。前额有显著的额甲，喙长而尖，稍向下弯曲。顶冠桔黄色，具金属光泽，翅呈棕红色，脸颊及颈部白色，有金黄色领，黑眼眉。脚趾特别长，可在荷叶上行走。性别差异不大，但雌鸟略大于雄鸟。","call":"发出低沉的‘woot’声，重复频率可达每秒五次，持续时间可达五秒。还发出类似‘see sree shrrr’的抱怨声，柔和的‘tchr tchr tchr’声，以及重复2-10次的‘ti’或‘hli’音。","habits":"栖息于水草繁盛的湖泊、池塘和沼泽地带，偏好部分生长的莎草和水生草类环境。善行走，能在水生植物上奔跑，也善游泳和潜水。主要以昆虫、虾、软体动物等小型无脊椎动物和水生植物为食。","breeding":"繁殖季节随地区和雨季变化，通常在湿季开始时出现于季节性泛滥的水域。筑巢于水生植物上，如莎草、Polygonum等，巢可自由浮动。通常产三枚蛋，极少数四枚，孵化期19-24天。雏鸟由双亲共同照顾，直到至少半大。","identification":"与非洲雉鸻幼鸟相似，但体型更小，背部颜色更深。飞行时，白色翼缘明显，易于辨认。","protection":"IUCN：LC（无危）","distribution":"分布于马里至加纳，东至埃塞俄比亚，南至纳米比亚、博茨瓦纳和非洲东南部。在肯尼亚、埃塞俄比亚和赞比亚的海拔高度分别为3000米、1830米和1800米。","other":"在繁殖区域与非繁殖区域之间移动，响应水位变化。曾被误认为非洲雉鸻的幼鸟，但通过体型和背部颜色可区分。"},{"name":"非洲雉鸻","english_name":"African Jacana","scientific_name":"Actophilornis africanus","overview":"非洲雉鸻（英文名：African Jacana，学名：Actophilornis africanus），是鸻形目水雉科非洲水雉属的鸟类。又名:非洲雉鸻鸻、长脚雉鸻，这种栗、白、黑相间的水鸟拥有天空蓝的喙和巨大的脚，雌鸟体型大于雄鸟。其分布于撒哈拉以南非洲内陆，栖息于水草繁盛的环境。","appearance":"非洲雉鸻体长23至31厘米，雄鸟体重115至224克，雌鸟体重167至290克。喙与前额盾连续，呈淡蓝至灰蓝色；头顶及颈背黑色；脸侧、下巴和喉部白色，上胸部金黄色；上体大部分为栗色至红肉桂色，臀部、次级飞羽及下体偏暗红的栗色；初级飞羽黑色，仅在飞行或展示时可见。雌鸟与雄鸟相似，但体型更大。幼鸟头部和颈背黑色带棕羽，上体淡棕色带光泽绿色，除红臀部、次级飞羽和大覆羽外。","call":"鸣叫声嘈杂多样，起飞时发出类似‘kaaaa kaaka-ka’的叫声，战斗中发出刺耳尖叫，雄鸟带雏时会发出高频率的抱怨式颤音。","habits":"栖息于水草丰富的湖泊、池塘、沼泽和河流，以及水生植物茂盛的人工水坝。以昆虫为主食，也会捕食小螃蟹、蜗牛，偶尔食用植物种子。飞行低弱，通常在水面附近，腿和脚尴尬地悬垂。","breeding":"实行一妻多夫制，雌鸟聚集在繁殖地，与多个雄鸟交配。雄鸟独自筑巢、孵化和抚养幼鸟，孵化期约20至26天。雌鸟在四天到三周内可产下替换蛋或为其他雄鸟产卵。","identification":"与其他雉鸻相比，非洲雉鸻的特征在于其特有的颜色组合和巨大的脚趾，使其能够在浮叶植物上行走。","protection":"IUCN：LC（无生存危机的物种）","distribution":"广泛分布于撒哈拉以南非洲内陆，包括津巴布韦、莫桑比克、纳米比亚、博茨瓦纳等地。","other":"该物种的寿命不详，已知最长寿个体为九岁。"},{"name":"马岛雉鸻","english_name":"Madagascar Jacana","scientific_name":"Actophilornis albinucha","overview":"马岛雉鸻（英文名：Madagascar Jacana，学名：Actophilornis albinucha），是鸻形目水雉科非洲水雉属的鸟类。又名:马岛雉鸻鸻，特有于马达加斯加。最显著的特征是额甲呈浅蓝色，头颈白色，喉胸黑色，全身余部栗色，翼尖黑色。分布于马达加斯加内陆西部，尤其偏好水草繁茂的湿地。","appearance":"马岛雉鸻体长约30厘米，雌鸟比雄鸟略大。其额甲呈浅蓝色，头部和颈部为白色，喉部和胸部为黑色，其余部分为栗色，翼尖呈现黑色。拥有长腿和巨大的脚趾，这在水雉科中是典型的特征。","call":"叫声为一系列中音调的‘trrrt’声，通常以每秒一次的速度连续发出，音调略有起伏变化，速度也会有所变化。同时，它还会发出一种急促的‘kreeeeeee’声，声音逐渐减弱，通常在同类间的争斗中发出。","habits":"栖息于淡水沼泽、湖泊边缘、池塘以及流速缓慢的河流旁，尤其偏爱有睡莲（Nymphaea stellata和N. lotus）的水域。以昆虫及其幼虫、水生植物的种子为食，有时也会食用小螃蟹和蜗牛。在浮游或半浮游植被上觅食，通常单独或成对活动，偶尔会形成数十只的小群体。","breeding":"繁殖行为全年皆可见，但具体研究有限。已知的繁殖记录集中在12月至6月。巢建于漂浮的水生植物堆上，一窝产四枚深橄榄色带有棕色和灰色斑点的蛋，由雄鸟单独孵化。雏鸟头顶、后颈和面部两侧为黑色，背部为肉桂色，侧面更鲜艳，有深褐色条纹，腹部、头部和颈部两侧为白色。","identification":"与非洲雉鸻相似，但额冠、后颈和颈侧为白色，与肩部相邻处为金黄色，面部和下颈为黑色。幼鸟的额冠、后颈和眼纹更黑。","protection":"IUCN：EN（濒危）","distribution":"主要分布在马达加斯加内陆西部，罕见于东部。常见于水生植被丰富的湿地。","other":"对人类活动并不警觉，但在面对普通沼鸡时表现出回避行为。"},{"name":"冠水雉","english_name":"Comb-crested Jacana","scientific_name":"Irediparra gallinacea","overview":"冠水雉（英文名：Comb-crested Jacana，学名：Irediparra gallinacea），是鸻形目水雉科冠水雉属的鸟类。冠水雉属的唯一物种。适应于热带淡水湿地的漂浮植被，分布于婆罗洲内陆东南部至新几内亚，以及澳大利亚北部和东部。拥有独特的外观和生活方式。","appearance":"成年冠水雉具有黑色的头部和颈部后部，前额和前顶冠覆盖着鲜红的肉质垂肉，与白色的面部和喉咙形成鲜明对比。繁殖期成年鸟的冠更为粉红，非繁殖期则更偏橙色。胸部下方有一条宽阔的黑色带纹，腹部白色。飞行时，黑色的下翼和飞羽最为显眼。背部和上翼主要呈灰棕色，翼尖覆羽、臀部和尾巴为黑色。长长的腿和极其细长的脚趾在飞行中拖曳。雄鸟较小，长20-22厘米，重68-84克；雌鸟较大，长24-27厘米，重120-150克。翼展范围在39至46厘米之间。幼鸟上部褐色，下部白色，缺乏成鸟的黑色胸部；冠和垂肉初生，首次换羽至成年羽毛约需一年。","call":"发出尖锐、高音的叽叽声，也可被描述为尖锐的颤音伴随柔和的号角声。","habits":"栖息于大型淡水湿地、沼泽和湖泊，偏好有丰富漂浮植被如睡莲或水葫芦的地方。它们能在水面的植被垫上行走。在澳大利亚，当湿地开始泛滥时，鸟类会移动到新近湿润的湿地，而当湿地干涸时，它们会再次消失。在北领地的一个地点，这种鸟在雨季倾向于低密度存在，但在旱季增加至年度最高点，出现在8月至9月。","breeding":"全年可繁殖，但在澳大利亚大部分地区仅限于雨季。实行多雄制，每只雌鸟有1-3个雄鸟伴侣。雄鸟保卫在漂浮植被上的领地，雌鸟则保卫1-4个相邻的雄鸟和它们的领地。巢由雄鸟主要建造，由茎和水生植物碎片构成，但雌鸟也会抛掷大量植被。通常产4枚蛋，孵化期约为28天，几乎全由雄鸟负责，尽管平均孵卵率仅为54%。孵化成功率低，仅20%。幼鸟条纹状，上面有条纹，下面白色；大约在50-60天后离巢。","identification":"其最显著的特征是巨大的脚和长长的趾，能够支撑它在漂浮的叶子上行走。此外，其头部的红色肉冠也是识别的关键。与同属的其他物种相比，冠水雉的体型更大，色彩更加鲜艳。","protection":"IUCN：LC（无危）。虽然在整个分布范围内似乎没有受到威胁，但湿地的退化或丧失仍然是持续的威胁，且在新南威尔士州被列为易危。在新几内亚，若湿地中引入了吃植物的外来鱼类，冠水雉似乎会消失。","distribution":"分布于南婆罗洲、苏拉威西、小巽他群岛、菲律宾南部的棉兰老岛、新几内亚、新不列颠（Lake Lalili）、澳大利亚北部和东部。在澳大利亚，尤其是北领地的卡卡杜国家公园，估计1987年有1500只鸟。在新几内亚，若湿地中引入了吃植物的外来鱼类，冠水雉似乎会消失。在苏拉威西南部的淡水沼泽和喀里曼丹（南婆罗洲）的一个地点，该物种局部丰盛。","other":"近年来在北苏拉威西和新不列颠的Lake Lalili有记录，显示其分布可能比之前认为的更为广泛。"},{"name":"水雉","english_name":"Pheasant-tailed Jacana","scientific_name":"Hydrophasianus chirurgus","overview":"水雉（英文名：Pheasant-tailed Jacana，学名：Hydrophasianus chirurgus），是鸻形目水雉科水雉属的鸟类。又称: 水凤凰、菱角鸟。繁殖成鸟尾羽极长，黑白分明的头部与亮黄色颈斑相映成趣，背部至尾部羽毛颜色从黑褐色至浅棕色不等。在中国台湾，因其常栖息于菱角田，故有菱角鸟之称，又因繁殖期独特的羽色和长长的尾羽，被誉为\"凌波仙子\"。水雉广泛分布于巴基斯坦至菲律宾北部，南至印度尼西亚西部。","appearance":"繁殖成鸟身长可达39-58厘米，尾羽长达25-35厘米；非繁殖期身长约31厘米。雄鸟体重约120-140克，雌鸟约190-231克。头部和下颈白色，黑色冠后部延伸至两侧颈部分隔金色后颈与白色前颈。背部至尾部羽毛颜色从黑褐色至浅棕色不等，背部可能带有绿色光泽。非繁殖期，背部和头部暗绿色至棕褐色，颈部两侧有黑色条纹，形成胸前带。尾羽短，仅11-12厘米。雌鸟与雄鸟相似但体型更大，幼鸟背部至额头红棕色，颈部两侧无黄色，胸前带不明显。","call":"发出类似猫叫的\"喵喵\"声，繁殖季节雄鸟和雌鸟有不同的叫声，冬季群体中可听到鼻音的\"teeun\"。","habits":"水雉栖息于丰富的挺水植物和漂浮植物的淡水湖泊、池塘和沼泽地带，喜欢单独或成小群活动，冬季有时会形成大群。它们善行走，能在水面的植物上奔跑和停歇，也擅长游泳和潜水。水雉主要以昆虫、虾、软体动物、甲壳类等小型无脊椎动物和水生植物为食。","breeding":"繁殖期为4-9月，实行一雌多雄制，雄鸟会为争夺配偶而斗争。巢建于莲叶、百合叶等水上植物上，每窝产卵4枚，卵呈梨形，颜色多样，大小约为33-40mm×26-29mm。雄鸟独自承担孵卵任务，孵化期为26天。","identification":"水雉是唯一具有不同繁殖和非繁殖羽色的jacana种类，其显著的白色翅膀和颈部黑色条纹帮助区分它与外形类似的铜翅水雉。","protection":"IUCN：LC（无危）；国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）。","distribution":"繁殖区广泛分布于巴基斯坦内陆至吕宋岛、棉兰老岛（菲律宾北部和南部）、爪哇岛和巴厘岛。非繁殖区南至印度尼西亚西部。","other":"水雉曾面临灭绝威胁，尤其是在台湾，但得益于湿地恢复项目，维持了一个稳定的小种群。"},{"name":"铜翅水雉","english_name":"Bronze-winged Jacana","scientific_name":"Metopidius indicus","overview":"铜翅水雉（英文名：Bronze-winged Jacana，学名：Metopidius indicus），是鸻形目水雉科铜翅水雉属的鸟类。具有明显的性别角色反转现象。头部、颈部和下体为黑色，带有金属光泽，眼至颈间有一条醒目的白色条纹，背部和内侧初级飞羽呈现橄榄铜绿色，尾下覆羽为栗色。广泛分布于南亚和东南亚，自印度内陆至越南和马来半岛北部，偶尔出现在爪哇岛（罕见）。在中国，仅偶见于云南西南部的西双版纳地区，数量稀少。","appearance":"铜翅水雉拥有光泽黑羽，背部、肩羽和上翼覆羽绿中带光，尾羽和腹面为赤褐色；喙绿黄相间，尖端黄，基部红，额顶盾状结构蓝转红，繁殖期间尤为鲜艳。眼至颈间的白色条纹显眼，腕部有角质瘤状突起。雌鸟较雄鸟大，体重可达雄鸟的60%以上，尤其在体重、喙长、翼展、跗蹠长和额顶盾高上更为明显。幼鸟头冠赤褐色，眼纹白，前颈浅黄，其余下体白色，上体深色。","call":"发出尖锐的‘seek-seek-seek’叫声和短促粗糙的吼声。","habits":"铜翅水雉偏好浮水和挺水植被丰富的淡水环境，如莲花、睡莲、水葫芦、水生植物丛生的湖泊、沼泽、池塘等地。它们能利用水生杂草覆盖的湿地，如水葫芦和蕹菜（空心菜）生长的地方。主要以昆虫、蜗牛等软体动物和水生植物的叶片、嫩芽为食。","breeding":"繁殖季节随雨季而启动，约在6月至9月，印度部分地区在3月雨水充沛时也有零星繁殖报道。实行一雌多雄制，雌鸟维护包含1至4个雄鸟的领地。雄鸟通过展示展开翅膀和伸长脖颈来保卫领土，有时会升级至啄斗。巢筑于水面植物如凤眼莲、水鳖、金鱼藻和水葫芦的茎叶之上，或直接置于莲花叶上。每窝产卵4枚，卵壳光滑，呈锥形，颜色为棕褐色，饰有不规则的黑色锯齿状斑点。孵化期约为29天，完全由雄鸟承担。雏鸟早熟，约十周后独立。","identification":"成鸟与黑水鸡容易区分，主要通过其独特的头部黑色和白色条纹组合，以及青铜色的翅膀。幼鸟可能与水雉的幼鸟相似，但缺乏后者特有的黑色颈环。","protection":"IUCN：LC（无危）","distribution":"繁殖区位于远东地区的印度内陆至越南和马来半岛北部，非繁殖区偶尔可见于爪哇岛，但极为罕见。","other":"铜翅水雉是国家二级保护动物，在某些地区可能面临栖息地丧失和狩猎威胁。"},{"name":"美洲水雉","english_name":"Northern Jacana","scientific_name":"Jacana spinosa","overview":"美洲水雉（英文名：Northern Jacana，学名：Jacana spinosa），是鸻形目水雉科美洲水雉属的鸟类。体长17-23厘米，羽毛呈红褐色，头部和颈部为黑色，具有醒目的金绿色飞羽，尤其在飞行时更为显眼。常见于墨西哥至巴拿马的热带低地淡水沼泽、湖泊和池塘，偶尔在美国南部的得克萨斯州出现。雌鸟体型显著大于雄鸟，且繁殖季节攻击性强，有‘产卵机器’之称。","appearance":"美洲水雉体长约23厘米，翼展约36厘米，体重约91克。头部和颈部为黑色，身体其余部分为红褐色，前额上有黄色斑块，嘴尖锐，黄色，基部带白色或淡蓝色。最显著特征为其极长的脚趾，使它们能在漂浮的植物上行走。飞行时可见其黄绿色的翼羽和锐利的翼弯刺。","call":"美洲水雉发出尖锐的叫声和嘈杂的鸣叫，尤其是在飞行时或遭遇威胁时更加明显。","habits":"美洲水雉单独或成小群体活动，冬季可能集结成大群。它们活跃，善行走，能轻松地在水面的浮生植物上移动。也擅长游泳和潜水，遇到危险时会迅速奔跑或藏匿于水草中。主要食物包括昆虫、蜗牛等软体动物以及水生植物。","breeding":"繁殖期间，角色反转，雄鸟负责筑巢、孵化和抚养幼鸟，雌鸟则较少参与。雌鸟可能同时与多达四个雄鸟结盟，雄鸟保卫自己的领地。雄鸟在孵化期几乎不离巢，孵化期约为28天，孵化后雄鸟继续照顾幼鸟。","identification":"美洲水雉可通过其独特的外形特征识别，包括长腿、长脚趾、黑色头部和颈部以及红褐色身体。雌雄差异显著，雌鸟体型更大。与肉垂水雉相比，美洲水雉的前额盾牌黄色，而肉垂水雉的为红色。","protection":"IUCN：LC（无危）","distribution":"分布于墨西哥南部至巴拿马西部，包括科苏梅尔岛（墨西哥）、古巴、牙买加和海地岛。偶尔出现在美国得克萨斯州南部。","other":"在某些地区，美洲水雉可能面临因湿地丧失导致的潜在威胁。"},{"name":"肉垂水雉","english_name":"Wattled Jacana","scientific_name":"Jacana jacana","overview":"肉垂水雉（英文名：Wattled Jacana，学名：Jacana jacana），是鸻形目水雉科美洲水雉属的鸟类。拥有独特的长趾，体型中等，遍布南美洲东部，包括巴拿马中西部至阿根廷北部，以及特立尼达岛。成鸟通常全黑或类似美洲水雉的红褐色背部。幼鸟与美洲水雉非常相似，但可通过黄色喙和长趾辨别。飞行时可见黄色翼羽。","appearance":"肉垂水雉长约17-23厘米，雌鸟比雄鸟大。成鸟有栗色背部和翼覆羽，其余部位主要为黑色。飞行时，绿色至黄绿色的飞羽十分显眼，还有黄色骨质翼刺用于自卫和保护幼鸟。头部有红色额盾和褶皱，腿和极长的脚趾呈暗蓝灰色。幼鸟最初全身下部为白色，羽毛中始终带有白色部分。","call":"发出一系列嘈杂的咔嚓声和其他响亮的叫声。","habits":"栖息于永久性和季节性淡水湿地，常见于浮生和浮生-挺水植被区。也出没于浅水区、邻近的农田和草地。在圭亚那，它们在沟渠、运河和小池塘筑巢，常在附近的稻田觅食。记录显示，其活动高度可达委内瑞拉南部的930米，最近一次记录是在哥伦比亚东安第斯山脉的3900米处。以昆虫（成虫和幼虫）、其他无脊椎动物、小型软体动物、小鱼和两栖动物为食。偶尔食用种子和果实，可能意外摄入植物物质。","breeding":"繁殖期因地域而异，潜在全年繁殖，如巴西南部的9月至11月。实行多配偶制，雌鸟保卫并与其1-5个相邻的领地雄鸟繁殖。雌鸟积极排除其他雌鸟，协助雄鸟驱逐入侵者。巢小，通常半淹没，由茎和水生植被构成。一窝四枚淡黄色带深色斑点的蛋，孵化期约28天。孵化和育雏由雄鸟负责，雏鸟为早熟型，出生时下部白色，上部有肉桂色和棕色条纹。雄鸟陪伴、保暖和保护雏鸟，但不喂食。雏鸟能几乎完全潜入水中躲避危险。","identification":"与美洲水雉相比，J. j. hypomelaena的全部栗色羽毛被黑色替代，而J. j. scapularis的栗色肩部有黑色羽毛，外侧初级飞羽为白色。雄鸟的面部装饰和翼展比例相对较小。","protection":"IUCN：LC（无危）依赖于适宜湿地的保护。水稻生产的发展既可能增加栖息地也可能破坏其生存环境，导致繁殖活动的人为干扰加剧。牧场和小水库的开发在南美洲大部分地区增加了栖息地。尽管面临湿地排水的威胁，物种总体上并未受到严重威胁。","distribution":"分布于南美洲东部，包括巴拿马中西部至阿根廷北部，以及特立尼达岛。在圭亚那、委内瑞拉南部、哥伦比亚东安第斯山脉均有记录。","other":"雌鸟在繁殖期间可与多个雄鸟形成群体，雄鸟负责孵卵和照顾幼鸟，而不参与交配。雌鸟在移除本地雌鸟后，有时会杀死三周以下的幼鸟。"},{"name":"领鹑","english_name":"Plains-wanderer","scientific_name":"Pedionomus torquatus","overview":"领鹑（英文名：Plains-wanderer，学名：Pedionomus torquatus），是鸻形目领鹑科领鹑属的鸟类。澳大利亚特有陆栖小型鹤形目单型科鸟类，栖息于中、南部稀疏原生低地草原。体长15–19厘米，雄鸟39–78克，雌鸟57–95克。上体红褐具黑细纹，下体白底黑斑；雌鸟颈具黑白领圈及鲜红颈斑，雄鸟羽色较淡。留鸟，极隐秘，晨昏活动，主食昆虫、蜘蛛及草籽。繁殖期8月至翌年2月，雌鸟营巢于草丛地面，雄鸟孵卵并独自育雏，雏鸟约两月独立。","appearance":"整体似澳洲鹌鹑但更修长，站姿挺拔，具后趾。雄鸟：上体淡红褐带黑纵纹，喉灰白，胸及胁具黑新月纹，翼长79–104毫米。雌鸟：体型较大，翼长95–109毫米，颈具宽黑领圈并白点斑，领圈上方鲜红颈斑，胸带黄褐至赤褐，眼圈、嘴基及腿在繁殖季呈橙黄色。幼鸟似雄成鸟，但下体为深褐圆斑，冠部淡鳞纹不显，覆羽缘更宽。","call":"白昼与夜间均发出低沉、似鸽的共鸣“oo”声，可能仅雌鸟在春季鸣唱；警戒时轻声“chuck”警告雏鸟，以拖长笛音召集幼鸟，并以轻微“irr-irr”回应雏鸟求救声。","habits":"留居于海拔低于300米的稀疏原生草地，植被高度多低于8厘米并散生10–40厘米高植株。日间极少飞行，夜飞呈起伏状以避猛禽；家域约12公顷，常由一对异性共用。杂食，日约三分之一时间觅食，主要啄取地面昆虫、蜘蛛及草籽，兼食藜科种子，雨后啄叶尖水珠，并吞食小石助磨。","breeding":"繁殖期在东南部为8月下旬至11月，若夏季降雨则可延至翌年2月，偏北地区3–6月。雌鸟独占领地，可能一雌多雄；7月配对，若春季过湿则推迟至10–11月。巢为地面浅坑，内衬细草或麦秸，偶覆草作顶；每窝4枚绿白卵，具褐灰斑，雄鸟孵卵23天，雏鸟芥末黄带褐斑，由雄鸟单独抚育约两月，雏鸟离巢时初级飞羽已长成。","identification":"与澳洲鹌鹑相比喙更细、颈腿更长；与同域两种三趾鹑相比体型更大、羽色较素，雄鸟上体斑纹淡，飞行时显白色初级飞羽斑块及宽淡色翼后缘，飞行节奏更吃力。雌雄差异明显：雌鸟具黑白领圈及鲜红颈斑，雄鸟无。","protection":"IUCN: CR（极危）。列入CITES附录Ⅱ。2015年估计成熟个体不足1000只，近三代下降逾90%，主要威胁为原生草地开垦、外来牧草入侵、过度放牧及杀虫剂使用。","distribution":"繁殖及常年留居于澳大利亚内陆东部，包括北维多利亚、中南新南威尔士、东北南澳大利亚及西昆士兰的稀疏低地草原。","other":"属单型科单型属，历史上曾误用于冢雉Leipoa，后经ICZN正式保留现名。栖息地呈破碎化小斑块，90%以上个体位于私有土地，需与农户合作保护。"},{"name":"棕腹籽鹬","english_name":"Rufous-bellied Seedsnipe","scientific_name":"Attagis gayi","overview":"棕腹籽鹬（英文名：Rufous-bellied Seedsnipe，学名：Attagis gayi），是鸻形目籽鹬科大籽鹬属的鸟类。中等体型，分布于南美洲的高山地带，从厄瓜多尔至智利东南部和阿根廷西南部。其独特的‘链甲’状羽纹和锈色腹部使其易于识别。","appearance":"棕腹籽鹬体型健硕，长度约为27至30厘米，体重介于283至403克之间。上体呈复杂交织的锈褐色，具有暗淡线条形成鳞片状效果；下体为淡粉色肉桂色。飞行时，整体呈现均匀的肉桂棕色，翅膀和尾巴无明显图案，翼内侧颜色与身体下部相似。雌雄羽毛相似，幼鸟上体斑纹更为细腻。不同亚种主要在色泽上有差异，latreillii亚种的后腹部颜色更深，simonsi亚种的胸部颜色更偏粉红肉桂色。","call":"在飞行或奔跑时会发出连续的旋律式叫声，如“gly-gly-gly...”或“cul-cul-cul...”，多个个体同时发声时会形成合唱。","habits":"栖息于安第斯山脉的岩石斜坡、碎石堆和其他荒凉的高山地形，靠近雪线，觅食时会下降到最近的沼泽或有垫状植物或低矮植被的区域。在厄瓜多尔，常见于最高海拔的草原。在分布范围的北半部，通常出现在4000至5500米的高处；向南延伸至2000米以上，最南端可达1000米以上。","breeding":"在智利9月至10月间产卵，北至12月。一窝产四枚蛋，蛋壳颜色为赭橄榄色，带有栗色和紫罗兰色斑点，尺寸约为48.1至49.6毫米×33.8至35毫米。雏鸟初生时覆盖着密布黑色条纹和斑点的浅黄色绒毛，不久后被灰色绒毛取代，随后再由羽毛取代。","identification":"在分布范围内无类似物种，注意其短而粗的喙和锈色的下体。与广泛共存的灰胸籽鹬雌鸟相比，本物种体型较大，下体为白色，喉部有白色斑块，喙色为黄而非蓝灰色。","protection":"IUCN：LC（无危）","distribution":"分布于南美，具体包括厄瓜多尔北部山区、智利东南部和阿根廷西南部至圣克鲁斯省南部。"},{"name":"白腹籽鹬","english_name":"White-bellied Seedsnipe","scientific_name":"Attagis malouinus","overview":"白腹籽鹬（英文名：White-bellied Seedsnipe，学名：Attagis malouinus），是鸻形目籽鹬科大籽鹬属的鸟类。体型较丰满，数量稀少，常出没于荒凉的山地草原、沼泽和树线以上的岩石斜坡。冬季会下降至巴塔哥尼亚低地草原，有时可见于路边。外观类似松鸡，具有独特的上体‘锁子甲’斑纹，腹部雪白，遇险时会静止不动以隐藏自己，使观察变得困难。飞行迅速有力，群起时发出响亮的尖叫合唱。","appearance":"体长约26.5至29厘米，体重约310至400克。上体和胸部有精细的黑色、肉桂色和淡黄色鳞状斑纹，下巴和腹部雪白。雌鸟的胸部和下腹部界限不如雄鸟明显，幼鸟颜色略淡，鳞片更重。","call":"飞行叫声为兴奋的‘tu-whit tu-whit’或‘too-ee too-ee…’，连续不断。","habits":"栖息于强风肆虐的山脊和沼泽地带，尤其在越橘灌木丛和Azorella垫状植物附近，以及岩石斜坡与溪流或小型湿地交汇处。繁殖季节分布在海拔650米至2000米之间，非繁殖季则主要出现在巴塔哥尼亚草原的石质地带。","breeding":"筑巢于地面浅坑中，用草、苔藓和地衣铺垫，通常产四枚橄榄黄色带有黑色斑点的蛋，尺寸约41毫米×34-35毫米。","identification":"与北半球松鸡（Lagopus）外观相似，但具有较短而粗壮的喙和鲜明的白色腹部，是其分布范围内无类似物种。","protection":"IUCN：LC（无危）","distribution":"繁殖于智利南部马格达莱纳斯和阿根廷里奥内格罗省南部至合恩角岛屿。非繁殖季降至阿根廷东南部平原。"},{"name":"灰胸籽鹬","english_name":"Grey-breasted Seedsnipe","scientific_name":"Thinocorus orbignyianus","overview":"灰胸籽鹬（英文名：Grey-breasted Seedsnipe，学名：Thinocorus orbignyianus），是鸻形目籽鹬科籽鹬属的鸟类。体型较小、类似鹌鹑的鸟类，主要栖息于南安第斯山脉的高海拔地区，从秘鲁到智利南部和阿根廷均有分布，适应极端寒冷气候，冬季会迁移到较低海拔地带。其特征为圆胖的身体、短腿和短钝的喙。","appearance":"灰胸籽鹬体长19至24厘米，体重介于96至140克之间。雄鸟具有灰色的头部、颈部和上胸部，喉咙白色带有黑色边缘，上体呈现复杂的肉桂色斑纹。飞行时，翅膀上方和下方展现出白色条纹，下腹部和胸部为白色，与上胸部由一条狭窄的黑色带隔开。雌鸟的头部和胸部呈淡黄色，伴有深色重叠的条纹。两种亚种外观相似，但T. o. ingae的翅膀和腿部较短。","call":"灰胸籽鹬的鸣唱为重复的鸽子般的“coocoop...coocoop...coocoop...”，每秒约两音节，也可被描述为“pooko-pooko-pooko...”或“poocuy-poocuy-poocuy...”。在日出和日落时的展示飞行中也会发出这种声音，音调时升时降。当受惊时，会发出尖锐的‘chrp’声。","habits":"灰胸籽鹬偏好安第斯山脉的普纳草原，常见于低矮密集的植被或靠近沼泽的短草地带，海拔高度在3400至5000米之间。它们通常成对或小家庭群出现，以草本植物和多肉植物的芽和叶尖为食。在季节性迁移中，它们可能下降至海平面附近的低地。","breeding":"繁殖季节从10月至11月，有时延续至1月至2月。灰胸籽鹬在草地或植被丛中筑巢，通常靠近水源。一窝通常有四枚蛋，颜色为玫瑰白色，带有灰色或棕色斑点，大小约为36.4至40.5毫米×26.1至27.7毫米。雏鸟的绒毛呈淡紫色至肉桂色，有复杂的黑色带状图案和密集的白色羽尖。","identification":"灰胸籽鹬与小籽鹬相比，体型更大，雄鸟的喉咙和胸部的黑色边缘更宽，两者间有明显的区别。雌鸟之间的差异主要体现在较为暗淡的黄色裸露部分和喉部白色斑块的黑色边界更加明显。","protection":"IUCN：LC（无危）","distribution":"灰胸籽鹬的繁殖区遍布南美洲，从秘鲁的山区延伸至智利南部和阿根廷。非繁殖季节，它们会迁移到邻近的低地。","other":"灰胸籽鹬在Tierra del Fuego岛冬季时会撤离，此时在其分布范围内可能会形成较大的群体。"},{"name":"小籽鹬","english_name":"Least Seedsnipe","scientific_name":"Thinocorus rumicivorus","overview":"小籽鹬（英文名：Least Seedsnipe，学名：Thinocorus rumicivorus），是鸻形目籽鹬科籽鹬属的鸟类。体型较小、结构紧凑的鸟类，常被比作鹌鹑。分布于南美，包括阿根廷、玻利维亚、智利和秘鲁等地。在阿根廷的巴塔哥尼亚草原、安第斯山脉的沙石平原、沿海沙丘及沙漠等干旱地带生活，有时以成对或小群体出现，非繁殖季节时可能形成较大的群落。","appearance":"小籽鹬的体长在16-19厘米之间，体重约48-60克。其上体色彩隐蔽，斑点和细纹比同科的灰胸籽鹬更明显，但飞行中的翼型相似，尾部楔形更显著。雄鸟脸部、颈部和胸部呈均匀灰色，有黑色边界，与白色喉部和下体相连，中央有一条黑线贯穿。雌鸟头部、颈部和胸部的灰色被淡色取代，有模糊的暗色标记；幼鸟类似雌鸟，但缺乏明显的暗色喉部边界。不同亚种在大小和整体色彩上有差异。","call":"被惊飞的小籽鹬会发出低沉的“juk”声，可能重复两次。领地内的雄鸟会在低矮的土丘、灌木或围栏上，或在飞行中发出一系列节奏重复、喉咙音浓重的‘kuk’、‘toop’或‘kwoo’音节，通常在黎明前或偶尔在白天展示时发出，声音空洞，通常以三连音呈现。","habits":"小籽鹬主要栖息于半沙漠地带，草丛稀疏，低矮草本或肉质植物较多的环境。它们适应了干燥的条件，可以在从沙滩到开阔草原，甚至北智利的一些沙漠地带生存。迁徙行为显示，大多数巴塔哥尼亚的个体在冬季迁徙，可能离开南部范围，向北最远可达阿根廷的门多萨和南美东部的乌拉圭。","breeding":"小籽鹬的繁殖期在8月至2月，可能有多次连续繁殖。它们在沙土地上挖掘巢穴，有时用动物粪便铺垫。一窝通常有四个带有红褐色斑点的灰色蛋，尺寸约为29.9-35毫米×21.6-24.1毫米。孵化期大约26天，雏鸟覆盖着淡紫色至肉桂灰色的绒毛，有黑色条带和斑点，背部有两条由密集的白色绒毛尖端形成的带子，大约7周后离巢。","identification":"与灰胸籽鹬相比，小籽鹬体型较小，偏好岩石较少的安第斯山脉生境，雄性小籽鹬胸部有独特的黑色Y形图案，而灰胸籽鹬的胸部是单一的灰色。","protection":"IUCN：LC（无危）","distribution":"小籽鹬广泛分布在南美洲，从厄瓜多尔西南部的低地沿海至智利北部，秘鲁南部山区至阿根廷西北部，以及巴塔哥尼亚低地。","other":"小籽鹬在人类影响有限的区域似乎适应良好，如灌溉计划有助于秘鲁沙漠的耕作。"},{"name":"高原鹬","english_name":"Upland Sandpiper","scientific_name":"Bartramia longicauda","overview":"高原鹬（英文名：Upland Sandpiper，学名：Bartramia longicauda），是鸻形目丘鹬科高原鹬属的鸟类。大型的沙鹬，与鹬科中的杓鹬关系密切。别称有upland plover和Bartram's sandpiper，俗称papabotte。属于Bartramia这一单型属，以美国自然学家威廉·巴特拉姆命名。该物种拥有长尾，这是其学名longicauda的由来。高原鹬在北美的内陆草甸和开阔地带筑巢，冬季则迁徙至南美南部的潘帕斯草原。","appearance":"成年高原鹬长约30厘米，翼展约66厘米，平均体重170克。其最显著的特征是拥有一个小巧的鸽子状头部，位于细长的颈部之上。背部和翅膀布满黑色和棕色的大理石状花纹，颈部和胸部有深棕色的条纹，腹部和尾下覆羽为白色。尾巴相对较长，眼圈为白色，腿部呈黄色。雌鸟体型略大于雄鸟，体重介于121-246克之间，而雄鸟则在112-179克之间。幼鸟与成鸟相似，但头部色泽较为平淡，缺乏成鸟的色彩对比，上半身的羽毛边缘更显苍白。","call":"高原鹬具有独特的长而圆润的‘狼哨’叫声，这种叫声在飞行中最为明显，通常由柔和的潺潺颤音开始，逐渐升高至响亮的口哨声，声音高低起伏，极具辨识度。","habits":"高原鹬偏好开放的草地环境，而非典型的海岸栖息地。它们常见于机场、蓝莓农场和废弃的矿场等开阔地带。它们会在田野中觅食，主要以昆虫、蜗牛、蚯蚓和种子为食。这种沙鹬的迁徙路线跨越南北美洲，冬季会前往南美洲的潘帕斯草原。","breeding":"高原鹬的繁殖季节从早夏持续至晚夏。它们在密集的草丛中地面筑巢，每窝产卵四枚。双亲共同照顾幼鸟，有时会展示引诱行为以保护巢穴和幼鸟免受捕食者的侵扰。","identification":"高原鹬凭借其独特的身形、颜色、鸣声和对干燥草原栖息地的偏好，很容易与所有其他涉禽区分开来。黄胸滨鹬是最接近的相似物种，但因体型较小、比例紧凑、喙和颈短，易于区分。","protection":"IUCN：LC（无危）","distribution":"繁殖区域主要位于北美内陆草甸，从阿拉斯加东部至加拿大北部，向东南延伸至加拿大东部和新英格兰，南部至俄克拉荷马州东北部和宾夕法尼亚州东南部，西部至俄勒冈州东北部和爱达荷州中部。非繁殖季节，它们迁往南美洲的潘帕斯草原，主要分布在巴拉圭南部、巴西南部、乌拉圭和阿根廷东北部。","other":"高原鹬的数量曾随19世纪初期森林的清理而增加，但在19世纪后期由于过度狩猎而急剧下降。目前，它们在北美中西部稳定存在，但在东部地区分布稀疏。"},{"name":"太平洋杓鹬","english_name":"Bristle-thighed Curlew","scientific_name":"Numenius tahitiensis","overview":"太平洋杓鹬（英文名：Bristle-thighed Curlew，学名：Numenius tahitiensis），是鸻形目丘鹬科杓鹬属的鸟类。中型涉禽，以其长而弯曲的喙和独特的腿部刚毛闻名。在夏威夷群岛和阿拉斯加之间迁徙，是唯一一种在海洋岛屿上越冬的迁徙性涉禽。分布于北美洲西部和南太平洋岛屿，拥有独特的飞行能力，能够进行长时间的不间断飞行。","appearance":"体型中等，总长400至440毫米，体重310至800克，喙长70至110毫米，向下弯曲。头部有明显的条纹，上体颜色从深棕色到灰棕色，下体颜色从奶油色到偶尔的丰富肉桂色。最显著的特征是臀部和上尾覆羽的亮肉桂色，以及腿上的刚毛状羽毛。性别间羽毛相似，但雌鸟通常较大。","call":"叫声为响亮的‘kee-oo-ee’。","habits":"栖息于湿地、沙丘、岩石海岸、牧场和高尔夫球场。主要在夏威夷西北群岛至南太平洋岛屿越冬，夏季部分年幼个体留在繁殖区。迁徙期间，能够在开阔海域进行长达数千公里的不间断飞行。","breeding":"繁殖季节，成鸟返回阿拉斯加的繁殖地，通常在5月初至中旬到达。雄鸟保卫大片领地，使用壮观的空中展示求偶。双方共同照顾雏鸟几周，之后大多数成鸟离开，留下雏鸟聚集在一起，由少数成鸟照看。","identification":"与蛎鹬相似，但色调更温暖，臀部呈肉桂色。在近距离观察时，腿上的刚毛状羽毛明显。飞行时，橙色至肉桂色的臀部和上尾覆羽以及尾羽上的深棕色和肉桂色条纹与上体形成鲜明对比。","protection":"IUCN：NT（近危）","distribution":"繁殖于阿拉斯加西部的低北极高地苔原，包括苏厄德半岛北部和育空三角洲北部。越冬于太平洋岛屿，包括密克罗尼西亚、斐济、图瓦卢、汤加、夏威夷群岛、萨摩亚、法属波利尼西亚和托纳雷瓦（彭林环礁）。","other":"太平洋杓鹬是最后一个被描述巢穴和卵的北美洲鸟类之一，直到1948年才在育空河以北发现其巢穴。"},{"name":"中杓鹬","english_name":"Eurasian Whimbrel","scientific_name":"Numenius phaeopus","overview":"中杓鹬（英文名：Eurasian Whimbrel，学名：Numenius phaeopus），是鸻形目丘鹬科杓鹬属的鸟类。大型涉禽。广泛分布于欧亚大陆的亚北极地区，南至苏格兰，是常见且分布广泛的杓鹬之一。中杓鹬以其独特的外观和叫声闻名。","appearance":"中杓鹬体长37-47厘米，翼展75-90厘米，体重270-493克。全身灰褐，背部白色（仅限于某些亚种），拥有长而弯曲的喙，喙中部有明显的折角而非平滑曲线。头部具有中央冠纹和明显的眉纹。","call":"其叫声为连续的哨音，延长成颤音，模仿了它的英文名'whimbrel'。","habits":"中杓鹬夏季栖息于北极和近北极的苔原森林及泰加林地带，偏好沼泽、湖泊和河岸草地。冬季迁徙至非洲、南亚和澳大利亚的海岸。它们常单独或小群活动，但在迁徙和栖息地会形成大群。以昆虫、螃蟹和其他小型无脊椎动物为食。","breeding":"繁殖期为5-7月，筑巢于湖泊、河流岸边的沼泽湿地，巢为地面上的浅坑，内衬苔藓、草茎和树叶。每窝产卵3-5枚，多为4枚，卵色蓝绿或橄榄褐，带有黑褐色或灰色斑点。孵化期约24天。","identification":"中杓鹬与较大的杓鹬相比，体型较小，喙更短且向下弯曲。与新世界的同类物种区别在于，欧洲和亚洲的中杓鹬臀部主要是白色的，而新世界物种的臀部颜色与身体其余部分相似。","protection":"IUCN：LC（无危）","distribution":"繁殖于亚北极苔原，从东北格陵兰和北苏格兰，通过俄罗斯北部至楚科奇半岛。非繁殖季节广泛分布于温带到热带的帕拉尔地区海岸，包括英国南部、马德拉群岛至佛得角、地中海西部、非洲、印度洋、澳大利亚至新西兰北部，以及密克罗尼西亚。","other":"历史上，由于迁徙途中的猎杀，中杓鹬数量曾大幅下降，但已逐渐恢复。气候变化、栖息地破坏和禽流感对其构成威胁。"},{"name":"小杓鹬","english_name":"Little Curlew","scientific_name":"Numenius minutus","appearance":"小杓鹬体长28-34厘米，体重118-221克，翼展68-71厘米。是最小的杓鹬，外观与或大黄脚鹬相似，具短而稍弯的喙，头部圆润，眼大，头上有深色眼纹，棕色顶纹和淡色眉纹；背部和臀部呈淡褐色。与极北杓鹬相似，但羽色更淡，腹部更白，翅膀较短，静止时无明显初级飞羽突出。雌鸟平均稍大，翼长184-192毫米，雄鸟178-187毫米。幼鸟与成鸟非常相似，但肩羽有淡色斑点和边缘，翼覆羽宽边淡色；侧腹和胸部条纹较少，飞行时次级飞羽比成鸟暗。无季节性变化。","call":"小杓鹬的鸣叫为重复的口哨声，叫声高亢而尖锐，类似于两个或三个音符的柔和音乐般的‘te te te’声，以及较为刺耳的‘tchew-tchew-tchew’警报声。","habits":"小杓鹬栖息于亚高山森林的开阔地带，如火烧迹地或稀疏的落叶松林地，迁徙时可见于沿海滩涂。非繁殖季，栖息于内陆草地、耕地或靠近淡水的地区，主要在澳大利亚北部，但也南至南澳大利亚的圣基尔达。喜集群，形成可观的群体。主要以昆虫、蜘蛛、植物种子为食，通过啄食和浅探的方式觅食。","breeding":"繁殖期为6月至7月，在亚高山森林或灌木地带的开阔林地或水边干芦苇地的凹坑中筑巢。巢由枯草构成，每窝产卵3-4枚，卵色为绿色或橄榄皮黄色，带有褐色或石板灰色斑点。双亲共同孵卵22-23天，幼鸟在五周后离巢。","identification":"小杓鹬与极北杓鹬相似，但羽色更淡，腹部更白，翅膀较短；与中杓鹬相比，体型较小，脸纹不同，喙较长。与中杓鹬的区别在于脸部条纹和喙的长度。","protection":"IUCN：LC（无危）。CITES: 附录I（1997年生效）。中国国家重点保护等级：二级（1989年生效）。","distribution":"繁殖于西至东西伯利亚的亚高山森林地带，非繁殖期分布于澳大利亚北部至南澳大利亚的圣基尔达，以及新几内亚的Trans-Fly和Port Moresby地区。迁徙时经过中国南部和东部。","other":"小杓鹬是强烈迁徙性的物种，冬季在澳大利亚和新几内亚等地。在澳大利亚，得益于提供水源点和大片草地用于畜牧业，数量受益。"},{"name":"极北杓鹬","english_name":"Eskimo Curlew","scientific_name":"Numenius borealis","overview":"极北杓鹬（英文名：Eskimo Curlew，学名：Numenius borealis），是鸻形目丘鹬科杓鹬属的鸟类。别名: 爱斯基摩勺鹬、北极勺鹬、北极麻斑勺鹬，中小型候鸟，体型约30厘米长，曾广泛分布于北极低地苔原，南迁至阿根廷的彭巴斯草原。20世纪初因人类过度猎杀，导致其野外数量急剧下降，现今被认为是极度濒危或可能已灭绝。","appearance":"极北杓鹬体长30-35厘米，身高约20-25厘米，体重在200-350克之间。它拥有长而略向下弯曲的暗灰色喙，上部羽毛呈斑驳的棕色，下部羽毛呈浅棕色，飞行时可见其肉桂色的翼内侧。与之相似的有哈德逊湾杓鹬和美洲中杓鹬，但体型更小。","call":"鸣叫声描述不明，但包括清晰的哨声。","habits":"极北杓鹬以视觉和探查的方式觅食，主要食物为昆虫、浆果、蜗牛和其他无脊椎动物。它们在加拿大进行秋季迁徙时大量食用浆果。迁徙路线经过北美大陆，穿越大西洋至南美洲过冬。","breeding":"繁殖行为不详，但记录显示会在6月筑巢，巢置于开阔地带地面，由干草或叶子构成，每窝产卵2枚，蛋壳绿色带棕色斑点。","identification":"与小杓鹬形成物种对，但体形更大、翼展更宽、腿更短，羽毛色调更温暖。主要辨识特征为初级飞羽下表面无条纹。","protection":"IUCN：CR (PE)（极危（可能已灭绝））","distribution":"繁殖于北美西北部低北极苔原地带，包括加拿大西北地区的北部（可能还包括阿拉斯加北部，但可能已经灭绝）。非繁殖期分布于南美洲东南部的草原地带，包括巴西东南部、乌拉圭和阿根廷东北部（可能已灭绝）。","other":"最后一次确证的目击是在1963年，自1987年后再无可靠记录。尽管受到阿根廷、巴西、加拿大、墨西哥和美国的全面保护，自1916年起禁止狩猎，但该物种可能已经灭绝。"},{"name":"长嘴杓鹬","english_name":"Long-billed Curlew","scientific_name":"Numenius americanus","overview":"长嘴杓鹬（英文名：Long-billed Curlew，学名：Numenius americanus），是鸻形目丘鹬科杓鹬属的鸟类。大型北美洲涉禽，亦称‘镰刀鸟’或‘蜡烛棍鸟’，以其异常长而弯曲的喙著称。分布于北美西部及中部的草原地带，冬季迁徙至海岸和内陆湿地。","appearance":"体长50-65厘米，翼展24.5-35.5英寸，体重介于490-950克。喙长11.3-21.9厘米，向下弯曲，雌鸟体型较雄鸟大，喙亦更长。全身泛着淡肉桂色，颈部和腹部色泽尤甚，头部带有褐色条纹。","call":"鸣声为响亮的‘cur-lee！’，是其名字的由来。","habits":"栖息于开阔的田野、沼泽及海滩，以小甲壳类、昆虫和其他小型无脊椎动物为食。冬季在湿地、潮间带、泥滩、浅水农田和海滩活动。","breeding":"在中西部北美的草地上筑巢，通常在日落后进行求偶飞行，一雄多雌制。巢为浅坑，铺垫草叶，每窝产卵4枚，孵化期约22-24天。","identification":"与斑背杓鹬、云斑塍鹬、大杓鹬相比，体形更大，喙更长，色彩更为鲜艳的肉桂色。与白腰杓鹬区别在于喙的形状和颜色。","protection":"IUCN：LC（无危）","distribution":"繁殖于加拿大西南部至美国西南部，冬季迁徙至美国南部沿海及墨西哥、中美洲的沿海和内陆。","other":"19世纪末因猎杀数量大幅下降，近现代有所恢复。在旧金山的Candlestick Point和Candlestick Park体育场命名中留下了历史痕迹。"},{"name":"大杓鹬","english_name":"Far Eastern Curlew","scientific_name":"Numenius madagascariensis","overview":"大杓鹬（英文名：Far Eastern Curlew，学名：Numenius madagascariensis），是鸻形目丘鹬科杓鹬属的鸟类。又名: 红背大勺鹬、红腰勺鹬、彰鸡，大型涉禽，以超长的弯刀状喙闻名。其体长60-66厘米，翼展可达110厘米，体重介于565-1150克之间，是世界上最大的沙锥鸟。繁殖季节在东北亚的沼泽和湖岸，非繁殖季节则主要在澳大利亚沿海地区。","appearance":"体长53-66厘米，体重390-1350克，雄鸟平均比雌鸟轻约110克；翼展97-110厘米。拥有最长的喙，长达184毫米。头部图案简单，上体有暗色羽心和淡色边缘；胸部和两侧细纹密布；翼下覆羽密集条纹棕色。与白腰杓鹬相比，背部、腰部及翼下覆羽非白色，色彩更暖，腰部呈淡褐色。","call":"叫声尖锐清脆，常重复发出“cuuue-reee”的呼啸声，音调比白腰杓鹬更深沉。","habits":"栖息于开阔的苔藓沼泽、过渡性沼泽和湿地牧场，以及小型湖泊的沼泽岸线。非繁殖季节主要在沿海地区，如河口、红树林沼泽、盐沼、潮间带泥滩或沙滩，尤其偏好有广泛海草（Zosteraceae）草甸的地区。以昆虫、贝类、甲壳类和蠕虫为食，利用长喙探测泥沙中的猎物。","breeding":"繁殖期为4月至7月，营巢于沼泽湿地或湖边沼泽的土丘上，巢较为简陋，每次产卵4枚，卵呈橄榄褐色或橄榄绿色，带有褐色或绿褐色斑点。","identification":"与白腰杓鹬相比，大杓鹬色泽更深，背部和尾部呈褐色，腹部皮黄色，翼下覆羽具明显横纹，喙更长且显著下弯。","protection":"IUCN：EN（濒危）。在中国台湾，大杓鹬曾在大肚溪口形成大量群体，但由于栖地破坏，数量曾大幅下降。现被列入《国家保护的有益的或者有重要经济、科学研究价值的陆生野生动物名录》及《世界自然保护联盟》易危物种名录。","distribution":"繁殖于俄罗斯远东地区至中国东北，非繁殖季节分布于澳大利亚、台湾、东南亚、菲律宾等地。","other":"迁徙过程中，大杓鹬会在中国东部地区短暂停留，数量不多。"},{"name":"细嘴杓鹬","english_name":"Slender-billed Curlew","scientific_name":"Numenius tenuirostris","overview":"细嘴杓鹬（英文名：Slender-billed Curlew，学名：Numenius tenuirostris），是鸻形目丘鹬科杓鹬属的鸟类。体型中等的杓鹬，长度介于36-41厘米之间，翼展可达77-88厘米。颜色和外观与白腰杓鹬相似，但在胸部、尾巴及翼底呈现更多的白色。细嘴杓鹬的喙较短且更纤细，底部较为直挺。这种杓鹬曾经在西伯利亚西南部繁殖，但确切繁殖范围已几乎未知。是候鸟，冬季会迁徙至地中海地区及南阿拉伯半岛的沿海地带。细嘴杓鹬被认为是极度濒危物种，全球现存数量可能不足50只。","appearance":"细嘴杓鹬成鸟在繁殖期上身呈灰褐色，下背部和臀部为白色，下身白色带有深褐色斑纹。两侧有圆形或心形斑点。雌鸟喙较雄鸟长，避免两性间的食物竞争。非繁殖期的成鸟两侧斑点较少。雏鸟两侧有褐色条纹，心形斑点在第一年末显现。与白腰杓鹬相比，细嘴杓鹬胸部、尾巴及翼底更白，喙更短、更细，基部更直。","call":"细嘴杓鹬发出的叫声类似白腰杓鹬，但音调更高，旋律更优美，且更短促。警报声为快速的“cu-ee”。","habits":"细嘴杓鹬主要在软泥中使用喙寻找小型无脊椎动物，也会在地面上捡拾其他小食物。它们在非繁殖季节高度群居，常与其他杓鹬如白腰杓鹬混群。栖息地包括广泛的泥炭沼和森林边缘的小岛屿，迁徙期间出现在沿海泻湖、盐沼、咸水或盐湖以及草原地区的鱼塘。","breeding":"细嘴杓鹬的繁殖生物学知之甚少，平均每个巢有四枚蛋。巢建于密集植被覆盖的干燥地区，由干草构成，位于浅洼中。幼鸟在7月初离巢，物种在8月下半月离开繁殖地。","identification":"细嘴杓鹬与白腰杓鹬相比，胸部、尾巴和翼底更白，喙更短且纤细，基部更直。白腰杓鹬两侧的斑点呈箭头状，而细嘴杓鹬的斑点呈圆形或心形。头部图案，具有深色顶冠和白色的眉线，类似于中杓鹬，但后者有中央顶冠条纹，整体标记更明显。","protection":"IUCN：CR（极危）","distribution":"繁殖区主要集中在西伯利亚西南部，具体位置现已不明。非繁殖期分布于北非沿海的突尼斯和摩洛哥，以及阿拉伯半岛南部。近几十年来，记录显著减少，可能已经灭绝。","other":"细嘴杓鹬历史上在欧洲西部、加那利群岛、亚速尔群岛、阿曼、加拿大及日本有迷鸟记录。最后一次确凿记录是在2004年，自那时起，该物种可能已灭绝。"},{"name":"白腰杓鹬","english_name":"Eurasian Curlew","scientific_name":"Numenius arquata","overview":"白腰杓鹬（英文名：Eurasian Curlew，学名：Numenius arquata），是鸻形目丘鹬科杓鹬属的鸟类。属于大型涉禽，广泛分布于温带欧洲与亚洲。此物种在欧洲通常简称‘杓鹬’，苏格兰地区则称为‘whaup’。其最显著的特征是长而弯曲的喙，以及背部的白色斑块。白腰杓鹬繁殖于从沿海沼泽到高沼地的各类草地生境，冬季则主要在沿海低地活动。","appearance":"白腰杓鹬体长50-60厘米，翼展80-100厘米，体重410-1360克，雌鸟通常比雄鸟大，尤其体现在喙的长度上。全身灰褐色，背部具白色斑块，翼下覆羽白色，腹部白色，两胁有条纹。与中杓鹬和大杓鹬相比，白腰杓鹬的体型更大，头部无条纹，喙长且弯曲。","call":"白腰杓鹬的叫声响亮，常发出‘coor-lee’的叫声。","habits":"白腰杓鹬主要栖息于各种开阔生境，包括沼泽、草地、森林边缘的潮湿地带、农田、沙洲和沿海沼泽。它们迁徙时会经过湿地和农田。食物主要包括甲壳类、软体动物、蠕虫、昆虫及其幼虫，偶尔也会捕食小鱼和蛙类。","breeding":"繁殖季节为5月至7月，白腰杓鹬会在沼泽湿地、湖泊或溪流附近的干燥地面筑巢，每窝产卵4枚，偶尔3-6枚，由双亲共同孵化，孵化期约28-30天。","identification":"白腰杓鹬与大杓鹬的区别在于腰部较白，大杓鹬的嘴更长且下弯更明显。与中杓鹬相比，白腰杓鹬体型更大，头部无条纹，嘴相应更长。","protection":"IUCN：NT（近危）, 国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"繁殖于亚北极和温带欧亚大陆，从法罗群岛、英国、斯堪的纳维亚半岛至法国南部，向东至哈萨克斯坦北部、蒙古北部、外贝加尔地区、中国东北和内蒙古。非繁殖期分布于非洲、地中海、中东、印度次大陆、东南亚、日本南部、朝鲜半岛、中国东南部、台湾和菲律宾等地。","other":"白腰杓鹬的全球数量估计在77,000至1,065,000之间，但由于栖息地丧失和农业集约化，多个地区种群正在下降。"},{"name":"哈德森杓鹬","english_name":"Hudsonian Whimbrel","scientific_name":"Numenius hudsonicus","overview":"哈德森杓鹬（英文名：Hudsonian Whimbrel，学名：Numenius hudsonicus），是鸻形目丘鹬科杓鹬属的大型涉禽。其英文名源自模仿其鸣叫的声音。曾为中杓鹬的一部分，后基于遗传和形态差异被独立为单独物种。繁殖于北美洲北极圈低地的苔原地带，包括阿拉斯加西部、北部和中部，加拿大西北部以及哈德森湾西南岸。","appearance":"体型较大，长度约37至47厘米，翼展可达75至90厘米，体重介于270至493克。全身灰褐色，背部颜色与上体一致，拥有弯曲的长喙，成年雌鸟的喙最长，带有明显的折角而非平滑曲线。头部有中央冠纹和显著的眉纹。","call":"发出涟漪般的哨声，叫声延长成颤音。","habits":"迁徙性鸟类，冬季栖息于南北美洲的海岸线，迁徙期间亦沿岸活动。喜群居，非繁殖季节尤为明显。哥伦比亚的红树林为其提供了远离陆地捕食者的休息地，同时接近觅食领地，但并不远离人类活动区域。","breeding":"以软泥中的小无脊椎动物和表面的小蟹为食，迁徙前浆果成为重要食物来源。巢穴为裸露的苔原或北极沼泽地上的浅坑，每窝产3至5枚卵。成鸟对巢区极具防御性，会攻击靠近的人类。","identification":"与范围内其他大型杓鹬相比，哈德森杓鹬较小，具有较短且向下弯曲的喙，头部有中央冠纹和明显的眉纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美低地北极苔原，包括阿拉斯加和加拿大部分地区。非繁殖期广泛分布于温带至热带的西半球沿海地区，如美国加州中部、东海岸南部、墨西哥湾至南美最南端，以及墨西哥远西的Revillagigedo群岛和Galapagos群岛。","other":"19世纪末，迁徙途中的猎杀曾严重减少其数量，但此后种群已恢复。"},{"name":"斑尾塍鹬","english_name":"Bar-tailed Godwit","scientific_name":"Limosa lapponica","overview":"斑尾塍鹬（英文名：Bar-tailed Godwit，学名：Limosa lapponica），是鸻形目丘鹬科塍鹬属的鸟类。别名: 斑尾鹬，体型较大的候鸟，以其长而略微上翘的双色喙闻名。繁殖季节时，雄鸟呈现深砖红色的下体，雌鸟则为较淡的橙色；非繁殖季节整体为灰褐色，腹部白色。主要分布于北极圈内的苔原地带，如远北欧、西伯利亚北部和阿拉斯加，冬季则迁徙至温带至热带的海岸线，如欧洲南部、非洲、东南亚、澳大利亚和新西兰。","appearance":"斑尾塍鹬拥有37至39厘米的体长，喙长8至12厘米，体重介于200至720克之间。其翅膀长而均匀，尾部具条纹，腿呈绿灰色，喙尖黑色，基部粉色。繁殖羽时，雄鸟颈部、胸部和腹部为不间断的砖红色，雌鸟则为更暗淡的栗色至肉桂色。非繁殖羽时，整体为灰褐色，带有较暗的羽轴纹，下体白色。幼鸟与非繁殖羽相似，但更显暖色系，胸部和侧翼有细纹。","call":"斑尾塍鹬的叫声特征尚未详述。","habits":"斑尾塍鹬偏好沿海岸线的栖息地，尤其在非繁殖季节，常成群出现在滩涂、咸水泻湖，利用其长喙在泥滩中觅食。它们的食谱包括甲壳类、蠕虫、昆虫和植物种子。春季迁徙期间，会与中杓鹬和红腰杓鹬混群飞行，雄鸟会在迁徙至越冬地时进行炫耀飞行。","breeding":"在西伯利亚、堪察加和阿拉斯加等地繁殖，巢建于苔原的塍脊草丛间，通常产卵3至5枚，卵色为橄榄色或绿色，带有暗褐色斑点。雌雄双方共同参与孵化和育雏过程，孵化期约为21天。","identification":"与黑尾塍鹬相比，斑尾塍鹬的尾部有黑白相间的横纹，且缺乏白色的翼带。雌鸟比雄鸟大，喙更长，羽毛颜色较为暗淡。","protection":"IUCN：NT（近危）","distribution":"繁殖区分布于北极圈内的低海拔苔原地带，包括远北欧、西伯利亚北部和阿拉斯加。非繁殖区广泛分布于温带至热带的海岸线，覆盖英国、南欧、地中海西部、非洲、马达加斯加、中东、印度次大陆、东南亚、印尼群岛、琉球群岛、中国东南沿海、台湾、菲律宾、新几内亚至美拉尼西亚和新西兰，以及斐济。","other":"斑尾塍鹬的迁徙路线惊人，尤其是阿拉斯加繁殖种群（L. l. baueri）迁徙至澳大利亚和新西兰，单程飞行距离可达11,000公里，为已知最长的无停歇迁徙。"},{"name":"黑尾塍鹬","english_name":"Black-tailed Godwit","scientific_name":"Limosa limosa","overview":"黑尾塍鹬（英文名：Black-tailed Godwit，学名：Limosa limosa），是鸻形目丘鹬科塍鹬属的鸟类。中型长腿长喙的涉禽，体型约36-44厘米。繁殖季节时，头部和胸部呈现亮丽的栗色，非繁殖期则为灰褐色，腹部具深色条纹。常见于草类丛生的湿地繁殖，冬季则广泛分布于淡水和咸淡水沼泽。该物种在全球范围内数量估计为634,000至805,000只，被列为近危物种。","appearance":"黑尾塍鹬体长36-44厘米，体重雄鸟160-440克，雌鸟244-500克，翼展70-82厘米。其特征为高挑优雅的身姿，胸腹部分为栗色，腹部下方白色，背部和肩羽有淡红、黑、灰相间的斑点。喙长且直，基部橙粉色，腿部修长。繁殖期雄鸟羽毛更鲜艳，雌鸟颜色较淡，且喙平均比雄鸟稍长。","call":"黑尾塍鹬在繁殖地较为活跃，发出连续的‘gruu-too-gruu-too-gruu-too-’或快速兴奋的‘whitu-whitu-whitu-whitu-’叫声，交替出现。此外，也会发出类似凤头麦鸡的拉长鼻音‘kyeeeeh’，短促的‘kek’声或类似结巴的系列叫声。","habits":"黑尾塍鹬偏好湿地环境，如草类湿地、沼泽、牧场和稻田，冬季则迁徙至受保护的河口、泻湖、沙滩、盐沼和内陆湿地。它们主要通过在深水中用长喙探测来觅食，食物包括昆虫、蠕虫、软体动物、蜘蛛、鱼卵和植物种子。","breeding":"繁殖期为4月至6月中旬，通常在短草覆盖的地面筑巢，每次产卵4枚，孵化期为22-24天，由双亲共同承担。幼鸟孵化后25-30天即可离巢。黑尾塍鹬对春季温度敏感，极端天气事件可能影响繁殖成功率。","identification":"与斑尾塍鹬相比，黑尾塍鹬体型更大，嘴部不上翘，尾部前半部接近黑色，腰部和尾基白色。在非繁殖期，头部、胸部和上体颜色单一，与斑尾塍鹬的胸部和背部条纹形成对比。","protection":"IUCN：NT（近危）","distribution":"繁殖区域包括冰岛、法罗群岛、英国、斯堪的纳维亚半岛至法国西南部、俄罗斯西北部、哈萨克斯坦北部、蒙古北部至楚科奇半岛、勘察加半岛、库页岛、阿穆尔地区和中国东北地区。非繁殖期分布于南欧、非洲（除南非）、中东、东南亚、印度尼西亚群岛、新几内亚南部、澳大利亚、琉球群岛、台湾岛、中国大陆东南部和菲律宾。","other":"黑尾塍鹬是荷兰的国鸟。"},{"name":"棕塍鹬","english_name":"Hudsonian Godwit","scientific_name":"Limosa haemastica","overview":"棕塍鹬（英文名：Hudsonian Godwit，学名：Limosa haemastica），是鸻形目丘鹬科塍鹬属的鸟类。曾被称作Ring-tailed Marlin或Goose-bird，是最不为人所知的四种塍鹬之一。体型较小，主要分布于加拿大和阿拉斯加的草地苔原，冬季迁徙至南美洲南部。全球数量约5万至7万只，集中于少数几个特定地点。繁殖季节的雄鸟具有丰富的赤褐色腹部和杂乱的黑色、灰色、白色背部图案。雌鸟色彩较淡。","appearance":"体长约39厘米，腿长，喙长且微向上弯曲，适合在草地和泥泞环境中觅食。繁殖期的雄鸟有深红色腹部和不规则的黑色、灰色、白色背部，雌鸟颜色更淡。非繁殖期全身呈灰褐色，幼鸟有更多肉桂色调。所有羽毛状态中都有白色眉纹，最明显的野外识别特征是黑色的翅膀下表面，仅在飞行中可见。","habits":"栖息于加拿大和阿拉斯加靠近树线的草地苔原繁殖，冬季迁徙至南美洲南部。迁徙期间出现在泛洪的田野、海滩、泥滩和浅水池塘，有时与斑翅鹬s或黄腿鸟混群。食物以昆虫和甲壳类为主。","breeding":"在靠近开阔水域的沼泽地或河口地带筑巢，巢为浅地洞，内衬苔藓或树叶。繁殖季节通常产4枚橄榄色带有深色斑点的蛋，孵化期约为22天，双亲共同照料幼鸟。","identification":"与黑尾塍鹬和斑尾塍鹬相比，棕塍鹬体型较小，颜色更深，黑尾塍鹬有更宽的翼条纹和尾部白色带，斑尾塍鹬的翼条纹不明显，尾部黑色带更宽。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于北美低北极苔原地带，从阿拉斯加西部到加拿大中部。非繁殖区主要在南美洲温带湿地沿海，高度局部化，包括秘鲁北部至智利南部的东太平洋南部海岸和巴西南部至阿根廷南部的大西洋西南海岸。"},{"name":"云斑塍鹬","english_name":"Marbled Godwit","scientific_name":"Limosa fedoa","overview":"云斑塍鹬（英文名：Marbled Godwit，学名：Limosa fedoa），是鸻形目丘鹬科塍鹬属的鸟类。大型涉禽，以其异常长且略上翘的双色喙著称。在北美草原繁殖地常见，冬季则聚集在美国南部加州和墨西哥西部。繁殖于美国北部和加拿大南部的草甸，小群孤立地出现在詹姆斯湾西南部和阿拉斯加。云斑塍鹬的生态知之甚少，近年来才开始详细研究其繁殖和种群生物学。","appearance":"体型大，腿长，喙极长且微弯，两色，总长度42–48厘米，喙长8–13厘米；体重285–454克。繁殖羽通常呈浅褐色，上身有暗褐色斑点和条纹，下身淡黄褐色，颈部和上胸有细暗条纹，两侧、腹侧和腹部有黑条纹；喙基部亮粉至橙色；腿长而灰或蓝灰色。雌雄外观相似，但雌鸟体型更大，喙明显更长。幼鸟类似成鸟非繁殖羽，但下身无条纹，胸部无条纹，翼覆羽标记较少，腋下无条纹。","habits":"栖息于湿草地和近水的草原地带，迁徙和越冬时偏好各种浅水湿地，如泥滩、海滩、河口和咸水池塘。常与其它大型滨鸟如矶鹞和白腰杓鹬结群活动。","breeding":"在地面筑巢，通常在短草丛中。以泥滩、沼泽或海滩上的探食为生，潮退时进食，主要食物为昆虫和甲壳类，也会食用水生植物的部分。潮涨时休息，常单脚站立，头部藏于体内。","identification":"与斑尾塍鹬相比，云斑塍鹬具有明亮的肉桂色下翼和飞羽，体型略大，腿较短，喙稍短。斑尾塍鹬的翼展更长，休息时翼尖远超尾端，而云斑塍鹬的翼尖接近尾端。成年云斑塍鹬在替换羽时下体更富色彩，而非繁殖羽的斑尾塍鹬下体多为灰白色。","protection":"IUCN：VU（易危）","distribution":"繁殖于北美的次北极到温带草原：阿拉斯加半岛中部、加拿大南部至美国北部中部、詹姆斯湾西部（加拿大北部和加拿大东部）。越冬于美国南部沿海和墨西哥：华盛顿至下加利福尼亚州，加利福尼亚湾至巴拿马东部（东北太平洋）；新泽西至佛罗里达州（西北大西洋），墨西哥湾至尤卡坦半岛。","other":"19世纪末因猎杀数量减少，随后有所恢复，但因适宜栖息地转变为农田，数量再次下降。"},{"name":"翻石鹬","english_name":"Ruddy Turnstone","scientific_name":"Arenaria interpres","overview":"翻石鹬（英文名：Ruddy Turnstone，学名：Arenaria interpres），是鸻形目丘鹬科翻石鹬属的鸟类。小而健壮的鹬类，以其独特的翻石觅食行为闻名。繁殖期间，展现出醒目的羽色：头部和颈部为鲜明的黑白图案，背部和翅膀显赤色和黑色，腿部橙色。非繁殖期和幼鸟则呈较暗的棕色，但仍保留着明显的面部图案。分布广泛，主要在北极苔原繁殖，冬季则遍及全球海岸线。","appearance":"体长约22-24厘米，翼展约50-57厘米，体重介于85-150克之间。喙短且尖，略向上弯曲，长度约2-2.5厘米。腿短，约3.5厘米，鲜亮的橙色。繁殖季节，上体呈红褐色，饰以黑色斑纹，头部主要是白色，带有黑色条纹，面部有独特的黑白色调。下体主要为黑色，两侧有一块白色区域，其余部分白色。飞行时，展示白色的翼带、翼根白块、下背、臀部和尾巴，以及尾上覆羽和尾端的黑色条纹。","call":"发出断续的颤音叫声，以及在繁殖季节常见的喋喋不休的警报叫声。","habits":"偏好岩石生境，但也可见于沙滩和泥滩。通常成小群活动，经常与其他鹬类混群。主要以无脊椎动物为食，通过翻动石头、贝壳等物体来寻找隐藏的猎物。迁徙时，利用淡水岸线、泥滩、岩石岸线和沙滩。在繁殖季节外，聚集在拥有泥滩、沙滩和岩石海岸的海岸线上。","breeding":"在北极苔原地区繁殖，靠近水边的开阔地带筑巢。巢穴简单，为浅坑，可能铺有叶子。每窝产卵2-5枚，平均4枚，卵呈梨形，淡绿色至褐色，有深色斑点。孵化期约为22天，主要由雌鸟负责，雄鸟在孵化后期提供辅助。","identification":"与黑翻石鹬相似，但黑翻石鹬全身颜色更均匀，腿部为紫色棕色，而非橙色，胸部颜色更暗且均匀，下巴和喉咙总是黑色。","protection":"IUCN：NT（近危），保护级别：Ⅱ级（2021.02.05）","distribution":"繁殖区位于北美洲和欧亚大陆的高北极和低北极苔原地带。非繁殖区遍布温带海洋至全球海岸线热带地区。在中国大陆，可在沿海地区观察到。","other":"翻石鹬的迁徙路线复杂，涉及多个停歇地，如冰岛，进行脂肪储备以支持长途飞行。"},{"name":"黑翻石鹬","english_name":"Black Turnstone","scientific_name":"Arenaria melanocephala","overview":"黑翻石鹬（英文名：Black Turnstone，学名：Arenaria melanocephala），是鸻形目丘鹬科翻石鹬属的鸟类。是北美特有种，体型较小，羽色以黑白为主，繁殖于阿拉斯加沿海湿地，冬季迁至北美洲太平洋沿岸至下加利福尼亚州南部。其独特的斑马状羽毛使其在暗礁上觅食和栖息时几乎隐形。","appearance":"体长22-25厘米，重100-170克。喙短而楔形，20-27毫米长，稍上翘。全身以黑白色调为主，上体在繁殖季节呈暗褐色，带青铜光泽。头部有白色眉纹，胸前有白色斑点，腹部纯白。翅膀上有明显的白色条纹，尾部具宽黑色横带。腿部颜色暗褐带红。幼鸟较成鸟羽色偏褐，翼覆羽有淡黄色边缘。","call":"有多种叫声，尤其是一种类似颤音的连续鸣叫，全年均可听到。叫声比翻石鹬更高更尖锐。","habits":"栖息于太平洋沿岸的岩石地带，包括岩礁、码头和防波堤，偶尔出现在海滩。在繁殖季节，偏好靠近海岸的湿地。以甲壳类、软体动物和昆虫为食，利用其短而楔形的喙撬开或凿碎固定的食物，如贻贝和藤壶。","breeding":"繁殖于阿拉斯加西部，筑巢于湿草甸，常在同一地区和同一伴侣返回繁殖。巢由雄鸟挖掘，通常位于草丛或柳树下。每窝产卵四枚，孵化期21-24天，双亲共同孵卵。幼鸟孵化后不久即可独立觅食，约30天后能飞行。","identification":"与翻石鹬相比，黑翻石鹬上体和双翼的红棕色斑纹较少，腿部颜色较暗，且在繁殖期头部、上体和胸部的白色较多。","protection":"IUCN：LC（无危）","distribution":"繁殖于阿拉斯加沿海，冬季迁徙至北美洲太平洋沿岸，南至墨西哥下加利福尼亚州北部。偶尔春季和秋季迁徙时出现在内陆，如加州的萨尔顿海和美国中西部诸州。","other":"在繁殖地，它可能形成群落，特别是在育空-库斯科维姆三角洲这样的地方。"},{"name":"土岛鹬","english_name":"Tuamotu Sandpiper","scientific_name":"Prosobonia parvirostris","overview":"土岛鹬（英文名：Tuamotu Sandpiper，学名：Prosobonia parvirostris），是鸻形目丘鹬科土岛鹬属的小型鸟类，分布于法属波利尼西亚的土阿莫土群岛。其显著特征包括非常暗褐色的外表，极短而细的喙，以及独特的白色眉纹。生活在海岸线和小环礁的裸露砾石地带。","appearance":"土岛鹬体型小，长度约15.5至16.5厘米，翼展短，羽毛呈斑驳的深棕色，下体有条纹或斑点。喙短而尖锐，类似食虫的雀形目鸟类而非涉禽。存在两种色型，淡色型上体中棕色，下体白色，胸腹部有淡色条纹或斑点；深色型上体深棕色，下体淡黄褐色或淡赭白色。腿和脚呈脏黄色至暗橄榄灰色。","call":"叫声包括柔和的高音哨声或笛声，被转录为'meh'，当兴奋时会发出响亮的笛鸣和一系列上升和下降的颤音。","habits":"偏好未受干扰的环礁环境，活动于开阔地带，如海岸线、海滩和灌木丛，偶尔在Pandanus树林中。以昆虫为主食，如蚂蚁、叶蝉和黄蜂，同时也会摄取部分植被。","breeding":"繁殖季节可能较长，一般在4月至6月间，不同岛屿时间可能不同。巢穴简单，由珊瑚碎片和草茎构成，通常位于泻湖岸边。每窝产卵2枚，卵壳白色带有紫色和紫罗兰色斑点。","identification":"与其他涉禽相比，土岛鹬的极短而细的喙、白色眉纹以及暗褐色的身体使其容易识别。","protection":"IUCN：EN（濒危）","distribution":"主要分布于法属波利尼西亚的土阿莫土群岛，包括Tenararo、Morane、Reitoru、Tahanea和Raraka等岛屿。","other":"历史上曾广泛分布，但由于引入的哺乳动物捕食者（尤其是鼠类和猫）以及椰子种植园导致的栖息地破坏，目前仅在少数无鼠岛屿上生存。"},{"name":"圣诞岛鹬","english_name":"Kiritimati Sandpiper","scientific_name":"Prosobonia cancellata","overview":"圣诞岛鹬（英文名：Kiritimati Sandpiper，学名：Prosobonia cancellata），是鸻形目丘鹬科土岛鹬属的鸟类。仅存的记录源于詹姆斯·库克船长第三次环球航行期间的描述与插图。","appearance":"关于圣诞岛鹬的具体外观细节，由于仅有的信息来自一幅同时代的插图和一段描述，具体特征已无法详尽描述。然而，它被归类为小型岸鸟，可能具有类似其他沙锥鸟的基本特征。","habits":"由于资料有限，圣诞岛鹬的生活习性和生态位的具体细节不得而知，但作为滨鸟，其可能栖息于潮间带，以小无脊椎动物为食。","identification":"作为已经灭绝的物种，圣诞岛鹬与现存物种的区别无法通过直接比较得出。其特有性在于它仅存在于Kiritimati岛，且其外观特征可能具有独特的条纹或格子状图案。","protection":"IUCN：EX（已灭绝）","distribution":"圣诞岛鹬原生于太平洋上的Kiritimati岛，该岛属于莱恩群岛，位于东波利尼西亚。","other":"圣诞岛鹬的分类历史复杂，最初由Gmelin描述为Tringa cancellata，后被归入Prosobonia属。"},{"name":"大溪地矶鹬","english_name":"Tahiti Sandpiper","scientific_name":"Prosobonia leucoptera","appearance":"塔希提矶鹬长约18厘米，体色朴素，下身呈褐色，背部颜色更深，翅膀上点缀着醒目的白色斑块。头部和颈部至双翼呈现乌黑的棕色，眼睛上方有一小白斑。下巴部分呈白色，而臀部和下身则显现出锈色，翼覆羽边缘带有锈色。飞羽内侧颜色较浅，翅膀下方呈深褐色，羽缘略淡。三级覆羽上可见新月形的白色斑块。它们拥有10条主翼羽和12条舵羽。尾羽中间部分为乌黑色，尖端染有锈色。喙部黑色，下颚稍淡，短而尖，类似某些食虫鸟的喙型。脚为淡草绿色，趾间无蹼。眼睛周围环绕着淡锈色的环纹，瞳孔深褐色。","habits":"塔希提矶鹬的生活习性记载不多，但据推测它们可能栖息于小溪流附近的环境中。","protection":"IUCN：EX（已灭绝）","distribution":"塔希提矶鹬的分布仅限于太平洋中的大溪地，位于社会群岛，属于东波利尼西亚的一部分。"},{"name":"莫岛矶鹬","english_name":"Moorea Sandpiper","scientific_name":"Prosobonia ellisi","overview":"莫岛矶鹬（英文名：Moorea Sandpiper，学名：Prosobonia ellisi），是鸻形目丘鹬科土岛鹬属的鸟类。已灭绝的大型涉禽家族成员，原生于法属波利尼西亚的Mo'orea岛，当地塔希提语称之为te-te。该物种仅通过两幅基于标本（现已遗失）的画作而为人所知，这些标本是在1777年库克船长第三次航行期间于Moorea岛上收集。","appearance":"插图描绘了一种比塔希提矶鹬略浅的棕色鸟类，眼后无白色斑点，拥有更为显眼的淡锈色眼环，两条白色的翼带，以及锈色的次级和初级覆羽。其中一只Latham标本的腿和脚呈黄色。","habits":"生活在接近小溪流的环境中，1776至1779年间，即库克最后一次航行期间，该物种至少仍然相当常见。","identification":"与塔希提矶鹬相比，其颜色更浅，眼后无白色斑点，眼环更为明显，翼带和覆羽颜色有所不同。","protection":"IUCN：EX（已灭绝）","distribution":"仅限于太平洋的Moorea岛（社会群岛，东波利尼西亚）。","other":"入侵的鼠类可能是导致其灭绝的因素之一。"},{"name":"大滨鹬","english_name":"Great Knot","scientific_name":"Calidris tenuirostris","overview":"大滨鹬（英文名：Great Knot，学名：Calidris tenuirostris），是鸻形目丘鹬科滨鹬属的鸟类。体型敦实，迁徙时几乎仅限于沿海滩涂，偶尔出现在内陆。繁殖羽翼上有赤褐色横斑，非繁殖期羽色转为淡灰褐色，上体有灰色斑点。分布于东北亚至澳大利亚，冬季可见于东南亚、阿拉伯、印度等地。","appearance":"大滨鹬长约26-28厘米，体重介于115-248克，翼展可达56-66厘米。繁殖期成鸟翼上具砖橙色斑块，背部黑色，胸前布满黑色斑点。非繁殖期和幼鸟上体灰褐色，下体白色，颈部和上胸有灰色斑点。比红腹滨鹬体型更大，喙较长。","call":"大滨鹬的飞行叫声为尖锐的哨音，类似于“kweet-kweet”。","habits":"大滨鹬栖息于亚北极的高原苔原，迁徙期间常出现在沿海泥滩、沙洲及河流湖泊岸边。主要食物包括甲壳类、软体动物、昆虫及其幼虫，通过探觅或视觉觅食。","breeding":"繁殖期为6月至8月，筑巢于西伯利亚北部冻原地带，巢为地面凹坑，内铺枯草和苔藓，每窝产卵4枚，卵呈灰黄色，带有红褐色斑点。","identification":"与红腹滨鹬相比，大滨鹬非繁殖羽更淡，喙更长，胸部和两胁有明显的黑色斑点。","protection":"IUCN：EN（濒危）国家重点保护野生动物名录新增，保护级别：Ⅱ级（2021.02.05）","distribution":"繁殖区位于东北亚低北极和亚北极高山苔原地带，非繁殖区广泛分布于阿拉伯半岛南部沿海、东南亚、印尼群岛、台湾岛、中国大陆东南部、菲律宾、新几内亚、澳大利亚及塔斯马尼亚。","other":"自2000年以来，由于韩国Saemanguem地区潮间带的填海工程，全球大滨鹬数量减少了至少9万只。"},{"name":"红腹滨鹬","english_name":"Red Knot","scientific_name":"Calidris canutus","overview":"红腹滨鹬（英文名：Red Knot，学名：Calidris canutus），是鸻形目丘鹬科滨鹬属的鸟类。一种中等体型的滨鹬，体长约为24厘米，以其独特的繁殖羽著称，下体呈鲜艳的橙红色，上体则为银灰色，带有复杂的花纹。繁殖于北极圈内的高寒冻原地带，主要分布在北美、欧洲和俄罗斯的北极地区。红腹滨鹬是长途迁徙鸟类，迁徙路线跨越全球，冬季时可见于南美、非洲、欧洲、澳大利亚和新西兰的海岸线。","appearance":"红腹滨鹬体型敦实，喙和腿均较短。繁殖羽下体橙红色，上体银灰色，有精细的花纹。非繁殖期整体呈灰色，腹部较淡，有白色的眉纹。腿部颜色暗绿或灰。雄鸟通常比雌鸟色彩更鲜艳，下体的橙色更为显著。","call":"红腹滨鹬的叫声为低沉的喉音，进食时会发出悦耳的叽喳声。","habits":"红腹滨鹬在繁殖期栖息于北极冻原地带，冬季则迁徙至全球各地的海岸、河口，甚至内陆河流与湖泊。它们常单独或小群活动，冬季则集结成大群。主要食物为软体动物、甲壳类、昆虫及幼虫等小型无脊椎动物，偶尔也会摄食植物的嫩芽和种子。","breeding":"繁殖期为6月至8月，营巢于冻原山地和低山丘陵，巢为地面上的浅坑，内铺有枯草和苔藓。每窝产卵4枚，卵色为橄榄绿色或橄榄皮黄色，带有褐色或黑褐色斑点，由雌雄双方轮流孵卵。","identification":"与三趾鹬和黑腹滨鹬在非繁殖羽时最为相似，但红腹滨鹬体型更大，喙更短。与大滨鹬相比，后者体型更大，腿更长，喙更细长。","protection":"IUCN：NT（近危）","distribution":"繁殖于北极圈内的高寒冻原地带，包括格陵兰岛西北部、欧亚大陆北部、西伯利亚东北部和楚科奇半岛北部。冬季广泛分布于全球温带至热带的海岸线，包括南美、欧洲、非洲、澳大利亚和新西兰。","other":"红腹滨鹬是长途迁徙鸟类，具有极长的迁徙距离，其迁徙路线和时间策略受气候变迁影响显著。"},{"name":"短嘴鹬","english_name":"Surfbird","scientific_name":"Calidris virgata","overview":"短嘴鹬（英文名：Surfbird，学名：Calidris virgata），是鸻形目丘鹬科滨鹬属的鸟类。小型涉禽，特征为短而粗的喙，橙黄色基部，暗黄腿脚。繁殖期腹部斑点增多，背部出现锈色斑块。常见于岩石海岸线，尤其偏爱靠近波浪冲击区域。","appearance":"短嘴鹬体长约23.5至25.5厘米，体重介于133至230克。繁殖羽时，头部、胸部和腹部呈白色，密布灰黑条纹与斑点；背部黑色，肩羽具锈色标记。非繁殖羽时，头、胸及背部灰色，眼圈白，下颏及眉纹白色，其余腹部白色，带少许深棕色条纹。喙短直而钝，基部橙黄；腿脚短且黄色。飞行时可见明显的白色翼带，尾部黑白相间。","call":"鸣叫特征未详述。","habits":"短嘴鹬偏好栖息于岩石海岸线，尤其在繁殖季节，选择偏远的岩石山脉，主要在阿拉斯加。常见于波浪冲击的岩石上，较少出现在沙滩，尤其是迁徙期间。通常群居，常与翻石鹬混群。","breeding":"繁殖期在早春五月，筑巢于北面或西面斜坡的裸露地带，巢由苔藓和山毛榉组成。每窝产卵4枚，双亲共同孵卵，孵化期估计为22至24天。雏鸟出生即能自立行走。","identification":"与黑翻石鹬相似，但短嘴鹬体型更大，腿脚黄色，背部有斑点，下颌基部橙黄色。比岩滨鹬大，喙更短直。与漂鹬相比，体型略小，喙较长，尾部更长。与红腹滨鹬幼鸟相比，颜色更淡，喙长且侧腹有淡色条纹。","protection":"IUCN：LC（无危）","distribution":"繁殖于北美低北极到亚北极的近北冰洋苔原地带，包括阿拉斯加大陆（除最北部）和加拿大西北部的育空地区。非繁殖期分布于北美西部太平洋岩石海岸，从阿拉斯加东南部至南美洲火地岛的东太平洋岩石海岸。","other":"无"},{"name":"流苏鹬","english_name":"Ruff","scientific_name":"Calidris pugnax","overview":"流苏鹬（英文名：Ruff，学名：Calidris pugnax），是鸻形目丘鹬科滨鹬属的鸟类。以其显著的颈部饰羽著称。繁殖雄鸟的颈饰色彩丰富，可为黑色、白色、棕色、红棕色或混合色。非繁殖期的个体和雌鸟外观较朴素，通常为灰褐色，腹部下方和尾下覆羽为白色。广泛分布于北极和亚北极地区的沼泽和草甸，迁徙时可见于欧洲、非洲、印度和东南亚等地。","appearance":"流苏鹬为中型涉禽，雄鸟体长26-32厘米，体重130-254克；雌鸟体长20-25厘米，体重70-170克。繁殖雄鸟头部饰羽和颈饰色彩多样，包括黑色、白色、棕黄色、红棕色、赭色或白色，面部疣子呈黄色至棕色。雌鸟较小，上体颜色变化大，下体通常暗色，腹部和尾下覆羽为白色。喙部颜色从棕色到暗橙色，腿部颜色从黄绿色到深橙色。幼鸟上体暗褐色，边缘为亮褐色，胸前和腹部为红褐色和缓冲色。","call":"流苏鹬在繁殖季节几乎不发声，其声音基本限于短促、低沉的喉音。","habits":"流苏鹬在繁殖季节栖息于北极和亚北极地区的沼泽、湿地和草甸，冬季迁徙至欧洲西部、非洲撒哈拉以南、中东、印度次大陆、东南亚、大巽他群岛和菲律宾等地。非繁殖季节偏好栖息于湖泊、池塘、河流、沼泽和泛滥平原的泥泞边缘，包括咸水、盐水或碱性水域。迁徙时，常见于欧洲西部的海岸线和新割草或短牧草地。夜间和日间都会觅食。","breeding":"繁殖期为5月至8月，流苏鹬采取多配偶制，雄鸟在传统求偶场进行复杂的求偶展示。雌鸟独自筑巢，巢位于草丛中或有植被遮蔽的地面上，一般较为隐蔽。每窝产卵通常为4枚，孵化期为20-23天，仅由雌鸟承担孵化和抚育幼鸟的责任。雏鸟出生后约25-28天离巢。","identification":"流苏鹬与红脚鹬相似，但流苏鹬喙更短且略下弯，腿更长，颜色从深灰至鲜橙不等。繁殖雄鸟的颈部饰羽颜色各异，是主要的辨识特征。雌鸟和非繁殖期的雄鸟外观较朴素，需通过细节特征区分。","protection":"IUCN：LC（无危）","distribution":"繁殖于北极和亚北极地区，从比利时、斯堪的纳维亚半岛经乌克兰北部、哈萨克斯坦西北部、蒙古北部至远东西伯利亚。冬季迁徙至非洲、中东、印度次大陆、东南亚、菲律宾、东亚部分地区，如中国东部、台湾和日本中部至南部，以及印尼群岛的较少数量。","other":"流苏鹬的繁殖范围在过去200年间有所收缩，尤其是在南部，主要是由于湿地排水导致。近年来，其在俄罗斯东部的繁殖范围和数量有所增加。"},{"name":"阔嘴鹬","english_name":"Broad-billed Sandpiper","scientific_name":"Calidris falcinellus","overview":"阔嘴鹬（英文名：Broad-billed Sandpiper，学名：Calidris falcinellus），是鸻形目丘鹬科滨鹬属的鸟类。上体暗色，与白色下体及纵纹胸部形成鲜明对比。繁殖于北极圈内的冻原沼泽地带，非繁殖季节广泛分布于东非至东南亚，澳大利亚等地。在迁徙和越冬时常见于海边和河口地带。","appearance":"阔嘴鹬体长16-18厘米，体重28-68克，翼展34-37厘米。喙长而宽，稍向下弯曲，头顶有明显的眉纹，腿短。繁殖季节成鸟背部黑褐色，边缘泛白，翼覆羽灰褐色；非繁殖季节成鸟上体灰褐色，具暗色条纹，下体白色，胸腹部有淡色纵纹。幼鸟上体有栗色和白色边缘，翼覆羽淡棕色，胸部呈淡棕色，有模糊的褐色纵纹。雌鸟平均体型略大于雄鸟。","call":"发出干燥的哨音‘dree-it, dree-it’和点击声‘dik dik’。","habits":"栖息于冻原和冻原森林地带的湖泊、河流、水塘和芦苇沼泽岸边，冬季移居至海岸、河口及附近沼泽湿地。常单独、成对或小群活动，非繁殖期有时形成大群。喜在海边潮间带松软泥地上觅食，以甲壳类、软体动物、蠕虫等小型无脊椎动物为主食，偶尔摄取植物种子。","breeding":"繁殖期为6月至7月，营巢于离水域不远的苔原草地上或沼泽草地中的土丘上，巢内铺垫有树叶和苔藓，每窝产卵4枚，卵色淡褐色或黄灰色，密布淡红褐色斑点，雌雄鸟轮流孵化。","identification":"与其它滨鹬属鸟类相比，阔嘴鹬的头部图案更为明显，尤其在冬季羽毛中。喙部的特征和体型大小也是辨识关键。","protection":"IUCN：VU（易危）。被列入中国国家重点保护野生动物名录，保护级别为二级（2021.02.05）。","distribution":"繁殖于北极圈内的欧亚大陆北部，从斯堪的纳维亚半岛至俄罗斯西北部和西伯利亚东北部。非繁殖季节分布于东非、红海和波斯湾，经东南亚、印度尼西亚群岛、新几内亚南部至澳大利亚（除西南部、东南部和塔斯马尼亚岛）。在中国主要为过境鸟。"},{"name":"尖尾滨鹬","english_name":"Sharp-tailed Sandpiper","scientific_name":"Calidris acuminata","appearance":"中型滨鹬，身长17-22厘米，体重雄鸟53-114克，雌鸟39-105克，翼展36-43厘米。繁殖成鸟有醒目的栗色帽状羽毛，上体深褐色，边缘带有栗色和白黄色；颈和胸部分布着深色条纹；下胸、上腹和两侧有厚重的黑色V形斑；腿色由黄到绿或棕；喙黑色，下颚基部带棕色或粉红色；飞行时可见狭窄的白色翼带和深色臀部及尾覆羽两侧的白色。非繁殖成鸟颜色较暗，胸部灰色，有淡色条纹，与白色腹部界限不明显。幼鸟色彩鲜明，上体有亮黄色、栗色和白黄色边缘，顶冠栗色，有醒目的白色眉纹；胸部亮黄色，有时有淡色条纹形成窄的颈环；两侧洗染黄色，随年龄增长而变暗。","call":"发出柔和的颤抖声'treeep'，特别是在飞行中。","habits":"尖尾滨鹬繁殖期栖息于西伯利亚的冻原平原，偏好有稀疏小柳树和苔原植物的湖泊、水塘、溪流岸边和附近的沼泽地带。非繁殖期则主要出现在海岸、河口以及附近的低草地和农田地带。通常单独或小群活动，食物丰富时会集结大群。受惊时会迅速形成紧密群体并快速协调飞行。在有低矮草本植物的水边干草地上或浅水处活动和觅食，有时在海边潮间带活动。主要以蚊子和其他昆虫幼虫为食，也吃小螺、甲壳类、软体动物和其他小型无脊椎动物，偶尔食用植物种子。","breeding":"繁殖于西伯利亚冻原带，繁殖期为6月至8月。巢筑于湿地和小柳树灌丛地区的草丛下的地面凹坑内，巢内铺有柳树叶。每窝产卵4枚，卵色橄榄褐色或绿色，带有黑褐色斑点，卵大小约39×27毫米。","identification":"与美洲尖尾滨鹬相似，但布满纹路的胸部和白色的腹部之间有明显的分界线。与长趾滨鹬相比，体型更大。","protection":"IUCN：VU（易危）","distribution":"繁殖区位于西伯利亚东北部的北极到亚北极冻原地带，从勒拿河到科雷马河（东北西伯利亚）。非繁殖区覆盖了新几内亚、澳大利亚、美拉尼西亚、新西兰和斐济（西南太平洋），以及华莱士线的沿海和内陆地区。极有可能发生极端迷鸟现象，到达北美洲和欧洲。","other":"尖尾滨鹬具有强烈的迁徙习性，从夏季的繁殖地到冬季的越冬地，途经多个国家和地区。"},{"name":"高跷鹬","english_name":"Stilt Sandpiper","scientific_name":"Calidris himantopus","overview":"高跷鹬（英文名：Stilt Sandpiper，学名：Calidris himantopus），是鸻形目丘鹬科滨鹬属的鸟类。中等体型的滨鹬属涉禽，以其独特的长腿和长喙著称。繁殖季节的成鸟拥有引人注目的黑白条纹下体和橙色脸颊，非繁殖期则呈现淡灰色调，具白色眉线。分布于北美洲北极苔原地带，迁徙期间可见于北美中部，冬季则主要在南美洲内陆。","appearance":"中等体型，约20至23厘米长，体重50至70克，长腿、长颈和长喙为其显著特征。繁殖羽时，下体重度斑驳，上体有红褐色斑块，非繁殖羽则背部呈棕色，喉部和胸部灰白色，腹部白色。雄鸟头部红褐色羽毛较亮且更广泛，下体条纹比雌鸟更明显。","call":"未提供具体描述。","habits":"栖息于北极苔原的湿地，迁徙时偏好淡水环境，包括沼泽、水淹田野和浅水池塘。常与黄腿鹬和鸻鹬混群活动，以软泥中的无脊椎动物为食。","breeding":"地面筑巢，每窝产卵三至四枚。雄鸟有展示飞行的行为。繁殖季外，通常在内陆水域而非开阔海岸活动。","identification":"与较小的滨鹬属物种相似，但腿更长且颜色更淡，缺乏明显的翼带。与弯嘴滨鹬相比，腿更长，颜色更浅，无明显的翼带。","protection":"IUCN：NT（近危）","distribution":"繁殖于北美洲北极苔原，包括阿拉斯加北部斜坡和加拿大北部至维多利亚岛北部；非繁殖期分布于墨西哥沿海和整个西印度群岛，中美洲太平洋沿岸，南美洲沿海至秘鲁和巴西北部，阿根廷北部潘帕斯草原。","other":"曾被认为属于独特单型属Micropalama，现归入Calidris属。"},{"name":"弯嘴滨鹬","english_name":"Curlew Sandpiper","scientific_name":"Calidris ferruginea","overview":"弯嘴滨鹬（英文名：Curlew Sandpiper，学名：Calidris ferruginea），是鸻形目丘鹬科滨鹬属的鸟类。小型涉禽，以其长而稍向下弯曲的喙著称。繁殖于西伯利亚北部的苔原地带，冬季迁徙至非洲、南亚、东南亚和澳大利亚等地。体长约18至23厘米，重约44至117克，展翅宽38至46厘米。成鸟繁殖季节头部和身体呈深锈色，非繁殖期羽毛灰白相间。","appearance":"弯嘴滨鹬的特征在于其中等体型，长颈、长腿和长而向下弯曲的喙。繁殖羽色为深锈色至深栗红色，头顶有暗色条纹，背部和肩羽为深棕色，边缘呈红棕色和白色。非繁殖羽色上身灰，下身白，具对比明显的白色眉纹，胸侧略带灰色。幼鸟上体灰色，边缘有白色，下体白色，胸部有淡黄色洗染，几乎无条纹。","call":"飞行中发出悦耳、柔和的啾啾声，如'chirrip'、'chirrup'或'chirririp'，与黑腹滨鹬叫声相似，但缺乏粗糙的音质。","habits":"繁殖期间，主要栖息于高北极的低地苔原，沿岸和岛屿，偏好带有沼泽洼地和池塘的开阔苔原。非繁殖期，主要栖息于海岸线，包括潮汐滩涂、沿海泻湖、河口和盐沼。在迁徙和冬季，也会出现在内陆的沼泽边缘、大河、湖泊、盐田、灌溉系统和泛滥平原。迁徙时能长途不间断飞行，雄鸟有高度的地点忠诚度。","breeding":"繁殖期为6月至7月，巢址位于沼泽边缘、池塘旁或苔原干燥地带。平均产卵数为3.8枚，间隔一天产一枚，仅雌鸟孵化，孵化期19至20天，雏鸟由雌鸟照顾，约14至16天后离巢。繁殖成功率受田鼠数量影响，低田鼠年份北极狐捕食增多。","identification":"与黑腹滨鹬相比，弯嘴滨鹬略大，喙更细长且腿更长。飞行时注意腰部的大片白斑。繁殖羽色与红腹滨鹬相似，但非繁殖期羽毛有明显差异，尤其是白色的眉纹和灰白相间的下体。","protection":"IUCN：VU（易危）。由于东亚-澳大利西亚迁徙路线上黄海区域的潮间带停歇地因围垦而丧失，导致该区域滨鸟种群下降。","distribution":"繁殖于西伯利亚北极地带，从亚马尔半岛至楚科奇半岛东北部。冬季迁徙至非洲、中东、南亚、东南亚和澳大利亚等地。在中国大陆，主要出现在沿海滩涂及近海的稻田和鱼塘。","other":"曾在美国阿拉斯加北部不规则繁殖，但数量稀少。在南非、澳大利亚等地的观察显示，自1975年至2009年间数量显著减少，可能与全球变暖有关。"},{"name":"青脚滨鹬","english_name":"Temminck's Stint","scientific_name":"Calidris temminckii","overview":"青脚滨鹬（英文名：Temminck's Stint，学名：Calidris temminckii），是鸻形目丘鹬科滨鹬属的鸟类。体型小而健壮，腿部呈黄绿色，上体在冬季为暗灰色，胸部转为灰色，逐渐过渡至近白色的腹部，最显著特征为纯白的外侧尾羽。主要栖息于北极苔原地带，繁殖季节可见于北欧及亚洲北部，越冬时则迁徙至非洲热带、印度次大陆、东南亚乃至中国南部。在云南、台湾、福建、广东及香港等地有记录。","appearance":"青脚滨鹬体长13.5-15厘米，体重15-36克，翼展可达34-37厘米。其腿短且颜色黄绿，背部至尾部的羽毛宽大且两侧闪现白色，与同属其他物种形成鲜明对比。成鸟的上体颜色从暗灰到橄榄棕不等，头部和胸部呈灰棕色，胸部有深棕色条纹，下颌、喉部和腹部为白色。雌鸟平均比雄鸟稍大，体现在翅膀、喙和跗跖长度以及体重上。非繁殖季成鸟上体和头部为单一暗灰色，胸部为淡灰棕色；雏鸟类似非繁殖季成鸟，但上体羽毛为棕色带暗端斑和浅色边缘。","call":"发出单个短促、清晰的‘tirr’或‘trrrrit’声作为接触或警报信号，尤其是在被惊扰或飞行时。在展示飞行中，雄鸟会在离地面约1米的高度，偶尔高达10米，发出连续起伏的‘kililililili...’或‘sirrrrrrrr...’声，声音类似黑斑蝗莺的鸣唱，但更响亮且不那么机械。","habits":"青脚滨鹬偏好内陆淡水环境，如泛滥平原、灌溉农田、污水处理场和植被密集的湿地。繁殖季节栖息于北极苔原的沼泽和森林沼泽地带，海拔高度可达1200米。迁徙时，以小规模群体移动，最多可达150-250只，不如小滨鹬那样群居。越冬时广泛分布于非洲、亚洲南部、东南亚、马来西亚半岛和婆罗洲等地。","breeding":"繁殖期为5月末至7月初，实行连续一夫多妻制，偶有三窝产卵。巢筑于地面，直径约85毫米，位于开阔或低矮植被中，由植物茎叶衬里。每窝产卵2-4枚，卵色为绿灰至淡黄色，表面有棕色斑点，平均尺寸28mm x 20.4mm。每窝由一方亲鸟独自孵化，孵化期21-22天，自最后一枚卵开始。雏鸟孵化后15-18天离巢。","identification":"青脚滨鹬与小滨鹬的区别在于后者腿色更深、尾羽外侧为灰色而非白色。在非繁殖季节，青脚滨鹬的暗灰色上体和头部以及淡灰棕色胸部也是辨识要点。此外，青脚滨鹬的叫声和展示飞行中的特殊鸣唱也有助于识别。","protection":"IUCN：LC（无危）。全球估计有100万至1000万对青脚滨鹬在1980-1990年间于俄罗斯繁殖。然而，气候变化可能对该物种造成负面影响，特别是在北方和寒带地区，已报告芬兰局部种群下降。","distribution":"繁殖区域覆盖北极苔原，从北欧延伸至俄罗斯东北部的楚科奇半岛，包括新西伯利亚群岛。越冬区遍及非洲热带、中东、印度次大陆、东南亚至马来半岛、婆罗洲、日本西南部、中国东部和台湾","other":"青脚滨鹬有记录显示可能与小滨鹬杂交。"},{"name":"长趾滨鹬","english_name":"Long-toed Stint","scientific_name":"Calidris subminuta","overview":"长趾滨鹬（英文名：Long-toed Stint，学名：Calidris subminuta），是鸻形目丘鹬科滨鹬属的鸟类。名称来源于希腊语kalidris，意指灰色水边鸟，特定名subminuta源自拉丁语，意为‘接近小型’，因其与小滨鹬相似。繁殖于北部亚洲，迁徙至东南亚和澳新界过冬。在欧洲西部极为罕见。","appearance":"体长13-16厘米，体重20-37克，翼展26-35厘米。拥有纤细的颈部、腿和长趾，通常看起来比小滨鹬更修长。繁殖成鸟和亚成鸟的羽色与青脚滨鹬相似，非繁殖成鸟上体呈褐色，下体偏白。雌鸟平均略大些。黄色腿，短而尖锐的黑色喙，仅下颚基部黄或浅棕色。上体羽毛有深棕色中心，边缘为红褐色和淡黄色。飞行时长趾略微超出尾羽。","call":"鸣唱为一系列连续的咕噜声。飞行叫声包括颤音'chee'或'prrrt'，以及柔和滚动的'kurrip'，类似麻雀或红颈滨鹬的声音，还有短促的'prit'。","habits":"栖息于亚北极到温带的沼泽地，偏好内陆湿地，如稻田，及沿海和近海淡水和咸水湿地的泥泞或植被边缘。在非繁殖季节，喜独居或小群活动，偶尔与其他滨鹬混群。以昆虫、小型软体动物、甲壳类和种子为食，常在水边植被中觅食。","breeding":"繁殖期为6月初至7月，可能单配偶制。散居繁殖，巢为浅凹处，铺满树叶，藏匿良好。每窝产四枚卵，有时三枚，双亲轮流孵化，雄鸟照料雏鸟。具体繁殖细节未知。","identification":"与红颈滨鹬相比，更纤细，体型稍小，色彩更鲜明，翼纹较弱。与北美美洲小滨鹬非常相似，但颈部更长，趾更长，颜色更亮。在地面时，可与红颈滨鹬混淆，但长趾滨鹬更为精致，体型略小。","protection":"IUCN：LC（无危）。全球数量估计在25,000至100,000只之间，澳大利亚的淡水湿地有规律的迁徙记录，每年最多记录277只。无具体威胁，但信息较少。","distribution":"繁殖于西伯利亚南部至楚科奇半岛、库页岛北部、科曼德群岛、蒙古北部。非繁殖期分布于印度、斯里兰卡、东南亚、印尼群岛、澳大利亚西部和东南部、菲律宾、中国东南部、台湾和日本南部。","other":"长趾滨鹬在迁徙期间可见于中国华东及华中的大部分地区，冬季在台湾、广东及香港越冬。"},{"name":"勺嘴鹬","english_name":"Spoon-billed Sandpiper","scientific_name":"Calidris pygmaea","overview":"勺嘴鹬（英文名：Spoon-billed Sandpiper，学名：Calidris pygmaea），是鸻形目丘鹬科滨鹬属的鸟类。又名: 琵嘴鹬或匙嘴鹬，小型的滨鹬，拥有独特的勺状喙尖。繁殖于西伯利亚东北部海岸冻原地带，冬季迁徙至东南亚的湿地。自1970年代以来，其数量显著下降，目前全球仅存不到100对，处于极度濒危状态。","appearance":"体长约14-16厘米，体重约29.5克（雄鸟平均值），翼展32-38厘米。繁殖季节的成鸟头部、颈部和胸部呈红褐色，背部黑色带淡褐色和浅锈色边缘。非繁殖季成鸟及亚成鸟头部无红褐色，冠部有细条纹，耳部有深色斑，整体较红颈滨鹬苍白。喙端呈勺形。","call":"发出柔和的‘prreee’叫声。","habits":"繁殖期栖息于北极海岸冻原沼泽、草地和水域岸边。非繁殖期栖息于海岸与河口地区的浅滩与泥地上，主要在水边浅水处和松软的烂泥地上觅食。食物包括昆虫、昆虫幼虫、甲壳类和其他小型无脊椎动物。","breeding":"繁殖于西伯利亚东北部海岸冻原地带，繁殖期6-7月。营巢于淡水塘边的苔藓草地上，巢由苔藓、枯草和柳叶构成。每窝产卵3-4枚，卵淡褐色，带有褐色斑点。","identification":"与红颈滨鹬相似，但勺嘴鹬喙端呈勺形，头部颜色更深，红褐色延伸至下胸。非繁殖季成鸟和亚成鸟头部无红褐色，有明显条纹和深色耳部斑。","protection":"IUCN：CR（极危）","distribution":"繁殖于俄罗斯东北部，楚科奇半岛至堪察加半岛北部。越冬地主要分布在泰国、缅甸和孟加拉国，记录显示也出现在中国东部、台湾、印度南部、斯里兰卡等地。","other":"自2011年起，英国启动了紧急保护计划，以应对勺嘴鹬数量的急剧下降。"},{"name":"红颈滨鹬","english_name":"Red-necked Stint","scientific_name":"Calidris ruficollis","overview":"红颈滨鹬（英文名：Red-necked Stint，学名：Calidris ruficollis），是鸻形目丘鹬科滨鹬属的鸟类。非繁殖期广泛分布于南亚、东南亚、澳大利亚等地。头部鲜橙色，翼上覆羽亮橙色带金色调，非繁殖期上体灰色，下体淡色，亚成鸟上体灰褐色，边缘淡色。飞行叫声为高而尖锐的“krreeet”。","appearance":"体长13-17厘米，翼展28-37厘米，体重21-51克。繁殖成鸟头部鲜橙色，翼上覆羽亮橙色并有金色调。非繁殖成鸟上体灰色，下体淡色；亚成鸟上体灰褐色更浓，边缘淡色。腿黑色，喙细长。冬羽灰色较深，羽色单调。","call":"飞行叫声为高而尖锐的“krreeet”，另有被描述为干涩的“churi”和叽叽喳喳的“chrit-chrit”或“chreek”，叫声比其他滨鹬更高更尖。","habits":"栖息于低海拔山地苔原带，偏好干燥、稍高的苔原环境。非繁殖季节多见于沿海泥滩、隐蔽的港湾、泻湖，也会出现在各种淡水、咸水湿地，偶尔光顾沙滩和岩石海岸。成群迁徙，使用多个中途停歇地。","breeding":"繁殖期为6月至8月，营巢于苔原植物丛中，每窝产卵4枚，偶尔3枚。卵色赭或黄，带有红色斑点，孵化期20.5-22天，双亲共同孵化，雄鸟照顾幼鸟直至离巢，孵化后16-17天幼鸟离巢。","identification":"与长趾滨鹬的区别在于其冬羽灰色更深，羽色更单调，腿黑色。较之长趾滨鹬更倾向于滨海环境。","protection":"IUCN：NT（近危）全球数量约31.5万只，由于全球变暖导致适宜的繁殖栖息地可能减少近50%，以及迁徙途中重要停歇地的丧失，种群面临下降风险。","distribution":"繁殖于北极圈内东北欧亚大陆，从泰梅尔半岛东至楚科奇半岛，南至堪察加半岛北部。非繁殖季节分布于印度东部、斯里兰卡、东南亚、印度尼西亚群岛、新几内亚、澳大利亚、美拉尼西亚、新西兰、菲律宾至日本南部的琉球群岛。","other":"红颈滨鹬在东亚-澳大利西亚迁飞路线上，因黄海区域重要停歇地的丧失，种群数量在过去50年显著下降，目前已被列为近危物种。"}];
